              <button id="startDocumentJobButton" class="primary" type="button" title="Create a document job. The file is streamed to the backend, then OCR/translation runs with checkpointed progress."><i class="ri-play-line"></i><span>Start</span></button>
              <button id="cancelDocumentJobButton" class="danger" type="button" disabled title="Request cancellation for the active document job. Finished checkpoint artifacts remain on disk."><i class="ri-stop-line"></i><span>Cancel</span></button>
              <button id="refreshDocumentJobsButton" type="button" title="Reload recent document jobs and the selected job status."><i class="ri-refresh-line"></i><span>Refresh</span></button>
            </div>
            <details class="document-details">
              <summary><span>advanced options</span><span id="documentRuntimeSummary">-</span></summary>
              <div class="document-details-body">
                <div class="document-form-grid">
                  <div class="field" title="Auto detects the input format from file extension and MIME type. Override only when the source was detected incorrectly.">
                    <label for="documentSourceKind">source kind</label>
                    <select id="documentSourceKind">
                      <option value="auto">auto</option>
                      <option value="pdf">pdf</option>
                      <option value="docx">docx</option>
                      <option value="pptx">pptx</option>
                      <option value="xlsx">xlsx</option>
                      <option value="image">image</option>
                      <option value="html">html</option>
                      <option value="markdown">markdown</option>
                      <option value="text">text</option>
                    </select>
                  </div>
                  <div class="field" title="Optional page range for document jobs, for example 1-20 or 1,3,8-12. Leave blank to process the whole file.">
                    <label for="documentPageRange">page range</label>
                    <input id="documentPageRange" autocomplete="off" placeholder="">
                  </div>
                  <div class="field" title="OCR language hint passed to the local OCR engine. Use auto or blank when the document language is mixed or unknown.">
                    <label for="documentOcrLanguage">ocr language</label>
                    <input id="documentOcrLanguage" autocomplete="off">
                  </div>
                  <div class="field" title="OCR preference for routing and preprocessing. Runtime follows current OCR settings; high accuracy and layout modes may be slower.">
                    <label for="documentOcrPreference">ocr preference</label>
                    <select id="documentOcrPreference">
                      <option value="">runtime</option>
                      <option value="balanced">balanced</option>
                      <option value="fast">fast</option>
                      <option value="high_accuracy">high accuracy</option>
                      <option value="layout">layout</option>
                    </select>
                  </div>
                </div>
