      apiSuppliersExpanded: false,
      hotkeys: [],
      hotkeyQuery: "",
      hotkeyRecordingAction: "",
      hotkeyKeyboardFocusAction: "",
      hotkeyBusy: false
    };

    window.openApiSupplierModalFromButton = event => {
      if (event) {
        event.preventDefault();
        event.stopPropagation();
        if (typeof event.stopImmediatePropagation === "function") {
          event.stopImmediatePropagation();
        }
      }

      const button = event && event.currentTarget instanceof HTMLButtonElement
        ? event.currentTarget
        : $("floatingAddSupplierButton") || $("addSupplierHeaderButton") || $("addSupplierButton");
      const originalDisabled = button ? button.disabled : false;
      if (button) {
        button.disabled = true;
      }

      Promise.resolve(openSupplierModal(null))
        .catch(error => {
          const message = error && error.message ? error.message : String(error || "Failed to open supplier dialog.");
          try { playUiSound("error"); } catch { /* sound is optional */ }
          try { appendMessage("error", "suppliers", message); } catch { window.alert(message); }
        })
        .finally(() => {
          if (button) {
            button.disabled = originalDisabled;
          }
        });

      return false;
    };

    const RUNTIME_LOCAL_PROVIDERS = Object.freeze(["llama-cpp", "ollama", "hybrid", "mock"]);
    const RUNTIME_API_PROVIDERS = Object.freeze(["api-compatible", "deepl"]);
    const RUNTIME_MODEL_TASK_META = Object.freeze({
      auto: { key: "runtime.task.auto", label: "Auto" },
      realtime: { key: "runtime.task.realtime", label: "Realtime" },
      ocr: { key: "runtime.task.ocr", label: "OCR" },
      document: { key: "runtime.task.document", label: "Document" },
      text: { key: "runtime.task.text", label: "Text" }
    });
    const RUNTIME_MODEL_SCOPE_META = Object.freeze({
      all: { key: "runtime.scope.all", label: "All" },
      local: { key: "runtime.scope.local", label: "Local" },
      api: { key: "runtime.scope.api", label: "API" },
      installed: { key: "runtime.scope.installed", label: "Installed" },
      installable: { key: "runtime.scope.installable", label: "Installable" }
    });
    const RUNTIME_MODEL_GROUP_KEYS = Object.freeze(["recommended", "installed", "installable"]);

    function defaultRuntimeModelGroupOpen() {
      return RUNTIME_MODEL_GROUP_KEYS.reduce((result, key) => {
        result[key] = true;
        return result;
      }, {});
    }

    function normalizeRuntimeModelTask(value) {
      return Object.prototype.hasOwnProperty.call(RUNTIME_MODEL_TASK_META, value) ? value : "auto";
    }

    function normalizeRuntimeModelScope(value) {
      return Object.prototype.hasOwnProperty.call(RUNTIME_MODEL_SCOPE_META, value) ? value : "all";
    }

    function loadRuntimeModelMenuPreferences() {
      const fallback = {
        touched: false,
        advancedOpen: false,
        groupOpen: defaultRuntimeModelGroupOpen()
      };

      try {
        const parsed = JSON.parse(window.localStorage.getItem(RUNTIME_MODEL_MENU_STORAGE_KEY) || "null");
        if (!parsed || parsed.touched !== true) {
          state.runtimeModelMenuPrefs = fallback;
          state.runtimeModelTask = "auto";
          state.runtimeModelScope = "all";
          return;
        }

        const groupOpen = defaultRuntimeModelGroupOpen();
        for (const key of RUNTIME_MODEL_GROUP_KEYS) {
          if (typeof parsed.groupOpen?.[key] === "boolean") {
            groupOpen[key] = parsed.groupOpen[key];
          }
        }

        state.runtimeModelMenuPrefs = {
          touched: true,
          advancedOpen: parsed.advancedOpen === true,
          groupOpen
        };
        state.runtimeModelTask = normalizeRuntimeModelTask(parsed.task);
        state.runtimeModelScope = normalizeRuntimeModelScope(parsed.scope);
      } catch {
        state.runtimeModelMenuPrefs = fallback;
        state.runtimeModelTask = "auto";
        state.runtimeModelScope = "all";
      }
    }

    function saveRuntimeModelMenuPreferences() {
      try {
        const prefs = state.runtimeModelMenuPrefs || {};
        const payload = {
          touched: true,
          task: normalizeRuntimeModelTask(state.runtimeModelTask || "auto"),
          scope: normalizeRuntimeModelScope(state.runtimeModelScope || "all"),
          advancedOpen: prefs.advancedOpen === true,
          groupOpen: {
            ...defaultRuntimeModelGroupOpen(),
            ...(prefs.groupOpen || {})
          }
        };
        state.runtimeModelMenuPrefs = payload;
        window.localStorage.setItem(RUNTIME_MODEL_MENU_STORAGE_KEY, JSON.stringify(payload));
      } catch {
        // Preference persistence is non-critical; keep the current in-memory UI state.
      }
    }

    function setRuntimeModelGroupOpen(groupKey, open) {
      if (!RUNTIME_MODEL_GROUP_KEYS.includes(groupKey)) {
        return;
      }

      state.runtimeModelMenuPrefs = {
        ...(state.runtimeModelMenuPrefs || {}),
        touched: true,
        groupOpen: {
          ...defaultRuntimeModelGroupOpen(),
          ...(state.runtimeModelMenuPrefs?.groupOpen || {}),
          [groupKey]: Boolean(open)
        }
      };
      saveRuntimeModelMenuPreferences();
    }

    function runtimeModelGroupIsOpen(groupKey) {
      const value = state.runtimeModelMenuPrefs?.groupOpen?.[groupKey];
      return typeof value === "boolean" ? value : true;
    }

    const terminal = $("terminal");
    const sourceText = $("sourceText");
    const lastOutput = $("lastOutput");
    const imageBase64 = $("imageBase64");
    const imageFile = $("imageFile");
    const ocrOutput = $("ocrOutput");
    const ocrTranslationOutput = $("ocrTranslationOutput");
    const ocrStructureTable = $("ocrStructureTable");
    const dropZone = $("dropZone");
    const documentFile = $("documentFile");
    const documentDropZone = $("documentDropZone");
    const documentJobsTable = $("documentJobsTable");
    const documentArtifacts = $("documentArtifacts");
    const documentEvents = $("documentEvents");
    const audioBase64 = $("audioBase64");
    const audioFile = $("audioFile");
    const audioSourceUrl = $("audioSourceUrl");
    const asrOutput = $("asrOutput");
    const speechSegmentsTable = $("speechSegmentsTable");
    const audioSessionList = $("audioSessionList");
    const selectedAudioSession = $("selectedAudioSession");
    const audioSessionStatus = $("audioSessionStatus");
    const toggleAudioSessionPollButton = $("toggleAudioSessionPollButton");
    const regionVideo = $("regionVideo");
    const regionStage = $("regionStage");
    const regionSelection = $("regionSelection");
    const regionOcrText = $("regionOcrText");
    const regionTranslationText = $("regionTranslationText");
    const regionTranslationOverlay = $("regionTranslationOverlay");
    const soundGroups = Object.freeze([
      { key: "tap", label: "Soft taps", labelKey: "settings.sound.group.tap", ids: ["staplebops-01", "staplebops-02", "staplebops-03", "staplebops-04", "staplebops-05", "staplebops-06", "staplebops-07"] },
      { key: "pulse", label: "Bip bops", labelKey: "settings.sound.group.pulse", ids: ["bip-bop-01", "bip-bop-02", "bip-bop-03", "bip-bop-04", "bip-bop-05", "bip-bop-06", "bip-bop-07", "bip-bop-08", "bip-bop-09", "bip-bop-10"] },
      { key: "success", label: "Success", labelKey: "settings.sound.group.success", ids: ["yup-01", "yup-02", "yup-03", "yup-04", "yup-05", "yup-06"] },
      { key: "warning", label: "Warnings", labelKey: "settings.sound.group.warning", ids: ["nope-01", "nope-02", "nope-03", "nope-04", "nope-05", "nope-06", "nope-07", "nope-08", "nope-09", "nope-10", "nope-11", "nope-12"] },
      { key: "alert", label: "Alerts", labelKey: "settings.sound.group.alert", ids: ["alert-01", "alert-02", "alert-03", "alert-04", "alert-05", "alert-06", "alert-07", "alert-08", "alert-09", "alert-10"] }
    ]);
    const soundIds = soundGroups.flatMap(group => group.ids);
    const soundLabels = Object.freeze(Object.fromEntries(soundGroups.flatMap(group =>
      group.ids.map((id, index) => [id, `${group.label} ${String(index + 1).padStart(2, "0")}`])
    )));
    const soundFiles = Object.fromEntries(
      soundIds.map(id => [id, `/vendor/opencode/audio/${id}.mp3`])
    );
    const soundCooldownMs = Object.freeze({
      click: 350,
      success: 900,
      error: 900,
      notification: 4000
    });
    const soundLastPlayed = Object.create(null);
    const defaultSoundSettings = {
      version: 3,
      enabled: true,
      click: "",
      success: "yup-02",
      error: "nope-04",
      notification: ""
    };
    const soundPresets = Object.freeze({
      balanced: Object.freeze({ click: "bip-bop-03", success: "yup-02", error: "nope-04", notification: "alert-04" }),
      soft: Object.freeze({ click: "staplebops-02", success: "yup-01", error: "nope-03", notification: "alert-03" }),
      clear: Object.freeze({ click: "bip-bop-08", success: "yup-05", error: "nope-11", notification: "alert-10" }),
      minimal: Object.freeze({ click: "", success: "yup-01", error: "nope-01", notification: "" })
    });
    const soundSettings = loadSoundSettings();
    const ocrProviderDescriptions = {
      external: {
        name: "Windows OCR",
        value: "external",
        use: "Windows OCR compatibility path for simple local text extraction."
      },
      tesseract: {
        name: "Tesseract OCR",
        value: "tesseract",
        use: "Offline OCR with installed language packs such as eng, jpn, chi_tra, and chi_sim."
      },
      easyocr: {
        name: "EasyOCR",
        value: "easyocr",
        use: "Python OCR engine with broad multilingual support for screenshots and mixed text."
      },
      paddleocr: {
        name: "PaddleOCR / PP-OCR",
        value: "paddleocr",
        use: "CJK-focused OCR with strong detection for dense image text."
      },
      "pp-structure-v3": {
        name: "PP-StructureV3",
        value: "pp-structure-v3",
        use: "Structured document OCR for tables, formulas, and layout-heavy pages."
      },
      "paddleocr-vl": {
        name: "PaddleOCR-VL",
        value: "paddleocr-vl",
        use: "Vision-language OCR for complex documents and layout reasoning."
      },
      pix2text: {
        name: "Pix2Text",
        value: "pix2text",
        use: "Formula and markdown-oriented OCR for math-heavy document extraction."
      },
      oneocr: {
        name: "Snipping Tool OCR (OneOCR)",
        value: "oneocr",
        use: "Windows native OCR path using the installed Snipping Tool runtime."
      },
      "rapidocr-net": {
        name: "RapidOcrNet / PP-OCRv5",
        value: "rapidocr-net",
        use: "Open-source .NET ONNX RapidOCR (PP-OCRv5); fallback when the PP-OCRv6 engine is unavailable."
      },
      "rapidocr-net-v6": {
        name: "RapidOcrNet / PP-OCRv6",
        value: "rapidocr-net-v6",
        use: "Default realtime engine: PP-OCRv6 medium detector + small recognizer; reads sparse/vertical kana and low-contrast Latin that v5 missed."
      },
      "rapidocr-ppocrv5": {
        name: "RapidOCR + PP-OCRv5",
        value: "rapidocr-ppocrv5",
        use: "Managed ONNX CJK OCR path tuned for local subtitle and screenshot text."
      },
      "dots-ocr": {
        name: "dots.ocr",
        value: "dots-ocr",
        use: "VLM OCR option for complex screenshots, diagrams, and document understanding."
      }
    };
    function loadSoundSettings() {
      try {
        const raw = window.localStorage.getItem("lth.soundSettings");
        const parsed = raw ? JSON.parse(raw) : {};
        const settings = { ...defaultSoundSettings, ...parsed };
        const legacyUniform = !parsed.version
          && settings.click === "staplebops-01"
          && settings.success === "staplebops-01"
          && settings.error === "staplebops-01"
          && settings.notification === "staplebops-01";
        if (legacyUniform) {
          return { ...defaultSoundSettings };
        }
        if (!Number.isFinite(Number(parsed.version)) || Number(parsed.version) < 3) {
          settings.click = "";
          settings.notification = "";
        }
        return { ...settings, version: 3 };
      } catch {
        return { ...defaultSoundSettings };
      }
    }

    function saveSoundSettings() {
      try {
        window.localStorage.setItem("lth.soundSettings", JSON.stringify(soundSettings));
      } catch {
      }
    }

    function saveOcrControlSettings() {
      try {
        window.localStorage.setItem("lth.ocrSettings", JSON.stringify({
          provider: $("ocrProvider").value,
          language: $("ocrLanguage").value,
          preprocessingPreset: $("ocrPreprocessingPreset").value
        }));
      } catch {
      }
    }

    function applyOcrControlSettings() {
      let saved;
      try {
        const raw = window.localStorage.getItem("lth.ocrSettings");
        saved = raw ? JSON.parse(raw) : null;
      } catch {
        saved = null;
      }

      if (!saved) {
        return;
      }

      if (saved.provider && Array.from($("ocrProvider").options).some(option => option.value === saved.provider && !option.disabled)) {
        $("ocrProvider").value = saved.provider;
      }

      if (saved.language) {
        $("ocrLanguage").value = saved.language;
      }

      if (saved.preprocessingPreset && Array.from($("ocrPreprocessingPreset").options).some(option => option.value === saved.preprocessingPreset)) {
        $("ocrPreprocessingPreset").value = saved.preprocessingPreset;
      }
    }

    function populateSoundSelect(select, selected) {
      select.innerHTML = "";
      const none = document.createElement("option");
      none.value = "";
      none.textContent = uiText("settings.sound.none", "None");
      select.appendChild(none);

      for (const group of soundGroups) {
        const optgroup = document.createElement("optgroup");
        const groupLabel = uiText(group.labelKey, group.label);
        optgroup.label = groupLabel;
        group.ids.forEach((id, index) => {
          const option = document.createElement("option");
          option.value = id;
          option.textContent = `${groupLabel} ${String(index + 1).padStart(2, "0")}`;
          optgroup.appendChild(option);
        });
        select.appendChild(optgroup);
      }

      select.value = selected in soundFiles || selected === "" ? selected : "";
    }

    function syncSoundControls() {
      $("soundEnabled").checked = Boolean(soundSettings.enabled);
      populateSoundSelect($("soundClick"), soundSettings.click);
      populateSoundSelect($("soundSuccess"), soundSettings.success);
      populateSoundSelect($("soundError"), soundSettings.error);
      populateSoundSelect($("soundNotification"), soundSettings.notification);
      updateSoundStatus();
    }

    function readSoundControls() {
      soundSettings.enabled = $("soundEnabled").checked;
      soundSettings.click = $("soundClick").value;
      soundSettings.success = $("soundSuccess").value;
      soundSettings.error = $("soundError").value;
      soundSettings.notification = $("soundNotification").value;
      soundSettings.version = 3;
      saveSoundSettings();
      updateSoundStatus();
    }

    function activeSoundPresetName() {
      return Object.entries(soundPresets).find(([, preset]) =>
        ["click", "success", "error", "notification"].every(kind => soundSettings[kind] === preset[kind])
      )?.[0] || "";
    }

    function refreshSoundPresetButtons() {
      const active = activeSoundPresetName();
      document.querySelectorAll("[data-sound-preset]").forEach(button => {
        button.classList.toggle("active", button.dataset.soundPreset === active);
        button.setAttribute("aria-pressed", String(button.dataset.soundPreset === active));
      });
    }

    function applySoundPreset(name) {
      const preset = soundPresets[name];
      if (!preset) {
        return;
      }
      Object.assign(soundSettings, preset, { enabled: true, version: 3 });
      saveSoundSettings();
      syncSoundControls();
      playUiSound("notification", true);
    }

    function updateSoundStatus() {
      const enabled = Boolean(soundSettings.enabled);
      const enabledState = $("soundEnabledState");
      const mappingSummary = $("soundMappingSummary");
      const enableToggle = document.querySelector(".sound-enable-toggle");
      const configuredCount = ["click", "success", "error", "notification"].filter(kind => Boolean(soundSettings[kind])).length;

      if (enabledState) {
        enabledState.textContent = enabled
          ? uiText("settings.sound.enabledState", "Enabled")
          : uiText("settings.sound.mutedState", "Muted");
      }
      if (mappingSummary) {
        mappingSummary.textContent = enabled
          ? formatUiTemplate("settings.sound.mappedCount", { count: configuredCount }, "{count} / 4 events mapped")
          : uiText("settings.sound.mutedSummary", "Sound feedback muted");
        mappingSummary.classList.toggle("is-muted", !enabled);
      }
      if (enableToggle) {
        enableToggle.classList.toggle("is-muted", !enabled);
      }
      refreshSoundPresetButtons();
    }

    function playUiSound(kind, force = false) {
      try {
        if (!force && !soundSettings.enabled) {
          return;
        }

        if (!force) {
          const now = performance.now();
          const cooldown = soundCooldownMs[kind] || 0;
          if (cooldown > 0 && now - (soundLastPlayed[kind] || 0) < cooldown) {
            return;
          }
          soundLastPlayed[kind] = now;
        }

        const id = soundSettings[kind] || "";
        const src = soundFiles[id];
        if (!src || typeof Audio === "undefined") {
          return;
        }

        const audio = new Audio(src);
        audio.volume = 0.62;
        audio.play().catch(() => undefined);
      } catch (err) {
        console.error("[Sound] playUiSound failed:", err);
      }
    }

    function setBusy(value) {
      state.busy = value;
      $("runButton").disabled = value;
      $("footerLeft").textContent = value ? "running" : "ready";
      updateDocumentControls();
    }

    function isAbortError(error) {
      return error && (error.name === "AbortError" || String(error.message || error).includes("aborted"));
    }

    function updateOcrJobControls() {
      const hasActiveJob = !!state.activeOcrJobId;
      $("cancelOcrJobButton").classList.toggle("hidden", !hasActiveJob);
      $("cancelOcrJobButton").disabled = !hasActiveJob || state.ocrJobCancelRequested;
    }

    async function api(path, options = {}) {
      const headers = { "content-type": "application/json", ...(options.headers || {}) };
      const response = await fetch(path, {
        ...options,
        headers
      });
      const text = await response.text();
      let data = null;
      if (text) {
        try {
          data = JSON.parse(text);
        } catch {
          data = text;
        }
      }
      if (!response.ok) {
        const message = data && (data.errorMessage || data.error || data.detail)
          ? data.errorMessage || data.error || data.detail
          : text || response.statusText;
        throw new Error(message);
      }
      return data;
    }

    function post(path, body, options = {}) {
      return api(path, { ...options, method: "POST", body: JSON.stringify(body) });
    }

    function postEmpty(path, options = {}) {
      return api(path, { ...options, method: "POST" });
    }

    function patch(path, body, options = {}) {
      return api(path, { ...options, method: "PATCH", body: JSON.stringify(body) });
    }

    function escapeHtml(str) {
      if (!str) return "";
      return str.replace(/&/g, "&amp;")
                .replace(/</g, "&lt;")
                .replace(/>/g, "&gt;")
                .replace(/"/g, "&quot;")
                .replace(/'/g, "&#039;");
    }

    const HOTKEY_MODIFIER_ORDER = ["Ctrl", "Alt", "Shift", "Win"];
    const HOTKEY_KEY_CODE_MAP = Object.freeze({
      Space: "Space",
      Enter: "Enter",
      Tab: "Tab",
      Backspace: "Back",
      Insert: "Insert",
      Delete: "Delete",
      Home: "Home",
      End: "End",
      PageUp: "PageUp",
      PageDown: "PageDown",
      ArrowUp: "Up",
      ArrowDown: "Down",
      ArrowLeft: "Left",
      ArrowRight: "Right",
      Minus: "OemMinus",
      Equal: "Oemplus",
      BracketLeft: "OemOpenBrackets",
      BracketRight: "OemCloseBrackets",
      Backslash: "OemPipe",
      Semicolon: "OemSemicolon",
      Quote: "OemQuotes",
      Comma: "Oemcomma",
      Period: "OemPeriod",
      Slash: "OemQuestion",
      Backquote: "Oemtilde"
    });

    function hotkeyStatusLabel(status) {
      switch (status) {
        case "registered": return "ready";
        case "failed": return "in use";
        case "invalid": return "invalid";
        case "disabled": return "off";
        default: return "pending";
      }
    }

    function hotkeyActionLabel(action) {
      const binding = state.hotkeys.find(item => item.action === action);
      return binding ? binding.label : action;
    }

    function formatHotkeySpecHtml(spec) {
      const parts = String(spec || "").split("+").map(part => part.trim()).filter(Boolean);
      if (parts.length === 0) {
        return '<span class="hotkey-unassigned">Unassigned</span>';
      }

      return `<span class="hotkey-kbd-list">${parts.map(part => {
        const isMod = HOTKEY_MODIFIER_ORDER.includes(part) || part === "Meta" || part === "Cmd" || part === "Command";
        return `<kbd${isMod ? ' class="modifier"' : ""}>${escapeHtml(part)}</kbd>`;
      }).join("")}</span>`;
    }

    // Virtual keyboard layout. Each key: { spec, label, units }. `spec` matches
    // the canonical token produced by hotkeyKeyFromEvent / HOTKEY_MODIFIER_ORDER
    // so we can light up the keys that make up a binding (or a live keypress).
    const HOTKEY_KEYBOARD_LAYOUT = Object.freeze([
      [
        { spec: "Escape", label: "Esc" }, { spec: "F1", label: "F1" }, { spec: "F2", label: "F2" },
        { spec: "F3", label: "F3" }, { spec: "F4", label: "F4" }, { spec: "F5", label: "F5" },
        { spec: "F6", label: "F6" }, { spec: "F7", label: "F7" }, { spec: "F8", label: "F8" },
        { spec: "F9", label: "F9" }, { spec: "F10", label: "F10" }, { spec: "F11", label: "F11" }, { spec: "F12", label: "F12" }
      ],
      [
        { spec: "Oemtilde", label: "`" }, { spec: "D1", label: "1" }, { spec: "D2", label: "2" }, { spec: "D3", label: "3" },
        { spec: "D4", label: "4" }, { spec: "D5", label: "5" }, { spec: "D6", label: "6" }, { spec: "D7", label: "7" },
        { spec: "D8", label: "8" }, { spec: "D9", label: "9" }, { spec: "D0", label: "0" },
        { spec: "OemMinus", label: "-" }, { spec: "Oemplus", label: "=" }, { spec: "Back", label: "Back", units: 2 }
      ],
      [
        { spec: "Tab", label: "Tab", units: 1.5 }, { spec: "Q", label: "Q" }, { spec: "W", label: "W" }, { spec: "E", label: "E" },
        { spec: "R", label: "R" }, { spec: "T", label: "T" }, { spec: "Y", label: "Y" }, { spec: "U", label: "U" },
        { spec: "I", label: "I" }, { spec: "O", label: "O" }, { spec: "P", label: "P" },
        { spec: "OemOpenBrackets", label: "[" }, { spec: "OemCloseBrackets", label: "]" }, { spec: "OemPipe", label: "\\", units: 1.5 }
      ],
      [
        { spec: "CapsLock", label: "Caps", units: 1.75 }, { spec: "A", label: "A" }, { spec: "S", label: "S" }, { spec: "D", label: "D" },
        { spec: "F", label: "F" }, { spec: "G", label: "G" }, { spec: "H", label: "H" }, { spec: "J", label: "J" },
        { spec: "K", label: "K" }, { spec: "L", label: "L" }, { spec: "OemSemicolon", label: ";" },
        { spec: "OemQuotes", label: "'" }, { spec: "Enter", label: "Enter", units: 2.25 }
      ],
      [
        { spec: "Shift", label: "Shift", units: 2.25, mod: true }, { spec: "Z", label: "Z" }, { spec: "X", label: "X" }, { spec: "C", label: "C" },
        { spec: "V", label: "V" }, { spec: "B", label: "B" }, { spec: "N", label: "N" }, { spec: "M", label: "M" },
        { spec: "Oemcomma", label: "," }, { spec: "OemPeriod", label: "." }, { spec: "OemQuestion", label: "/" },
        { spec: "Shift", label: "Shift", units: 2.75, mod: true }
      ],
      [
        { spec: "Ctrl", label: "Ctrl", units: 1.5, mod: true }, { spec: "Win", label: "Win", units: 1.25, mod: true },
        { spec: "Alt", label: "Alt", units: 1.25, mod: true }, { spec: "Space", label: "Space", units: 6.25 },
        { spec: "Alt", label: "Alt", units: 1.25, mod: true }, { spec: "Win", label: "Win", units: 1.25, mod: true },
        { spec: "Ctrl", label: "Ctrl", units: 1.5, mod: true }
      ]
    ]);

    let hotkeyKeyboardCollapsed = false;

    function renderHotkeyKeyboard() {
      const surface = $("hotkeyKeyboardSurface");
      if (!surface || surface.childElementCount > 0) {
        return;
      }
      const fragment = document.createDocumentFragment();
      for (const row of HOTKEY_KEYBOARD_LAYOUT) {
        const rowEl = document.createElement("div");
        rowEl.className = "hotkey-keyboard-row";
        for (const key of row) {
          const keyEl = document.createElement("div");
          keyEl.className = `hotkey-key${key.units && key.units !== 1 ? " is-wide" : ""}${key.mod ? " is-modifier" : ""}`;
          keyEl.style.setProperty("--key-units", String(key.units || 1));
          keyEl.dataset.keySpec = key.spec;
          keyEl.textContent = key.label;
          rowEl.appendChild(keyEl);
        }
        fragment.appendChild(rowEl);
      }
      surface.appendChild(fragment);
    }

    function setHotkeyboardKeyClass(className, specs) {
      const surface = $("hotkeyKeyboardSurface");
      if (!surface) {
        return;
      }
      const wanted = new Set((specs || []).map(spec => String(spec || "").trim()).filter(Boolean));
      surface.querySelectorAll(".hotkey-key").forEach(keyEl => {
        keyEl.classList.toggle(className, wanted.has(keyEl.dataset.keySpec));
      });
    }

    function highlightHotkeyboardBinding(spec) {
      const parts = String(spec || "").split("+").map(part => part.trim()).filter(Boolean);
      setHotkeyboardKeyClass("is-bound", parts);
    }

    function updateHotkeyboardStatus() {
      const keyboard = $("hotkeyKeyboard");
      const status = $("hotkeyKeyboardStatus");
      if (!keyboard) {
        return;
      }
      const recordingAction = state.hotkeyRecordingAction;
      keyboard.classList.toggle("is-recording", Boolean(recordingAction));
      if (!status) {
        return;
      }
      if (recordingAction) {
        status.textContent = `Recording ${hotkeyActionLabel(recordingAction)} — press the keys.`;
        return;
      }
      const focus = state.hotkeyKeyboardFocusAction;
      const binding = focus ? state.hotkeys.find(item => item.action === focus) : null;
      if (binding && binding.spec) {
        status.textContent = `${binding.label || binding.action}: ${binding.spec}`;
      } else if (binding) {
        status.textContent = `${binding.label || binding.action}: unassigned`;
      } else {
        status.textContent = "Hover or record a shortcut to preview its keys.";
      }
    }

    function focusHotkeyboardBinding(action) {
      state.hotkeyKeyboardFocusAction = action || "";
      const binding = action ? state.hotkeys.find(item => item.action === action) : null;
      highlightHotkeyboardBinding(binding ? binding.spec : "");
      updateHotkeyboardStatus();
    }

    function setHotkeyboardLiveKeys(event) {
      const active = [];
      if (event.ctrlKey) active.push("Ctrl");
      if (event.altKey) active.push("Alt");
      if (event.shiftKey) active.push("Shift");
      if (event.metaKey) active.push("Win");
      const key = hotkeyKeyFromEvent(event);
      if (key) {
        active.push(key);
      }
      setHotkeyboardKeyClass("is-active", active);
    }

    function clearHotkeyboardLiveKeys() {
      setHotkeyboardKeyClass("is-active", []);
    }

    function hotkeyKeyFromEvent(event) {
      const code = event.code || "";
      if (/^Key[A-Z]$/.test(code)) {
        return code.slice(3);
      }
      if (/^Digit[0-9]$/.test(code)) {
        return `D${code.slice(5)}`;
      }
      if (/^Numpad[0-9]$/.test(code)) {
        return `NumPad${code.slice(6)}`;
      }
      if (/^F([1-9]|1[0-9]|2[0-4])$/.test(code)) {
        return code;
      }
      if (HOTKEY_KEY_CODE_MAP[code]) {
        return HOTKEY_KEY_CODE_MAP[code];
      }

      const key = event.key || "";
      if (/^[a-z]$/i.test(key)) {
        return key.toUpperCase();
      }
      if (/^[0-9]$/.test(key)) {
        return `D${key}`;
      }
      return "";
    }

    function hotkeySpecFromEvent(event) {
      const key = hotkeyKeyFromEvent(event);
      if (!key) {
        return "";
      }

      const parts = [];
      if (event.ctrlKey) parts.push("Ctrl");
      if (event.altKey) parts.push("Alt");
      if (event.shiftKey) parts.push("Shift");
      if (event.metaKey) parts.push("Win");
      parts.push(key);
      return parts.join("+");
    }

    function findHotkeyDuplicate(action, spec) {
      const normalized = String(spec || "").trim().toLowerCase();
      if (!normalized) {
        return null;
      }

      return state.hotkeys.find(item =>
        item.action !== action &&
        String(item.spec || "").trim().toLowerCase() === normalized);
    }

    function setHotkeySummary(message, warning = false) {
      const summary = $("hotkeySummary");
      if (!summary) {
        return;
      }
      summary.textContent = message;
      summary.classList.toggle("has-warning", warning);
    }

    function updateHotkeySummary() {
      const total = state.hotkeys.length;
      const registered = state.hotkeys.filter(item => item.status === "registered").length;
      const failed = state.hotkeys.filter(item => item.status === "failed" || item.status === "invalid").length;
      const disabled = state.hotkeys.filter(item => !item.enabled || item.status === "disabled").length;
      if (failed > 0) {
        setHotkeySummary(`${registered}/${total} ready, ${failed} need attention`, true);
      } else if (disabled > 0) {
        setHotkeySummary(`${registered}/${total} ready, ${disabled} disabled`);
      } else {
        setHotkeySummary(`${registered}/${total} ready`);
      }
    }

    function renderHotkeys() {
      const list = $("hotkeyList");
      if (!list) {
        return;
      }

      const query = (state.hotkeyQuery || "").trim().toLowerCase();
      const rows = state.hotkeys.filter(item => {
        if (!query) {
          return true;
        }
        return [item.group, item.label, item.description, item.spec, item.status]
          .some(value => String(value || "").toLowerCase().includes(query));
      });

      list.innerHTML = "";
      if (rows.length === 0) {
        list.innerHTML = '<div class="hotkey-empty">No shortcut commands match the current search.</div>';
        updateHotkeySummary();
        return;
      }

      const groups = new Map();
      for (const row of rows) {
        const group = row.group || "Shortcuts";
        if (!groups.has(group)) {
          groups.set(group, []);
        }
        groups.get(group).push(row);
      }

      for (const [group, groupRows] of groups) {
        const section = document.createElement("section");
        section.className = "hotkey-group";
        const title = document.createElement("div");
        title.className = "hotkey-group-title";
        title.innerHTML = `<span>${escapeHtml(group)} (${groupRows.length})</span>`;
        section.appendChild(title);

        for (const binding of groupRows) {
          const recording = state.hotkeyRecordingAction === binding.action;
          const row = document.createElement("div");
          row.className = `hotkey-row${recording ? " is-recording" : ""}`;
          row.dataset.hotkeyAction = binding.action;
          row.innerHTML = `
            <div class="hotkey-row-copy">
              <div class="hotkey-row-title">${escapeHtml(binding.label || binding.action)}</div>
              <div class="hotkey-row-desc">${escapeHtml(binding.description || "")}</div>
            </div>
            <button class="hotkey-recorder${recording ? " is-recording" : ""}" type="button" data-hotkey-record="${escapeHtml(binding.action)}" title="${escapeHtml(binding.message || "Click to record")}">
              ${recording ? "Press keys..." : formatHotkeySpecHtml(binding.spec)}
            </button>
            <div class="hotkey-row-meta">
              <span class="hotkey-chip ${escapeHtml(binding.status || "pending")}" title="${escapeHtml(binding.message || "")}">${escapeHtml(hotkeyStatusLabel(binding.status))}</span>
              <div class="hotkey-row-actions">
                <button type="button" data-hotkey-test="${escapeHtml(binding.action)}" title="Test action"><i class="ri-play-line" aria-hidden="true"></i></button>
                <button type="button" data-hotkey-reset="${escapeHtml(binding.action)}" title="Reset to default"><i class="ri-reset-left-line" aria-hidden="true"></i></button>
                <button type="button" data-hotkey-clear="${escapeHtml(binding.action)}" title="Disable shortcut"><i class="ri-close-line" aria-hidden="true"></i></button>
              </div>
            </div>
          `;
          section.appendChild(row);
        }

        list.appendChild(section);
      }

      const hint = $("hotkeyRecorderHint");
      if (hint) {
        hint.textContent = state.hotkeyRecordingAction
          ? `Recording ${hotkeyActionLabel(state.hotkeyRecordingAction)}. Press Esc to cancel, Backspace to clear.`
          : "Click a shortcut to record. Duplicate shortcuts are rejected.";
      }

      renderHotkeyKeyboard();
      const activeAction = state.hotkeyRecordingAction || state.hotkeyKeyboardFocusAction;
      const activeBinding = activeAction ? state.hotkeys.find(item => item.action === activeAction) : null;
      highlightHotkeyboardBinding(activeBinding ? activeBinding.spec : "");
      updateHotkeyboardStatus();
      updateHotkeySummary();
    }

    async function loadHotkeys() {
      const data = await api("/hotkeys");
      state.hotkeys = data && Array.isArray(data.bindings) ? data.bindings : [];
      renderHotkeys();
    }

    async function saveHotkeyBinding(action, spec) {
      const duplicate = findHotkeyDuplicate(action, spec);
      if (duplicate) {
        throw new Error(`${spec} is already assigned to ${duplicate.label || duplicate.action}.`);
      }

      const bindings = {};
      for (const item of state.hotkeys) {
        bindings[item.action] = item.action === action ? spec : (item.spec || "");
      }
      if (!Object.prototype.hasOwnProperty.call(bindings, action)) {
        bindings[action] = spec || "";
      }

      state.hotkeyBusy = true;
      setHotkeySummary("saving shortcuts...");
      try {
        const data = await api("/hotkeys", {
          method: "PUT",
          body: JSON.stringify({ bindings })
        });
        state.hotkeys = data && Array.isArray(data.bindings) ? data.bindings : state.hotkeys;
        renderHotkeys();
        window.setTimeout(() => loadHotkeys().catch(error => appendMessage("error", "hotkeys", error.message || String(error))), 160);
      } finally {
        state.hotkeyBusy = false;
      }
    }

    async function resetHotkeys() {
      const data = await postEmpty("/hotkeys/reset");
      state.hotkeyRecordingAction = "";
      state.hotkeys = data && Array.isArray(data.bindings) ? data.bindings : [];
      renderHotkeys();
      window.setTimeout(() => loadHotkeys().catch(error => appendMessage("error", "hotkeys", error.message || String(error))), 160);
    }

    async function testHotkeyAction(action) {
      const binding = state.hotkeys.find(item => item.action === action);
      setHotkeySummary(`testing ${binding?.label || action}...`);
      const result = await postEmpty(`/hotkeys/trigger/${encodeURIComponent(action)}`);
      appendMessage("result", "hotkey", `${binding?.label || action} triggered`, result && result.action ? result.action : "test");
      await loadHotkeys();
    }

    function handleHotkeyListClick(event) {
      const record = event.target.closest("[data-hotkey-record]");
      const test = event.target.closest("[data-hotkey-test]");
      const reset = event.target.closest("[data-hotkey-reset]");
      const clear = event.target.closest("[data-hotkey-clear]");

      if (record) {
        state.hotkeyRecordingAction = record.dataset.hotkeyRecord || "";
        state.hotkeyKeyboardFocusAction = state.hotkeyRecordingAction;
        clearHotkeyboardLiveKeys();
        renderHotkeys();
        return;
      }

      if (test) {
        testHotkeyAction(test.dataset.hotkeyTest || "")
          .catch(error => {
            setHotkeySummary(error.message || String(error), true);
            appendMessage("error", "hotkey test", error.message || String(error));
          });
        return;
      }

      if (reset) {
        const action = reset.dataset.hotkeyReset || "";
        const binding = state.hotkeys.find(item => item.action === action);
        saveHotkeyBinding(action, binding?.defaultSpec || "")
          .catch(error => {
            setHotkeySummary(error.message || String(error), true);
            appendMessage("error", "hotkeys", error.message || String(error));
          });
        return;
      }

      if (clear) {
        saveHotkeyBinding(clear.dataset.hotkeyClear || "", "")
          .catch(error => {
            setHotkeySummary(error.message || String(error), true);
            appendMessage("error", "hotkeys", error.message || String(error));
          });
      }
    }

    function handleHotkeyRecordingKeydown(event) {
      if (!state.hotkeyRecordingAction) {
        return;
      }

      event.preventDefault();
      event.stopPropagation();

      setHotkeyboardLiveKeys(event);

      if (event.key === "Escape") {
        state.hotkeyRecordingAction = "";
        clearHotkeyboardLiveKeys();
        renderHotkeys();
        return;
      }

      if (event.key === "Backspace" || event.key === "Delete") {
        const action = state.hotkeyRecordingAction;
        state.hotkeyRecordingAction = "";
        clearHotkeyboardLiveKeys();
        saveHotkeyBinding(action, "")
          .catch(error => {
            setHotkeySummary(error.message || String(error), true);
            appendMessage("error", "hotkeys", error.message || String(error));
          });
        renderHotkeys();
        return;
      }

      if (["Control", "Shift", "Alt", "Meta"].includes(event.key)) {
        return;
      }

      const spec = hotkeySpecFromEvent(event);
      if (!spec) {
        setHotkeySummary("That key cannot be used as a global shortcut.", true);
        return;
      }

      const action = state.hotkeyRecordingAction;
      state.hotkeyRecordingAction = "";
      clearHotkeyboardLiveKeys();
      saveHotkeyBinding(action, spec)
        .catch(error => {
          setHotkeySummary(error.message || String(error), true);
          appendMessage("error", "hotkeys", error.message || String(error));
        });
      renderHotkeys();
    }

    function handleHotkeyRecordingKeyup(event) {
      if (!state.hotkeyRecordingAction) {
        return;
      }
      // Repaint held modifiers as keys are released so the preview tracks state.
      setHotkeyboardLiveKeys(event);
    }

    function handleHotkeyListHover(event) {
      const record = event.target.closest("[data-hotkey-record]");
      if (state.hotkeyRecordingAction) {
        return;
      }
      focusHotkeyboardBinding(record ? record.dataset.hotkeyRecord || "" : "");
    }

    const SIDEBAR_COLLAPSED_STORAGE_KEY = "verbeam.sidebarCollapsed.v1";
    const LAYOUT_RESIZE_STORAGE_KEY = "verbeam.layoutResize.v1";
    const WORKSPACE_TABS_STORAGE_KEY = "verbeam.workspaceTabs.v1";
    const RUNTIME_MODEL_MENU_STORAGE_KEY = "verbeam.runtimeModelMenu.v1";
    const AUDIO_SESSION_SELECTION_STORAGE_KEY = "verbeam.audioSessionSelection.v1";
    const AUDIO_SESSION_POLL_STORAGE_KEY = "verbeam.audioSessionPoll.v1";

    function loadAudioSessionPreferences() {
      try {
        state.selectedAudioSessionKey = window.localStorage.getItem(AUDIO_SESSION_SELECTION_STORAGE_KEY) || "";
        const savedPoll = window.localStorage.getItem(AUDIO_SESSION_POLL_STORAGE_KEY);
        state.audioSessionPollEnabled = savedPoll === null ? true : savedPoll === "true";
      } catch {
        state.selectedAudioSessionKey = "";
        state.audioSessionPollEnabled = true;
      }
    }

    function saveAudioSessionSelection(key) {
      state.selectedAudioSessionKey = key || "";
      try {
        if (state.selectedAudioSessionKey) {
          window.localStorage.setItem(AUDIO_SESSION_SELECTION_STORAGE_KEY, state.selectedAudioSessionKey);
        } else {
          window.localStorage.removeItem(AUDIO_SESSION_SELECTION_STORAGE_KEY);
        }
      } catch {
      }
    }

    function saveAudioSessionPollPreference() {
      try {
        window.localStorage.setItem(AUDIO_SESSION_POLL_STORAGE_KEY, state.audioSessionPollEnabled ? "true" : "false");
      } catch {
      }
    }

    function audioSessionKey(session) {
      if (!session) {
        return "";
      }
      return [
        session.processId || 0,
        session.instanceId || session.id || session.processName || session.displayName || "session"
      ].join(":");
    }

    function audioSessionLabel(session) {
      if (!session) {
        return "";
      }
      return session.displayName || session.mainWindowTitle || session.processName || `PID ${session.processId || 0}`;
    }

    function setAudioSessionStatus(text, kind = "") {
      audioSessionStatus.textContent = text;
      audioSessionStatus.classList.toggle("ready", kind === "ready");
      audioSessionStatus.classList.toggle("error", kind === "error");
    }

    function setAudioSessionPollUi() {
      toggleAudioSessionPollButton.classList.toggle("active", state.audioSessionPollEnabled);
      toggleAudioSessionPollButton.setAttribute("aria-pressed", state.audioSessionPollEnabled ? "true" : "false");
      toggleAudioSessionPollButton.querySelector("span").textContent = state.audioSessionPollEnabled ? "Auto on" : "Auto";
    }

    function updateSelectedAudioSessionPanel() {
      const selected = state.selectedAudioSession;
      selectedAudioSession.innerHTML = "";
      if (!selected) {
        selectedAudioSession.textContent = state.selectedAudioSessionKey ? "Selected app is not active" : "No app selected";
        return;
      }

      const label = document.createElement("strong");
      label.textContent = audioSessionLabel(selected);
      const suffix = document.createTextNode(`  PID ${selected.processId || 0} · ${selected.isAudible ? "audible" : selected.state || "idle"}`);
      selectedAudioSession.append(label, suffix);
    }

    function renderAudioSessions() {
      const sessions = state.audioSessions || [];
      const selectedKey = state.selectedAudioSessionKey || "";
      state.selectedAudioSession = sessions.find(session => audioSessionKey(session) === selectedKey) || null;
      updateSelectedAudioSessionPanel();
      setAudioSessionPollUi();
      audioSessionList.innerHTML = "";

      if (!state.audioSessionSnapshot || state.audioSessionSnapshot.supported === false) {
        const empty = document.createElement("div");
        empty.className = "audio-source-empty";
        empty.textContent = state.audioSessionSnapshot && state.audioSessionSnapshot.errorMessage
          ? state.audioSessionSnapshot.errorMessage
          : "Windows audio sessions are not available.";
        audioSessionList.appendChild(empty);
        setAudioSessionStatus("unavailable", "error");
        return;
      }

      if (sessions.length === 0) {
        const empty = document.createElement("div");
        empty.className = "audio-source-empty";
        empty.textContent = "No active app audio sessions. Start audio in another app, then refresh.";
        audioSessionList.appendChild(empty);
        setAudioSessionStatus("0 apps", "");
        return;
      }

      for (const session of sessions) {
        const key = audioSessionKey(session);
        const peak = Math.max(0, Math.min(1, Number(session.peak) || 0));
        const card = document.createElement("button");
        card.type = "button";
        card.className = "audio-session-card";
        card.classList.toggle("selected", key === selectedKey);
        card.title = `${audioSessionLabel(session)} · PID ${session.processId || 0}`;
        card.addEventListener("click", () => {
          saveAudioSessionSelection(key);
          state.selectedAudioSession = session;
          renderAudioSessions();
          appendMessage("result", "audio source", audioSessionLabel(session), `pid ${session.processId || 0}`);
        });

        const main = document.createElement("div");
        main.className = "audio-session-main";
        const name = document.createElement("div");
        name.className = "audio-session-name";
        const icon = document.createElement("i");
        icon.className = session.isAudible ? "ri-volume-up-line" : "ri-volume-mute-line";
        icon.setAttribute("aria-hidden", "true");
        const title = document.createElement("span");
        title.textContent = audioSessionLabel(session);
        name.append(icon, title);

        const meta = document.createElement("div");
        meta.className = "audio-session-meta";
        const process = session.processName || "process";
        const stateLabel = session.isAudible ? "audible" : session.state || "idle";
        meta.textContent = `${process} · PID ${session.processId || 0} · ${stateLabel}${session.muted ? " · muted" : ""}`;
        main.append(name, meta);

        const meter = document.createElement("div");
        meter.className = "audio-session-meter";
        const track = document.createElement("div");
        track.className = "audio-session-meter-track";
        const fill = document.createElement("div");
        fill.className = "audio-session-meter-fill";
        fill.style.width = `${Math.round(peak * 100)}%`;
        track.appendChild(fill);
        const meterLabel = document.createElement("div");
        meterLabel.className = "audio-session-meter-label";
        meterLabel.textContent = `${Math.round(peak * 100)}%`;
        meter.append(track, meterLabel);

        card.append(main, meter);
        audioSessionList.appendChild(card);
      }

      const audibleCount = sessions.filter(session => session.isAudible).length;
      setAudioSessionStatus(`${audibleCount}/${sessions.length} live`, "ready");
    }

    async function loadAudioSessions({ quiet = false } = {}) {
      if (state.audioSessionLoading) {
        return;
      }
      state.audioSessionLoading = true;
      if (!quiet) {
        setAudioSessionStatus("loading");
      }

      try {
        const snapshot = await api("/audio/sessions");
        const sessions = Array.isArray(snapshot && snapshot.sessions) ? snapshot.sessions : [];
        state.audioSessionSnapshot = snapshot;
        state.audioSessions = sessions
          .filter(session => session && !session.isSystemSounds)
          .sort((a, b) => Number(b.isAudible) - Number(a.isAudible)
            || (Number(b.peak) || 0) - (Number(a.peak) || 0)
            || audioSessionLabel(a).localeCompare(audioSessionLabel(b)));
        renderAudioSessions();
      } catch (error) {
        state.audioSessionSnapshot = { supported: false, errorMessage: error.message || String(error), sessions: [] };
        state.audioSessions = [];
        renderAudioSessions();
      } finally {
        state.audioSessionLoading = false;
      }
    }

    function stopAudioSessionPoll() {
      if (state.audioSessionPollTimer) {
        window.clearTimeout(state.audioSessionPollTimer);
        state.audioSessionPollTimer = 0;
      }
    }

    function scheduleAudioSessionPoll(delay = 1800) {
      stopAudioSessionPoll();
      if (!state.audioSessionPollEnabled || state.mode !== "audio") {
        return;
      }
      state.audioSessionPollTimer = window.setTimeout(async () => {
        await loadAudioSessions({ quiet: true });
        scheduleAudioSessionPoll();
      }, delay);
    }

    function refreshAudioSessions({ quiet = false } = {}) {
      return loadAudioSessions({ quiet }).finally(() => scheduleAudioSessionPoll());
    }
