    const SIDEBAR_MODE_WIDTHS = Object.freeze({
      compact: { sidebar: 188, settingsNav: 208 },
      full: { sidebar: 224, settingsNav: 236 },
      rail: { sidebar: 188, settingsNav: 208 }
    });
    const LAYOUT_RESIZE_VARS = Object.freeze([
      "--rail-w",
      "--sidebar-w",
      "--terminal-drawer-h",
      "--text-result-w",
      "--audio-result-w",
      "--ocr-inspector-w",
      "--ocr-text-result-w",
      "--document-detail-w",
      "--region-result-w",
      "--settings-nav-w",
      "--provider-detail-w",
      "--memory-list-w",
      "--ocr-history-jobs-w"
    ]);

    function normalizeHexColor(value, fallback) {
      if (typeof value === "string" && /^#[0-9a-f]{6}$/i.test(value.trim())) {
        return value.trim().toLowerCase();
      }
      return fallback;
    }

    function hexToRgbArray(hex) {
      const safe = normalizeHexColor(hex, "#000000").slice(1);
      return [
        parseInt(safe.slice(0, 2), 16),
        parseInt(safe.slice(2, 4), 16),
        parseInt(safe.slice(4, 6), 16)
      ];
    }

    function rgbArrayToHex(rgb) {
      return `#${rgb.map(value => Math.round(Math.min(255, Math.max(0, value))).toString(16).padStart(2, "0")).join("")}`;
    }

    function hexToRgbString(hex) {
      return hexToRgbArray(hex).join(", ");
    }

    function mixHex(foreground, background, amount) {
      const fg = hexToRgbArray(foreground);
      const bg = hexToRgbArray(background);
      const ratio = Math.min(1, Math.max(0, Number(amount) || 0));
      return rgbArrayToHex(fg.map((value, index) => value * ratio + bg[index] * (1 - ratio)));
    }

    function getRelativeLuminance(hex) {
      const rgb = hexToRgbArray(hex).map(value => {
        const channel = value / 255;
        return channel <= 0.03928 ? channel / 12.92 : Math.pow((channel + 0.055) / 1.055, 2.4);
      });
      return rgb[0] * 0.2126 + rgb[1] * 0.7152 + rgb[2] * 0.0722;
    }

    function normalizeNumberPreference(value, fallback, min, max) {
      const parsed = Number(value);
      if (!Number.isFinite(parsed)) {
        return fallback;
      }
      return Math.min(max, Math.max(min, Math.round(parsed)));
    }

    function normalizeAppearanceSettings(value) {
      const source = value && typeof value === "object" ? value : {};
      const theme = source.theme === "system" || source.theme === "custom" || Object.prototype.hasOwnProperty.call(THEME_PALETTES, source.theme)
        ? source.theme
        : DEFAULT_APPEARANCE.theme;
      const density = ["compact", "cozy", "comfortable"].includes(source.density) ? source.density : DEFAULT_APPEARANCE.density;
      const sidebarMode = ["compact", "full", "rail"].includes(source.sidebarMode) ? source.sidebarMode : DEFAULT_APPEARANCE.sidebarMode;
      const topStatus = ["minimal", "visible"].includes(source.topStatus) ? source.topStatus : DEFAULT_APPEARANCE.topStatus;
      const accent = Object.prototype.hasOwnProperty.call(ACCENT_COLORS, source.accent) ? source.accent : DEFAULT_APPEARANCE.accent;
      const uiFont = Object.prototype.hasOwnProperty.call(UI_FONT_STACKS, source.uiFont) ? source.uiFont : DEFAULT_APPEARANCE.uiFont;
      const monoFont = Object.prototype.hasOwnProperty.call(MONO_FONT_STACKS, source.monoFont) ? source.monoFont : DEFAULT_APPEARANCE.monoFont;
      const uiFontSize = normalizeNumberPreference(source.uiFontSize, DEFAULT_APPEARANCE.uiFontSize, 12, 16);
      const codeFontSize = normalizeNumberPreference(source.codeFontSize, DEFAULT_APPEARANCE.codeFontSize, 11, 16);
      const uiFontWeight = ["400", "500", "600"].includes(String(source.uiFontWeight)) ? String(source.uiFontWeight) : DEFAULT_APPEARANCE.uiFontWeight;
      const language = DISPLAY_LANGUAGE_KEYS.includes(source.language) ? source.language : DEFAULT_APPEARANCE.language;
      const sourceCustom = source.custom && typeof source.custom === "object" ? source.custom : {};
      const custom = {
        accent: normalizeHexColor(sourceCustom.accent ?? source.customAccent, DEFAULT_APPEARANCE.custom.accent),
        background: normalizeHexColor(sourceCustom.background ?? source.customBackground, DEFAULT_APPEARANCE.custom.background),
        surface: normalizeHexColor(sourceCustom.surface ?? source.customSurface, DEFAULT_APPEARANCE.custom.surface),
        foreground: normalizeHexColor(sourceCustom.foreground ?? source.customForeground, DEFAULT_APPEARANCE.custom.foreground)
      };
      return { theme, density, sidebarMode, topStatus, accent, uiFont, monoFont, uiFontSize, codeFontSize, uiFontWeight, language, custom };
    }

    function loadAppearanceSettings() {
      try {
        const raw = window.localStorage.getItem(APPEARANCE_STORAGE_KEY);
        return normalizeAppearanceSettings(raw ? JSON.parse(raw) : DEFAULT_APPEARANCE);
      } catch {
        return normalizeAppearanceSettings(DEFAULT_APPEARANCE);
      }
    }

    function saveAppearanceSettings() {
      try {
        window.localStorage.setItem(APPEARANCE_STORAGE_KEY, JSON.stringify(state.appearance || DEFAULT_APPEARANCE));
      } catch {
        // Appearance still works for the current session if storage is blocked.
      }
    }

    function getSystemAppearanceTheme() {
      try {
        return window.matchMedia && window.matchMedia("(prefers-color-scheme: light)").matches ? "light" : "dark";
      } catch {
        return "dark";
      }
    }

    function resolveAppearancePalette(appearance) {
      const resolvedTheme = appearance.theme === "system" ? getSystemAppearanceTheme() : appearance.theme;
      if (resolvedTheme !== "custom") {
        return { resolvedTheme, palette: THEME_PALETTES[resolvedTheme] || THEME_PALETTES.dark };
      }

      const custom = appearance.custom || DEFAULT_APPEARANCE.custom;
      const bg = normalizeHexColor(custom.background, DEFAULT_APPEARANCE.custom.background);
      const surface = normalizeHexColor(custom.surface, DEFAULT_APPEARANCE.custom.surface);
      const text = normalizeHexColor(custom.foreground, DEFAULT_APPEARANCE.custom.foreground);
      const scheme = getRelativeLuminance(bg) > 0.55 ? "light" : "dark";
      return {
        resolvedTheme,
        palette: {
          scheme,
          bg,
          rail: mixHex(text, surface, scheme === "light" ? 0.08 : 0.03),
          panel: surface,
          panel2: mixHex(text, surface, scheme === "light" ? 0.08 : 0.06),
          line: mixHex(text, bg, scheme === "light" ? 0.2 : 0.14),
          lineSoft: mixHex(text, bg, scheme === "light" ? 0.13 : 0.1),
          lineStrong: mixHex(text, bg, scheme === "light" ? 0.28 : 0.22),
          text,
          muted: mixHex(text, bg, scheme === "light" ? 0.72 : 0.70),
          faint: mixHex(text, bg, scheme === "light" ? 0.58 : 0.56),
          inputBg: scheme === "light" ? "rgba(255, 255, 255, 0.9)" : "rgba(7, 9, 12, 0.85)",
          inputBgFocus: scheme === "light" ? "#ffffff" : "rgba(7, 9, 12, 0.95)",
          topbarBg: mixHex(text, bg, scheme === "light" ? 0.03 : 0.05),
          topbarBg2: bg
        }
      };
    }

    function applyPaletteVariables(palette) {
      const root = document.documentElement;
      const mappings = {
        "--bg": palette.bg,
        "--rail": palette.rail,
        "--panel": palette.panel,
        "--panel-2": palette.panel2,
        "--line": palette.line,
        "--line-soft": palette.lineSoft,
        "--line-strong": palette.lineStrong,
        "--text": palette.text,
        "--muted": palette.muted,
        "--faint": palette.faint,
        "--input-bg": palette.inputBg,
        "--input-bg-focus": palette.inputBgFocus,
        "--topbar-bg": palette.topbarBg,
        "--topbar-bg-2": palette.topbarBg2,
        "--panel-rgb": hexToRgbString(palette.panel)
      };
      for (const [name, value] of Object.entries(mappings)) {
        root.style.setProperty(name, value);
      }
      root.style.colorScheme = palette.scheme;
    }

    function applyTypographyVariables(appearance) {
      const root = document.documentElement;
      const uiFontSize = normalizeNumberPreference(appearance.uiFontSize, DEFAULT_APPEARANCE.uiFontSize, 12, 16);
      const codeFontSize = normalizeNumberPreference(appearance.codeFontSize, DEFAULT_APPEARANCE.codeFontSize, 11, 16);
      const uiScale = uiFontSize / DEFAULT_APPEARANCE.uiFontSize;
      const scaled = (base, min, max = 28) => {
        const next = Math.round(base * uiScale);
        return Math.min(max, Math.max(min, next));
      };
      root.style.setProperty("--sans", UI_FONT_STACKS[appearance.uiFont] || UI_FONT_STACKS.outfit);
      root.style.setProperty("--mono", MONO_FONT_STACKS[appearance.monoFont] || MONO_FONT_STACKS.jetbrains);
      root.style.setProperty("--ui-font-size", `${uiFontSize}px`);
      root.style.setProperty("--ui-font-xxs", `${scaled(9, 8, 14)}px`);
      root.style.setProperty("--ui-font-xs", `${scaled(10, 9, 15)}px`);
      root.style.setProperty("--ui-font-sm", `${scaled(12, 10, 18)}px`);
      root.style.setProperty("--ui-font-md", `${scaled(13, 11, 20)}px`);
      root.style.setProperty("--ui-font-lg", `${scaled(16, 13, 24)}px`);
      root.style.setProperty("--ui-font-xl", `${scaled(18, 15, 26)}px`);
      root.style.setProperty("--ui-font-2xl", `${scaled(22, 18, 30)}px`);
      root.style.setProperty("--code-font-size", `${codeFontSize}px`);
      root.style.setProperty("--ui-font-weight", appearance.uiFontWeight);
    }

    function resolveDisplayLanguage(language) {
      if (language && language !== "auto") {
        return DISPLAY_LANGUAGE_KEYS.includes(language) ? language : "en";
      }
      const preferred = Array.isArray(navigator.languages) ? navigator.languages : [navigator.language || "en"];
      const match = preferred.find(item => typeof item === "string" && item.toLowerCase().startsWith("zh"));
      return match ? "zh-TW" : "en";
    }

    function getUiTranslation(key, resolvedLanguage = getActiveUiLanguage(), fallback = "") {
      return UI_I18N_FINAL_PATCH[resolvedLanguage]?.[key]
        || UI_I18N_FINAL_PATCH.en?.[key]
        || UI_I18N_PATCH[resolvedLanguage]?.[key]
        || UI_I18N_PATCH.en?.[key]
        || UI_I18N_OVERRIDES[resolvedLanguage]?.[key]
        || UI_I18N[resolvedLanguage]?.[key]
        || UI_I18N_OVERRIDES.en?.[key]
        || UI_I18N.en?.[key]
        || fallback
        || key;
    }

    function uiText(key, fallback = "") {
      return getUiTranslation(key, getActiveUiLanguage(), fallback);
    }

    function workspaceTabLabel(item) {
      return item && item.i18nKey ? uiText(item.i18nKey, item.label) : item?.label || "";
    }

    function workspaceModeLabel(mode) {
      return workspaceTabLabel(WORKSPACE_TAB_DEFS[mode] || WORKSPACE_TAB_DEFS.text);
    }

    function formatUiTemplate(key, values, fallback = "") {
      return Object.entries(values || {}).reduce(
        (text, [name, value]) => text.replaceAll(`{${name}}`, value),
        uiText(key, fallback));
    }

    function applyDisplayLanguage(language) {
      const resolved = resolveDisplayLanguage(language);
      document.documentElement.lang = resolved;
      document.body.dataset.displayLanguage = language || "auto";
      document.body.dataset.resolvedDisplayLanguage = resolved;
      for (const element of document.querySelectorAll("[data-i18n]")) {
        const key = element.dataset.i18n;
        // Use the author-written text as the fallback so a missing dictionary entry keeps the
        // English label instead of rendering the raw i18n key.
        const value = getUiTranslation(key, resolved, (element.textContent || "").trim());
        if (value) {
          element.textContent = value;
        }
      }
      for (const element of document.querySelectorAll("[data-i18n-title]")) {
        const value = getUiTranslation(element.dataset.i18nTitle, resolved, element.title || "");
        if (value) {
          element.title = value;
        }
      }
      for (const element of document.querySelectorAll("[data-i18n-aria-label]")) {
        const value = getUiTranslation(element.dataset.i18nAriaLabel, resolved, element.getAttribute("aria-label") || "");
        if (value) {
          element.setAttribute("aria-label", value);
        }
      }
      refreshTranslationLanguageControls();
      renderWorkspaceTabs();
      syncRuntimeQuickControls();
      syncMemoryAdvancedLabels();
      renderAppearanceOptionPreviews();
      if (state.mode) {
        $("modeLabel").textContent = workspaceModeLabel(state.mode);
      }
    }

    function postShellAppearance(colorScheme) {
      try {
        window.chrome?.webview?.postMessage?.({
          type: "appearance",
          colorScheme
        });
      } catch {
      }
    }

    function ensureAppearanceDynamicSections() {
      const panel = document.querySelector('[data-settings-panel="appearance"]');
      const body = panel?.querySelector(".settings-tab-body");
      if (!panel || !body) {
        return;
      }

      const languageSections = Array.from(panel.querySelectorAll(".settings-section"))
        .filter(section => section.querySelector("select#appearanceLanguage"));
      languageSections.slice(1).forEach(section => section.remove());

      const legacyPreview = panel.querySelector(".appearance-preview")?.closest(".settings-section");
      if (legacyPreview) {
        legacyPreview.remove();
      }

      if ($("appearanceSlotGrid")) {
        return;
      }

      const section = document.createElement("section");
      section.className = "settings-section";
      const title = document.createElement("div");
      title.className = "settings-section-title";
      title.dataset.i18n = "appearance.saved.title";
      title.textContent = "Saved appearances";
      const grid = document.createElement("div");
      grid.id = "appearanceSlotGrid";
      grid.className = "appearance-slot-grid";
      grid.setAttribute("aria-label", "Saved appearance slots");
      const resetRow = document.createElement("div");
      resetRow.className = "settings-reset-row";
      const reset = document.createElement("button");
      reset.id = "appearanceResetButton";
      reset.type = "button";
      reset.innerHTML = '<i class="ri-reset-left-line" aria-hidden="true"></i><span data-i18n="appearance.reset">Reset appearance</span>';
      resetRow.appendChild(reset);
      section.append(title, grid, resetRow);
      body.appendChild(section);
    }

    function getSelectOptionLabel(selectId, value, fallback = "") {
      const select = $(selectId);
      const option = Array.from(select?.options || []).find(item => item.value === value);
      return (option?.textContent || fallback || value || "").trim();
    }

    function getSelectOptions(selectId) {
      const select = $(selectId);
      return Array.from(select?.options || []).map(option => ({
        value: option.value,
        label: (option.textContent || option.value).trim()
      }));
    }

    let appearancePickerDocumentBound = false;

    function applyFontOptionStyles(selectId, stacks) {
      const select = $(selectId);
      if (!select) {
        return;
      }
      for (const option of select.options) {
        option.style.fontFamily = stacks[option.value] || "";
      }
    }

    function getAppearancePicker(selectId) {
      return Array.from(document.querySelectorAll(".appearance-picker"))
        .find(picker => picker.dataset.pickerFor === selectId) || null;
    }

    function closeAppearancePickers(except = null) {
      for (const picker of document.querySelectorAll(".appearance-picker.open")) {
        if (picker !== except) {
          picker.classList.remove("open");
          picker.querySelector(".appearance-picker-trigger")?.setAttribute("aria-expanded", "false");
        }
      }
    }

    function bindAppearancePickerDocumentEvents() {
      if (appearancePickerDocumentBound) {
        return;
      }
      appearancePickerDocumentBound = true;
      document.addEventListener("click", event => {
        if (!event.target.closest(".appearance-picker")) {
          closeAppearancePickers();
        }
      });
      document.addEventListener("keydown", event => {
        if (event.key === "Escape") {
          closeAppearancePickers();
        }
      });
    }

    function ensureAppearancePicker(selectId, hostId) {
      const select = $(selectId);
      const host = $(hostId);
      if (!select || !host) {
        return;
      }
      select.classList.add("appearance-native-select");
      select.tabIndex = -1;
      select.setAttribute("aria-hidden", "true");
      if (host.closest(".appearance-picker")) {
        return;
      }

      const picker = document.createElement("div");
      picker.className = "appearance-picker";
      picker.dataset.pickerFor = selectId;
      const trigger = document.createElement("button");
      trigger.type = "button";
      trigger.className = "appearance-picker-trigger";
      trigger.setAttribute("aria-haspopup", "listbox");
      trigger.setAttribute("aria-expanded", "false");
      const menu = document.createElement("div");
      menu.className = "appearance-picker-menu";
      menu.setAttribute("role", "listbox");

      select.insertAdjacentElement("afterend", picker);
      picker.append(trigger, menu);
      menu.appendChild(host);
      trigger.addEventListener("click", event => {
        event.preventDefault();
        const open = !picker.classList.contains("open");
        closeAppearancePickers(picker);
        picker.classList.remove("drop-up");
        if (open) {
          const rect = picker.getBoundingClientRect();
          const bottomSpace = window.innerHeight - rect.bottom;
          picker.classList.toggle("drop-up", bottomSpace < 300 && rect.top > bottomSpace);
        }
        picker.classList.toggle("open", open);
        trigger.setAttribute("aria-expanded", open ? "true" : "false");
        if (open) {
          window.requestAnimationFrame(() => picker.querySelector(".appearance-picker-menu")?.scrollIntoView({ block: "nearest" }));
        }
      });
      bindAppearancePickerDocumentEvents();
    }

    function setAppearancePickerTrigger(selectId, contentBuilder) {
      const select = $(selectId);
      const picker = getAppearancePicker(selectId);
      const trigger = picker?.querySelector(".appearance-picker-trigger");
      if (!select || !trigger) {
        return;
      }
      trigger.replaceChildren();
      const main = document.createElement("span");
      main.className = "appearance-picker-trigger-main";
      contentBuilder(main, select.value);
      const arrow = document.createElement("span");
      arrow.className = "appearance-picker-trigger-arrow";
      arrow.setAttribute("aria-hidden", "true");
      arrow.textContent = "v";
      trigger.append(main, arrow);
    }

    function appendPickerLabel(parent, label, fontFamily = "") {
      const text = document.createElement("span");
      text.className = "appearance-picker-trigger-label";
      text.textContent = label;
      if (fontFamily) {
        text.style.fontFamily = fontFamily;
      }
      parent.appendChild(text);
    }

    function appendPickerSwatches(parent, colors) {
      const swatches = document.createElement("span");
      swatches.className = "appearance-picker-trigger-swatches";
      for (const color of colors) {
        const swatch = document.createElement("span");
        swatch.className = "appearance-picker-trigger-swatch";
        swatch.style.setProperty("--swatch", color);
        swatches.appendChild(swatch);
      }
      parent.appendChild(swatches);
    }

    function appendPickerSample(parent, text, fontFamily = "") {
      const sample = document.createElement("span");
      sample.className = "appearance-picker-trigger-sample";
      sample.textContent = text;
      if (fontFamily) {
        sample.style.fontFamily = fontFamily;
      }
      parent.appendChild(sample);
    }

    function updateAppearancePickerTriggers() {
      const current = state.appearance || DEFAULT_APPEARANCE;
      setAppearancePickerTrigger("appearanceThemePreset", (main, value) => {
        const { palette, accent } = getAppearancePreviewPalette(value, current, true);
        appendPickerLabel(main, getSelectOptionLabel("appearanceThemePreset", value));
        appendPickerSwatches(main, [palette.bg, palette.panel, palette.text, accent]);
      });
      setAppearancePickerTrigger("appearanceAccent", (main, value) => {
        appendPickerLabel(main, getSelectOptionLabel("appearanceAccent", value));
        const dot = document.createElement("span");
        dot.className = "appearance-picker-trigger-dot";
        dot.style.setProperty("--accent-dot", ACCENT_COLORS[value] || ACCENT_COLORS.blue);
        dot.setAttribute("aria-hidden", "true");
        main.appendChild(dot);
      });
      setAppearancePickerTrigger("appearanceUiFont", (main, value) => {
        appendPickerLabel(main, getSelectOptionLabel("appearanceUiFont", value), UI_FONT_STACKS[value] || "");
        appendPickerSample(main, "Aa 123", UI_FONT_STACKS[value] || "");
      });
      setAppearancePickerTrigger("appearanceMonoFont", (main, value) => {
        appendPickerLabel(main, getSelectOptionLabel("appearanceMonoFont", value), MONO_FONT_STACKS[value] || "");
        appendPickerSample(main, "auto -> zh-TW", MONO_FONT_STACKS[value] || "");
      });
    }

    function getAppearancePreviewPalette(theme, appearanceOverride = state.appearance || DEFAULT_APPEARANCE, usePresetAccent = false) {
      const current = appearanceOverride || DEFAULT_APPEARANCE;
      const preview = normalizeAppearanceSettings({
        ...current,
        theme,
        accent: usePresetAccent ? (THEME_PALETTES[theme]?.defaultAccent || current.accent) : current.accent
      });
      const { palette } = resolveAppearancePalette(preview);
      const accent = theme === "custom"
        ? preview.custom.accent
        : (ACCENT_COLORS[preview.accent] || ACCENT_COLORS[palette.defaultAccent] || ACCENT_COLORS.blue);
      return { palette, accent };
    }

    function appendAppearanceSwatch(parent, color, className) {
      const swatch = document.createElement("span");
      swatch.className = className;
      swatch.style.setProperty("--swatch", color);
      parent.appendChild(swatch);
    }

    function renderAppearanceThemeCards() {
      const host = $("appearanceThemeCards");
      if (!host) {
        return;
      }
      const current = state.appearance || DEFAULT_APPEARANCE;
      host.replaceChildren();
      for (const option of getSelectOptions("appearanceThemePreset")) {
        const { palette, accent } = getAppearancePreviewPalette(option.value, current, true);
        const button = document.createElement("button");
        button.type = "button";
        button.className = "appearance-theme-card";
        button.classList.toggle("active", current.theme === option.value);
        button.setAttribute("aria-pressed", current.theme === option.value ? "true" : "false");
        button.style.setProperty("--theme-bg", palette.bg);
        button.style.setProperty("--theme-panel", palette.panel);
        button.style.setProperty("--theme-text", palette.text);
        button.style.setProperty("--theme-accent", accent);

        const title = document.createElement("div");
        title.className = "appearance-theme-card-title";
        title.textContent = option.label;
        const meta = document.createElement("div");
        meta.className = "appearance-theme-card-meta";
        meta.textContent = palette.scheme === "light"
          ? uiText("appearance.scheme.light", "light")
          : uiText("appearance.scheme.dark", "dark");
        const swatches = document.createElement("div");
        swatches.className = "appearance-theme-swatches";
        appendAppearanceSwatch(swatches, palette.bg, "appearance-theme-swatch");
        appendAppearanceSwatch(swatches, palette.panel, "appearance-theme-swatch");
        appendAppearanceSwatch(swatches, palette.text, "appearance-theme-swatch");
        appendAppearanceSwatch(swatches, accent, "appearance-theme-swatch");

        button.append(title, meta, swatches);
        button.addEventListener("click", () => {
          const select = $("appearanceThemePreset");
          if (select) {
            select.value = option.value;
          }
          updateThemePresetFromControls();
          closeAppearancePickers();
        });
        host.appendChild(button);
      }
    }

    function renderAppearanceAccentGrid() {
      const host = $("appearanceAccentGrid");
      if (!host) {
        return;
      }
      const current = state.appearance || DEFAULT_APPEARANCE;
      host.replaceChildren();
      for (const option of getSelectOptions("appearanceAccent")) {
        const button = document.createElement("button");
        button.type = "button";
        button.className = "appearance-accent-button";
        button.classList.toggle("active", current.accent === option.value);
        button.setAttribute("aria-pressed", current.accent === option.value ? "true" : "false");
        button.style.setProperty("--accent-dot", ACCENT_COLORS[option.value] || ACCENT_COLORS.blue);
        const dot = document.createElement("span");
        dot.className = "appearance-accent-dot";
        dot.setAttribute("aria-hidden", "true");
        const label = document.createElement("span");
        label.textContent = option.label;
        button.append(dot, label);
        button.addEventListener("click", () => {
          const select = $("appearanceAccent");
          if (select) {
            select.value = option.value;
          }
          updateAppearanceFromControls();
          closeAppearancePickers();
        });
        host.appendChild(button);
      }
    }

    function renderAppearanceFontGrid(selectId, hostId, stacks, sampleText) {
      const host = $(hostId);
      const select = $(selectId);
      if (!host || !select) {
        return;
      }
      host.replaceChildren();
      const currentValue = select.value;
      for (const option of Array.from(select.options)) {
        const button = document.createElement("button");
        button.type = "button";
        button.className = "appearance-font-card";
        button.classList.toggle("active", option.value === currentValue);
        button.setAttribute("aria-pressed", option.value === currentValue ? "true" : "false");
        button.style.fontFamily = stacks[option.value] || "";

        const title = document.createElement("div");
        title.className = "appearance-font-card-title";
        title.textContent = option.textContent.trim();
        const sample = document.createElement("div");
        sample.className = "appearance-font-card-sample";
        sample.textContent = sampleText;
        button.append(title, sample);
        button.addEventListener("click", () => {
          select.value = option.value;
          updateAppearanceFromControls();
          closeAppearancePickers();
        });
        host.appendChild(button);
      }
    }

    function appearanceSlotSnapshot(appearance = state.appearance || DEFAULT_APPEARANCE) {
      const current = normalizeAppearanceSettings(appearance);
      return {
        theme: current.theme,
        density: current.density,
        sidebarMode: current.sidebarMode,
        topStatus: current.topStatus,
        accent: current.accent,
        uiFont: current.uiFont,
        monoFont: current.monoFont,
        uiFontSize: current.uiFontSize,
        codeFontSize: current.codeFontSize,
        uiFontWeight: current.uiFontWeight,
        custom: { ...current.custom }
      };
    }

    function normalizeAppearanceSlot(value) {
      if (!value || typeof value !== "object") {
        return null;
      }
      return appearanceSlotSnapshot({ ...value, language: DEFAULT_APPEARANCE.language });
    }

    function loadAppearanceSlots() {
      try {
        const parsed = JSON.parse(window.localStorage.getItem(APPEARANCE_SLOTS_STORAGE_KEY) || "[]");
        const list = Array.isArray(parsed?.slots) ? parsed.slots : (Array.isArray(parsed) ? parsed : []);
        return Array.from({ length: APPEARANCE_SLOT_COUNT }, (_, index) => normalizeAppearanceSlot(list[index]));
      } catch {
        return Array.from({ length: APPEARANCE_SLOT_COUNT }, () => null);
      }
    }

    function saveAppearanceSlots(slots) {
      try {
        window.localStorage.setItem(APPEARANCE_SLOTS_STORAGE_KEY, JSON.stringify({
          version: 1,
          slots: Array.from({ length: APPEARANCE_SLOT_COUNT }, (_, index) => normalizeAppearanceSlot(slots[index]))
        }));
      } catch {
      }
    }

    function saveAppearanceSlot(index) {
      const slots = loadAppearanceSlots();
      slots[index] = appearanceSlotSnapshot();
      saveAppearanceSlots(slots);
      renderAppearanceSlots();
    }

    function applyAppearanceSlot(index) {
      const slot = loadAppearanceSlots()[index];
      if (!slot) {
        return;
      }
      const current = state.appearance || DEFAULT_APPEARANCE;
      state.appearance = normalizeAppearanceSettings({
        ...current,
        ...slot,
        language: current.language
      });
      applyAppearanceSettings();
    }

    function clearAppearanceSlot(index) {
      const slots = loadAppearanceSlots();
      slots[index] = null;
      saveAppearanceSlots(slots);
      renderAppearanceSlots();
    }

    function renderAppearanceSlots() {
      const host = $("appearanceSlotGrid");
      if (!host) {
        return;
      }
      host.replaceChildren();
      const slots = loadAppearanceSlots();
      slots.forEach((slot, index) => {
        const card = document.createElement("div");
        card.className = "appearance-slot-card";
        card.classList.toggle("is-empty", !slot);
        const title = document.createElement("div");
        title.className = "appearance-slot-title";
        title.textContent = formatUiTemplate("appearance.slot.title", { number: index + 1 }, `Custom ${index + 1}`);
        const meta = document.createElement("div");
        meta.className = "appearance-slot-meta";
        meta.textContent = slot
          ? `${getSelectOptionLabel("appearanceThemePreset", slot.theme)} / ${getSelectOptionLabel("appearanceUiFont", slot.uiFont)} / ${slot.uiFontSize}px`
          : uiText("appearance.slot.empty", "Empty slot");
        const swatches = document.createElement("div");
        swatches.className = "appearance-slot-swatches";
        if (slot) {
          const { palette, accent } = getAppearancePreviewPalette(slot.theme, {
            ...DEFAULT_APPEARANCE,
            ...slot,
            custom: slot.custom || DEFAULT_APPEARANCE.custom
          });
          appendAppearanceSwatch(swatches, palette.bg, "appearance-slot-swatch");
          appendAppearanceSwatch(swatches, palette.panel, "appearance-slot-swatch");
          appendAppearanceSwatch(swatches, palette.text, "appearance-slot-swatch");
          appendAppearanceSwatch(swatches, accent, "appearance-slot-swatch");
        } else {
          ["--line", "--panel-2", "--muted", "--cyan"].forEach(token => appendAppearanceSwatch(swatches, `var(${token})`, "appearance-slot-swatch"));
        }
        const actions = document.createElement("div");
        actions.className = "appearance-slot-actions";
        const save = document.createElement("button");
        save.type = "button";
        save.textContent = uiText("appearance.slot.save", "Save");
        save.addEventListener("click", () => saveAppearanceSlot(index));
        const apply = document.createElement("button");
        apply.type = "button";
        apply.textContent = uiText("appearance.slot.apply", "Apply");
        apply.disabled = !slot;
        apply.addEventListener("click", () => applyAppearanceSlot(index));
        const clear = document.createElement("button");
        clear.type = "button";
        clear.textContent = uiText("appearance.slot.clear", "Clear");
        clear.disabled = !slot;
        clear.addEventListener("click", () => clearAppearanceSlot(index));
        actions.append(save, apply, clear);
        card.append(title, meta, swatches, actions);
        host.appendChild(card);
      });
    }

    function renderAppearanceOptionPreviews() {
      ensureAppearancePicker("appearanceThemePreset", "appearanceThemeCards");
      ensureAppearancePicker("appearanceAccent", "appearanceAccentGrid");
      ensureAppearancePicker("appearanceUiFont", "appearanceUiFontOptions");
      ensureAppearancePicker("appearanceMonoFont", "appearanceMonoFontOptions");
      applyFontOptionStyles("appearanceUiFont", UI_FONT_STACKS);
      applyFontOptionStyles("appearanceMonoFont", MONO_FONT_STACKS);
      renderAppearanceThemeCards();
      renderAppearanceAccentGrid();
      renderAppearanceFontGrid("appearanceUiFont", "appearanceUiFontOptions", UI_FONT_STACKS, "Verbeam Aa 123");
      renderAppearanceFontGrid("appearanceMonoFont", "appearanceMonoFontOptions", MONO_FONT_STACKS, "auto -> zh-TW 123");
      updateAppearancePickerTriggers();
      renderAppearanceSlots();
    }

    function applyAppearanceSettings(options = {}) {
      const next = normalizeAppearanceSettings(state.appearance || DEFAULT_APPEARANCE);
      state.appearance = next;
      const { resolvedTheme, palette } = resolveAppearancePalette(next);
      applyPaletteVariables(palette);
      applyTypographyVariables(next);
      document.body.dataset.theme = next.theme;
      document.body.dataset.resolvedTheme = resolvedTheme;
      document.body.dataset.colorScheme = palette.scheme;
      document.body.dataset.density = next.density;
      document.body.dataset.sidebarMode = next.sidebarMode;
      document.body.dataset.topStatus = next.topStatus;
      postShellAppearance(palette.scheme);
      const accentColor = next.theme === "custom" ? next.custom.accent : (ACCENT_COLORS[next.accent] || ACCENT_COLORS[palette.defaultAccent] || ACCENT_COLORS.blue);
      document.documentElement.style.setProperty("--cyan", accentColor);
      document.documentElement.style.setProperty("--accent-rgb", next.theme === "custom" ? hexToRgbString(accentColor) : (ACCENT_RGB[next.accent] || ACCENT_RGB.blue));
      const widths = SIDEBAR_MODE_WIDTHS[next.sidebarMode] || SIDEBAR_MODE_WIDTHS.compact;
      document.documentElement.style.setProperty("--sidebar-w", `${widths.sidebar}px`);
      document.documentElement.style.setProperty("--settings-nav-w", `${widths.settingsNav}px`);
      setSidebarCollapsed(next.sidebarMode === "rail", options.persistSidebar !== false);
      syncAppearanceControls();
      applyDisplayLanguage(next.language);
      if (options.persist !== false) {
        saveAppearanceSettings();
        persistLayoutResize();
      }
    }

    function syncAppearanceControls() {
      const current = state.appearance || DEFAULT_APPEARANCE;
      const bindings = [
        ["appearanceThemePreset", current.theme],
        ["appearanceDensity", current.density],
        ["appearanceSidebarMode", current.sidebarMode],
        ["appearanceTopStatus", current.topStatus],
        ["appearanceAccent", current.accent],
        ["appearanceUiFont", current.uiFont],
        ["appearanceMonoFont", current.monoFont],
        ["appearanceUiFontSize", current.uiFontSize],
        ["appearanceCodeFontSize", current.codeFontSize],
        ["appearanceUiWeight", current.uiFontWeight],
        ["appearanceLanguage", current.language],
        ["appearanceCustomAccent", current.custom?.accent || DEFAULT_APPEARANCE.custom.accent],
        ["appearanceCustomBackground", current.custom?.background || DEFAULT_APPEARANCE.custom.background],
        ["appearanceCustomSurface", current.custom?.surface || DEFAULT_APPEARANCE.custom.surface],
        ["appearanceCustomText", current.custom?.foreground || DEFAULT_APPEARANCE.custom.foreground]
      ];
      for (const [id, value] of bindings) {
        const control = $(id);
        if (control && control.value !== value) {
          control.value = value;
        }
      }
      for (const button of document.querySelectorAll("[data-appearance-theme]")) {
        const active = button.dataset.appearanceTheme === current.theme;
        button.classList.toggle("active", active);
        button.setAttribute("aria-pressed", active ? "true" : "false");
      }
      const customPanel = $("appearanceCustomPanel");
      if (customPanel) {
        customPanel.classList.toggle("active", current.theme === "custom");
      }
      const uiSizeValue = $("appearanceUiFontSizeValue");
      if (uiSizeValue) {
        uiSizeValue.textContent = `${current.uiFontSize}px`;
      }
      const codeSizeValue = $("appearanceCodeFontSizeValue");
      if (codeSizeValue) {
        codeSizeValue.textContent = `${current.codeFontSize}px`;
      }
      renderAppearanceOptionPreviews();
    }

    function updateAppearanceFromControls() {
      const current = state.appearance || DEFAULT_APPEARANCE;
      state.appearance = normalizeAppearanceSettings({
        ...current,
        theme: $("appearanceThemePreset")?.value || current.theme,
        density: $("appearanceDensity")?.value,
        sidebarMode: $("appearanceSidebarMode")?.value,
        topStatus: $("appearanceTopStatus")?.value,
        accent: $("appearanceAccent")?.value,
        uiFont: $("appearanceUiFont")?.value,
        monoFont: $("appearanceMonoFont")?.value,
        uiFontSize: $("appearanceUiFontSize")?.value,
        codeFontSize: $("appearanceCodeFontSize")?.value,
        uiFontWeight: $("appearanceUiWeight")?.value,
        language: $("appearanceLanguage")?.value,
        custom: {
          accent: $("appearanceCustomAccent")?.value,
          background: $("appearanceCustomBackground")?.value,
          surface: $("appearanceCustomSurface")?.value,
          foreground: $("appearanceCustomText")?.value
        }
      });
      applyAppearanceSettings();
    }

    function updateThemePresetFromControls() {
      const current = state.appearance || DEFAULT_APPEARANCE;
      const theme = $("appearanceThemePreset")?.value || DEFAULT_APPEARANCE.theme;
      const palette = THEME_PALETTES[theme];
      state.appearance = normalizeAppearanceSettings({
        ...current,
        theme,
        accent: palette?.defaultAccent || current.accent
      });
      applyAppearanceSettings();
    }

    function updateCustomAppearanceFromControls() {
      const current = state.appearance || DEFAULT_APPEARANCE;
      state.appearance = normalizeAppearanceSettings({
        ...current,
        theme: "custom",
        custom: {
          accent: $("appearanceCustomAccent")?.value,
          background: $("appearanceCustomBackground")?.value,
          surface: $("appearanceCustomSurface")?.value,
          foreground: $("appearanceCustomText")?.value
        }
      });
      applyAppearanceSettings();
    }

    function formatMemorySize(mb) {
      const value = Number(mb);
      if (!Number.isFinite(value)) {
        return "--";
      }
      if (value >= 1024) {
        return `${(value / 1024).toFixed(value >= 10240 ? 0 : 1)} GB`;
      }
      return `${value >= 100 ? Math.round(value) : value.toFixed(value >= 10 ? 0 : 1)} MB`;
    }

    function memoryGroupMeta(group) {
      const count = Number(group?.processCount || 0);
      return `${count} proc · private ${formatMemorySize(group?.privateMb)}`;
    }

    function renderMemoryCard(valueId, metaId, group) {
      const value = $(valueId);
      const meta = $(metaId);
      if (value) {
        value.textContent = formatMemorySize(group?.workingSetMb);
      }
      if (meta) {
        meta.textContent = memoryGroupMeta(group);
      }
    }

    function renderGpuMemoryCard(gpu) {
      const value = $("memorySummaryGpu");
      const meta = $("memorySummaryGpuMeta");
      if (!gpu?.available) {
        if (value) {
          value.textContent = "--";
        }
        if (meta) {
          meta.textContent = gpu?.reason || "unavailable";
        }
        return;
      }

      if (value) {
        value.textContent = `${formatMemorySize(gpu.usedMb)} / ${formatMemorySize(gpu.totalMb)}`;
      }
      if (meta) {
        const tracked = Number(gpu.trackedProcessMb || 0);
        meta.textContent = tracked > 0
          ? `model ${formatMemorySize(tracked)} · ${gpu.percent || 0}%`
          : `${gpu.percent || 0}% used`;
      }
    }

    function renderMemorySummary(summary) {
      if (!summary) {
        return;
      }
      state.memorySummary = summary;
      renderMemoryCard("memorySummaryApp", "memorySummaryAppMeta", summary.app);
      renderMemoryCard("memorySummaryWebView", "memorySummaryWebViewMeta", summary.webView);
      renderMemoryCard("memorySummaryModel", "memorySummaryModelMeta", summary.model);
      renderGpuMemoryCard(summary.gpu);

      const section = $("memorySummarySection");
      if (section) {
        const total = summary.total || {};
        const gpu = summary.gpu || {};
        section.title = [
          `Total RAM: ${formatMemorySize(total.workingSetMb)}`,
          `Private: ${formatMemorySize(total.privateMb)}`,
          gpu.available ? `GPU VRAM: ${formatMemorySize(gpu.usedMb)} / ${formatMemorySize(gpu.totalMb)}` : "",
          summary.note || ""
        ].filter(Boolean).join("\n");
      }

      const list = $("memorySummaryProcessList");
      if (!list) {
        return;
      }
      list.replaceChildren();
      const rows = Array.isArray(summary.processes) ? summary.processes.slice(0, 12) : [];
      if (rows.length === 0) {
        const empty = document.createElement("div");
        empty.className = "memory-summary-process-row";
        empty.textContent = "No process data";
        list.appendChild(empty);
        return;
      }
      for (const row of rows) {
        const item = document.createElement("div");
        item.className = "memory-summary-process-row";
        item.title = `${row.name || "process"} #${row.pid} · ${row.category || "other"} · private ${formatMemorySize(row.privateMb)}`;
        const name = document.createElement("span");
        name.textContent = `${row.name || "process"} #${row.pid}`;
        const category = document.createElement("span");
        category.textContent = row.category || "other";
        const memory = document.createElement("span");
        memory.textContent = formatMemorySize(row.workingSetMb);
        item.append(name, category, memory);
        list.appendChild(item);
      }
    }

    async function loadMemorySummary({ quiet = false } = {}) {
      const button = $("memorySummaryRefreshButton");
      if (button) {
        button.disabled = true;
      }
      try {
        const summary = await api("/system/memory-summary");
        renderMemorySummary(summary);
      } catch (error) {
        if (!quiet) {
          appendMessage("error", "memory", error.message || String(error));
        }
      } finally {
        if (button) {
          button.disabled = false;
        }
      }
    }

    function initializeAppearanceControls() {
      ensureAppearanceDynamicSections();
      state.appearance = loadAppearanceSettings();
      applyAppearanceSettings({ persist: false, persistSidebar: false });
      for (const id of ["appearanceDensity", "appearanceSidebarMode", "appearanceTopStatus", "appearanceAccent", "appearanceUiFont", "appearanceMonoFont", "appearanceUiWeight", "appearanceLanguage"]) {
        const control = $(id);
        if (control) {
          control.addEventListener("change", updateAppearanceFromControls);
        }
      }
      const preset = $("appearanceThemePreset");
      if (preset) {
        preset.addEventListener("change", updateThemePresetFromControls);
      }
      for (const id of ["appearanceUiFontSize", "appearanceCodeFontSize"]) {
        const control = $(id);
        if (control) {
          control.addEventListener("input", updateAppearanceFromControls);
          control.addEventListener("change", updateAppearanceFromControls);
        }
      }
      for (const button of document.querySelectorAll("[data-appearance-theme]")) {
        button.addEventListener("click", () => {
          const theme = button.dataset.appearanceTheme;
          const palette = THEME_PALETTES[theme];
          state.appearance = normalizeAppearanceSettings({
            ...(state.appearance || DEFAULT_APPEARANCE),
            theme,
            accent: palette?.defaultAccent || (state.appearance || DEFAULT_APPEARANCE).accent
          });
          applyAppearanceSettings();
        });
      }
      for (const id of ["appearanceCustomAccent", "appearanceCustomBackground", "appearanceCustomSurface", "appearanceCustomText"]) {
        const control = $(id);
        if (control) {
          control.addEventListener("input", updateCustomAppearanceFromControls);
          control.addEventListener("change", updateCustomAppearanceFromControls);
        }
      }
      const memoryRefresh = $("memorySummaryRefreshButton");
      if (memoryRefresh) {
        memoryRefresh.addEventListener("click", () => loadMemorySummary());
      }
      loadMemorySummary({ quiet: true }).catch(() => {});
      if (!state.memorySummaryTimer) {
        state.memorySummaryTimer = window.setInterval(() => {
          if (document.querySelector('[data-settings-panel="appearance"]:not(.hidden)')) {
            loadMemorySummary({ quiet: true }).catch(() => {});
          }
        }, 10000);
      }
      try {
        const systemTheme = window.matchMedia && window.matchMedia("(prefers-color-scheme: light)");
        if (systemTheme) {
          systemTheme.addEventListener("change", () => {
            if ((state.appearance || DEFAULT_APPEARANCE).theme === "system") {
              applyAppearanceSettings({ persist: false });
            }
          });
        }
      } catch {
        // System appearance tracking is optional.
      }
      const reset = $("appearanceResetButton");
      if (reset) {
        reset.addEventListener("click", () => {
          state.appearance = normalizeAppearanceSettings(DEFAULT_APPEARANCE);
          applyAppearanceSettings();
        });
      }
    }

    function setSidebarCollapsed(collapsed, persist = true) {
      const shell = document.querySelector(".shell");
      const button = $("sidebarToggle");
      const next = Boolean(collapsed);
      state.sidebarCollapsed = next;
      if (shell) {
        shell.classList.toggle("sidebar-collapsed", next);
      }
      if (button) {
        const label = next ? "Expand sidebar" : "Collapse sidebar";
        button.setAttribute("aria-label", label);
        button.setAttribute("aria-pressed", next ? "true" : "false");
        button.title = label;
      }
      if (persist) {
        try {
          window.localStorage.setItem(SIDEBAR_COLLAPSED_STORAGE_KEY, next ? "1" : "0");
        } catch {
          // Non-essential preference persistence can fail in private contexts.
        }
      }
      window.requestAnimationFrame(() => {
        if (typeof scheduleOcrComposerOverlayFit === "function") {
          scheduleOcrComposerOverlayFit();
        }
        if (typeof renderRegionSelection === "function") {
          renderRegionSelection();
        }
      });
    }

    function loadSidebarCollapsedPreference() {
      try {
        setSidebarCollapsed(window.localStorage.getItem(SIDEBAR_COLLAPSED_STORAGE_KEY) === "1", false);
      } catch {
        setSidebarCollapsed(false, false);
      }
    }

    function initializeSidebarToggle() {
      loadSidebarCollapsedPreference();
      const button = $("sidebarToggle");
      if (!button) {
        return;
      }
      button.addEventListener("click", () => {
        const nextCollapsed = !state.sidebarCollapsed;
        setSidebarCollapsed(nextCollapsed);
        state.appearance = normalizeAppearanceSettings({
          ...(state.appearance || DEFAULT_APPEARANCE),
          sidebarMode: nextCollapsed ? "rail" : ((state.appearance && state.appearance.sidebarMode !== "rail") ? state.appearance.sidebarMode : "compact")
        });
        syncAppearanceControls();
        saveAppearanceSettings();
      });
    }

    function layoutClamp(value, min, max) {
      const safeMin = Number.isFinite(min) ? min : 0;
      const safeMax = Number.isFinite(max) ? Math.max(safeMin, max) : safeMin;
      const safeValue = Number.isFinite(value) ? value : safeMin;
      return Math.min(safeMax, Math.max(safeMin, safeValue));
    }

    function splitMax(containerWidth, otherMin, min) {
      return Math.max(min, containerWidth - otherMin - 10);
    }

    function getLayoutResizeSnapshot(handle) {
      if (!handle || !(handle instanceof Element)) {
        return null;
      }

      const layout = handle.dataset.resizeLayout || "";
      const isSidebar = layout === "sidebar";
      const isRail = layout === "rail";
      const isShellResize = isSidebar || isRail;
      const container = isShellResize ? document.querySelector(".shell") : handle.parentElement;
      const resizePrevious = layout === "settingsNav" || layout === "memory" || layout === "terminal";
      const target = isSidebar
        ? document.querySelector(".sidebar")
        : isRail ? document.querySelector(".activity-rail")
        : resizePrevious ? handle.previousElementSibling : handle.nextElementSibling;
      if (!container || !target) {
        return null;
      }

      const containerRect = container.getBoundingClientRect();
      const targetRect = target.getBoundingClientRect();
      const axis = layout === "terminal" ? "y" : "x";
      if (axis === "y") {
        if (!containerRect.height || !targetRect.height) {
          return null;
        }
      } else if (!containerRect.width || !targetRect.width) {
        return null;
      }

      let varName = "";
      let min = 220;
      let max = targetRect.width;
      let direction = -1;

      if (layout === "rail") {
        varName = "--rail-w";
        min = 44;
        max = 88;
        direction = 1;
      } else if (layout === "sidebar") {
        varName = "--sidebar-w";
        min = 176;
        max = Math.max(min, Math.min(420, window.innerWidth - 440));
        direction = 1;
      } else if (layout === "terminal") {
        varName = "--terminal-drawer-h";
        min = 34;
        max = Math.max(min, Math.min(420, containerRect.height - 240));
        direction = -1;
      } else if (layout === "text") {
        varName = "--text-result-w";
        min = 220;
        max = splitMax(containerRect.width, 240, min);
      } else if (layout === "audio") {
        varName = "--audio-result-w";
        min = 220;
        max = splitMax(containerRect.width, 240, min);
      } else if (layout === "ocr") {
        varName = "--ocr-inspector-w";
        min = 280;
        max = splitMax(containerRect.width, 320, min);
      } else if (layout === "ocrText") {
        varName = "--ocr-text-result-w";
        min = 220;
        max = splitMax(containerRect.width, 220, min);
      } else if (layout === "document") {
        varName = "--document-detail-w";
        min = 320;
        max = splitMax(containerRect.width, 300, min);
      } else if (layout === "region") {
        varName = "--region-result-w";
        min = 220;
        max = splitMax(containerRect.width, 220, min);
      } else if (layout === "settingsNav") {
        varName = "--settings-nav-w";
        min = 168;
        max = Math.max(min, Math.min(360, containerRect.width - 420));
        direction = 1;
      } else if (layout === "provider") {
        varName = "--provider-detail-w";
        min = 240;
        max = splitMax(containerRect.width, 240, min);
      } else if (layout === "memory") {
        varName = "--memory-list-w";
        min = 200;
        max = Math.max(min, Math.min(520, containerRect.width - 360));
        direction = 1;
      } else if (layout === "ocrHistory") {
        varName = "--ocr-history-jobs-w";
        min = 220;
        max = splitMax(containerRect.width, 220, min);
      } else {
        return null;
      }

      return {
        layout,
        handle,
        varName,
        axis,
        direction,
        min,
        max,
        startValue: layoutClamp(axis === "y" ? targetRect.height : targetRect.width, min, max),
        startX: 0,
        startY: 0
      };
    }

    function applyLayoutResizeValue(snapshot, value) {
      if (!snapshot) {
        return;
      }

      const next = layoutClamp(value, snapshot.min, snapshot.max);
      document.documentElement.style.setProperty(snapshot.varName, `${Math.round(next)}px`);
      snapshot.handle.setAttribute("aria-valuemin", String(Math.round(snapshot.min)));
      snapshot.handle.setAttribute("aria-valuemax", String(Math.round(snapshot.max)));
      snapshot.handle.setAttribute("aria-valuenow", String(Math.round(next)));

      if (snapshot.layout === "ocr" && typeof scheduleOcrComposerOverlayFit === "function") {
        scheduleOcrComposerOverlayFit();
      }
      if (snapshot.layout === "region" && typeof renderRegionSelection === "function") {
        window.requestAnimationFrame(renderRegionSelection);
      }
    }

    function persistLayoutResize() {
      try {
        const styles = getComputedStyle(document.documentElement);
        const payload = {};
        for (const varName of LAYOUT_RESIZE_VARS) {
          const raw = styles.getPropertyValue(varName).trim();
          if (!raw.endsWith("px")) {
            continue;
          }
          const value = Number.parseFloat(raw);
          if (Number.isFinite(value) && value > 0) {
            payload[varName] = Math.round(value);
          }
        }
        window.localStorage.setItem(LAYOUT_RESIZE_STORAGE_KEY, JSON.stringify(payload));
      } catch {
        // Non-essential preference persistence can fail in private contexts.
      }
    }

    function loadLayoutResizePreferences() {
      try {
        const raw = window.localStorage.getItem(LAYOUT_RESIZE_STORAGE_KEY);
        const payload = raw ? JSON.parse(raw) : {};
        for (const varName of LAYOUT_RESIZE_VARS) {
          const value = Number(payload[varName]);
          if (Number.isFinite(value) && value > 0) {
            document.documentElement.style.setProperty(varName, `${Math.round(value)}px`);
          }
        }
      } catch {
        // Ignore stale or malformed layout preferences.
      }
    }

    function clampVisibleLayoutResizes() {
      for (const handle of document.querySelectorAll("[data-resize-layout]")) {
        if (!(handle instanceof Element) || (handle.offsetParent === null && handle.dataset.resizeLayout !== "sidebar")) {
          continue;
        }
        const snapshot = getLayoutResizeSnapshot(handle);
        if (!snapshot) {
          continue;
        }
        const inlineValue = document.documentElement.style.getPropertyValue(snapshot.varName).trim();
        if (!inlineValue.endsWith("px")) {
          continue;
        }
        applyLayoutResizeValue(snapshot, snapshot.startValue);
      }
    }

    function beginLayoutResize(event) {
      if (event.button !== 0 || !(event.target instanceof Element)) {
        return;
      }

      const handle = event.target.closest("[data-resize-layout]");
      if (!handle) {
        return;
      }

      const snapshot = getLayoutResizeSnapshot(handle);
      if (!snapshot) {
        return;
      }

      event.preventDefault();
      event.stopPropagation();
      snapshot.startX = event.clientX;
      snapshot.startY = event.clientY;
      state.layoutResize = snapshot;
      handle.classList.add("is-active");
      document.body.classList.add(snapshot.axis === "y" ? "is-resizing-layout-y" : "is-resizing-layout");
      if (snapshot.layout === "terminal") {
        const drawer = $("terminalDrawer");
        if (drawer) {
          drawer.open = true;
          if (typeof clearTerminalDrawerBadge === "function") {
            clearTerminalDrawerBadge();
          }
        }
      }
      try {
        handle.setPointerCapture(event.pointerId);
      } catch {
        // Window-level pointer listeners still handle the drag.
      }
    }

    function updateLayoutResize(event) {
      if (!state.layoutResize) {
        return;
      }

      event.preventDefault();
      const snapshot = state.layoutResize;
      const delta = snapshot.axis === "y" ? event.clientY - snapshot.startY : event.clientX - snapshot.startX;
      applyLayoutResizeValue(snapshot, snapshot.startValue + delta * snapshot.direction);
    }

    function endLayoutResize(event) {
      if (!state.layoutResize) {
        return;
      }

      const snapshot = state.layoutResize;
      snapshot.handle.classList.remove("is-active");
      document.body.classList.remove("is-resizing-layout");
      document.body.classList.remove("is-resizing-layout-y");
      try {
        if (event && Number.isFinite(event.pointerId)) {
          snapshot.handle.releasePointerCapture(event.pointerId);
        }
      } catch {
        // Pointer capture may already be released by the browser.
      }
      state.layoutResize = null;
      persistLayoutResize();
    }

    function onLayoutResizeKeyDown(event) {
      if (!(event.target instanceof Element)) {
        return;
      }

      const handle = event.target.closest("[data-resize-layout]");
      if (!handle) {
        return;
      }

      const snapshot = getLayoutResizeSnapshot(handle);
      if (!snapshot) {
        return;
      }

      const resizeKeys = snapshot.axis === "y"
        ? ["ArrowUp", "ArrowDown", "Home", "End"]
        : ["ArrowLeft", "ArrowRight", "Home", "End"];
      if (!resizeKeys.includes(event.key)) {
        return;
      }

      event.preventDefault();
      const step = event.shiftKey ? 48 : 24;
      let next = snapshot.startValue;
      if (event.key === "Home") {
        next = snapshot.min;
      } else if (event.key === "End") {
        next = snapshot.max;
      } else {
        const positiveKey = snapshot.axis === "y" ? "ArrowDown" : "ArrowRight";
        next = snapshot.startValue + (event.key === positiveKey ? step : -step) * snapshot.direction;
      }
      applyLayoutResizeValue(snapshot, next);
      persistLayoutResize();
    }

    function initializeLayoutResizing() {
      loadLayoutResizePreferences();
      clampVisibleLayoutResizes();
      document.addEventListener("pointerdown", beginLayoutResize);
      window.addEventListener("pointermove", updateLayoutResize);
      window.addEventListener("pointerup", endLayoutResize);
      window.addEventListener("pointercancel", endLayoutResize);
      document.addEventListener("keydown", onLayoutResizeKeyDown);
      window.addEventListener("resize", () => {
        clampVisibleLayoutResizes();
        if (typeof scheduleOcrComposerOverlayFit === "function") {
          scheduleOcrComposerOverlayFit();
        }
        if (typeof renderRegionSelection === "function") {
          window.requestAnimationFrame(renderRegionSelection);
        }
      });
    }

    const SUPPLIER_ICON_BASE = "/design-system/icons/";
    const SUPPLIER_ICON_BY_KEY = Object.freeze({
      aihubmix: "aihubmix-color.svg",
