    });
    const SUPPLIER_COLOR_BY_KEY = Object.freeze({
      api: "linear-gradient(135deg, #00a67e, #047857)",
      apicompatible: "linear-gradient(135deg, #00a67e, #047857)",
      aihubmix: "linear-gradient(135deg, #006ffb, #1d4ed8)",
