      compsharecoding: "linear-gradient(135deg, #4e5065, #111827)",
      deepl: "linear-gradient(135deg, #042b48, #0f6f9e)",
      deepseek: "linear-gradient(135deg, #0ea5e9, #0284c7)",
      eflowcode: "linear-gradient(135deg, #0f172a, #000000)",
      openrouter: "linear-gradient(135deg, #6566f1, #4f46e5)",
      siliconflow: "linear-gradient(135deg, #6e29f6, #4c1d95)",
      openai: "linear-gradient(135deg, #00a67e, #047857)",
      anthropic: "linear-gradient(135deg, #d97757, #b45309)",
      google: "linear-gradient(135deg, #4285f4, #2563eb)",
      gemma: "linear-gradient(135deg, #4285f4, #2563eb)",
      qwen: "linear-gradient(135deg, #624aff, #4f46e5)",
      tencent: "linear-gradient(135deg, #1d9bf0, #2563eb)",
      tencentcloud: "linear-gradient(135deg, #1d9bf0, #2563eb)",
      zhipu: "linear-gradient(135deg, #0f62fe, #1d4ed8)",
      kimi: "linear-gradient(135deg, #6366f1, #4338ca)",
      kimicoding: "linear-gradient(135deg, #6366f1, #4338ca)",
      moonshot: "linear-gradient(135deg, #6366f1, #4338ca)",
      lmstudio: "linear-gradient(135deg, #111827, #000000)",
      metaai: "linear-gradient(135deg, #1877f2, #2563eb)",
      minimax: "linear-gradient(135deg, #ff6b6b, #e11d48)",
      minimaxcoding: "linear-gradient(135deg, #ff6b6b, #e11d48)",
      modelscope: "linear-gradient(135deg, #624aff, #4f46e5)",
      stepfun: "linear-gradient(135deg, #16d6d2, #0f766e)",
      doubao: "linear-gradient(135deg, #3370ff, #1d4ed8)",
      nvidia: "linear-gradient(135deg, #76b900, #4d7c0f)",
      opencodego: "linear-gradient(135deg, #211e1e, #000000)",
      packycode: "linear-gradient(135deg, #3b82f6, #1d4ed8)",
      perplexity: "linear-gradient(135deg, #20b2aa, #0f766e)",
      pipellm: "linear-gradient(135deg, #475569, #111827)",
      qianfancoding: "linear-gradient(135deg, #2932e1, #1d4ed8)",
      relaxycode: "linear-gradient(135deg, #111827, #000000)",
      rightcode: "linear-gradient(135deg, #e96b2c, #9a3412)",
      sssaicode: "linear-gradient(135deg, #0ff5ce, #147a8a)",
      sudocode: "linear-gradient(135deg, #111827, #000000)",
      cohere: "linear-gradient(135deg, #39594d, #1f352f)",
      mock: "linear-gradient(135deg, #64748b, #475569)",
      custom: "linear-gradient(135deg, #8b5cf6, #7c3aed)"
    });
    const supplierSvgIconCache = new Map();

    function normalizeSupplierKey(value) {
      return String(value || "").toLowerCase().replace(/[^a-z0-9]/g, "");
    }

    function getSupplierInitials(name, fallback = "API") {
      const words = String(name || "").trim().split(/\s+/).filter(Boolean);
      if (words.length >= 2) {
        return (words[0][0] + words[1][0]).toUpperCase();
      }
      if (words.length === 1) {
        return words[0].substring(0, Math.min(2, words[0].length)).toUpperCase();
      }
      return fallback;
    }

    function getSupplierColor(key, name) {
      if (SUPPLIER_COLOR_BY_KEY[key]) return SUPPLIER_COLOR_BY_KEY[key];
      const colors = [
        "linear-gradient(135deg, #6366f1, #4f46e5)",
        "linear-gradient(135deg, #8b5cf6, #7c3aed)",
        "linear-gradient(135deg, #ec4899, #db2777)",
        "linear-gradient(135deg, #14b8a6, #0d9488)",
        "linear-gradient(135deg, #a855f7, #9333ea)",
        "linear-gradient(135deg, #f43f5e, #e11d48)"
      ];
      let hash = 0;
      const source = String(name || key || "api");
      for (let i = 0; i < source.length; i++) {
        hash = source.charCodeAt(i) + ((hash << 5) - hash);
      }
      return colors[Math.abs(hash) % colors.length];
    }

    function getSupplierIconName(key, name = "") {
      if (SUPPLIER_ICON_BY_KEY[key]) return SUPPLIER_ICON_BY_KEY[key];
      const normalizedName = normalizeSupplierKey(name);
      return SUPPLIER_ICON_BY_KEY[normalizedName] || "";
    }

    function getSupplierAvatarHtml(key, name, sizeClass = "") {
      const normalizedKey = normalizeSupplierKey(key);
      const initials = getSupplierInitials(name || key, "API");
      const iconName = getSupplierIconName(normalizedKey, name);
      const bgColor = getSupplierColor(normalizedKey, name);
      const className = `supplier-avatar${iconName ? " has-icon" : ""}${sizeClass ? " " + sizeClass : ""}`;
      const img = iconName && iconName.toLowerCase().endsWith(".svg")
        ? `<span class="supplier-avatar-icon" data-supplier-icon="${escapeHtml(iconName)}" aria-hidden="true"></span>`
        : iconName
          ? `<img src="${SUPPLIER_ICON_BASE}${escapeHtml(iconName)}" alt="" loading="lazy" onerror="this.parentElement.classList.add('icon-failed'); this.remove();">`
          : "";
      return `<div class="${className}" style="background: ${iconName ? "rgba(255, 255, 255, 0.06)" : bgColor};">${img}<span class="supplier-avatar-initials">${escapeHtml(initials)}</span></div>`;
    }

    function hydrateSupplierIcons(root = document) {
      root.querySelectorAll("[data-supplier-icon]").forEach(async node => {
        const iconName = node.getAttribute("data-supplier-icon") || "";
        if (!iconName || node.dataset.loaded === "1") return;
        node.dataset.loaded = "1";
        try {
          let svg = supplierSvgIconCache.get(iconName);
          if (!svg) {
            const response = await fetch(`${SUPPLIER_ICON_BASE}${iconName}`);
            if (!response.ok) throw new Error(`HTTP ${response.status}`);
            svg = await response.text();
            svg = `<style>svg{width:100%!important;height:100%!important}</style>${svg}`;
            supplierSvgIconCache.set(iconName, svg);
          }
          node.innerHTML = svg;
        } catch {
          const avatar = node.closest(".supplier-avatar");
          if (avatar) {
            avatar.classList.add("icon-failed");
          }
          node.remove();
        }
      });
    }

    function getSupplierAvatar(supplier) {
      return getSupplierAvatarHtml(supplier.presetId || supplier.name, supplier.name || supplier.presetId);
    }

    const SUPPLIER_PRESET_CATEGORY_ORDER = Object.freeze([
      "custom",
      "official",
      "cn_official",
      "aggregator",
      "first_party",
      "third_party",
      "coding_plan"
    ]);

    const SUPPLIER_PRESET_CATEGORY_LABELS = Object.freeze({
      all: "All",
      custom: "Custom model",
      official: "Official",
      cn_official: "CN official",
      aggregator: "Aggregator",
      first_party: "First party",
      third_party: "Third party",
      coding_plan: "Coding plan"
    });

    function normalizeSupplierPresetCategory(category) {
      const value = String(category || "third_party")
        .trim()
        .toLowerCase()
        .replace(/[\s-]+/g, "_");
      return value || "third_party";
    }

    function supplierPresetCategoryLabel(category) {
      const normalized = normalizeSupplierPresetCategory(category);
      return SUPPLIER_PRESET_CATEGORY_LABELS[normalized] || normalized
        .split("_")
        .map(part => part ? part[0].toUpperCase() + part.slice(1) : part)
        .join(" ");
    }

    function supplierPresetCategoryRank(category) {
      const normalized = normalizeSupplierPresetCategory(category);
      const index = SUPPLIER_PRESET_CATEGORY_ORDER.indexOf(normalized);
      return index >= 0 ? index : SUPPLIER_PRESET_CATEGORY_ORDER.length;
    }

    function sortedSupplierPresets() {
      ensureCustomSupplierPreset();
      return [...(state.presets || [])].sort((a, b) => {
        const rank = supplierPresetCategoryRank(a.category) - supplierPresetCategoryRank(b.category);
        if (rank !== 0) return rank;
        return String(a.displayName || a.id || "").localeCompare(String(b.displayName || b.id || ""), undefined, { sensitivity: "base" });
      });
    }

    function renderPresetGrid() {
      const grid = $("supplierPresetGrid");
      if (!grid) return;
      grid.innerHTML = "";

      const select = $("supplierPreset");
      const currentValue = select ? select.value : "";
      const isDisabled = select ? select.disabled : false;
      const presets = sortedSupplierPresets();
      const categories = [...new Set(presets.map(preset => normalizeSupplierPresetCategory(preset.category)))]
        .sort((a, b) => supplierPresetCategoryRank(a) - supplierPresetCategoryRank(b) || supplierPresetCategoryLabel(a).localeCompare(supplierPresetCategoryLabel(b)));
      const activeCategory = categories.includes(state.supplierPresetCategory) ? state.supplierPresetCategory : "all";
      state.supplierPresetCategory = activeCategory;
      const visibleCategories = activeCategory === "all" ? categories : categories.filter(category => category === activeCategory);

      const picker = document.createElement("div");
      picker.className = "supplier-preset-picker";

      const tabs = document.createElement("div");
      tabs.className = "supplier-preset-tabs";
      const tabDefs = [
        { id: "all", label: SUPPLIER_PRESET_CATEGORY_LABELS.all, count: presets.length },
        ...categories.map(category => ({
          id: category,
          label: supplierPresetCategoryLabel(category),
          count: presets.filter(preset => normalizeSupplierPresetCategory(preset.category) === category).length
        }))
      ];
      tabDefs.forEach(tab => {
        const button = document.createElement("button");
        button.type = "button";
        button.className = "supplier-preset-tab" + (tab.id === activeCategory ? " active" : "");
        button.innerHTML = `${escapeHtml(tab.label)}<span class="supplier-preset-tab-count">${tab.count}</span>`;
        button.addEventListener("click", () => {
          state.supplierPresetCategory = tab.id;
          renderPresetGrid();
        });
        tabs.appendChild(button);
      });
      picker.appendChild(tabs);

      const groups = document.createElement("div");
      groups.className = "supplier-preset-groups";

      function createPresetButton(preset) {
        const btn = document.createElement("button");
        btn.type = "button";
        btn.className = "preset-btn" + (preset.id === currentValue ? " active" : "") + (isDisabled ? " disabled" : "");
        btn.disabled = isDisabled;

        const presetKey = normalizeSupplierKey(preset.id);
        const iconName = getSupplierIconName(presetKey, preset.displayName);
        const dotColor = getSupplierColor(presetKey || "custom", preset.displayName);
        const iconHtml = iconName && iconName.toLowerCase().endsWith(".svg")
          ? `<span class="supplier-avatar-icon" data-supplier-icon="${escapeHtml(iconName)}" aria-hidden="true"></span>`
          : iconName
            ? `<img src="${SUPPLIER_ICON_BASE}${escapeHtml(iconName)}" alt="" loading="lazy" onerror="this.replaceWith(document.createTextNode('${escapeHtml(getSupplierInitials(preset.displayName, 'API'))}'));">`
            : `<span>${escapeHtml(getSupplierInitials(preset.displayName, "API"))}</span>`;
        const metaParts = [
          supplierPresetCategoryLabel(preset.category),
          preset.defaultModel || preset.protocol || ""
        ].filter(Boolean);

        btn.innerHTML = `
          <div class="preset-btn-dot" style="background: ${iconName ? "rgba(255, 255, 255, 0.06)" : dotColor}; box-shadow: ${iconName ? "none" : "0 0 6px rgba(255,255,255,0.08)"};">${iconHtml}</div>
          <div class="preset-btn-copy">
            <div class="preset-btn-label">${escapeHtml(preset.displayName)}</div>
            <div class="preset-btn-meta">${escapeHtml(metaParts.join(" / "))}</div>
          </div>
        `;

        if (!isDisabled) {
          btn.addEventListener("click", () => {
            if (select) {
              select.value = preset.id;
              select.dispatchEvent(new Event("change"));
            }
          });
        }
        return btn;
      }

      visibleCategories.forEach(category => {
        const categoryPresets = presets.filter(preset => normalizeSupplierPresetCategory(preset.category) === category);
        if (categoryPresets.length === 0) return;

        const section = document.createElement("section");
        section.className = "supplier-preset-group";
        section.innerHTML = `
          <div class="supplier-preset-group-head">
            <div class="supplier-preset-group-title">${escapeHtml(supplierPresetCategoryLabel(category))}</div>
            <div class="supplier-preset-group-meta">${categoryPresets.length} provider${categoryPresets.length === 1 ? "" : "s"}</div>
          </div>
        `;

        const categoryGrid = document.createElement("div");
        categoryGrid.className = "preset-button-grid";
        categoryPresets.forEach(preset => categoryGrid.appendChild(createPresetButton(preset)));
        section.appendChild(categoryGrid);
        groups.appendChild(section);
      });
      picker.appendChild(groups);
      grid.appendChild(picker);
      hydrateSupplierIcons(grid);
    }

    function createCustomSupplierPreset() {
      return {
        id: "custom",
        displayName: "Custom API",
        category: "custom",
        websiteUrl: "",
        apiKeyUrl: "",
        protocol: "openai_chat",
        baseUrl: "",
        modelsUrl: "",
        requiresApiKey: false,
        defaultModel: ""
      };
    }

    function ensureCustomSupplierPreset() {
      if (!Array.isArray(state.presets)) {
        state.presets = [];
      }
      if (!state.presets.some(p => p.id === "custom")) {
        state.presets.push(createCustomSupplierPreset());
      }
    }

    async function ensureSupplierPresetsReady() {
      if (!Array.isArray(state.presets) || state.presets.length === 0) {
        await loadPresets();
      }
      ensureCustomSupplierPreset();
      const select = $("supplierPreset");
      if (select && select.options.length !== state.presets.length) {
        populateSupplierPresetsSelect();
      }
    }

    async function loadPresets() {
      try {
        const response = await api("/translation/api-supplier-presets");
        state.presets = response && response.presets ? response.presets : [];
        ensureCustomSupplierPreset();
        populateSupplierPresetsSelect();
        renderTranslationProviders();
      } catch (error) {
        ensureCustomSupplierPreset();
        populateSupplierPresetsSelect();
        appendMessage("error", "presets", error.message || String(error));
      }
    }

    function populateSupplierPresetsSelect() {
      const select = $("supplierPreset");
      if (!select) return;
      select.innerHTML = "";
      sortedSupplierPresets().forEach(preset => {
        const opt = document.createElement("option");
        opt.value = preset.id;
        opt.textContent = preset.displayName;
        select.appendChild(opt);
      });
      renderPresetGrid();
      handlePresetChange();
    }

    function handlePresetChange() {
      const select = $("supplierPreset");
      if (!select) return;
      ensureCustomSupplierPreset();
      const presetId = select.value || "custom";
      let preset = state.presets.find(p => p.id === presetId);
      if (!preset) {
        preset = state.presets.find(p => p.id === "custom");
        if (!preset) return;
        select.value = preset.id;
      }

      if (state.editingSupplierId === null) {
        $("supplierName").value = preset.displayName;
        $("supplierBaseUrl").value = preset.baseUrl;
        $("supplierModelsUrl").value = preset.modelsUrl || "";
        $("supplierActiveModel").value = preset.defaultModel || "";

        const keyInput = $("supplierApiKey");
        if (preset.requiresApiKey) {
          keyInput.placeholder = "API Key is required";
          keyInput.required = true;
        } else {
          keyInput.placeholder = "API Key (Optional)";
          keyInput.required = false;
        }

        $("fetchModalModelsButton").disabled = true;
        $("fetchModalModelsButton").title = "Save the supplier first to fetch models";

        $("supplierModelDatalist").innerHTML = "";
        if (preset.defaultModel) {
          const opt = document.createElement("option");
          opt.value = preset.defaultModel;
          $("supplierModelDatalist").appendChild(opt);
        }
      }
      renderPresetGrid();
    }

    function setApiSuppliersExpanded(expanded) {
      state.apiSuppliersExpanded = !!expanded;
      const body = $("apiSuppliersBody");
      const toggle = $("apiSuppliersToggle");
      const icon = $("apiSuppliersToggleIcon");
      if (body) {
        body.classList.toggle("collapsed", !state.apiSuppliersExpanded);
      }
      if (toggle) {
        toggle.setAttribute("aria-expanded", state.apiSuppliersExpanded ? "true" : "false");
      }
      if (icon) {
        icon.textContent = state.apiSuppliersExpanded ? "-" : "+";
      }
    }

    function updateApiSuppliersCount() {
      const count = $("apiSuppliersCount");
      if (count) {
        count.textContent = `(${state.suppliers.length})`;
      }
    }

    async function loadSuppliers() {
      try {
        const [suppliers, route] = await Promise.all([
          api("/translation/api-suppliers"),
          api("/translation/routes/active")
        ]);
        state.suppliers = suppliers || [];
        state.activeRoute = route;
        renderSuppliers();
        renderTranslationProviders();
      } catch (error) {
        appendMessage("error", "suppliers", error.message || String(error));
      }
    }

    function renderSuppliers() {
      const grid = $("supplierListGrid");
      updateApiSuppliersCount();
      if (!grid) return;
      grid.innerHTML = "";

      if (state.suppliers.length === 0) {
        grid.innerHTML = `<div class="supplier-grid-empty">No API compatible suppliers configured. Click "Add API Supplier" to create one.</div>`;
        return;
      }

      state.suppliers.forEach(supplier => {
        const isCurrentlyActive = state.activeRoute &&
          state.activeRoute.provider.toLowerCase() === "api-compatible" &&
          state.activeRoute.supplierId === supplier.id;

        const card = document.createElement("div");
        card.className = "supplier-card" + (isCurrentlyActive ? " active" : "");

        let latencyHtml = "latency: --";
        let latencyClass = "";
        if (supplier.lastHealth && supplier.lastHealth.status !== "unknown") {
          if (supplier.lastHealth.status === "ready" || supplier.lastHealth.status === "healthy" || supplier.lastHealth.status === "ok") {
            const ms = supplier.lastHealth.latencyMs;
            latencyHtml = `latency: ${ms !== null && ms !== undefined ? ms + "ms" : "ok"}`;
            latencyClass = ms !== null && ms !== undefined && ms < 300 ? "latency-good" : "latency-warn";
          } else {
            latencyHtml = `error: ${supplier.lastHealth.message || "failed"}`;
            latencyClass = "latency-error";
          }
        }

        const activeModelText = supplier.activeModel || "(none)";

        card.innerHTML = `
          <div class="supplier-card-header">
            <div class="supplier-card-title">
              ${getSupplierAvatar(supplier)}
              <span>${escapeHtml(supplier.name)}</span>
            </div>
            <div class="supplier-card-actions">
              <button class="activate-btn" type="button" data-supplier-action="activate" data-supplier-id="${escapeHtml(supplier.id)}" ${isCurrentlyActive ? "disabled" : ""}>
                ${isCurrentlyActive ? '<i class="ri-checkbox-circle-line"></i> Active' : 'Activate'}
              </button>
            </div>
          </div>
          <div class="supplier-card-body">
            <div class="supplier-card-field">
              <span>Protocol</span>
              <strong>${escapeHtml(supplier.protocol)}</strong>
            </div>
            <div class="supplier-card-field">
              <span>Base URL</span>
              <strong title="${escapeHtml(supplier.baseUrl)}">${escapeHtml(supplier.baseUrl)}</strong>
            </div>
            <div class="supplier-card-field">
              <span>Active Model</span>
              <strong title="${escapeHtml(activeModelText)}">${escapeHtml(activeModelText)}</strong>
            </div>
          </div>
          <div class="supplier-card-footer">
            <span class="supplier-latency ${latencyClass}">
              <i class="ri-pulse-line"></i> ${escapeHtml(latencyHtml)}
            </span>
            ${supplierBalanceHtml(supplier)}
            <div class="supplier-card-toolbar">
              <button type="button" data-supplier-action="test" data-supplier-id="${escapeHtml(supplier.id)}" title="Test connection latency"><i class="ri-wifi-line"></i><span>Test</span></button>
              ${supplier.supportsBalance ? `<button type="button" data-supplier-action="balance" data-supplier-id="${escapeHtml(supplier.id)}" title="Refresh balance"><i class="ri-bank-card-line"></i><span>Balance</span></button>` : ""}
              <button type="button" data-supplier-action="fetch" data-supplier-id="${escapeHtml(supplier.id)}" title="Fetch model catalog"><i class="ri-download-cloud-line"></i><span>Fetch</span></button>
              <button type="button" data-supplier-action="edit" data-supplier-id="${escapeHtml(supplier.id)}" class="icon-only" title="Edit settings" aria-label="Edit supplier"><i class="ri-edit-line"></i></button>
              <button type="button" data-supplier-action="delete" data-supplier-id="${escapeHtml(supplier.id)}" class="danger icon-only" title="Delete supplier" aria-label="Delete supplier"><i class="ri-delete-bin-line"></i></button>
            </div>
          </div>
        `;
        grid.appendChild(card);
      });
      hydrateSupplierIcons(grid);
    }

    function showSupplierEditor() {
      const modal = $("supplierModal");
      const mount = $("supplierInlineEditorMount");
      if (!modal) {
        return;
      }
      if (typeof setApiSuppliersExpanded === "function") {
        setApiSuppliersExpanded(true);
      }
      if (mount) {
        mount.classList.remove("hidden");
        if (modal.parentElement !== mount) {
          mount.appendChild(modal);
        }
        modal.classList.add("inline-supplier-editor");
      }
      modal.classList.remove("hidden");
    }

    function hideSupplierEditor() {
      const modal = $("supplierModal");
      if (modal) {
        modal.classList.add("hidden");
      }
      const mount = $("supplierInlineEditorMount");
      if (mount) {
        mount.classList.add("hidden");
      }
    }

    async function openSupplierModal(supplierId = null, preferredPresetId = "custom") {
      state.editingSupplierId = supplierId;
      const modal = $("supplierModal");
      const title = $("supplierModalTitle");
      const nameInput = $("supplierName");
      const baseUrlInput = $("supplierBaseUrl");
      const modelsUrlInput = $("supplierModelsUrl");
      const apiKeyInput = $("supplierApiKey");
      const activeModelInput = $("supplierActiveModel");
      const presetSelect = $("supplierPreset");
      const fetchBtn = $("fetchModalModelsButton");

      if (!modal || !title || !nameInput || !baseUrlInput || !modelsUrlInput || !apiKeyInput || !activeModelInput || !presetSelect || !fetchBtn) {
        appendMessage("error", "suppliers", "Supplier modal is missing required controls.");
        return;
      }

      showSupplierEditor();

      try {
        await ensureSupplierPresetsReady();
      } catch (error) {
        const message = error && error.message ? error.message : String(error);
        appendMessage("error", "suppliers", message);
      }

      apiKeyInput.type = "password";
      $("toggleSupplierApiKey").innerHTML = '<i class="ri-eye-line"></i>';

      if (supplierId === null) {
        title.innerHTML = '<i class="ri-add-line"></i> Add API Supplier';
        presetSelect.disabled = false;
        state.supplierPresetCategory = "all";
        nameInput.value = "";
        baseUrlInput.value = "";
        modelsUrlInput.value = "";
        apiKeyInput.value = "";
        activeModelInput.value = "";
        apiKeyInput.placeholder = "sk-...";
        apiKeyInput.required = false;
        if ($("supplierBalanceTemplate")) $("supplierBalanceTemplate").value = "";
        if ($("supplierBalanceUrl")) $("supplierBalanceUrl").value = "";
        if ($("supplierBalanceAuto")) $("supplierBalanceAuto").value = "0";

        const optionValues = Array.from(presetSelect.options).map(option => option.value);
        const selectedPreset = optionValues.includes(preferredPresetId)
          ? preferredPresetId
          : optionValues.includes("custom")
            ? "custom"
            : optionValues[0] || "";
        if (selectedPreset) {
          presetSelect.value = selectedPreset;
        }
        handlePresetChange();
      } else {
        title.innerHTML = '<i class="ri-edit-line"></i> Edit API Supplier';
        presetSelect.disabled = true;

        const supplier = state.suppliers.find(s => s.id === supplierId);
        if (supplier) {
          presetSelect.value = supplier.presetId || "";
          const preset = state.presets.find(p => p.id === supplier.presetId);
          state.supplierPresetCategory = preset ? normalizeSupplierPresetCategory(preset.category) : "all";
          nameInput.value = supplier.name || "";
          baseUrlInput.value = supplier.baseUrl || "";
          modelsUrlInput.value = supplier.modelsUrl || "";
          apiKeyInput.value = "";
          apiKeyInput.placeholder = supplier.hasApiKey ? "?ＴＴＴＴＴＴＴＴＴＴＴ?(Saved)" : "Enter API Key";
          apiKeyInput.placeholder = supplier.hasApiKey ? "Saved API key" : "Enter API Key";
          apiKeyInput.required = false;
          activeModelInput.value = supplier.activeModel || "";
          if ($("supplierBalanceTemplate")) $("supplierBalanceTemplate").value = supplier.balanceTemplate || "";
          if ($("supplierBalanceUrl")) $("supplierBalanceUrl").value = supplier.balanceUrl || "";
          if ($("supplierBalanceAuto")) $("supplierBalanceAuto").value = String(supplier.balanceAutoIntervalMinutes || 0);

          fetchBtn.disabled = false;
          fetchBtn.title = "Fetch model catalog from provider";

        }
      }
      renderPresetGrid();
      showSupplierEditor();
    }

    function populateModelDatalist(models) {
      const dl = $("supplierModelDatalist");
      if (!dl) return;
      dl.innerHTML = "";
      models.forEach(m => {
        const opt = document.createElement("option");
        opt.value = m.id;
        opt.textContent = m.displayName || m.id;
        dl.appendChild(opt);
      });
    }

    async function saveSupplier() {
      const name = $("supplierName").value.trim();
      const baseUrl = $("supplierBaseUrl").value.trim();
      const modelsUrl = $("supplierModelsUrl").value.trim();
      const apiKey = $("supplierApiKey").value;
      const activeModel = $("supplierActiveModel").value.trim();
      const presetId = $("supplierPreset").value;

      if (!name || !baseUrl) {
        alert("Please enter Name and Base URL.");
        return;
      }

      if (state.editingSupplierId === null) {
        const preset = state.presets.find(p => p.id === presetId);
        if (preset && preset.requiresApiKey && !apiKey) {
          alert("API Key is required for this preset.");
          return;
        }
      }

      const body = {
        presetId,
        name,
        baseUrl,
        modelsUrl,
        apiKey,
        activeModel,
        balanceTemplate: $("supplierBalanceTemplate") ? $("supplierBalanceTemplate").value : "",
        balanceUrl: $("supplierBalanceUrl") ? $("supplierBalanceUrl").value.trim() : "",
        balanceAutoIntervalMinutes: $("supplierBalanceAuto") ? (parseInt($("supplierBalanceAuto").value, 10) || 0) : 0
      };

      const btn = $("saveSupplierButton");
      const originalText = btn.innerHTML;
      btn.disabled = true;
      btn.innerHTML = '<i class="ri-loader-4-line animate-spin"></i> Saving...';

      try {
        if (state.editingSupplierId === null) {
          await post("/translation/api-suppliers", body);
          playUiSound("success");
          appendMessage("result", "suppliers", `Supplier "${name}" created successfully`, "suppliers");
        } else {
          await api(`/translation/api-suppliers/${state.editingSupplierId}`, {
            method: "PUT",
            body: JSON.stringify(body)
          });
          playUiSound("success");
          appendMessage("result", "suppliers", `Supplier "${name}" updated successfully`, "suppliers");
        }
        hideSupplierEditor();
        await loadSuppliers();

        if (state.activeRoute && state.activeRoute.provider.toLowerCase() === "api-compatible" && state.activeRoute.supplierId === state.editingSupplierId) {
          await loadTranslationModels();
        }
      } catch (error) {
        playUiSound("error");
        alert(error.message || "Failed to save supplier.");
        appendMessage("error", "suppliers", error.message || String(error));
      } finally {
        btn.disabled = false;
        btn.innerHTML = originalText;
      }
    }

    async function deleteSupplier(id) {
      const supplier = state.suppliers.find(s => s.id === id);
      const name = supplier ? supplier.name : "this supplier";
      if (!confirm(`Are you sure you want to delete supplier "${name}"?`)) {
        return;
      }
      try {
        await api(`/translation/api-suppliers/${id}`, { method: "DELETE" });
        playUiSound("success");
        appendMessage("result", "suppliers", `Supplier "${name}" deleted`, "suppliers");
        await loadSuppliers();

        if (state.activeRoute && state.activeRoute.supplierId === id) {
          await loadTranslationModels();
        }
      } catch (error) {
        playUiSound("error");
        alert(error.message || "Failed to delete supplier.");
        appendMessage("error", "suppliers", error.message || String(error));
      }
    }

    async function testSupplier(id, btn) {
      const originalText = btn.innerHTML;
      btn.disabled = true;
      btn.innerHTML = '<i class="ri-loader-4-line animate-spin"></i>';
      try {
        const result = await postEmpty(`/translation/api-suppliers/${id}/test`);
        if (result.status === "ready" || result.status === "healthy" || result.status === "ok") {
          playUiSound("success");
          appendMessage("result", "suppliers", `Supplier connection test succeeded: ${result.latencyMs}ms`, "suppliers");
        } else {
          playUiSound("error");
          appendMessage("error", "suppliers", `Supplier connection test failed: ${result.message || "error"}`);
        }
        await loadSuppliers();
      } catch (error) {
        playUiSound("error");
        appendMessage("error", "suppliers", error.message || String(error));
        await loadSuppliers();
      } finally {
        btn.disabled = false;
        btn.innerHTML = originalText;
      }
    }

    async function refreshSupplierBalance(id, btn) {
      const originalText = btn.innerHTML;
      btn.disabled = true;
      btn.innerHTML = '<i class="ri-loader-4-line animate-spin"></i>';
      try {
        const result = await postEmpty(`/translation/api-suppliers/${id}/balance`);
        if (result.status === "ready") {
          playUiSound("success");
        } else {
          playUiSound("error");
          appendMessage("error", "suppliers", `Balance check: ${result.message || result.status}`);
        }
        await loadSuppliers();
      } catch (error) {
        playUiSound("error");
        appendMessage("error", "suppliers", error.message || String(error));
        await loadSuppliers();
      } finally {
        btn.disabled = false;
        btn.innerHTML = originalText;
      }
    }

    function formatRelativeAgo(iso) {
      if (!iso) {
        return "";
      }
      const then = Date.parse(iso);
      if (!Number.isFinite(then)) {
        return "";
      }
      const diff = Math.max(0, Math.floor((Date.now() - then) / 1000));
      if (diff < 60) return "just now";
      if (diff < 3600) return `${Math.floor(diff / 60)}m ago`;
      if (diff < 86400) return `${Math.floor(diff / 3600)}h ago`;
      return `${Math.floor(diff / 86400)}d ago`;
    }

    function formatBalanceAmount(value, unit) {
      if (value === null || value === undefined || !Number.isFinite(Number(value))) {
        return "--";
      }
      const num = Number(value);
      const u = String(unit || "").toUpperCase();
      if (u === "USD") return `$${num.toFixed(2)}`;
      if (u === "CNY") return `¥${num.toFixed(2)}`;
      if (u === "CREDITS") return `${Math.round(num).toLocaleString()} cr`;
      return unit ? `${num.toFixed(2)} ${unit}` : num.toFixed(2);
    }

    // Returns the inner HTML for a supplier card's balance line, or "" when none.
    function supplierBalanceHtml(supplier) {
      if (!supplier.supportsBalance) {
        return "";
      }
      const bal = supplier.lastBalance;
      if (!bal || !bal.status) {
        return `<span class="supplier-balance pending"><i class="ri-bank-card-line"></i> balance --</span>`;
      }
      if (bal.status !== "ready") {
        const msg = bal.status === "auth_error" ? "key invalid"
          : bal.status === "missing_key" ? "no key"
          : bal.status === "unsupported" ? "unsupported"
          : bal.status === "timeout" ? "timed out"
          : bal.status === "unreachable" ? "unreachable"
          : "error";
        return `<span class="supplier-balance error" title="${escapeHtml(bal.message || bal.status)}"><i class="ri-error-warning-line"></i> ${escapeHtml(msg)}</span>`;
      }
      const plans = bal.plans || [];
      if (plans.length === 0) {
        return `<span class="supplier-balance pending"><i class="ri-bank-card-line"></i> no plans</span>`;
      }
      const plan = plans[0];
      const remaining = plan.remaining;
      const total = plan.total;
      const ago = formatRelativeAgo(bal.checkedAt);
      let toneClass = "ok";
      let barHtml = "";
      if (total !== null && total !== undefined && Number(total) > 0 && remaining !== null && remaining !== undefined) {
        const pctRemaining = Math.max(0, Math.min(100, (Number(remaining) / Number(total)) * 100));
        if (pctRemaining < 10) toneClass = "low";
        barHtml = `<span class="supplier-balance-bar"><span style="width:${pctRemaining.toFixed(0)}%"></span></span>`;
      }
      const amount = formatBalanceAmount(remaining, plan.unit);
      return `<span class="supplier-balance ${toneClass}" title="${escapeHtml(bal.message || "")}">`
        + `<i class="ri-bank-card-line"></i> ${escapeHtml(amount)}${barHtml}`
        + (ago ? `<span class="supplier-balance-ago">· ${escapeHtml(ago)}</span>` : "")
        + `</span>`;
    }

    async function fetchSupplierModels(id, btn) {
      const originalText = btn.innerHTML;
      btn.disabled = true;
      btn.innerHTML = '<i class="ri-loader-4-line animate-spin"></i>';
      try {
        const result = await postEmpty(`/translation/api-suppliers/${id}/models/fetch`);
        if (result.status === "ready" || result.status === "ok") {
          playUiSound("success");
          const count = result.models ? result.models.length : 0;
          appendMessage("result", "suppliers", `Fetched ${count} models from supplier`, "suppliers");

          if (state.editingSupplierId === id) {
            populateModelDatalist(result.models || []);
          }
        } else {
          playUiSound("error");
          appendMessage("error", "suppliers", `Failed to fetch models: ${result.message || "error"}`);
        }
        await loadSuppliers();

        if (state.activeRoute && state.activeRoute.provider.toLowerCase() === "api-compatible" && state.activeRoute.supplierId === id) {
          await loadTranslationModels();
        }
      } catch (error) {
        playUiSound("error");
        appendMessage("error", "suppliers", error.message || String(error));
        await loadSuppliers();
      } finally {
        btn.disabled = false;
        btn.innerHTML = originalText;
      }
    }

    async function activateSupplier(id) {
      try {
        const supplier = state.suppliers.find(s => s.id === id);
        if (!supplier) return;

        const activeModel = supplier.activeModel || "";
        await post(`/translation/api-suppliers/${id}/activate`, {});

        playUiSound("success");
        appendMessage("result", "suppliers", `Activated supplier "${supplier.name}"`, "suppliers");

        state.activeRoute = {
          provider: "api-compatible",
          supplierId: id,
          model: activeModel
        };

        const providerDropdown = $("translationProvider");
        providerDropdown.value = "api-compatible";
        $("metricProvider").textContent = "api-compatible";

        await loadTranslationModels();

        const modelInput = $("translationModel");
        modelInput.value = activeModel;
        $("metricModel").textContent = activeModel || "-";

        updateRuntimeSummary();
        syncRuntimeQuickControls();
        syncModelRecommendation();
        renderSuppliers();
        renderTranslationProviders();
      } catch (error) {
        playUiSound("error");
        appendMessage("error", "suppliers", error.message || String(error));
      }
    }

    function populateSelect(select, items, getValue, getLabel, fallback) {
      select.innerHTML = "";
      for (const item of items) {
        const option = document.createElement("option");
        option.value = getValue(item);
        option.textContent = getLabel(item);
        select.appendChild(option);
      }
      if (fallback && Array.from(select.options).some(option => option.value === fallback)) {
        select.value = fallback;
      }
    }

    function createGlossaryHelpPopover() {
      const popover = document.createElement("div");
      popover.id = "glossarySelectHelpPopover";
      popover.className = "ocr-select-help-popover hidden";
      popover.setAttribute("role", "tooltip");

      const title = document.createElement("div");
      title.className = "ocr-select-help-title";
      title.dataset.role = "title";
      popover.appendChild(title);

      const meta = document.createElement("div");
      meta.className = "ocr-select-help-meta";
      meta.dataset.role = "meta";
      popover.appendChild(meta);

      const body = document.createElement("div");
      body.className = "ocr-select-help-body";
      body.dataset.role = "body";
      popover.appendChild(body);

      return popover;
    }

    function glossaryDescription(item) {
      const value = item.id || "";
      const termCount = Number(item.termCount || 0);
      if (!value) {
        return {
          name: "No glossary",
          value: "none",
          use: "No glossary terms will be added to the translation prompt."
        };
      }

      const hash = item.hash ? String(item.hash).slice(0, 10) : "";
      return {
        name: item.name || item.id,
        value,
        use: `Adds ${termCount} glossary terms${hash ? ` with hash ${hash}` : ""} to translation prompts for consistent terminology.`
      };
    }
    function updateGlossaryHelp(description) {
      $("glossaryHelpName").textContent = description.name;
      $("glossaryHelpValue").textContent = `Glossary value: ${description.value}`;
      $("glossaryHelpUse").textContent = description.use;
      $("glossary").title = `${description.name} | ${description.value} | ${description.use}`;
    }

    function hideGlossaryHelpPopover() {
      const popover = $("glossarySelectHelpPopover");
      if (popover) {
        popover.classList.add("hidden");
      }
    }

    function showGlossaryHelpPopover(item, description) {
      const dropdown = $("glossarySelectDropdown");
      const popover = $("glossarySelectHelpPopover");
      if (!dropdown || !popover || !item) {
        return;
      }

      updateGlossaryHelp(description);
      popover.querySelector('[data-role="title"]').textContent = description.name;
      popover.querySelector('[data-role="meta"]').textContent = `glossary: ${description.value}`;
      popover.querySelector('[data-role="body"]').textContent = description.use;

      popover.classList.remove("hidden");
      popover.style.visibility = "hidden";
      popover.style.top = "0px";

      const height = popover.offsetHeight || 72;
      const minTop = dropdown.scrollTop + 6;
      const maxTop = dropdown.scrollTop + dropdown.clientHeight - height - 6;
      const below = item.offsetTop + item.offsetHeight + 4;
      const above = item.offsetTop - height - 4;
      const top = below <= maxTop ? below : Math.max(minTop, above);

      popover.style.top = `${Math.max(6, top)}px`;
      popover.style.visibility = "";
    }

    function findGlossaryOption(value) {
      const dropdown = $("glossarySelectDropdown");
      return Array.from(dropdown.querySelectorAll(".ocr-select-option"))
        .find(item => item.dataset.value === value) || null;
    }

    function syncGlossarySelectTrigger() {
      const select = $("glossary");
      const triggerText = $("glossarySelectTriggerText");
      const dropdown = $("glossarySelectDropdown");
      const selected = select.selectedOptions[0];
      triggerText.textContent = selected ? selected.textContent : "none";
      for (const item of dropdown.querySelectorAll(".ocr-select-option")) {
        item.classList.toggle("selected", item.dataset.value === select.value);
      }

      if (selected) {
        updateGlossaryHelp({
          name: selected.dataset.helpName || selected.textContent || "No glossary",
          value: selected.dataset.helpValue || selected.value || "none",
          use: selected.dataset.helpUse || "No local terminology file will be applied."
        });
      }
    }

    function pulseGlossaryHelp() {
      const select = $("glossary");
      const wrapper = $("glossarySelectWrapper");
      const selected = select.selectedOptions[0];
      if (!selected) {
        return;
      }

      const desc = {
        name: selected.dataset.helpName || selected.textContent || "No glossary",
        value: selected.dataset.helpValue || selected.value || "none",
        use: selected.dataset.helpUse || "No local terminology file will be applied."
      };

      updateGlossaryHelp(desc);
      if (wrapper.classList.contains("open")) {
        showGlossaryHelpPopover(findGlossaryOption(select.value), desc);
      }
    }

    function closeGlossarySelect() {
      const wrapper = $("glossarySelectWrapper");
      const trigger = $("glossarySelectTrigger");
      wrapper.classList.remove("open");
      trigger.setAttribute("aria-expanded", "false");
      hideGlossaryHelpPopover();
    }

    function toggleGlossarySelect() {
      const wrapper = $("glossarySelectWrapper");
      const trigger = $("glossarySelectTrigger");
      const isOpen = wrapper.classList.toggle("open");
      trigger.setAttribute("aria-expanded", isOpen ? "true" : "false");
      if (isOpen) {
        syncGlossarySelectTrigger();
        pulseGlossaryHelp();
      } else {
        hideGlossaryHelpPopover();
      }
    }

    function populateGlossarySelect(glossaries, fallback) {
      const select = $("glossary");
      const dropdown = $("glossarySelectDropdown");
      const items = [{ id: "", name: "none", termCount: 0, hash: "" }, ...(glossaries || [])];
      select.innerHTML = "";
      dropdown.innerHTML = "";
      dropdown.appendChild(createGlossaryHelpPopover());
      dropdown.onmouseleave = hideGlossaryHelpPopover;

      for (const item of items) {
        const value = item.id || "";
        const label = item.name || item.id || "none";
        const desc = glossaryDescription(item);

        const option = document.createElement("option");
        option.value = value;
        option.textContent = label;
        option.dataset.helpName = desc.name;
        option.dataset.helpValue = desc.value;
        option.dataset.helpUse = desc.use;
        select.appendChild(option);

        const row = document.createElement("div");
        row.className = "ocr-select-option";
        row.dataset.value = value;
        row.dataset.helpName = desc.name;
        row.dataset.helpValue = desc.value;
        row.dataset.helpUse = desc.use;
        row.setAttribute("role", "option");

        const nameSpan = document.createElement("span");
        nameSpan.textContent = label;
        nameSpan.style.cssText = "overflow:hidden;text-overflow:ellipsis;flex:1;min-width:0;";
        row.appendChild(nameSpan);

        const badge = document.createElement("span");
        badge.className = "ocr-select-option-status";
        badge.textContent = value ? `${Number(item.termCount || 0)} terms` : "off";
        row.appendChild(badge);

        row.addEventListener("mouseenter", () => showGlossaryHelpPopover(row, desc));
        row.addEventListener("click", () => {
          select.value = value;
          select.dispatchEvent(new Event("change", { bubbles: true }));
          closeGlossarySelect();
        });

        dropdown.appendChild(row);
      }

      if (fallback && Array.from(select.options).some(option => option.value === fallback)) {
        select.value = fallback;
      } else {
        select.value = "";
      }

      syncGlossarySelectTrigger();
    }

    function getTranslationProviderDescription(provider) {
      const key = normalizeSupplierKey(provider.name);
      if (key === "ollama") {
        return "Local Ollama runtime for low-latency private translation.";
      }
      if (key === "llamacpp") {
        return "Managed llama.cpp runtime and GGUF model downloads.";
      }
      if (key === "apicompatible") {
        return "OpenAI-compatible remote supplier route configured below.";
      }
      if (key === "mock") {
        return "Local test provider for smoke checks and demos.";
      }
      return provider.requiresNetwork ? "Remote translation provider." : "Local translation provider.";
    }

    function getTranslationProviderKind(provider) {
      if (provider.isLocal) return "local";
      if (provider.requiresNetwork) return "remote";
      return provider.kind || "provider";
    }

    function getTranslationProviderModelLabel(provider, isActive) {
      if (isActive && $("translationModel").value.trim()) {
        return $("translationModel").value.trim();
      }
      if (provider.defaultModel) {
        return provider.defaultModel;
      }
      if (normalizeSupplierKey(provider.name) === "apicompatible") {
        return "configured supplier route";
      }
      return "default route";
    }

    function renderTranslationProviders() {
      renderTranslationProviderCatalog();
      return;

      const grid = $("translationProviderGrid");
      const select = $("translationProvider");
      if (!grid || !select) return;

      const providers = state.translationProviders || [];
      if (providers.length === 0) {
        grid.innerHTML = `<div class="supplier-grid-empty">No translation providers available.</div>`;
        return;
      }

      const activeValue = select.value;
      grid.innerHTML = providers.map(provider => {
        const key = normalizeSupplierKey(provider.name);
        const isActive = provider.name === activeValue;
        const displayName = provider.displayName || provider.name;
        const kind = getTranslationProviderKind(provider);
        const model = getTranslationProviderModelLabel(provider, isActive);
        const networkBadge = provider.requiresNetwork ? "network" : "offline";
        return `
          <button type="button"
            class="provider-card${isActive ? " active" : ""}"
            data-provider="${escapeHtml(provider.name)}"
            aria-pressed="${isActive ? "true" : "false"}"
            title="${escapeHtml(getTranslationProviderDescription(provider))}">
            <div class="provider-card-main">
              ${getSupplierAvatarHtml(key, displayName)}
              <div class="provider-card-title">
                <strong>${escapeHtml(displayName)}</strong>
                <span>${escapeHtml(kind)} / ${escapeHtml(provider.kind || provider.name)}</span>
              </div>
            </div>
            <div class="provider-card-badges">
              <span class="provider-card-badge">${escapeHtml(networkBadge)}</span>
              <span class="provider-card-badge">${provider.isLocal ? "local" : "remote"}</span>
            </div>
            <div class="provider-card-model">${escapeHtml(model)}</div>
          </button>
        `;
      }).join("");

      grid.querySelectorAll(".provider-card").forEach(card => {
        card.addEventListener("click", () => {
          const nextProvider = card.dataset.provider || "";
          if (!nextProvider || select.value === nextProvider) {
            syncTranslationProviderCards();
            return;
          }
          select.value = nextProvider;
          select.dispatchEvent(new Event("change", { bubbles: true }));
        });
      });
    }

    function syncTranslationProviderCards() {
      syncTranslationProviderCatalogCards();
      return;

      const grid = $("translationProviderGrid");
      const select = $("translationProvider");
      if (!grid || !select) return;

      grid.querySelectorAll(".provider-card").forEach(card => {
        const active = card.dataset.provider === select.value;
        card.classList.toggle("active", active);
        card.setAttribute("aria-pressed", String(active));
        if (active) {
          const provider = state.translationProviders.find(item => item.name === select.value);
          const model = provider ? getTranslationProviderModelLabel(provider, true) : $("translationModel").value.trim();
          const modelNode = card.querySelector(".provider-card-model");
          if (modelNode) {
            modelNode.textContent = model || "default route";
          }
        }
      });
    }

    const PROVIDER_CATEGORIES = [
      { id: "local", label: "Local" },
      { id: "official", label: "Official" },
      { id: "cn_official", label: "CN Official" },
      { id: "aggregator", label: "Aggregator" },
      { id: "third_party", label: "Third Party" },
      { id: "coding_plan", label: "Coding Plan" }
    ];

    const LOCAL_PROVIDER_CATALOG = [
      {
        id: "ollama",
        name: "Ollama",
        category: "local",
        runtimeProvider: "ollama",
        endpoint: "http://localhost:11434",
        model: "verbeam-mort-qwen2.5-0.5b:latest",
        description: "Local LLM runtime served through the Ollama API. Useful for private offline translation and quick model switching.",
        models: [
          { name: "verbeam-mort-qwen2.5-0.5b:latest", installed: true, isDefault: true, source: "ollama" },
          { name: "qwen2.5:7b", installed: true, isDefault: false, source: "ollama" },
          { name: "qwen2.5:14b", installed: false, isDefault: false, source: "configured" },
          { name: "gemma2:9b", installed: true, isDefault: false, source: "ollama" },
          { name: "llama3.1:8b", installed: true, isDefault: false, source: "ollama" }
        ]
      },
      {
        id: "llama-cpp",
        name: "llama.cpp",
        category: "local",
        runtimeProvider: "llama-cpp",
        endpoint: "http://localhost:8088/v1",
        model: "hy-mt2-1.8b-q4km",
        description: "Lightweight local GGUF runtime managed by Verbeam. Best for private low-latency OCR and region translation.",
        models: [
          { name: "hy-mt2-1.8b-q4km", displayName: "Tencent Hy-MT2 1.8B (Q4_K_M)", installed: true, isDefault: true, isRecommended: true, source: "managed GGUF", recommendedUse: "best realtime OCR and region translation default" },
          { name: "hy-mt2-1.8b-q6k", displayName: "Tencent Hy-MT2 1.8B (Q6_K)", installed: true, isDefault: false, isRecommended: true, source: "managed GGUF", recommendedUse: "higher-quality local translation when latency allows" },
          { name: "gemmafit-gemma4-e2b-iq2m", displayName: "GemmaFit Gemma4 E2B IQ2_M", installed: true, isDefault: false, isRecommended: false, source: "local GGUF", recommendedUse: "quality candidate; slower for realtime" },
          { name: "verbeam-mort-qwen2.5-0.5b", displayName: "Verbeam MORT Qwen2.5 0.5B", installed: true, isDefault: false, source: "managed", recommendedUse: "fallback OCR overlay" },
          { name: "qwen2.5-0.5b", displayName: "Qwen2.5 0.5B", installed: false, isDefault: false, source: "download", recommendedUse: "smoke test" }
        ]
      },
      {
        id: "hybrid",
        name: "Hybrid (local + cloud fallback)",
        category: "local",
        runtimeProvider: "hybrid",
        endpoint: "local first, cloud rescue",
        model: "hybrid",
        description: "Local model translates first; slow requests can fall back to a configured cloud provider when available.",
        models: [
          { name: "hybrid", displayName: "Hybrid runtime", installed: true, isDefault: true, isRecommended: true, source: "composite", recommendedUse: "latency-sensitive local translation with fallback" }
        ]
      },
      {
        id: "deepl",
        name: "DeepL",
        category: "official",
        runtimeProvider: "deepl",
        endpoint: "https://api-free.deepl.com / https://api.deepl.com",
        model: "default",
        description: "DeepL text translation API provider. Configure an API key in Verbeam:DeepL:ApiKey or VB_Verbeam__DeepL__ApiKey.",
        models: [
          { name: "default", displayName: "DeepL default", installed: true, isDefault: true, isRecommended: true, source: "deepl", recommendedUse: "high-quality text translation" },
          { name: "quality_optimized", displayName: "DeepL quality optimized", installed: true, isDefault: false, source: "deepl", recommendedUse: "next-gen translation quality when supported" }
        ]
      }
    ];
    function providerCategoryLabel(category) {
      return (PROVIDER_CATEGORIES.find(item => item.id === category) || { label: category || "Provider" }).label;
    }

    function buildTranslationProviderCatalog() {
      const backendNames = new Set((state.translationProviders || []).map(item => item.name.toLowerCase()));
      const cards = LOCAL_PROVIDER_CATALOG
        .filter(item => backendNames.has(item.runtimeProvider.toLowerCase()))
        .map(item => ({ ...item, source: "runtime" }));

      for (const preset of state.presets || []) {
        if (!preset || preset.id === "custom") continue;
        cards.push({
          id: `preset:${preset.id}`,
          presetId: preset.id,
          name: preset.displayName || preset.id,
          category: preset.category || "third_party",
          runtimeProvider: "api-compatible",
          endpoint: preset.baseUrl || "",
          model: preset.defaultModel || "",
          description: preset.websiteUrl
            ? `${preset.displayName || preset.id} API supplier preset.`
            : "OpenAI-compatible remote supplier preset.",
          source: "preset"
        });
      }

      if (backendNames.has("mock")) {
        cards.push({
          id: "mock",
          name: "Mock Provider",
          category: "third_party",
          runtimeProvider: "mock",
          endpoint: "local test",
          model: "mock",
          description: "Local test provider for smoke checks.",
          source: "runtime"
        });
      }

      return cards;
    }

    function activeSupplierPresetId() {
      const activeSupplierId = state.activeRoute && state.activeRoute.provider &&
        state.activeRoute.provider.toLowerCase() === "api-compatible"
        ? state.activeRoute.supplierId
        : "";
      if (!activeSupplierId) return "";
      const supplier = state.suppliers.find(item => item.id === activeSupplierId);
      return supplier ? supplier.presetId || "" : "";
    }

    function isTranslationProviderCatalogCardActive(card) {
      const selectedProvider = $("translationProvider").value;
      if (card.source === "preset") {
        return selectedProvider === "api-compatible" && activeSupplierPresetId() === card.presetId;
      }
      return selectedProvider === card.runtimeProvider;
    }

    function translationProviderCatalogModelLabel(card, active) {
      if (card.source === "preset") {
        const supplier = state.suppliers.find(item => item.presetId === card.presetId);
        return supplier && supplier.activeModel ? supplier.activeModel : card.model || "configure supplier";
      }
      if (active && $("translationModel").value.trim()) {
        return $("translationModel").value.trim();
      }
      return card.model || "default route";
    }

    function renderTranslationProviderCatalogFilters(cards) {
      const usedCategories = new Set(cards.map(card => card.category));
      const filters = [{ id: "all", label: "All" }, ...PROVIDER_CATEGORIES.filter(item => usedCategories.has(item.id))];
      return `
        <div class="provider-filter-bar">
          ${filters.map(filter => `
            <button type="button"
              class="provider-filter-button${state.providerFilter === filter.id ? " active" : ""}"
              data-provider-filter="${escapeHtml(filter.id)}">
              ${escapeHtml(filter.label)}
            </button>
          `).join("")}
        </div>
      `;
    }

    function renderTranslationProviderCatalog() {
      const grid = $("translationProviderGrid");
      if (!grid) return;

      const allCards = buildTranslationProviderCatalog();
      const visibleCards = state.providerFilter === "all"
        ? allCards
        : allCards.filter(card => card.category === state.providerFilter);

      if (allCards.length === 0) {
        grid.innerHTML = `<div class="supplier-grid-empty">No translation providers available.</div>`;
        return;
      }

      const codingPlanHint = "Coding-plan providers are often sold as monthly or quota bundles for coding-agent workloads. If you run a lot of OCR cleanup, translation, or batch routing, a plan can be cheaper than pure pay-per-token API billing. Check provider terms and model compatibility before relying on one.";
      const renderProviderCard = card => {
        const active = isTranslationProviderCatalogCardActive(card);
        const model = translationProviderCatalogModelLabel(card, active);
        const iconKey = card.presetId || card.id;
        const hasTooltip = !!card.description;
        const modelCount = card.models ? card.models.length : 0;
        return `
          <div class="provider-card-wrap">
            <button type="button"
              class="provider-card${active ? " active" : ""}"
              data-provider-card="${escapeHtml(card.id)}"
              aria-pressed="${active ? "true" : "false"}"
              title="${escapeHtml(card.name)}">
              <div class="provider-card-main">
                ${getSupplierAvatarHtml(iconKey, card.name)}
                <div class="provider-card-title">
                  <strong>${escapeHtml(card.name)}</strong>
                  <span>${escapeHtml(providerCategoryLabel(card.category))}${modelCount > 0 ? " &middot; " + modelCount + " models" : ""}</span>
                </div>
              </div>
              <div class="provider-card-badges">
                <span class="provider-card-badge">${card.source === "preset" ? "api" : "runtime"}</span>
                <span class="provider-card-badge">${card.runtimeProvider === "api-compatible" ? "remote" : "local"}</span>
              </div>
              <div class="provider-card-model">${escapeHtml(model)}</div>
            </button>
            ${hasTooltip ? `
              <div class="provider-card-tooltip">
                <div class="provider-card-tooltip-title">${escapeHtml(card.name)}</div>
                <div class="provider-card-tooltip-body">${escapeHtml(card.description)}</div>
                ${modelCount > 0 ? `<div class="provider-card-tooltip-meta">${modelCount} models available</div>` : ""}
              </div>
            ` : ""}
          </div>
        `;
      };
      const categories = PROVIDER_CATEGORIES
        .filter(category => category.id !== "coding_plan" && visibleCards.some(card => card.category === category.id));
      const categoryHtml = categories.map(category => {
        const cards = visibleCards.filter(card => card.category === category.id);
        return `
          <div class="provider-catalog-section">
            <div class="provider-category-label">${escapeHtml(category.label)}</div>
            <div class="provider-card-grid">
            ${cards.map(card => {
              const active = isTranslationProviderCatalogCardActive(card);
              const model = translationProviderCatalogModelLabel(card, active);
              const iconKey = card.presetId || card.id;
              const hasTooltip = !!card.description;
              const modelCount = card.models ? card.models.length : 0;
              return `
                <div class="provider-card-wrap">
                  <button type="button"
                    class="provider-card${active ? " active" : ""}"
                    data-provider-card="${escapeHtml(card.id)}"
                    aria-pressed="${active ? "true" : "false"}"
                    title="${escapeHtml(card.name)}">
                    <div class="provider-card-main">
                      ${getSupplierAvatarHtml(iconKey, card.name)}
                      <div class="provider-card-title">
                        <strong>${escapeHtml(card.name)}</strong>
                        <span>${escapeHtml(providerCategoryLabel(card.category))}${modelCount > 0 ? " / " + modelCount + " models" : ""}</span>
                      </div>
                    </div>
                    <div class="provider-card-badges">
                      <span class="provider-card-badge">${card.source === "preset" ? "api" : "runtime"}</span>
                      <span class="provider-card-badge">${card.runtimeProvider === "api-compatible" ? "remote" : "local"}</span>
                    </div>
                    <div class="provider-card-model">${escapeHtml(model)}</div>
                  </button>
                  ${hasTooltip ? `
                    <div class="provider-card-tooltip">
                      <div class="provider-card-tooltip-title">${escapeHtml(card.name)}</div>
                      <div class="provider-card-tooltip-body">${escapeHtml(card.description)}</div>
                      ${modelCount > 0 ? `<div class="provider-card-tooltip-meta">${modelCount} models available</div>` : ""}
                    </div>
                  ` : ""}
                </div>
              `;
            }).join("")}
            </div>
          </div>
        `;
      }).join("");
      const codingCards = visibleCards.filter(card => card.category === "coding_plan");
      const codingCategoryHtml = codingCards.length > 0 ? `
        <div class="provider-catalog-section provider-coding-plan${state.codingPlanExpanded ? "" : " collapsed"}">
          <button type="button"
            class="provider-coding-toggle"
            data-coding-plan-toggle
            aria-expanded="${state.codingPlanExpanded ? "true" : "false"}"
            title="${escapeHtml(codingPlanHint)}">
            <span class="provider-coding-toggle-left">
              <span class="provider-coding-toggle-icon">${state.codingPlanExpanded ? "-" : "+"}</span>
              <span class="provider-coding-toggle-copy">
                <span class="provider-coding-toggle-title">Coding Plan</span>
                <span class="provider-coding-toggle-subtitle">Optional plan-based API suppliers</span>
              </span>
            </span>
            <span class="provider-coding-toggle-count">${codingCards.length} providers</span>
          </button>
          <div class="provider-coding-note">${escapeHtml(codingPlanHint)}</div>
          <div class="provider-card-grid">
            ${codingCards.map(renderProviderCard).join("")}
          </div>
        </div>
      ` : "";

      const fullCategoryHtml = `${categoryHtml}${codingCategoryHtml}`;
      const catalogHtml = `${renderTranslationProviderCatalogFilters(allCards)}<div class="provider-catalog-scroll">${fullCategoryHtml || `<div class="supplier-grid-empty">No providers match this filter.</div>`}</div>`;
      grid.innerHTML = catalogHtml.replace(/\u7e5a/g, "&middot;");
      hydrateSupplierIcons(grid);

      grid.querySelectorAll("[data-provider-filter]").forEach(button => {
        button.addEventListener("click", () => {
          state.providerFilter = button.dataset.providerFilter || "all";
          renderTranslationProviderCatalog();
        });
      });

      const codingToggle = grid.querySelector("[data-coding-plan-toggle]");
      if (codingToggle) {
        codingToggle.addEventListener("click", () => {
          state.codingPlanExpanded = !state.codingPlanExpanded;
          renderTranslationProviderCatalog();
        });
      }

      grid.querySelectorAll("[data-provider-card]").forEach(button => {
        button.addEventListener("click", () => {
          const card = buildTranslationProviderCatalog().find(item => item.id === button.dataset.providerCard);
          if (card) {
            selectTranslationProviderCatalogCard(card).catch(error => appendMessage("error", "provider", error.message || String(error)));
          }
        });
      });

      grid.querySelectorAll(".provider-card-wrap").forEach(wrap => {
        const tooltip = wrap.querySelector(".provider-card-tooltip");
        if (!tooltip) return;
        wrap.addEventListener("mouseenter", () => {
          const rect = wrap.getBoundingClientRect();
          const tooltipWidth = 280;
          const viewportWidth = window.innerWidth;
          const viewportHeight = window.innerHeight;
          let left = rect.right + 8;
          let top = rect.top;
          if (left + tooltipWidth > viewportWidth - 16) {
            left = rect.left - tooltipWidth - 8;
          }
          if (left < 16) {
            left = rect.left;
            top = rect.bottom + 8;
          }
          if (top + 200 > viewportHeight) {
            top = viewportHeight - 210;
          }
          tooltip.style.left = left + "px";
          tooltip.style.top = top + "px";
        });
      });

      renderProviderDetails();
    }

    async function selectTranslationProviderCatalogCard(card) {
      if (card.source === "preset") {
        const supplier = state.suppliers.find(item => item.presetId === card.presetId);
        if (supplier) {
          await activateSupplier(supplier.id);
          return;
        }

        await openSupplierModal(null, card.presetId);
        appendMessage("result", "provider", `configure ${card.name} supplier`, "api-compatible");
        return;
      }

      const select = $("translationProvider");
      if (card.runtimeProvider === "llama-cpp") {
        if (select.value !== card.runtimeProvider) {
          select.value = card.runtimeProvider;
          $("metricProvider").textContent = select.value || "-";
          updateRuntimeSummary();
          syncDocumentRuntimeBadges();
          syncRuntimeQuickControls();
          syncTranslationProviderCards();
        }

        await loadTranslationModels();
        syncRuntimeQuickControls();
        await loadLlamaCppDownloads(true);
        const runtime = state.llamaCppHealth && state.llamaCppHealth.runtime;
        if (!runtime || !runtime.isManagedRunning) {
          appendMessage("result", "llama.cpp", "starting managed runtime", card.model || "managed");
          await installAndUseLlamaCpp();
        }
        return;
      }

      if (select.value !== card.runtimeProvider) {
        select.value = card.runtimeProvider;
        select.dispatchEvent(new Event("change", { bubbles: true }));
      } else {
        syncTranslationProviderCatalogCards();
      }
    }

    function syncTranslationProviderCatalogCards() {
      const grid = $("translationProviderGrid");
      if (!grid) return;

      grid.querySelectorAll(".provider-card").forEach(button => {
        const card = buildTranslationProviderCatalog().find(item => item.id === button.dataset.providerCard);
        const active = card ? isTranslationProviderCatalogCardActive(card) : false;
        button.classList.toggle("active", active);
        button.setAttribute("aria-pressed", String(active));
        if (card) {
          const modelNode = button.querySelector(".provider-card-model");
          if (modelNode) {
            modelNode.textContent = translationProviderCatalogModelLabel(card, active);
          }
        }
      });

      renderProviderDetails();
    }

    function renderProviderDetails() {
      const select = $("translationProvider");
      if (!select) return;
      const selectedProvider = select.value;
      const allCards = buildTranslationProviderCatalog();
      const activeCard = allCards.find(card => isTranslationProviderCatalogCardActive(card));

      const aboutDesc = $("providerAboutDescription");
      const aboutControl = $("providerAboutControl");
      const modelsDesc = $("providerModelsDescription");
      const modelsChips = $("providerModelsChips");

      if (!activeCard) {
        if (aboutDesc) aboutDesc.textContent = "Select a provider to see details.";
        if (aboutControl) aboutControl.innerHTML = "";
        if (modelsDesc) modelsDesc.textContent = "Available models for the selected provider.";
        if (modelsChips) modelsChips.innerHTML = "";
        return;
      }

      if (aboutDesc && activeCard.description) {
        aboutDesc.textContent = activeCard.description;
      } else if (aboutDesc) {
        aboutDesc.textContent = activeCard.name + " translation provider.";
      }

      if (aboutControl) {
        const iconKey = activeCard.presetId || activeCard.id;
        aboutControl.innerHTML = `
          ${getSupplierAvatarHtml(iconKey, activeCard.name)}
          <div>
            <div style="color: var(--text); font-weight: 600; font-size: 13px;">${escapeHtml(activeCard.name)}</div>
            <div style="color: var(--muted); font-size: 11px; font-family: var(--mono);">${escapeHtml(activeCard.endpoint || activeCard.runtimeProvider)}</div>
          </div>
        `;
        hydrateSupplierIcons(aboutControl);
      }

      const models = getProviderDetailModels(activeCard, selectedProvider);
      const installedCount = models.filter(m => m.installed).length;

      if (modelsDesc) {
        modelsDesc.textContent = models.length > 0
          ? `${installedCount} installed, ${models.length} total. Click a model card to select.`
          : "No model catalog available for this provider.";
      }

      if (modelsChips) {
        if (models.length === 0) {
          modelsChips.innerHTML = `<span style="color: var(--muted); font-size: 11px;">No models listed</span>`;
          return;
        }

        const currentModel = $("translationModel").value.trim();
        modelsChips.innerHTML = models.map(m => {
          const isActive = m.name === currentModel || (!currentModel && m.isDefault);
          const displayName = m.displayName || m.name;
          const source = m.source || (m.installed ? "installed" : "configured");
          const use = m.recommendedUse || source;
          return `
            <button type="button"
              class="provider-model-chip${isActive ? " active" : ""}"
              data-model-name="${escapeHtml(m.name)}"
              title="${escapeHtml(`${displayName} | ${m.name} | ${use}`)}">
              ${m.installed ? `<span class="dot"${m.isDefault ? ' style="background: var(--green);"' : ""}></span>` : `<i class="ri-download-cloud-line" style="font-size: 14px; color: var(--muted); margin-top: 1px;"></i>`}
              <span class="provider-model-main">
                <span class="provider-model-title">${escapeHtml(displayName)}</span>
                <span class="provider-model-alias">${escapeHtml(m.name)}</span>
                <span class="provider-model-meta">
                  ${m.installed ? `<span class="provider-model-badge good">installed</span>` : `<span class="provider-model-badge">not installed</span>`}
                  ${m.isRecommended ? `<span class="provider-model-badge recommended">recommended</span>` : ""}
                  ${m.isDefault ? `<span class="provider-model-badge good">default</span>` : ""}
                  <span class="provider-model-badge">${escapeHtml(source)}</span>
                </span>
              </span>
            </button>
          `;
        }).join("");

        modelsChips.querySelectorAll("[data-model-name]").forEach(chip => {
          chip.addEventListener("click", () => {
            const modelName = chip.dataset.modelName;
            const modelInput = $("translationModel");
            if (modelInput && modelName) {
              modelInput.value = modelName;
              modelInput.dispatchEvent(new Event("change", { bubbles: true }));
              renderProviderDetails();
            }
          });
        });
      }
    }

    function getProviderDetailModels(card, selectedProvider) {
      if (card.runtimeProvider === selectedProvider && state.translationModels && state.translationModels.length > 0) {
        return state.translationModels.map(item => ({
          name: item.name,
          displayName: item.displayName || item.name,
          installed: !!item.isInstalled,
          isDefault: !!item.isDefault,
          isRecommended: !!item.isRecommended,
          source: item.source || "",
          recommendedUse: item.recommendedUse || "",
          recommendationReason: item.recommendationReason || ""
        }));
      }

      return card.models || [];
    }

    const TRANSLATION_LANGUAGE_LABELS_LEGACY = Object.freeze({
      auto: { en: "Auto detect", "zh-TW": "自動偵測" },
      ja: { en: "Japanese", "zh-TW": "日本語" },
      en: { en: "English", "zh-TW": "English" },
      "zh-TW": { en: "Traditional Chinese (Taiwan)", "zh-TW": "繁體中文（台灣）" },
      "zh-CN": { en: "Simplified Chinese (China)", "zh-TW": "简体中文（中国）" },
      zh: { en: "Chinese", "zh-TW": "中文" },
      ko: { en: "Korean", "zh-TW": "한국어" }
    });

    const TRANSLATION_LANGUAGE_LABELS = Object.freeze({
      auto: Object.freeze({ en: "Auto detect", "zh-TW": "自動偵測" }),
      ja: Object.freeze({ en: "Japanese", "zh-TW": "日文" }),
      en: Object.freeze({ en: "English", "zh-TW": "英文" }),
      "zh-TW": Object.freeze({ en: "Traditional Chinese (Taiwan)", "zh-TW": "繁體中文（台灣）" }),
      "zh-CN": Object.freeze({ en: "Simplified Chinese (China)", "zh-TW": "簡體中文（中國）" }),
      zh: Object.freeze({ en: "Chinese", "zh-TW": "中文" }),
      ko: Object.freeze({ en: "Korean", "zh-TW": "韓文" })
    });

    function getActiveUiLanguage() {
      return resolveDisplayLanguage((state.appearance || DEFAULT_APPEARANCE).language);
    }

    function getTranslationLanguageLabel(code, item = null) {
      const key = String(code || "").trim();
      const language = getActiveUiLanguage();
      const labels = TRANSLATION_LANGUAGE_LABELS[key];
      if (labels) {
        return labels[language] || labels.en || key;
      }

      return item?.nativeName || item?.displayName || key || "-";
    }

    function getTranslationLanguageTitle(code, item = null) {
      const key = String(code || "").trim();
      const promptName = item?.promptName || item?.displayName || item?.nativeName || key;
      return key ? `${key} - ${promptName}` : promptName;
    }

    function refreshTranslationLanguageControls() {
      if (!Array.isArray(state.translationLanguages) || state.translationLanguages.length === 0) {
        return;
      }

      const source = $("source");
      const target = $("target");
      const sourceValue = source?.value || "auto";
      const targetValue = target?.value || "zh-TW";
      if (source) {
        populateLanguageSelect(source, state.translationLanguages, sourceValue, true);
      }
      if (target) {
        populateLanguageSelect(target, state.translationLanguages, targetValue);
      }
      populateLanguageDatalist(state.translationLanguages);
      syncTranslateUi();
    }

    function populateLanguageSelect(select, languages, fallback, allowAuto = false) {
      select.innerHTML = "";
      if (allowAuto) {
        const autoOption = document.createElement("option");
        autoOption.value = "auto";
        autoOption.textContent = getTranslationLanguageLabel("auto");
        autoOption.title = getActiveUiLanguage() === "zh-TW"
          ? "翻譯前自動偵測文字或 OCR 的來源語言。"
          : "Detect the source language from text or OCR before translation.";
        select.appendChild(autoOption);
      }
      for (const item of languages || []) {
        const option = document.createElement("option");
        option.value = item.code;
        option.textContent = getTranslationLanguageLabel(item.code, item);
        option.title = getTranslationLanguageTitle(item.code, item);
        select.appendChild(option);
      }

      const options = Array.from(select.options);
      const fallbackOption = options.find(option => option.value.toLowerCase() === String(fallback || "").toLowerCase());
      select.value = (fallbackOption || options[0])?.value || "";
    }

    function populateLanguageDatalist(languages) {
      const list = $("translationLanguageList");
      list.innerHTML = "";
      for (const item of languages || []) {
        const option = document.createElement("option");
        option.value = item.code;
        option.label = getTranslationLanguageTitle(item.code, item);
        list.appendChild(option);
      }
    }

    function syncPromptHint() {
      const selected = state.promptPresets.find(item => item.id === $("preset").value);
      $("promptPresetName").textContent = selected ? selected.name || selected.id : "-";
      $("promptPresetVersion").textContent = selected ? selected.version || "-" : "-";
      $("promptPresetDescription").textContent = selected ? selected.description || "-" : "-";
    }

    function runtimeModelSearchText(item) {
      return [
        item?.provider,
        item?.name,
        item?.displayName,
        item?.source,
        item?.recommendedUse,
        item?.recommendationReason,
        item?.supplierId,
        item?.supplierName
      ].map(value => String(value || "").toLowerCase()).join(" ");
    }

    function runtimeModelProviderName(item = null) {
      return String(item?.provider || $("translationProvider")?.value || "").trim().toLowerCase();
    }

    function runtimeModelIsLocal(item) {
      const provider = runtimeModelProviderName(item);
      const text = runtimeModelSearchText(item);
      return RUNTIME_LOCAL_PROVIDERS.includes(provider)
        || text.includes("local")
        || text.includes("gguf")
        || text.includes("ollama")
        || text.includes("managed");
    }

    function runtimeModelIsApi(item) {
      const provider = runtimeModelProviderName(item);
      return RUNTIME_API_PROVIDERS.includes(provider) || !!item?.supplierId;
    }

    function runtimeModelIsSelectable(item) {
      if (!item) {
        return false;
      }

      return runtimeModelProviderName(item) === "llama-cpp"
        ? !!item.isInstalled || !!item.isDefault
        : true;
    }

    function inferRuntimeModelTask() {
      switch (state.mode) {
        case "region":
          return "realtime";
        case "ocr":
          return "ocr";
        case "document":
          return "document";
        case "audio":
          return "text";
        default:
          return "text";
      }
    }

    function activeRuntimeModelTask() {
      return state.runtimeModelTask && state.runtimeModelTask !== "auto"
        ? state.runtimeModelTask
        : inferRuntimeModelTask();
    }

    function runtimeModelTaskLabel(task = activeRuntimeModelTask()) {
      const meta = RUNTIME_MODEL_TASK_META[task] || RUNTIME_MODEL_TASK_META.text;
      return uiText(meta.key, meta.label);
    }

    function runtimeModelScopeLabel(scope = state.runtimeModelScope || "all") {
      const meta = RUNTIME_MODEL_SCOPE_META[scope] || RUNTIME_MODEL_SCOPE_META.all;
      return uiText(meta.key, meta.label);
    }

    function runtimeModelScore(item, task = activeRuntimeModelTask()) {
      const text = runtimeModelSearchText(item);
      const provider = runtimeModelProviderName(item);
      const isHyMt = text.includes("hy-mt2") || text.includes("hy mt2") || text.includes("hymt") || text.includes("tencent");
      const isHyQ4 = isHyMt && (text.includes("q4_k_m") || text.includes("q4km") || text.includes("q4_k"));
      const isHyQ6 = isHyMt && (text.includes("q6_k") || text.includes("q6k"));
      const isGemma = text.includes("gemma") || text.includes("gemmafit");
      let score = 0;

      if (item?.isDefault) score += 18;
      if (item?.isInstalled) score += 16;
      if (item?.isRecommended) score += 10;
      if (runtimeModelIsLocal(item)) score += 4;
      if (runtimeModelIsApi(item)) score += 4;

      if (task === "realtime" || task === "ocr") {
        if (isHyQ4) score += 120;
        else if (isHyQ6) score += 82;
        else if (isHyMt) score += 68;
        if (text.includes("realtime")) score += 18;
        if (text.includes("overlay") || text.includes("region")) score += 10;
        if (text.includes("short_text") || text.includes("short text")) score += 8;
        if (text.includes("ocr")) score += task === "ocr" ? 14 : 6;
        if (isGemma) score -= task === "realtime" ? 58 : 34;
        if (provider === "deepl" || provider === "api-compatible") score -= 10;
      } else if (task === "document") {
        if (provider === "deepl" || provider === "api-compatible") score += 44;
        if (isHyQ6) score += 34;
        else if (isHyQ4) score += 24;
        else if (isHyMt) score += 22;
        if (text.includes("quality")) score += 10;
        if (isGemma) score -= 12;
      } else {
        if (provider === "deepl" || provider === "api-compatible") score += 28;
        if (isHyQ6) score += 30;
        else if (isHyQ4) score += 26;
        else if (isHyMt) score += 22;
        if (isGemma) score -= 8;
      }

      return score;
    }

    function runtimeModelIsSlowForTask(item, task = activeRuntimeModelTask()) {
      const text = runtimeModelSearchText(item);
      return (task === "realtime" || task === "ocr")
        && (text.includes("gemma") || text.includes("gemmafit"));
    }

    function chooseRecommendedModel(task = activeRuntimeModelTask(), models = state.translationModels || []) {
      const candidates = (models || []).filter(Boolean);
      if (!candidates.length) {
        return null;
      }

      const selectable = candidates.filter(runtimeModelIsSelectable);
      const pool = selectable.length > 0 ? selectable : candidates;
      return pool
        .map((item, index) => ({ item, index, score: runtimeModelScore(item, task) }))
        .sort((a, b) => b.score - a.score || a.index - b.index)[0]?.item || null;
    }

    function currentProviderIsLlamaCpp() {
      return $("translationProvider").value.trim().toLowerCase() === "llama-cpp";
    }

    function formatBytes(value) {
      const bytes = Number(value || 0);
      if (!Number.isFinite(bytes) || bytes <= 0) {
        return "-";
      }

      const units = ["B", "KB", "MB", "GB"];
      let size = bytes;
      let unitIndex = 0;
      while (size >= 1024 && unitIndex < units.length - 1) {
        size /= 1024;
        unitIndex += 1;
      }

      const digits = size >= 100 || unitIndex === 0 ? 0 : size >= 10 ? 1 : 2;
      return `${size.toFixed(digits)} ${units[unitIndex]}`;
    }

    function setChip(id, label, tone = "") {
      const chip = $(id);
      chip.className = `memory-chip${tone ? ` ${tone}` : ""}`;
      chip.textContent = label;
    }

    function selectLlamaCppArtifact() {
      const artifacts = state.llamaCppArtifacts || [];
      const recommended = chooseRecommendedModel();
      const modelValue = $("translationModel").value.trim();
      const aliases = [
        modelValue,
        recommended && recommended.name,
        recommended && recommended.modelAlias,
        state.llamaCppHealth && state.llamaCppHealth.model
      ]
        .filter(Boolean)
        .map(value => String(value).toLowerCase());

      return artifacts.find(item =>
        aliases.includes(String(item.modelId || "").toLowerCase())
        || aliases.includes(String(item.modelAlias || "").toLowerCase()))
        || artifacts.find(item => item.verified)
        || artifacts[0]
        || null;
    }

    function selectLlamaCppBinary() {
      const binaries = state.llamaCppBinaries || [];
      const flavor = state.llamaCppHealth && state.llamaCppHealth.binaryFlavor
        ? String(state.llamaCppHealth.binaryFlavor).toLowerCase()
        : "";

      return binaries.find(item => item.ready && String(item.flavor || "").toLowerCase() === flavor)
        || binaries.find(item => String(item.flavor || "").toLowerCase() === flavor)
        || binaries.find(item => item.ready)
        || binaries[0]
        || null;
    }

    function setLlamaCppButton(id, label, icon, disabled) {
      const button = $(id);
      button.innerHTML = `<i class="${icon}"></i>${label}`;
      button.disabled = Boolean(disabled);
    }

    function formatSpeed(bytesPerSecond) {
      const value = Number(bytesPerSecond || 0);
      if (!Number.isFinite(value) || value <= 0) {
        return "-";
      }

      return `${formatBytes(value)}/s`;
    }

    function formatEta(seconds) {
      if (!Number.isFinite(seconds) || seconds <= 0) {
        return "-";
      }

      const total = Math.round(seconds);
      const hours = Math.floor(total / 3600);
      const minutes = Math.floor((total % 3600) / 60);
      const secs = total % 60;
      if (hours > 0) {
        return `${hours}h ${minutes}m`;
      }

      return minutes > 0 ? `${minutes}m ${secs}s` : `${secs}s`;
    }

    function getLlamaCppProgress(kind) {
      return (state.llamaCppDownloadProgress || []).find(item => item.kind === kind) || null;
    }

    function renderDownloadProgressRow(prefix, progress) {
      const wrap = $(`${prefix}Progress`);
      const pauseButton = $(`${prefix}PauseButton`);
      const active = currentProviderIsLlamaCpp()
        && progress
        && (progress.status === "downloading" || progress.status === "paused");

      wrap.classList.toggle("hidden", !active);
      pauseButton.classList.toggle("hidden", !(active && progress.status === "downloading"));

      if (!active) {
        return;
      }

      const total = Number(progress.totalBytes || 0);
      const received = Number(progress.receivedBytes || 0);
      const ratio = total > 0 ? Math.min(1, received / total) : 0;
      const percent = `${(ratio * 100).toFixed(1)}%`;
      const fill = $(`${prefix}ProgressFill`);
      fill.style.width = percent;
      fill.classList.toggle("paused", progress.status === "paused");
      fill.classList.remove("failed");

      $(`${prefix}ProgressPercent`).textContent = progress.status === "paused" ? `${percent} (paused)` : percent;
      $(`${prefix}ProgressBytes`).textContent = `${formatBytes(received)} / ${formatBytes(total)}`;
      $(`${prefix}ProgressSpeed`).textContent = progress.status === "downloading" ? formatSpeed(progress.bytesPerSecond) : "-";
      $(`${prefix}ProgressEta`).textContent = progress.status === "downloading" && progress.bytesPerSecond > 0
        ? `ETA ${formatEta((total - received) / progress.bytesPerSecond)}`
        : "-";
    }

    function renderLlamaCppProgress() {
      renderDownloadProgressRow("llamaCppArtifact", getLlamaCppProgress("model"));
      renderDownloadProgressRow("llamaCppBinary", getLlamaCppProgress("runtime"));
    }

    async function pollLlamaCppDownloadProgress() {
      try {
        const items = await api("/translation/llama-cpp/downloads");
        state.llamaCppDownloadProgress = Array.isArray(items) ? items : [];
      } catch {
        // Keep the last snapshot if polling fails transiently.
      }

      renderLlamaCppProgress();
    }

    function startLlamaCppProgressPolling() {
      if (state.llamaCppProgressTimer) {
        return;
      }

      state.llamaCppProgressTimer = window.setInterval(pollLlamaCppDownloadProgress, 700);
      pollLlamaCppDownloadProgress();
    }

    function stopLlamaCppProgressPolling() {
      if (state.llamaCppProgressTimer) {
        window.clearInterval(state.llamaCppProgressTimer);
        state.llamaCppProgressTimer = null;
      }

      pollLlamaCppDownloadProgress();
    }

    async function pauseLlamaCppDownload(kind) {
      const progress = getLlamaCppProgress(kind);
      if (!progress || progress.status !== "downloading") {
        return;
      }

      try {
        await postEmpty(`/translation/llama-cpp/downloads/pause?key=${encodeURIComponent(progress.key)}`);
        appendMessage("result", "llama.cpp download", `pause requested for ${progress.id || kind}`);
      } catch (error) {
        appendMessage("error", "llama.cpp download", error.message || String(error), "pause");
      }
    }

    function renderLlamaCppDownloads() {
      const isLlamaCpp = currentProviderIsLlamaCpp();
      const busy = state.llamaCppDownloadBusy;
      const artifact = selectLlamaCppArtifact();
      const binary = selectLlamaCppBinary();
      const health = state.llamaCppHealth || {};
      const runtime = health.runtime || null;
      const recommended = chooseRecommendedModel();

      $("llamaCppDownloadPanel").classList.toggle("disabled", !isLlamaCpp);
      $("llamaCppDownloadNotice").classList.toggle("hidden", isLlamaCpp);

      if (!isLlamaCpp) {
        setChip("llamaCppArtifactStatus", "select provider");
        $("llamaCppArtifactName").textContent = "-";
        $("llamaCppArtifactMeta").textContent = "-";
        $("llamaCppArtifactPath").textContent = "-";
        setChip("llamaCppBinaryStatus", "select provider");
        $("llamaCppBinaryName").textContent = "-";
        $("llamaCppBinaryMeta").textContent = "-";
        $("llamaCppBinaryPath").textContent = "-";
        setChip("llamaCppRuntimeStatus", "stopped");
        $("llamaCppRuntimeName").textContent = "-";
        $("llamaCppRuntimeMeta").textContent = "-";
        $("llamaCppRuntimeMessage").textContent = "-";
      } else {
        if (artifact) {
          const artifactTone = artifact.verified ? "good" : artifact.exists ? "warn" : "bad";
          const artifactStatus = artifact.verified ? "verified" : artifact.exists ? "needs check" : "missing";
          setChip("llamaCppArtifactStatus", artifactStatus, artifactTone);
          $("llamaCppArtifactName").textContent = artifact.displayName || artifact.modelAlias || artifact.modelId || "-";
          $("llamaCppArtifactMeta").textContent = `${artifact.filename || "-"} / ${formatBytes(artifact.actualSizeBytes || artifact.sizeBytes)} / ${artifact.modelId || "-"}`;
          $("llamaCppArtifactPath").textContent = artifact.message || artifact.localPath || "-";
          $("llamaCppArtifactPath").title = artifact.localPath || artifact.downloadUrl || "";
        } else {
          setChip("llamaCppArtifactStatus", "not loaded", "warn");
          $("llamaCppArtifactName").textContent = "No model artifacts returned.";
          $("llamaCppArtifactMeta").textContent = "-";
          $("llamaCppArtifactPath").textContent = "Refresh download status.";
          $("llamaCppArtifactPath").title = "";
        }

        if (binary) {
          const binaryTone = binary.ready ? "good" : binary.archiveExists ? "warn" : "bad";
          const binaryStatus = binary.ready ? "ready" : binary.archiveExists ? "needs extract" : "missing";
          setChip("llamaCppBinaryStatus", binaryStatus, binaryTone);
          $("llamaCppBinaryName").textContent = `${binary.flavor || "-"} ${binary.version || ""}`.trim();
          $("llamaCppBinaryMeta").textContent = `${binary.filename || "-"} / ${formatBytes(binary.actualSizeBytes || binary.sizeBytes)} / ${binary.platform || "-"}/${binary.architecture || "-"}`;
          $("llamaCppBinaryPath").textContent = binary.message || binary.executablePath || "-";
          $("llamaCppBinaryPath").title = binary.executablePath || binary.archivePath || binary.downloadUrl || "";
        } else {
          setChip("llamaCppBinaryStatus", "not loaded", "warn");
          $("llamaCppBinaryName").textContent = "No runtime binaries returned.";
          $("llamaCppBinaryMeta").textContent = "-";
          $("llamaCppBinaryPath").textContent = "Refresh download status.";
          $("llamaCppBinaryPath").title = "";
        }

        const runtimeRunning = Boolean(runtime && runtime.isManagedRunning);
        setChip("llamaCppRuntimeStatus", runtimeRunning ? "running" : "stopped", runtimeRunning ? "good" : "");
        $("llamaCppRuntimeName").textContent = runtime && runtime.modelAlias
          ? runtime.modelAlias
          : health.model || recommended?.name || "-";
        $("llamaCppRuntimeMeta").textContent = `mode ${runtime?.mode || health.mode || "-"} / ${runtime?.baseUrl || health.baseUrl || "-"}${runtime?.port ? ` / port ${runtime.port}` : ""}`;
        $("llamaCppRuntimeMessage").textContent = runtime && runtime.lastError
          ? runtime.lastError
          : runtimeRunning ? "Managed llama.cpp server is running." : "Managed server is stopped.";
      }

      const modelPaused = getLlamaCppProgress("model")?.status === "paused";
      const runtimePaused = getLlamaCppProgress("runtime")?.status === "paused";
      setLlamaCppButton("llamaCppRefreshButton", busy === "refresh" ? "Refreshing..." : "Refresh", "ri-refresh-line", busy);
      setLlamaCppButton(
        "llamaCppDownloadModelButton",
        busy === "model" ? "Downloading..." : modelPaused ? "Resume Model" : "Download Model",
        modelPaused && busy !== "model" ? "ri-play-line" : "ri-download-cloud-2-line",
        !isLlamaCpp || busy || !artifact || artifact.verified);
      setLlamaCppButton(
        "llamaCppDownloadRuntimeButton",
        busy === "runtime" ? "Downloading..." : runtimePaused ? "Resume Runtime" : "Download Runtime",
        runtimePaused && busy !== "runtime" ? "ri-play-line" : "ri-download-2-line",
        !isLlamaCpp || busy || !binary || binary.ready);
      setLlamaCppButton("llamaCppInstallUseButton", busy === "install" ? "Installing..." : "Install and Use", "ri-play-circle-line", !isLlamaCpp || busy || !recommended);
      setLlamaCppButton("llamaCppStopButton", busy === "stop" ? "Stopping..." : "Stop", "ri-stop-circle-line", !isLlamaCpp || busy || !(runtime && runtime.isManagedRunning));
      renderLlamaCppProgress();
    }

    function syncModelRecommendation() {
      const input = $("translationModel");
      const models = state.translationModels || [];
      const active = models.find(item => item.name.toLowerCase() === input.value.trim().toLowerCase());
      const recommended = chooseRecommendedModel();
      const display = recommended ? recommended.displayName || recommended.name : "-";
      const activeReason = active && active.recommendationReason ? active.recommendationReason : "";
      const recommendedReason = recommended && recommended.recommendationReason ? recommended.recommendationReason : "";

      $("recommendedModel").textContent = recommended ? display : "-";
      $("recommendedModelUse").textContent = recommended ? recommended.recommendedUse || "recommended" : "-";
      $("recommendedModelReason").textContent = activeReason || recommendedReason || "-";
      const provider = $("translationProvider").value.toLowerCase();
      const needsLlamaInstall = provider === "llama-cpp" && recommended && !recommended.isInstalled;
      const button = $("applyRecommendedModelButton");
      button.textContent = needsLlamaInstall ? "Install and Use" : "Use Recommended";
      button.disabled = !recommended || (!needsLlamaInstall && input.value.trim().toLowerCase() === recommended.name.toLowerCase());
      renderLlamaCppDownloads();
    }

    function runtimePairLabel() {
      const source = $("source")?.value || "-";
      const target = $("target")?.value || "-";
      return `${source} -> ${target}`;
    }

    function runtimeTargetLabel() {
      return $("target")?.value || "-";
    }

    function compactRuntimeLabel(value, fallback = "-") {
      const raw = String(value || "").trim();
      if (!raw) {
        return fallback;
      }

      if (raw.length <= 24) {
        return raw;
      }

      return `${raw.slice(0, 23).trim()}...`;
    }

    function textMetricLabel(value) {
      const text = String(value || "");
      const chars = Array.from(text).length;
      const lines = text ? text.split(/\r\n|\r|\n/).length : 0;
      return `${chars} ${uiText("metric.chars", "chars")} / ${lines} ${uiText("metric.lines", "lines")}`;
    }

    function normalizeTokenUsage(usage) {
      if (!usage) {
        return null;
      }

      const input = Number(usage.inputTokens ?? usage.InputTokens ?? usage.input_tokens ?? 0);
      const output = Number(usage.outputTokens ?? usage.OutputTokens ?? usage.output_tokens ?? 0);
      const rawTotal = Number(usage.totalTokens ?? usage.TotalTokens ?? usage.total_tokens ?? 0);
      const total = Number.isFinite(rawTotal) && rawTotal > 0 ? rawTotal : input + output;
      return {
        input: Number.isFinite(input) ? input : 0,
        output: Number.isFinite(output) ? output : 0,
        total: Number.isFinite(total) ? total : 0,
        source: String(usage.source ?? usage.Source ?? "").trim(),
        estimated: Boolean(usage.isEstimated ?? usage.IsEstimated)
      };
    }

    function compactTokenCount(value) {
      const count = Number(value || 0);
      if (!Number.isFinite(count) || count <= 0) {
        return "0";
      }

      if (count >= 1000000) {
        return `${(count / 1000000).toFixed(count >= 10000000 ? 0 : 1)}m`;
      }

      if (count >= 1000) {
        return `${(count / 1000).toFixed(count >= 10000 ? 0 : 1)}k`;
      }

      return String(Math.round(count));
    }

    function tokenUsageLabel(usage) {
      const normalized = normalizeTokenUsage(usage);
      if (!normalized) {
        return "tokens --";
      }

      return `${compactTokenCount(normalized.total)} tok${normalized.estimated ? "*" : ""}`;
    }

    function tokenUsageTitle(usage) {
      const normalized = normalizeTokenUsage(usage);
      if (!normalized) {
        return "No token usage reported";
      }

      const mode = normalized.estimated ? "estimated" : "exact";
      const source = normalized.source ? ` / ${normalized.source}` : "";
      return `input ${normalized.input} / output ${normalized.output} / total ${normalized.total} / ${mode}${source}`;
    }

    function tokenUsageMeta(usage) {
      const normalized = normalizeTokenUsage(usage);
      if (!normalized) {
        return "";
      }

      return `${compactTokenCount(normalized.total)} tok${normalized.estimated ? " estimated" : ""}`;
    }

    function appendTokenUsageMeta(meta, usage) {
      const tokenMeta = tokenUsageMeta(usage);
      return tokenMeta ? `${meta} / ${tokenMeta}` : meta;
    }

    function zeroTokenUsage(source) {
      return { inputTokens: 0, outputTokens: 0, totalTokens: 0, source, isEstimated: false };
    }

    function tokenUsageModeKey(mode = state.mode) {
      return WORKSPACE_TAB_DEFS[mode] ? mode : "text";
    }

    function tokenUsageForMode(mode = state.mode) {
      return (state.tokenUsageByMode || {})[tokenUsageModeKey(mode)] || null;
    }

    function readTokenUsage(value) {
      return value
        ? value.tokenUsage || value.TokenUsage || value.usage || value.Usage || null
        : null;
    }

    function mergeTokenUsages(usages, source) {
      const values = (usages || [])
        .map(normalizeTokenUsage)
        .filter(Boolean);
      if (!values.length) {
        return null;
      }

      const input = values.reduce((sum, usage) => sum + usage.input, 0);
      const output = values.reduce((sum, usage) => sum + usage.output, 0);
      let total = values.reduce((sum, usage) => sum + usage.total, 0);
      if (total <= 0) {
        total = input + output;
      }

      return {
        inputTokens: input,
        outputTokens: output,
        totalTokens: total,
        source,
        isEstimated: values.some(usage => usage.estimated)
      };
    }

    // Known model context-window sizes (tokens). Prefix-matched, so dated /
    // suffixed model ids (e.g. "claude-3-5-sonnet-20241022") resolve to the
    // closest base entry. Extend as new models ship.
    const MODEL_CONTEXT_LIMITS = Object.freeze({
      "claude-opus-4": 200000,
      "claude-sonnet-4": 200000,
      "claude-haiku-4": 200000,
      "claude-3-7-sonnet": 200000,
      "claude-3-5-sonnet": 200000,
      "claude-3-5-haiku": 200000,
      "claude-3-opus": 200000,
      "claude-3-sonnet": 200000,
      "claude-3-haiku": 200000,
      "claude": 200000,
      "gpt-4o-mini": 128000,
      "gpt-4o": 128000,
      "gpt-4-turbo": 128000,
      "gpt-4": 8192,
      "gpt-3.5-turbo": 16385,
      "o1": 200000,
      "gemini-1.5-pro": 2000000,
      "gemini-1.5-flash": 1000000,
      "gemini": 1000000,
      "deepseek": 64000,
      "qwen": 32768,
      "llama": 8192,
      "mistral": 32768,
      "default": 128000
    });

    function getModelContextLimit(modelId) {
      const id = String(modelId || "").trim().toLowerCase();
      if (!id) {
        return MODEL_CONTEXT_LIMITS.default;
      }
      if (MODEL_CONTEXT_LIMITS[id]) {
        return MODEL_CONTEXT_LIMITS[id];
      }
      let best = null;
      for (const key of Object.keys(MODEL_CONTEXT_LIMITS)) {
        if (key === "default") {
          continue;
        }
        if (id.startsWith(key) && (!best || key.length > best.length)) {
          best = key;
        }
      }
      return best ? MODEL_CONTEXT_LIMITS[best] : MODEL_CONTEXT_LIMITS.default;
    }

    // Estimated per-million-token USD prices (input / output). Prefix-matched
    // like MODEL_CONTEXT_LIMITS. Used only for the rough cost / "saved by
    // running locally" estimate in the token-usage popover — always shown with
    // a "~" and an "estimated" caveat, never billed. Extend as models ship.
    const MODEL_PRICING_USD = Object.freeze({
      "claude-opus-4": { in: 15, out: 75 },
      "claude-sonnet-4": { in: 3, out: 15 },
      "claude-haiku-4": { in: 1, out: 5 },
      "claude-3-7-sonnet": { in: 3, out: 15 },
      "claude-3-5-sonnet": { in: 3, out: 15 },
      "claude-3-5-haiku": { in: 0.8, out: 4 },
      "claude-3-opus": { in: 15, out: 75 },
      "claude-3-haiku": { in: 0.25, out: 1.25 },
      "claude": { in: 3, out: 15 },
      "gpt-4o-mini": { in: 0.15, out: 0.6 },
      "gpt-4o": { in: 2.5, out: 10 },
      "gpt-4-turbo": { in: 10, out: 30 },
      "gpt-4": { in: 30, out: 60 },
      "gpt-3.5-turbo": { in: 0.5, out: 1.5 },
      "o1": { in: 15, out: 60 },
      "gemini-1.5-pro": { in: 1.25, out: 5 },
      "gemini-1.5-flash": { in: 0.075, out: 0.3 },
      "gemini": { in: 1.25, out: 5 },
      "deepseek": { in: 0.27, out: 1.1 },
      "default": { in: 0, out: 0 }
    });

    // When a LOCAL model runs, this is the cloud model we price it against to
    // estimate "money saved by running locally". A mainstream mid-tier default.
    const LOCAL_SAVINGS_BASELINE = Object.freeze({ name: "gpt-4o", in: 2.5, out: 10 });

    function getModelPricing(modelId) {
      const id = String(modelId || "").trim().toLowerCase();
      if (!id) {
        return MODEL_PRICING_USD.default;
      }
      if (MODEL_PRICING_USD[id]) {
        return MODEL_PRICING_USD[id];
      }
      let best = null;
      for (const key of Object.keys(MODEL_PRICING_USD)) {
        if (key === "default") {
          continue;
        }
        if (id.startsWith(key) && (!best || key.length > best.length)) {
          best = key;
        }
      }
      return best ? MODEL_PRICING_USD[best] : MODEL_PRICING_USD.default;
    }

    function providerIsLocal(providerName) {
      const key = String(providerName || "").trim().toLowerCase();
      if (!key) {
        return false;
      }
      if (RUNTIME_LOCAL_PROVIDERS.includes(key)) {
        return true;
      }
      if (RUNTIME_API_PROVIDERS.includes(key)) {
        return false;
      }
      // Fall back to the loaded provider descriptor when available.
      const descriptor = (state.translationProviders || []).find(item => item.name === key || item.id === key);
      return descriptor ? Boolean(descriptor.isLocal) : false;
    }

    function estimateUsageCostUsd(usage, modelId) {
      const normalized = normalizeTokenUsage(usage);
      if (!normalized) {
        return 0;
      }
      const pricing = getModelPricing(modelId);
      return (normalized.input / 1000000) * pricing.in + (normalized.output / 1000000) * pricing.out;
    }

    function estimateLocalSavingsUsd(usage) {
      const normalized = normalizeTokenUsage(usage);
      if (!normalized) {
        return 0;
      }
      return (normalized.input / 1000000) * LOCAL_SAVINGS_BASELINE.in
        + (normalized.output / 1000000) * LOCAL_SAVINGS_BASELINE.out;
    }

    function formatUsd(value) {
      const v = Number(value || 0);
      if (!Number.isFinite(v) || v <= 0) {
        return "$0.00";
      }
      if (v < 0.01) {
        return `$${v.toFixed(4)}`;
      }
      if (v < 1) {
        return `$${v.toFixed(3)}`;
      }
      return `$${v.toFixed(2)}`;
    }

    function compactContextLimit(limit) {
      if (limit >= 1000000) {
        return `${(limit / 1000000).toFixed(limit % 1000000 === 0 ? 0 : 1)}M`;
      }
      if (limit >= 1000) {
        return `${Math.round(limit / 1000)}K`;
      }
      return String(limit);
    }

    function renderTokenUsageRing(ring, textEl, usage, modelId) {
      if (!ring) {
        return;
      }
      const normalized = normalizeTokenUsage(usage);
      ring.classList.remove("warning", "danger", "empty");
      if (!normalized || normalized.total <= 0) {
        ring.style.setProperty("--usage-percent", "0");
        ring.classList.add("empty");
        if (textEl) {
          textEl.textContent = "--";
        }
        ring.title = tokenUsageTitle(usage);
        return;
      }

      const limit = getModelContextLimit(modelId);
      const percent = Math.max(0, Math.min(100, (normalized.total / limit) * 100));
      ring.style.setProperty("--usage-percent", percent.toFixed(1));
      if (percent >= 90) {
        ring.classList.add("danger");
      } else if (percent >= 75) {
        ring.classList.add("warning");
      }
      if (textEl) {
        textEl.textContent = `${compactTokenCount(normalized.total)}${normalized.estimated ? "*" : ""}`;
      }
      ring.title = `${tokenUsageTitle(usage)}\ncontext ${compactContextLimit(limit)} (${percent.toFixed(0)}% used)`;
    }

    function updateTokenUsageDisplays() {
      const activeUsage = tokenUsageForMode(state.mode);
      const activeModel = $("translationModel")?.value?.trim() || "";
      const textRing = $("textTokenUsageRing");
      if (textRing) {
        renderTokenUsageRing(textRing, $("textTokenUsageText"), tokenUsageForMode("text"), activeModel);
      }
      const metricRing = $("metricTokensRing");
      if (metricRing) {
        renderTokenUsageRing(metricRing, $("metricTokens"), activeUsage, activeModel);
      }
      // Keep an open popover in sync as new usage streams in.
      if (state.tokenUsagePopoverOpen) {
        renderTokenUsagePopover();
      }
    }

    function tokenUsagePopoverEl() {
      return $("tokenUsagePopover");
    }

    function closeTokenUsagePopover() {
      const el = tokenUsagePopoverEl();
      if (el) {
        el.classList.add("hidden");
      }
      if (state.tokenUsagePopoverAnchor) {
        state.tokenUsagePopoverAnchor.classList.remove("is-open");
      }
      state.tokenUsagePopoverOpen = false;
      state.tokenUsagePopoverAnchor = null;
    }

    function tokenUsageDetailRow(label, value, accentClass, hint) {
      return `<div class="token-pop-stat${accentClass ? " " + accentClass : ""}"${hint ? ` title="${escapeHtml(hint)}"` : ""}>`
        + `<span class="token-pop-stat-label">${escapeHtml(label)}</span>`
        + `<span class="token-pop-stat-value">${escapeHtml(value)}</span></div>`;
    }

    function renderTokenUsagePopover() {
      const el = tokenUsagePopoverEl();
      if (!el) {
        return;
      }
      const mode = state.tokenUsagePopoverMode || tokenUsageModeKey(state.mode);
      const usage = tokenUsageForMode(mode);
      const normalized = normalizeTokenUsage(usage);
      const provider = $("translationProvider")?.value || "-";
      const model = $("translationModel")?.value?.trim() || "";
      const isLocal = providerIsLocal(provider);
      const limit = getModelContextLimit(model);
      const total = normalized ? normalized.total : 0;
      const percent = limit > 0 ? Math.max(0, Math.min(100, (total / limit) * 100)) : 0;
      const barClass = percent >= 90 ? "danger" : percent >= 75 ? "warning" : "";

      const runtimeLabel = model ? `${provider} / ${model}` : provider;
      const estimatedFlag = normalized && normalized.estimated;

      // Cost / savings framing differs for local vs cloud.
      let moneyBlock = "";
      if (normalized && total > 0) {
        if (isLocal) {
          const saved = estimateLocalSavingsUsd(usage);
          moneyBlock = `<div class="token-pop-money local">`
            + `<div class="token-pop-money-row"><span><i class="ri-cpu-line"></i> ${escapeHtml(uiText("tokenUsage.localRun", "Local model — no API cost"))}</span><strong>${escapeHtml(formatUsd(0))}</strong></div>`
            + `<div class="token-pop-money-row saved"><span><i class="ri-bank-card-line"></i> ${escapeHtml(uiText("tokenUsage.saved", "Saved vs cloud"))}</span><strong>~${escapeHtml(formatUsd(saved))}</strong></div>`
            + `<div class="token-pop-money-note">${escapeHtml(uiText("tokenUsage.savedNote", "estimated against") + " " + LOCAL_SAVINGS_BASELINE.name)}</div>`
            + `</div>`;
        } else {
          const cost = estimateUsageCostUsd(usage, model);
          moneyBlock = `<div class="token-pop-money cloud">`
            + `<div class="token-pop-money-row"><span><i class="ri-bank-card-line"></i> ${escapeHtml(uiText("tokenUsage.estCost", "Estimated cost"))}</span><strong>~${escapeHtml(formatUsd(cost))}</strong></div>`
            + `<div class="token-pop-money-note">${escapeHtml(uiText("tokenUsage.estCostNote", "rough estimate, not billed"))}</div>`
            + `</div>`;
        }
      }

      const totalDisplay = total > 0 ? total.toLocaleString() : "0";
      el.querySelector(".token-pop-body").innerHTML = `
        <div class="token-pop-head">
          <div class="token-pop-title">
            <span class="token-pop-total">${escapeHtml(totalDisplay)}</span>
            <span class="token-pop-total-unit">${escapeHtml(uiText("tokenUsage.tokens", "tokens"))}${estimatedFlag ? " *" : ""}</span>
          </div>
          <div class="token-pop-runtime" title="${escapeHtml(runtimeLabel)}"><i class="${isLocal ? "ri-cpu-line" : "ri-cloud-line"}"></i> ${escapeHtml(compactRuntimeLabel(runtimeLabel, "runtime"))}</div>
        </div>
        <div class="token-pop-context">
          <div class="token-pop-context-head">
            <span>${escapeHtml(uiText("tokenUsage.context", "Context window"))}</span>
            <span class="token-pop-context-pct">${escapeHtml(compactContextLimit(limit))} · ${percent.toFixed(0)}%</span>
          </div>
          <div class="token-pop-bar"><span class="token-pop-bar-fill ${barClass}" style="width:${percent.toFixed(1)}%"></span></div>
        </div>
        <div class="token-pop-grid">
          ${tokenUsageDetailRow(uiText("tokenUsage.input", "input"), normalized ? normalized.input.toLocaleString() : "0", "accent-blue")}
          ${tokenUsageDetailRow(uiText("tokenUsage.output", "output"), normalized ? normalized.output.toLocaleString() : "0", "accent-purple")}
          ${tokenUsageDetailRow(uiText("tokenUsage.total", "total"), totalDisplay, "")}
          ${tokenUsageDetailRow(uiText("tokenUsage.mode", "mode"), estimatedFlag ? uiText("tokenUsage.estimated", "estimated") : uiText("tokenUsage.exact", "exact"), "")}
        </div>
        ${moneyBlock}
        ${normalized && normalized.source ? `<div class="token-pop-source">${escapeHtml(normalized.source)}</div>` : ""}
        ${estimatedFlag ? `<div class="token-pop-source">* ${escapeHtml(uiText("tokenUsage.estNote", "token counts estimated client-side"))}</div>` : ""}
      `;
    }

    function positionTokenUsagePopover(anchor) {
      const el = tokenUsagePopoverEl();
      if (!el || !anchor) {
        return;
      }
      el.classList.remove("hidden");
      const rect = anchor.getBoundingClientRect();
      const popWidth = el.offsetWidth || 280;
      const popHeight = el.offsetHeight || 200;
      const gap = 8;
      let top = rect.bottom + gap;
      if (top + popHeight > window.innerHeight - 8) {
        top = Math.max(8, rect.top - gap - popHeight);
      }
      let left = rect.left + rect.width / 2 - popWidth / 2;
      left = Math.max(8, Math.min(left, window.innerWidth - popWidth - 8));
      el.style.top = `${Math.round(top)}px`;
      el.style.left = `${Math.round(left)}px`;
    }

    function openTokenUsagePopover(anchor, mode) {
      const el = tokenUsagePopoverEl();
      if (!el || !anchor) {
        return;
      }
      if (state.tokenUsagePopoverAnchor && state.tokenUsagePopoverAnchor !== anchor) {
        state.tokenUsagePopoverAnchor.classList.remove("is-open");
      }
      state.tokenUsagePopoverOpen = true;
      state.tokenUsagePopoverAnchor = anchor;
      state.tokenUsagePopoverMode = mode || tokenUsageModeKey(state.mode);
      anchor.classList.add("is-open");
      renderTokenUsagePopover();
      positionTokenUsagePopover(anchor);
    }

    function toggleTokenUsagePopover(anchor, mode) {
      if (state.tokenUsagePopoverOpen && state.tokenUsagePopoverAnchor === anchor) {
        closeTokenUsagePopover();
        return;
      }
      openTokenUsagePopover(anchor, mode);
    }

    function bindTokenUsageRing(ringId, mode) {
      const ring = $(ringId);
      if (!ring || ring.dataset.tokenPopBound === "1") {
        return;
      }
      ring.dataset.tokenPopBound = "1";
      ring.addEventListener("click", event => {
        event.stopPropagation();
        toggleTokenUsagePopover(ring, mode);
      });
      ring.addEventListener("keydown", event => {
        if (event.key === "Enter" || event.key === " ") {
          event.preventDefault();
          toggleTokenUsagePopover(ring, mode);
        } else if (event.key === "Escape") {
          closeTokenUsagePopover();
        }
      });
    }

    function initTokenUsagePopover() {
      bindTokenUsageRing("metricTokensRing", "");
      bindTokenUsageRing("textTokenUsageRing", "text");
      // Dismiss on outside click, Escape, scroll, or resize.
      document.addEventListener("click", event => {
        if (!state.tokenUsagePopoverOpen) {
          return;
        }
        const el = tokenUsagePopoverEl();
        if (el && el.contains(event.target)) {
          return;
        }
        if (state.tokenUsagePopoverAnchor && state.tokenUsagePopoverAnchor.contains(event.target)) {
          return;
        }
        closeTokenUsagePopover();
      });
      document.addEventListener("keydown", event => {
        if (event.key === "Escape" && state.tokenUsagePopoverOpen) {
          closeTokenUsagePopover();
        }
      });
      window.addEventListener("resize", () => {
        if (state.tokenUsagePopoverOpen) {
          positionTokenUsagePopover(state.tokenUsagePopoverAnchor);
        }
      });
      window.addEventListener("scroll", () => {
        if (state.tokenUsagePopoverOpen) {
          positionTokenUsagePopover(state.tokenUsagePopoverAnchor);
        }
      }, true);
    }

    // ── Usage settings dashboard ───────────────────────────────
    let usageRange = "today";
    let usageLoading = false;

    function compactUsageNumber(value) {
      const n = Number(value || 0);
      if (!Number.isFinite(n) || n <= 0) {
        return "0";
      }
      if (n >= 1000000) {
        return `${(n / 1000000).toFixed(n >= 10000000 ? 0 : 2)}M`;
      }
      if (n >= 1000) {
        return `${(n / 1000).toFixed(n >= 100000 ? 0 : 1)}K`;
      }
      return String(Math.round(n));
    }

    function renderUsageSummary(summary) {
      const total = Number(summary?.totalTokens ?? summary?.TotalTokens ?? 0);
      const requests = Number(summary?.totalRequests ?? summary?.TotalRequests ?? 0);
      const input = Number(summary?.totalInputTokens ?? summary?.TotalInputTokens ?? 0);
      const output = Number(summary?.totalOutputTokens ?? summary?.TotalOutputTokens ?? 0);
      const byProvider = summary?.byProvider ?? summary?.ByProvider ?? [];
      const daily = summary?.daily ?? summary?.Daily ?? [];

      if ($("usageHeroTotal")) {
        $("usageHeroTotal").textContent = total.toLocaleString();
      }
      if ($("usageHeroRequests")) {
        $("usageHeroRequests").textContent = requests.toLocaleString();
      }
      if ($("usageInputOutput")) {
        $("usageInputOutput").textContent = `in ${compactUsageNumber(input)} · out ${compactUsageNumber(output)}`;
      }

      // Money: sum cloud cost (for cloud providers) and local savings (for local).
      let cloudCost = 0;
      let savedCost = 0;
      for (const row of byProvider) {
        const provider = row.provider ?? row.Provider ?? "";
        const model = row.model ?? row.Model ?? "";
        const rIn = Number(row.inputTokens ?? row.InputTokens ?? 0);
        const rOut = Number(row.outputTokens ?? row.OutputTokens ?? 0);
        const usageLike = { inputTokens: rIn, outputTokens: rOut, totalTokens: Number(row.totalTokens ?? row.TotalTokens ?? 0) };
        if (providerIsLocal(provider)) {
          savedCost += estimateLocalSavingsUsd(usageLike);
        } else {
          cloudCost += estimateUsageCostUsd(usageLike, model);
        }
      }
      if ($("usageHeroSaved")) {
        $("usageHeroSaved").textContent = `~${formatUsd(savedCost)}`;
      }
      if ($("usageHeroSpent")) {
        $("usageHeroSpent").textContent = `~${formatUsd(cloudCost)}`;
      }

      // Provider/model breakdown rows.
      const list = $("usageProviderList");
      if (list) {
        list.innerHTML = "";
        if (!byProvider.length) {
          const empty = document.createElement("div");
          empty.className = "usage-empty";
          empty.textContent = uiText("settings.usage.empty", "No translations recorded for this range yet.");
          list.appendChild(empty);
        } else {
          const maxTotal = byProvider.reduce((m, r) => Math.max(m, Number(r.totalTokens ?? r.TotalTokens ?? 0)), 0) || 1;
          for (const row of byProvider) {
            const provider = row.provider ?? row.Provider ?? "";
            const model = row.model ?? row.Model ?? "";
            const rTotal = Number(row.totalTokens ?? row.TotalTokens ?? 0);
            const rIn = Number(row.inputTokens ?? row.InputTokens ?? 0);
            const rOut = Number(row.outputTokens ?? row.OutputTokens ?? 0);
            const rReq = Number(row.requests ?? row.Requests ?? 0);
            const isLocal = providerIsLocal(provider);
            const usageLike = { inputTokens: rIn, outputTokens: rOut, totalTokens: rTotal };
            const money = isLocal
              ? `<span class="saved">~${escapeHtml(formatUsd(estimateLocalSavingsUsd(usageLike)))} ${escapeHtml(uiText("settings.usage.savedShort", "saved"))}</span>`
              : `<span class="spent">~${escapeHtml(formatUsd(estimateUsageCostUsd(usageLike, model)))}</span>`;
            const pct = Math.max(2, Math.min(100, (rTotal / maxTotal) * 100));
            const label = model ? `${provider} / ${model}` : provider;

            const el = document.createElement("div");
            el.className = "usage-provider-row";
            el.innerHTML = `
              <span class="usage-provider-dot ${isLocal ? "local" : "cloud"}"></span>
              <div class="usage-provider-info">
                <div class="usage-provider-name" title="${escapeHtml(label)}">${escapeHtml(label)}</div>
                <div class="usage-provider-bar"><span style="width:${pct.toFixed(1)}%"></span></div>
              </div>
              <div class="usage-provider-meta"><strong>${escapeHtml(compactUsageNumber(rTotal))}</strong>${escapeHtml(rReq.toLocaleString())} ${escapeHtml(uiText("settings.usage.reqShort", "req"))} · ${money}</div>
            `;
            list.appendChild(el);
          }
        }
      }

      // Daily trend bars.
      const trend = $("usageTrend");
      if (trend) {
        trend.innerHTML = "";
        const maxDay = daily.reduce((m, d) => Math.max(m, Number(d.totalTokens ?? d.TotalTokens ?? 0)), 0) || 1;
        if (!daily.length) {
          const hint = $("usageTrendHint");
          if (hint) {
            hint.textContent = "";
          }
        } else {
          for (const d of daily) {
            const date = d.date ?? d.Date ?? "";
            const dayTotal = Number(d.totalTokens ?? d.TotalTokens ?? 0);
            const h = Math.max(2, (dayTotal / maxDay) * 100);
            const bar = document.createElement("div");
            bar.className = "usage-trend-bar";
            bar.style.height = `${h.toFixed(1)}%`;
            bar.title = `${date}: ${dayTotal.toLocaleString()} tokens`;
            trend.appendChild(bar);
          }
          const hint = $("usageTrendHint");
          if (hint) {
            hint.textContent = `${daily.length} ${uiText("settings.usage.days", "days")}`;
          }
        }
      }

      // By app surface (feature source) breakdown.
      const bySurface = summary?.bySurface ?? summary?.BySurface ?? [];
      const surfaceList = $("usageSurfaceList");
      if (surfaceList) {
        surfaceList.innerHTML = "";
        if (!bySurface.length) {
          const empty = document.createElement("div");
          empty.className = "usage-empty";
          empty.textContent = uiText("settings.usage.empty", "No translations recorded for this range yet.");
          surfaceList.appendChild(empty);
        } else {
          const maxSurface = bySurface.reduce((m, r) => Math.max(m, Number(r.totalTokens ?? r.TotalTokens ?? 0)), 0) || 1;
          for (const row of bySurface) {
            const surfaceKey = String(row.surface ?? row.Surface ?? "unknown");
            const rTotal = Number(row.totalTokens ?? row.TotalTokens ?? 0);
            const rReq = Number(row.requests ?? row.Requests ?? 0);
            const pct = Math.max(2, Math.min(100, (rTotal / maxSurface) * 100));
            const label = USAGE_SURFACE_LABELS[surfaceKey] || surfaceKey;
            const icon = USAGE_SURFACE_ICONS[surfaceKey] || "ri-apps-2-line";

            const el = document.createElement("div");
            el.className = "usage-provider-row";
            el.innerHTML = `
              <i class="${icon} usage-surface-icon" aria-hidden="true"></i>
              <div class="usage-provider-info">
                <div class="usage-provider-name">${escapeHtml(label)}</div>
                <div class="usage-provider-bar"><span style="width:${pct.toFixed(1)}%"></span></div>
              </div>
              <div class="usage-provider-meta"><strong>${escapeHtml(compactUsageNumber(rTotal))}</strong>${escapeHtml(rReq.toLocaleString())} ${escapeHtml(uiText("settings.usage.reqShort", "req"))}</div>
            `;
            surfaceList.appendChild(el);
          }
        }
      }
    }

    const USAGE_SURFACE_LABELS = Object.freeze({
      text: "Text translate",
      region: "Region (live)",
      ocr: "OCR image",
      audio: "Audio / speech",
      document: "Document",
      unknown: "Other"
    });
    const USAGE_SURFACE_ICONS = Object.freeze({
      text: "ri-translate-2",
      region: "ri-focus-3-line",
      ocr: "ri-scan-2-line",
      audio: "ri-mic-line",
      document: "ri-file-copy-2-line",
      unknown: "ri-apps-2-line"
    });

    async function loadUsageSummary() {
      if (usageLoading) {
        return;
      }
      usageLoading = true;
      const refreshBtn = $("usageRefreshButton");
      if (refreshBtn) {
        refreshBtn.disabled = true;
      }
      try {
        const summary = await api(`/translation/usage-summary?range=${encodeURIComponent(usageRange)}`);
        renderUsageSummary(summary || {});
      } catch (error) {
        appendMessage("error", "usage", error.message || String(error));
      } finally {
        usageLoading = false;
        if (refreshBtn) {
          refreshBtn.disabled = false;
        }
      }
    }

    function initUsageTab() {
      for (const button of document.querySelectorAll("[data-usage-range]")) {
        button.addEventListener("click", () => {
          usageRange = button.dataset.usageRange || "today";
          for (const other of document.querySelectorAll("[data-usage-range]")) {
            other.classList.toggle("active", other === button);
          }
          loadUsageSummary();
        });
      }
      if ($("usageRefreshButton")) {
        $("usageRefreshButton").addEventListener("click", loadUsageSummary);
      }
    }

    function applyTokenUsage(usage, mode = state.mode) {
      const key = tokenUsageModeKey(mode);
      state.tokenUsageByMode = state.tokenUsageByMode || {};
      state.tokenUsageByMode[key] = usage || null;
      if (key === "text") {
        state.translationTokenUsage = usage || null;
      }
      updateTokenUsageDisplays();
    }

    function addTokenUsage(usage, mode = state.mode, source = "session") {
      const next = mergeTokenUsages([tokenUsageForMode(mode), usage], source);
      applyTokenUsage(next, mode);
      return next;
    }

    function clearAllTokenUsage() {
      state.tokenUsageByMode = {};
      state.translationTokenUsage = null;
      updateTokenUsageDisplays();
    }

    function syncTranslateUi() {
      const sourceValue = sourceText ? sourceText.value : "";
      const resultValue = lastOutput ? lastOutput.value : "";
      const sourceLanguage = $("source")?.value || "auto";
      const targetLanguage = $("target")?.value || "-";
      const provider = $("translationProvider")?.value || "-";
      const model = $("translationModel")?.value?.trim() || "";
      const runtime = model ? `${provider} / ${model}` : provider;

      if ($("textSourceLanguageBadge")) {
        $("textSourceLanguageBadge").textContent = getTranslationLanguageLabel(sourceLanguage);
        $("textSourceLanguageBadge").title = getTranslationLanguageTitle(sourceLanguage);
      }
      if ($("textSourceCount")) {
        $("textSourceCount").textContent = textMetricLabel(sourceValue);
      }
      if ($("textTargetLanguageBadge")) {
        $("textTargetLanguageBadge").textContent = getTranslationLanguageLabel(targetLanguage);
        $("textTargetLanguageBadge").title = `${uiText("runtime.target", "Target")} ${getTranslationLanguageTitle(targetLanguage)}`;
      }
      if ($("textRuntimeBadge")) {
        $("textRuntimeBadge").textContent = compactRuntimeLabel(runtime, "runtime");
        $("textRuntimeBadge").title = runtime;
      }
      if ($("textTokenUsageRing")) {
        renderTokenUsageRing($("textTokenUsageRing"), $("textTokenUsageText"), tokenUsageForMode("text"), model);
      }
      if ($("textResultCount")) {
        $("textResultCount").textContent = textMetricLabel(resultValue);
      }
      if ($("copyTextResultButton")) {
        $("copyTextResultButton").disabled = !resultValue.trim();
      }
    }

    async function copyTextResult() {
      const text = lastOutput ? lastOutput.value.trim() : "";
      if (!text) {
        appendMessage("error", "translation", "nothing to copy");
        return;
      }

      await navigator.clipboard.writeText(text);
      appendMessage("result", "translation", "copied");
    }

    function mirrorSelectOptions(target, source) {
      if (!target || !source) {
        return;
      }

      const value = source.value;
      target.innerHTML = "";
      for (const option of source.options) {
        const clone = document.createElement("option");
        clone.value = option.value;
        clone.textContent = option.textContent;
        clone.disabled = option.disabled;
        clone.title = option.title;
        target.appendChild(clone);
      }
      target.value = value;
    }

    function syncRuntimeQuickControls() {
      mirrorSelectOptions($("runtimeTarget"), $("target"));
      mirrorSelectOptions($("runtimeProvider"), $("translationProvider"));
      if ($("runtimeModel") && $("translationModel")) {
        $("runtimeModel").value = $("translationModel").value || "";
      }

      updateRuntimeModelTrigger();
      renderRuntimeModelOptions();
    }

    function currentRuntimeModelName() {
      return $("translationModel")?.value?.trim() || "";
    }

    function findRuntimeModel(name = currentRuntimeModelName()) {
      const normalized = String(name || "").toLowerCase();
      if (!normalized) {
        return null;
      }

      return (state.translationModels || []).find(item => {
        const itemName = String(item.name || "").toLowerCase();
        const displayName = String(item.displayName || "").toLowerCase();
        return itemName === normalized || displayName === normalized;
      }) || null;
    }

    function runtimeModelDisplayName(item, fallback = currentRuntimeModelName()) {
      return item ? item.displayName || item.name || fallback : fallback;
    }

    function runtimeModelShortName(value) {
      let label = String(value || "").trim();
      if (!label) {
        return "-";
      }

      label = label.replace(/^(Tencent|Meta|Google|Alibaba|Microsoft|OpenAI)\s+/i, "");
      label = label.replace(/\s*\((?:Q\d|q\d|FP\d|fp\d|INT\d|int\d)[^)]+\)\s*$/i, "");
      label = label.replace(/[-_\s]*(?:q\d(?:_?k_?m|km)?|fp\d+|int\d+)$/i, "");
      label = label.replace(/\s{2,}/g, " ").trim();
      if (label.length > 24) {
        return `${label.slice(0, 23).trim()}...`;
      }
      return label || String(value || "-");
    }

    function runtimeProviderLabel() {
      return $("translationProvider")?.value?.trim() || "-";
    }

    function runtimeModelIconKey(item, provider = runtimeProviderLabel()) {
      const text = [
        item?.iconKey,
        item?.provider,
        item?.source,
        item?.name,
        item?.displayName,
        item?.recommendedUse,
        provider
      ].map(value => String(value || "").toLowerCase()).join(" ");
      if (text.includes("gemma") || text.includes("gemini") || text.includes("google")) return "gemini";
      if (text.includes("qwen") || text.includes("mort")) return "qwen";
      if (text.includes("hy-mt") || text.includes("hymt") || text.includes("tencent")) return "modelscope";
      if (text.includes("llama3") || text.includes("meta")) return "meta";
      if (text.includes("ollama")) return "ollama";
      if (text.includes("deepl")) return "deepl";
      if (text.includes("openai") || text.includes("gpt")) return "openai";
      return normalizeSupplierKey(provider);
    }

    function updateRuntimeModelTrigger() {
      const model = findRuntimeModel();
      const displayName = runtimeModelDisplayName(model) || "-";
      const provider = runtimeProviderLabel();
      const menu = $("runtimeModelMenu");
      const trigger = $("runtimeModelTrigger");
      const avatar = $("runtimeModelAvatar");
      if (avatar) {
        avatar.innerHTML = getSupplierAvatarHtml(runtimeModelIconKey(model, provider), displayName || provider, "runtime-model-avatar");
        hydrateSupplierIcons(avatar);
      }
      if ($("runtimeModelLabel")) {
        $("runtimeModelLabel").textContent = runtimeModelShortName(displayName);
      }
      if ($("runtimeModelProviderLabel")) {
        $("runtimeModelProviderLabel").textContent = provider;
        $("runtimeModelProviderLabel").title = provider;
      }
      if ($("runtimeMenuSubtitle")) {
        $("runtimeMenuSubtitle").textContent = formatUiTemplate("runtime.subtitleWithValues", {
          target: runtimeTargetLabel(),
          provider
        }, "Target {target} · {provider}");
      }
      if (trigger && menu) {
        trigger.setAttribute("aria-expanded", menu.classList.contains("hidden") ? "false" : "true");
        trigger.title = `${displayName} (${provider})`;
      }
    }

    function runtimeModelBadge(label, extraClass = "") {
      const className = extraClass ? `runtime-model-badge ${extraClass}` : "runtime-model-badge";
      return `<span class="${className}">${escapeHtml(String(label || ""))}</span>`;
    }

    function runtimeModelMetaLabel(item, task = activeRuntimeModelTask()) {
      const text = runtimeModelSearchText(item);
      if (item?.isDefault) {
        return uiText("runtime.modelMeta.currentDefault", "current default");
      }
      if (text.includes("hy-mt2") || text.includes("hymt") || text.includes("tencent")) {
        if (text.includes("q4_k_m") || text.includes("q4km") || text.includes("q4_k")) {
          return uiText("runtime.modelMeta.hyQ4", "fast local translation");
        }
        if (text.includes("q6_k") || text.includes("q6k")) {
          return uiText("runtime.modelMeta.hyQ6", "higher quality, a little slower");
        }
      }
      if (text.includes("gemma") || text.includes("gemmafit")) {
        return task === "realtime" || task === "ocr"
          ? uiText("runtime.modelMeta.gemmaSlow", "quality candidate, slower realtime")
          : uiText("runtime.modelMeta.gemma", "quality candidate");
      }
      if (!runtimeModelIsSelectable(item)) {
        return uiText("runtime.modelMeta.installFirst", "install before use");
      }

      return item?.recommendedUse || item?.source || item?.recommendationReason || item?.name || "Available model";
    }

    function runtimeModelScopeMatches(item, scope = state.runtimeModelScope || "all") {
      switch (scope) {
        case "local":
          return runtimeModelIsLocal(item);
        case "api":
          return runtimeModelIsApi(item);
        case "installed":
          return runtimeModelIsSelectable(item);
        case "installable":
          return !runtimeModelIsSelectable(item);
        default:
          return true;
      }
    }

    function syncRuntimeModelFilters() {
      const task = state.runtimeModelTask || "auto";
      const scope = state.runtimeModelScope || "all";
      const taskSelect = $("runtimeTaskSelect");
      const scopeSelect = $("runtimeScopeSelect");
      if (taskSelect && taskSelect.value !== task) {
        taskSelect.value = task;
      }
      if (scopeSelect && scopeSelect.value !== scope) {
        scopeSelect.value = scope;
      }
      if ($("runtimeModelFilterSummary")) {
        $("runtimeModelFilterSummary").textContent = `${runtimeModelTaskLabel(task === "auto" ? activeRuntimeModelTask() : task)} / ${runtimeModelScopeLabel(scope)}`;
      }
      document.querySelectorAll("[data-runtime-task]").forEach(button => {
        button.setAttribute("aria-pressed", String((button.dataset.runtimeTask || "auto") === task));
      });
      document.querySelectorAll("[data-runtime-scope]").forEach(button => {
        button.setAttribute("aria-pressed", String((button.dataset.runtimeScope || "all") === scope));
      });
    }

    function initializeRuntimeModelFilters() {
      loadRuntimeModelMenuPreferences();
      const taskSelect = $("runtimeTaskSelect");
      const scopeSelect = $("runtimeScopeSelect");
      const advanced = $("runtimeModelAdvanced");
      if (advanced) {
        advanced.open = state.runtimeModelMenuPrefs?.advancedOpen === true;
        advanced.addEventListener("toggle", () => {
          state.runtimeModelMenuPrefs = {
            ...(state.runtimeModelMenuPrefs || {}),
            touched: true,
            advancedOpen: advanced.open,
            groupOpen: {
              ...defaultRuntimeModelGroupOpen(),
              ...(state.runtimeModelMenuPrefs?.groupOpen || {})
            }
          };
          saveRuntimeModelMenuPreferences();
        });
      }
      if (taskSelect) {
        taskSelect.addEventListener("change", () => {
          state.runtimeModelTask = taskSelect.value || "auto";
          saveRuntimeModelMenuPreferences();
          syncRuntimeModelFilters();
          syncModelRecommendation();
          renderRuntimeModelOptions();
        });
      }
      if (scopeSelect) {
        scopeSelect.addEventListener("change", () => {
          state.runtimeModelScope = scopeSelect.value || "all";
          saveRuntimeModelMenuPreferences();
          syncRuntimeModelFilters();
          renderRuntimeModelOptions();
        });
      }

      document.querySelectorAll("[data-runtime-task]").forEach(button => {
        button.addEventListener("click", () => {
          state.runtimeModelTask = button.dataset.runtimeTask || "auto";
          saveRuntimeModelMenuPreferences();
          syncRuntimeModelFilters();
          syncModelRecommendation();
          renderRuntimeModelOptions();
        });
      });

      document.querySelectorAll("[data-runtime-scope]").forEach(button => {
        button.addEventListener("click", () => {
          state.runtimeModelScope = button.dataset.runtimeScope || "all";
          saveRuntimeModelMenuPreferences();
          syncRuntimeModelFilters();
          renderRuntimeModelOptions();
        });
      });
      syncRuntimeModelFilters();
    }

    function renderRuntimeModelOptions() {
      const host = $("runtimeModelOptions");
      if (!host) {
        return;
      }
      syncRuntimeModelFilters();

      const models = state.translationModels || [];
      if (!models.length) {
        host.innerHTML = `<div class="runtime-model-empty">No models loaded for this provider.</div>`;
        return;
      }

      const task = activeRuntimeModelTask();
      const scopedModels = models.filter(item => runtimeModelScopeMatches(item));
      if (!scopedModels.length) {
        host.innerHTML = `<div class="runtime-model-empty">${escapeHtml(uiText("runtime.modelEmpty.filtered", "No models match this filter."))}</div>`;
        return;
      }

      const current = currentRuntimeModelName().toLowerCase();
      const recommended = chooseRecommendedModel(task, scopedModels);
      const recommendedName = String(recommended?.name || "").toLowerCase();
      const sortedModels = (items) => items
        .map((item, index) => ({ item, index, score: runtimeModelScore(item, task) }))
        .sort((a, b) => b.score - a.score || a.index - b.index)
        .map(entry => entry.item);
      const isRecommendedItem = (item) => {
        const itemName = String(item.name || "").toLowerCase();
        if (recommendedName && itemName === recommendedName) {
          return true;
        }
        return !!item.isRecommended
          && runtimeModelScore(item, task) >= 70
          && !runtimeModelIsSlowForTask(item, task)
          && runtimeModelIsSelectable(item);
      };
      const isPrimaryRecommendedItem = (item) => !!recommendedName && String(item.name || "").toLowerCase() === recommendedName;

      const optionHtml = (item, groupKey = "") => {
        const name = String(item.name || item.displayName || "");
        const displayName = String(item.displayName || item.name || name);
        // For API suppliers the active route's model is flagged server-side via isDefault; honor it
        // so the active remote model highlights even when the custom-model input is blank.
        const isActive = item.supplierId
          ? (!!item.isDefault || (current && (String(item.name || "").toLowerCase() === current || String(item.displayName || "").toLowerCase() === current)))
          : (current
            ? (String(item.name || "").toLowerCase() === current || String(item.displayName || "").toLowerCase() === current)
            : !!item.isDefault);
        const isRecommended = isRecommendedItem(item);
        const isSelectable = runtimeModelIsSelectable(item);
        const isSlow = runtimeModelIsSlowForTask(item, task);
        const badges = [];
        if (isPrimaryRecommendedItem(item)) {
          badges.push(runtimeModelBadge(uiText("runtime.modelBadge.best", "Best match"), "best"));
        } else if (isRecommended) {
          badges.push(runtimeModelBadge(uiText("runtime.modelBadge.recommended", "Recommended"), "recommended"));
        }
        if (item.isDefault && !isPrimaryRecommendedItem(item)) {
          badges.push(item.supplierId
            ? runtimeModelBadge(uiText("runtime.modelBadge.active", "Active"), "active")
            : runtimeModelBadge(uiText("runtime.modelBadge.default", "Default")));
        }
        if (runtimeModelProviderName(item) === "llama-cpp" && !isSelectable) {
          badges.push(runtimeModelBadge(uiText("runtime.modelBadge.installable", "Installable"), "installable"));
        }
        if (runtimeModelIsApi(item) && runtimeModelProviderName(item) !== "api-compatible") {
          badges.push(runtimeModelBadge(uiText("runtime.modelBadge.api", "API"), "api"));
        }
        if (isSlow) {
          badges.push(runtimeModelBadge(uiText("runtime.modelBadge.slow", "Slow realtime"), "slow"));
        }
        const meta = runtimeModelMetaLabel(item, task);
        const reason = isSelectable
          ? item.recommendationReason || meta
          : uiText("runtime.modelHint.installable", "Install this model before selecting it.");
        const iconKey = item.supplierId ? normalizeSupplierKey(item.supplierName || name) : runtimeModelIconKey(item);
        return `
          <button class="runtime-model-option${isActive ? " active" : ""}${isSelectable ? "" : " installable"}${isSlow ? " slow" : ""}" type="button" role="option" aria-selected="${isActive ? "true" : "false"}" aria-disabled="${isSelectable ? "false" : "true"}" data-runtime-model="${escapeHtml(name)}" data-supplier-id="${escapeHtml(String(item.supplierId || ""))}" data-runtime-installable="${isSelectable ? "false" : "true"}" data-runtime-group="${escapeHtml(groupKey)}" title="${escapeHtml(String(reason))}">
            <span class="runtime-model-option-main">
              ${getSupplierAvatarHtml(iconKey, displayName)}
              <span class="runtime-model-option-copy">
                <span class="runtime-model-option-title">${escapeHtml(displayName)}</span>
                <span class="runtime-model-option-meta">${escapeHtml(String(meta))}</span>
              </span>
            </span>
            <span class="runtime-model-option-side">
              <span class="runtime-model-option-badges">${badges.join("")}</span>
              <i class="ri-check-line runtime-model-check" aria-hidden="true"></i>
            </span>
          </button>`;
      };

      // Group by supplier when the list carries supplier identity (api-compatible). Each configured
      // supplier — including ones added later — gets its own labelled section; other providers
      // (llama-cpp/ollama/…) keep the flat list.
      const recommendedItems = sortedModels(scopedModels.filter(item => isRecommendedItem(item) && runtimeModelIsSelectable(item)));
      const recommendedNames = new Set(recommendedItems.map(item => String(item.name || "").toLowerCase()));
      const sections = [
        {
          key: "recommended",
          title: uiText("runtime.modelGroup.recommended", "Recommended"),
          items: recommendedItems
        },
        {
          key: "installed",
          title: uiText("runtime.modelGroup.installed", "Installed"),
          items: sortedModels(scopedModels.filter(item => !recommendedNames.has(String(item.name || "").toLowerCase()) && runtimeModelIsSelectable(item)))
        },
        {
          key: "installable",
          title: uiText("runtime.modelGroup.installable", "Installable"),
          items: sortedModels(scopedModels.filter(item => !runtimeModelIsSelectable(item)))
        }
      ].filter(section => section.items.length > 0);

      if (!sections.length) {
        host.innerHTML = `<div class="runtime-model-empty">No models loaded for this provider.</div>`;
        return;
      }

      const sectionHtml = (section) => {
        const body = section.items.map(item => optionHtml(item, section.key)).join("");
        const open = runtimeModelGroupIsOpen(section.key);
        const head = `
          <div class="runtime-model-status-head">
            <span class="runtime-model-status-title">${escapeHtml(section.title)}</span>
            <span class="runtime-model-status-count">${section.items.length}</span>
            <span class="runtime-model-status-toggle" aria-hidden="true"><i class="ri-arrow-down-s-line"></i></span>
          </div>`;

        return `
          <details class="runtime-model-status-group" data-runtime-model-group="${escapeHtml(section.key)}"${open ? " open" : ""}>
            <summary>${head}</summary>
            ${body}
          </details>`;
      };

      host.innerHTML = sections.map(sectionHtml).join("");

      hydrateSupplierIcons(host);

      host.querySelectorAll("details[data-runtime-model-group]").forEach(details => {
        details.addEventListener("toggle", () => {
          setRuntimeModelGroupOpen(details.dataset.runtimeModelGroup || "", details.open);
        });
      });

      host.querySelectorAll("[data-runtime-model]").forEach(button => {
        button.addEventListener("click", () => {
          if (button.dataset.runtimeInstallable === "true") {
            return;
          }
          const supplierId = button.dataset.supplierId || "";
          if (supplierId) {
            selectRuntimeApiModel(supplierId, button.dataset.runtimeModel);
          } else {
            selectRuntimeModel(button.dataset.runtimeModel);
          }
        });
      });
    }

    function setRuntimeModelMenuOpen(open) {
      const menu = $("runtimeModelMenu");
      const trigger = $("runtimeModelTrigger");
      if (!menu || !trigger) {
        return;
      }

      menu.classList.toggle("hidden", !open);
      trigger.setAttribute("aria-expanded", open ? "true" : "false");
      if (open) {
        renderRuntimeModelOptions();
        menu.querySelector(".runtime-model-option.active")?.scrollIntoView({ block: "nearest" });
      }
      updateRuntimeModelTrigger();
    }

    function toggleRuntimeModelMenu() {
      const menu = $("runtimeModelMenu");
      if (!menu) {
        return;
      }
      setRuntimeModelMenuOpen(menu.classList.contains("hidden"));
    }

    function selectRuntimeModel(name) {
      const model = $("translationModel");
      if (!model || !name) {
        return;
      }

      model.value = name;
      model.dispatchEvent(new Event("change", { bubbles: true }));
      setRuntimeModelMenuOpen(false);
    }

    // Picking a model that belongs to an API supplier activates that supplier+model as the default
    // route (the backend resolves the right key/baseUrl per supplier), then refreshes the picker so
    // the new active model is reflected. Falls back to selectRuntimeModel for non-supplier models.
    async function selectRuntimeApiModel(supplierId, name) {
      if (!supplierId || !name) {
        return;
      }
      try {
        await post(`/translation/api-suppliers/${encodeURIComponent(supplierId)}/activate?model=${encodeURIComponent(name)}`, {});
        state.activeRoute = { provider: "api-compatible", supplierId, model: name };
        const providerSelect = $("translationProvider");
        if (providerSelect) {
          providerSelect.value = "api-compatible";
        }
        if ($("metricProvider")) {
          $("metricProvider").textContent = "api-compatible";
        }
        const modelInput = $("translationModel");
        if (modelInput) {
          modelInput.value = name;
          modelInput.dispatchEvent(new Event("change", { bubbles: true }));
        }
        await loadTranslationModels();
        syncRuntimeQuickControls();
        renderRuntimeModelOptions();
        updateRuntimeModelTrigger();
        setRuntimeModelMenuOpen(false);
      } catch (error) {
        appendMessage("error", "model", error.message || String(error));
      }
    }

    function updateRuntimeLanguageMetric() {
      if ($("metricLanguage")) {
        $("metricLanguage").textContent = runtimePairLabel();
      }
      updateRuntimeSummary();
    }

    function updateRuntimeSummary() {
      const language = $("metricLanguage")?.textContent.trim();
      const model = $("metricModel").textContent.trim();
      const provider = $("metricProvider").textContent.trim();
      const engine = model && model !== "-" ? model : provider || "-";
      $("runtimeSummary").textContent = [language && language !== "-" ? language : "", engine && engine !== "-" ? engine : ""]
        .filter(Boolean)
        .join(" / ") || "-";
    }

    function applyRuntimeQuickSelect(sourceId, targetId) {
      const source = $(sourceId);
      const target = $(targetId);
      if (!source || !target) {
        return;
      }

      target.value = source.value;
      target.dispatchEvent(new Event("change", { bubbles: true }));
      syncRuntimeQuickControls();
      requestRegionRetranslateForSettingsChange();
    }

    function setSourceLanguageAuto() {
      const source = $("source");
      if (!source || source.value === "auto") {
        return;
      }

      const hasAuto = Array.from(source.options).some(option => option.value === "auto");
      if (!hasAuto) {
        return;
      }

      source.value = "auto";
      source.dispatchEvent(new Event("change", { bubbles: true }));
    }

    function applyRuntimeTargetSelect() {
      setSourceLanguageAuto();
      applyRuntimeQuickSelect("runtimeTarget", "target");
    }

    function applyRuntimeQuickModel() {
      const quick = $("runtimeModel");
      const model = $("translationModel");
      if (!quick || !model) {
        return;
      }

      model.value = quick.value;
      model.dispatchEvent(new Event("input", { bubbles: true }));
    }

    function swapRuntimeLanguages() {
      const source = $("source");
      const target = $("target");
      if (!source || !target || source.value === "auto") {
        syncRuntimeQuickControls();
        return;
      }

      const nextSource = target.value;
      const nextTarget = source.value;
      const targetCanUseSource = Array.from(target.options).some(option => option.value === nextTarget && !option.disabled);
      if (!nextSource || !targetCanUseSource) {
        syncRuntimeQuickControls();
        return;
      }

      source.value = nextSource;
      target.value = nextTarget;
      source.dispatchEvent(new Event("change", { bubbles: true }));
      target.dispatchEvent(new Event("change", { bubbles: true }));
      syncRuntimeQuickControls();
    }

    function setRuntimeCollapsed(collapsed, persist = true) {
      const section = $("runtimeSection");
      section.classList.toggle("collapsed", collapsed);
      $("runtimeToggle").setAttribute("aria-expanded", String(!collapsed));

      if (persist) {
        localStorage.setItem("verbeam.runtimeCollapsed", collapsed ? "1" : "0");
      }
    }

    function initializeRuntimeToggle() {
      setRuntimeCollapsed(localStorage.getItem("verbeam.runtimeCollapsed") === "1", false);
      updateRuntimeSummary();
    }

    function populateModelList(models, fallback) {
      const input = $("translationModel");
      const list = $("translationModelList");
      state.translationModels = models || [];
      list.innerHTML = "";

      for (const item of models || []) {
        const option = document.createElement("option");
        option.value = item.name;
        const source = item.isInstalled ? "installed" : item.source || "configured";
        option.label = item.isRecommended
          ? `${item.displayName || item.name} / ${item.recommendedUse || source}`
          : `${item.displayName || item.name} (${source})`;
        list.appendChild(option);
      }

      const names = Array.from(list.options).map(option => option.value);
      const recommendedModel = chooseRecommendedModel();
      const defaultModel = currentProviderIsLlamaCpp()
        ? recommendedModel?.name || (models || []).find(item => item.isDefault)?.name || fallback || names[0] || ""
        : (models || []).find(item => item.isDefault)?.name || recommendedModel?.name || fallback || names[0] || "";
      if (!input.value || (names.length > 0 && !names.includes(input.value))) {
        input.value = defaultModel;
      }

      $("metricModel").textContent = input.value || "-";
      updateRuntimeSummary();
      syncModelRecommendation();
      syncTranslationProviderCards();
      syncRuntimeQuickControls();
    }

    function getOcrProviderDescription(value, displayName, note) {
      const key = String(value || "").toLowerCase();
      const description = ocrProviderDescriptions[key];
      if (description) {
        return description;
      }

      return {
        name: displayName || value || "OCR provider",
        value: value || "-",
        use: note || "selected OCR provider will process the uploaded image."
      };
    }

    function formatOcrProviderDescription(description) {
      return `${description.name} | Provider value: ${description.value} | ${description.use}`;
    }

    function updateOcrProviderHelp(description) {
      $("ocrProviderHelpName").textContent = description.name;
      $("ocrProviderHelpValue").textContent = `Provider value: ${description.value}`;
      $("ocrProviderHelpUse").textContent = description.use;
      $("ocrProvider").title = formatOcrProviderDescription(description);
    }

    function createOcrSelectHelpPopover() {
      const popover = document.createElement("div");
      popover.id = "ocrSelectHelpPopover";
      popover.className = "ocr-select-help-popover hidden";
      popover.setAttribute("role", "tooltip");

      const title = document.createElement("div");
      title.className = "ocr-select-help-title";
      title.dataset.role = "title";
      popover.appendChild(title);

      const meta = document.createElement("div");
      meta.className = "ocr-select-help-meta";
      meta.dataset.role = "meta";
      popover.appendChild(meta);

      const body = document.createElement("div");
      body.className = "ocr-select-help-body";
      body.dataset.role = "body";
      popover.appendChild(body);

      return popover;
    }

    function getOcrItemDescription(item, fallbackLabel = "") {
      return {
        name: item.dataset.helpName || fallbackLabel || item.textContent || "OCR provider",
        value: item.dataset.helpValue || item.dataset.value || "-",
        use: item.dataset.helpUse || item.dataset.note || "selected OCR provider will process the uploaded image."
      };
    }

    function findOcrSelectOption(value) {
      const dropdown = $("ocrSelectDropdown");
      return Array.from(dropdown.querySelectorAll(".ocr-select-option"))
        .find(item => item.dataset.value === value) || null;
    }

    function hideOcrSelectHelpPopover() {
      const popover = $("ocrSelectHelpPopover");
      if (popover) {
        popover.classList.add("hidden");
      }
    }

    function showOcrSelectHelpPopover(item, description) {
      const dropdown = $("ocrSelectDropdown");
      const popover = $("ocrSelectHelpPopover");
      if (!dropdown || !popover || !item) {
        return;
      }

      const desc = description || getOcrItemDescription(item);
      updateOcrProviderHelp(desc);
      popover.querySelector('[data-role="title"]').textContent = desc.name;
      popover.querySelector('[data-role="meta"]').textContent = `provider: ${desc.value}`;
      popover.querySelector('[data-role="body"]').textContent = desc.use;

      popover.classList.remove("hidden");
      popover.style.visibility = "hidden";
      popover.style.top = "0px";

      const height = popover.offsetHeight || 72;
      const minTop = dropdown.scrollTop + 6;
      const maxTop = dropdown.scrollTop + dropdown.clientHeight - height - 6;
      const below = item.offsetTop + item.offsetHeight + 4;
      const above = item.offsetTop - height - 4;
      const top = below <= maxTop ? below : Math.max(minTop, above);

      popover.style.top = `${Math.max(6, top)}px`;
      popover.style.visibility = "";
    }

    function pulseOcrProviderHelp() {
      const select = $("ocrProvider");
      const wrapper = $("ocrSelectWrapper");
      const selected = select.selectedOptions[0];
      if (!selected) {
        return;
      }

      const desc = {
        name: selected.dataset.helpName || selected.textContent || "OCR provider",
        value: selected.dataset.helpValue || selected.value || "-",
        use: selected.dataset.helpUse || selected.dataset.note || "selected OCR provider will process the uploaded image."
      };

      updateOcrProviderHelp(desc);
      if (wrapper.classList.contains("open")) {
        showOcrSelectHelpPopover(findOcrSelectOption(select.value), desc);
      }
    }

    function populateOcrEngines(engines, fallback) {
      const select = $("ocrProvider");
      const dropdown = $("ocrSelectDropdown");
      select.innerHTML = "";
      dropdown.innerHTML = "";
      dropdown.appendChild(createOcrSelectHelpPopover());
      dropdown.onmouseleave = hideOcrSelectHelpPopover;

      function addEngine(value, label, dataset, isDisabled) {
        const option = document.createElement("option");
        option.value = value;
        option.textContent = label;
        option.disabled = isDisabled;
        for (const [key, val] of Object.entries(dataset)) {
          option.dataset[key] = val;
        }
        option.title = formatOcrProviderDescription({
          name: dataset.helpName || label,
          value: dataset.helpValue || value,
          use: dataset.helpUse || ""
        });
        select.appendChild(option);

        const item = document.createElement("div");
        item.className = "ocr-select-option" + (isDisabled ? " disabled" : "");
        item.dataset.value = value;
        item.setAttribute("role", "option");
        item.setAttribute("aria-disabled", isDisabled ? "true" : "false");

        const nameSpan = document.createElement("span");
        nameSpan.textContent = label;
        nameSpan.style.cssText = "overflow:hidden;text-overflow:ellipsis;flex:1;min-width:0;";
        item.appendChild(nameSpan);

        if (dataset.status && dataset.status !== "available") {
          const statusBadge = document.createElement("span");
          statusBadge.className = "ocr-select-option-status";
          statusBadge.textContent = dataset.status === "requires_api_configuration"
            ? "api config"
            : dataset.status === "planned_structure"
              ? "structure"
              : dataset.status === "missing_dependency"
                ? "missing deps"
                : dataset.status === "planned_local"
                  ? "planned local"
                  : dataset.status;
          item.appendChild(statusBadge);
        }

        for (const [key, val] of Object.entries(dataset)) {
          item.dataset[key] = val;
        }

        item.addEventListener("mouseenter", () => {
          if (isDisabled) return;
          showOcrSelectHelpPopover(item, getOcrItemDescription(item, label));
        });

        item.addEventListener("click", () => {
          if (isDisabled) return;
          select.value = value;
          select.dispatchEvent(new Event("change", { bubbles: true }));
          closeOcrSelect();
        });

        dropdown.appendChild(item);
      }

      addEngine("auto", "Auto route", {
        note: "Chooses the OCR lane from content type and preference.",
        source: "router",
        status: "available",
        available: "true",
        defaultLanguage: "",
        helpName: "Auto route",
        helpValue: "auto",
        helpUse: "Chooses realtime, CJK text, structure, or VLM OCR from the routing controls."
      }, false);

      for (const item of engines || []) {
        const statusLabel = item.status === "requires_api_configuration"
          ? "api config"
          : item.status === "planned_structure"
            ? "structure"
            : item.status === "missing_dependency"
              ? "missing deps"
          : item.status === "planned_local"
            ? "planned local"
            : item.status || "unavailable";
        const label = item.isAvailable ? item.displayName : `${item.displayName} (${statusLabel})`;
        const description = getOcrProviderDescription(item.name, item.displayName, item.note);
        addEngine(item.name, label, {
          note: item.note || "",
          source: item.source || item.kind || "",
          status: item.status || "",
          available: item.isAvailable ? "true" : "false",
          defaultLanguage: item.defaultLanguage || "",
          helpName: description.name,
          helpValue: description.value,
          helpUse: description.use
        }, !item.isAvailable);
      }

      const options = Array.from(select.options);
      const fallbackOption = options.find(option => option.value === fallback && !option.disabled);
      const defaultOption = options.find(option => !option.disabled && (engines || []).find(item => item.name === option.value && item.isDefault));
      const firstAvailable = options.find(option => !option.disabled);
      select.value = (fallbackOption || defaultOption || firstAvailable || options[0])?.value || "";
      syncOcrHint();
    }

    function toggleOcrSelect() {
      const wrapper = $("ocrSelectWrapper");
      const trigger = $("ocrSelectTrigger");
      const isOpen = wrapper.classList.toggle("open");
      trigger.setAttribute("aria-expanded", isOpen ? "true" : "false");
      if (isOpen) {
        syncOcrSelectTrigger();
        pulseOcrProviderHelp();
      } else {
        hideOcrSelectHelpPopover();
        syncOcrHint();
      }
    }

    function closeOcrSelect() {
      const wrapper = $("ocrSelectWrapper");
      const trigger = $("ocrSelectTrigger");
      wrapper.classList.remove("open");
      trigger.setAttribute("aria-expanded", "false");
      hideOcrSelectHelpPopover();
      syncOcrHint();
    }

    function syncOcrSelectTrigger() {
      const select = $("ocrProvider");
      const triggerText = $("ocrSelectTriggerText");
      const dropdown = $("ocrSelectDropdown");
      const selected = select.selectedOptions[0];
      triggerText.textContent = selected ? selected.textContent : "Select OCR engine";
      for (const item of dropdown.querySelectorAll(".ocr-select-option")) {
        item.classList.toggle("selected", item.dataset.value === select.value);
      }
    }

    document.addEventListener("click", (event) => {
      const wrapper = $("ocrSelectWrapper");
      if (wrapper && !wrapper.contains(event.target)) {
        closeOcrSelect();
      }

      const glossaryWrapper = $("glossarySelectWrapper");
      if (glossaryWrapper && !glossaryWrapper.contains(event.target)) {
        closeGlossarySelect();
      }
    });

    document.addEventListener("keydown", (event) => {
      if (event.key === "Escape") {
        closeOcrSelect();
        closeGlossarySelect();
      }
    });

    function populateSpeechEngines(engines, fallback) {
      const select = $("speechProvider");
      select.innerHTML = "";

      for (const item of engines || []) {
        const option = document.createElement("option");
        option.value = item.name;
        option.textContent = item.isAvailable ? item.displayName : `${item.displayName} (unavailable)`;
        option.disabled = !item.isAvailable;
        option.dataset.note = item.note || "";
        option.dataset.source = item.source || item.kind || "";
        option.dataset.available = item.isAvailable ? "true" : "false";
        option.dataset.defaultLanguage = item.defaultLanguage || "";
        select.appendChild(option);
      }

      const options = Array.from(select.options);
      const fallbackOption = options.find(option => option.value === fallback && !option.disabled);
      const defaultOption = options.find(option => !option.disabled && (engines || []).find(item => item.name === option.value && item.isDefault));
      const firstAvailable = options.find(option => !option.disabled);
      select.value = (fallbackOption || defaultOption || firstAvailable || options[0])?.value || "";
      syncSpeechHint();
    }

    async function loadTranslationModels() {
      const provider = $("translationProvider").value;
      try {
        const models = await api(`/translation/models?provider=${encodeURIComponent(provider)}`);
        populateModelList(models || [], $("translationModel").value);
      } catch (error) {
        $("metricModel").textContent = $("translationModel").value || "-";
        appendMessage("error", "models", error.message || String(error));
      }
    }

    async function loadLlamaCppDownloads(silent = false) {
      if (!currentProviderIsLlamaCpp()) {
        state.llamaCppHealth = null;
        renderLlamaCppDownloads();
        return;
      }

      if (!silent) {
        state.llamaCppDownloadBusy = "refresh";
        renderLlamaCppDownloads();
      }

      try {
        const [artifacts, binaries, health] = await Promise.all([
          api("/translation/llama-cpp/artifacts"),
          api("/translation/llama-cpp/binaries"),
          api("/health")
        ]);
        state.llamaCppArtifacts = Array.isArray(artifacts) ? artifacts : [];
        state.llamaCppBinaries = Array.isArray(binaries) ? binaries : [];
        state.llamaCppHealth = health && health.llamaCpp ? health.llamaCpp : null;
      } catch (error) {
        if (!silent) {
          appendMessage("error", "llama.cpp downloads", error.message || String(error));
        }
      } finally {
        if (state.llamaCppDownloadBusy === "refresh") {
          state.llamaCppDownloadBusy = "";
        }
        renderLlamaCppDownloads();
      }
    }

    async function downloadLlamaCppModel() {
      const artifact = selectLlamaCppArtifact();
      if (!artifact || !artifact.modelId) {
        return;
      }

      state.llamaCppDownloadBusy = "model";
      renderLlamaCppDownloads();
      startLlamaCppProgressPolling();

      try {
        const result = await postEmpty(`/translation/llama-cpp/artifacts/${encodeURIComponent(artifact.modelId)}/download`);
        if (result && result.paused) {
          appendMessage("result", "llama.cpp model", result.message || "download paused", artifact.modelId);
        } else {
          appendMessage("result", "llama.cpp model", result.message || `downloaded ${artifact.modelId}`, formatBytes(result.bytesWritten));
          await loadTranslationModels();
        }
        await loadLlamaCppDownloads(true);
      } catch (error) {
        appendMessage("error", "llama.cpp model", error.message || String(error), artifact.modelId);
      } finally {
        state.llamaCppDownloadBusy = "";
        stopLlamaCppProgressPolling();
        renderLlamaCppDownloads();
      }
    }

    async function downloadLlamaCppRuntime() {
      state.llamaCppDownloadBusy = "runtime";
      renderLlamaCppDownloads();
      startLlamaCppProgressPolling();

      try {
        const result = await postEmpty("/translation/llama-cpp/binaries/download");
        if (result && result.paused) {
          appendMessage("result", "llama.cpp runtime", result.message || "download paused");
        } else {
          appendMessage("result", "llama.cpp runtime", result.message || "runtime downloaded", formatBytes(result.bytesWritten));
        }
        await loadLlamaCppDownloads(true);
      } catch (error) {
        appendMessage("error", "llama.cpp runtime", error.message || String(error));
      } finally {
        state.llamaCppDownloadBusy = "";
        stopLlamaCppProgressPolling();
        renderLlamaCppDownloads();
      }
    }

    async function installAndUseLlamaCpp() {
      const recommended = chooseRecommendedModel();
      const artifact = selectLlamaCppArtifact();
      const modelId = recommended?.name || artifact?.modelId;
      if (!modelId) {
        return;
      }

      state.llamaCppDownloadBusy = "install";
      renderLlamaCppDownloads();
      startLlamaCppProgressPolling();

      try {
        const result = await post("/translation/llama-cpp/install-and-use", {
          modelId,
          mode: "managed",
          startServer: true,
          useForCurrentSession: true
        });
        if (result && result.paused) {
          appendMessage("result", "llama.cpp", result.message || "download paused", modelId);
          await loadLlamaCppDownloads(true);
          return;
        }
        const modelName = result.modelAlias || result.modelId || modelId;
        $("translationProvider").value = result.provider || "llama-cpp";
        $("metricProvider").textContent = $("translationProvider").value || "-";
        $("translationModel").value = modelName;
        $("metricModel").textContent = modelName || "-";
        updateRuntimeSummary();
        syncRuntimeQuickControls();
        syncTranslationProviderCards();
        await loadTranslationModels();
        syncRuntimeQuickControls();
        await loadLlamaCppDownloads(true);
        appendMessage("result", "llama.cpp", result.message || `ready ${modelName}`, result.mode || "managed");
      } catch (error) {
        appendMessage("error", "llama.cpp", error.message || String(error), modelId);
      } finally {
        state.llamaCppDownloadBusy = "";
        stopLlamaCppProgressPolling();
        renderLlamaCppDownloads();
      }
    }

    async function stopLlamaCppRuntime() {
      state.llamaCppDownloadBusy = "stop";
      renderLlamaCppDownloads();

      try {
        const status = await postEmpty("/translation/llama-cpp/stop");
        state.llamaCppHealth = {
          ...(state.llamaCppHealth || {}),
          runtime: status
        };
        appendMessage("result", "llama.cpp", "managed runtime stopped", status.mode || "managed");
        await loadLlamaCppDownloads(true);
      } catch (error) {
        appendMessage("error", "llama.cpp", error.message || String(error), "stop");
      } finally {
        state.llamaCppDownloadBusy = "";
        renderLlamaCppDownloads();
      }
    }

    async function applyRecommendedModel() {
      const recommended = chooseRecommendedModel();
      if (!recommended) {
        return;
      }

      const provider = $("translationProvider").value;
      if (provider.toLowerCase() === "llama-cpp") {
        const button = $("applyRecommendedModelButton");
        const previousLabel = button.textContent;
        button.disabled = true;
        button.textContent = "Installing...";
        startLlamaCppProgressPolling();

        try {
          const result = await post("/translation/llama-cpp/install-and-use", {
            modelId: recommended.name,
            mode: "managed",
            startServer: true,
            useForCurrentSession: true
          });
          if (result && result.paused) {
            appendMessage("result", "llama.cpp", result.message || "download paused", recommended.name);
            await loadLlamaCppDownloads(true);
            return;
          }
          const modelName = result.modelAlias || result.modelId || recommended.name;
          $("translationProvider").value = result.provider || "llama-cpp";
          $("metricProvider").textContent = $("translationProvider").value || "-";
          $("translationModel").value = modelName;
          $("metricModel").textContent = modelName || "-";
          updateRuntimeSummary();
          syncRuntimeQuickControls();
          syncTranslationProviderCards();
          await loadTranslationModels();
          syncRuntimeQuickControls();
          await loadLlamaCppDownloads(true);
          appendMessage("result", "llama.cpp", result.message || `ready ${modelName}`, result.mode || "managed");
        } catch (error) {
          appendMessage("error", "llama.cpp", error.message || String(error), recommended.name);
        } finally {
          button.textContent = previousLabel;
          stopLlamaCppProgressPolling();
          syncModelRecommendation();
        }
        return;
      }

      $("translationModel").value = recommended.name;
      $("metricModel").textContent = recommended.name || "-";
      updateRuntimeSummary();
      syncRuntimeQuickControls();
      syncModelRecommendation();
      syncTranslationProviderCards();
      appendMessage("result", "model", `selected ${recommended.name}`, recommended.recommendedUse || "recommended");
    }

    function appendMessage(kind, title, body, meta = "") {
      const wrap = document.createElement("article");
      wrap.className = `message ${kind}`;

      const head = document.createElement("div");
      head.className = "message-head";

      const left = document.createElement("span");
      left.textContent = title;

      const right = document.createElement("span");
      right.textContent = meta || new Date().toLocaleTimeString();

      const content = document.createElement("div");
      content.className = "message-body";
      content.textContent = body || "";

      head.append(left, right);
      wrap.append(head, content);
      terminal.appendChild(wrap);
      // Cap the log so history doesn't pile up unbounded (keep the most recent entries).
      while (terminal.childElementCount > 50) {
        terminal.removeChild(terminal.firstElementChild);
      }
      terminal.scrollTop = terminal.scrollHeight;

      if (kind === "error") {
        // drawer stays collapsed; flag unread errors with a badge instead
        bumpTerminalDrawerBadge();
        playUiSound("error");
      } else if (kind === "result") {
        const quietResult = /^(ocr|region|region translation|ocr job|ocr preview|ocr history|ocr corrections|ocr correction)\b/i.test(String(title || ""));
        if (!quietResult) {
          playUiSound("success");
        }
      }
    }

    function bumpTerminalDrawerBadge() {
      const drawer = $("terminalDrawer");
      const badge = $("terminalDrawerBadge");
      if (!drawer || !badge || drawer.open) {
        return;
      }

      const next = (Number(badge.dataset.count || "0") || 0) + 1;
      badge.dataset.count = String(next);
      badge.textContent = String(next);
      badge.classList.remove("hidden");
    }

    function clearTerminalDrawerBadge() {
      const badge = $("terminalDrawerBadge");
      if (!badge) {
        return;
      }

      badge.dataset.count = "0";
      badge.textContent = "";
      badge.classList.add("hidden");
    }

    function renderSessions() {
      const list = $("sessionList");
      if (list) {
        list.innerHTML = "";
      }
    }

    function currentMemoryKindForCreate() {
      return $("memoryKindFilter").value || "translation";
    }

    function memoryQueryString() {
      const params = new URLSearchParams();
      params.set("profile", $("memoryProfile").value.trim() || "default");
      params.set("limit", "200");
      if ($("memoryKindFilter").value) params.set("type", $("memoryKindFilter").value);
      if ($("memoryTrustFilter").value) params.set("trust", $("memoryTrustFilter").value);
      if ($("memoryVisibilityFilter").value) params.set("visibility", $("memoryVisibilityFilter").value);
      if ($("source").value) params.set("source", $("source").value);
      if ($("target").value) params.set("target", $("target").value);
      if ($("memoryQuery").value.trim()) params.set("q", $("memoryQuery").value.trim());
      if ($("memoryIncludeInactive").checked) params.set("includeInactive", "true");
      return params.toString();
    }

    async function loadMemories(selectId = state.selectedMemoryId) {
      $("memoryList").textContent = "Loading memory...";
      const items = await api(`/memories?${memoryQueryString()}`);
      state.memoryItems = items || [];
      state.memoryConflictIds = new Set();
      // drop batch selections for rows that are no longer present
      const visibleIds = new Set(state.memoryItems.map(item => item.id));
      for (const id of Array.from(state.memoryBatchIds)) {
        if (!visibleIds.has(id)) {
          state.memoryBatchIds.delete(id);
        }
      }
      if (!state.memoryItems.some(item => item.id === selectId)) {
        selectId = state.memoryItems[0]?.id || null;
      }
      renderMemoryList();
      updateMemoryBatchButtons();
      refreshMemoryPendingCount().catch(() => {});
      if (selectId) {
        selectMemory(selectId);
      } else {
        clearMemoryEditor();
      }
    }

    function memoryAclProfile() {
      return $("memoryProfile").value.trim() || "default";
    }

    function memoryAdminHeaders() {
      const token = $("memoryAdminToken").value.trim();
      return token ? { "X-Verbeam-Admin-Token": token } : {};
    }

    function memoryAclRolePreset(role) {
      if (role === "blocked") return { canReadSharedMemory: false, canWriteMemory: false, canApproveMemory: false };
      if (role === "reader") return { canReadSharedMemory: true, canWriteMemory: false, canApproveMemory: false };
      if (role === "contributor") return { canReadSharedMemory: true, canWriteMemory: true, canApproveMemory: false };
      if (role === "reviewer") return { canReadSharedMemory: true, canWriteMemory: false, canApproveMemory: true };
      if (role === "admin") return { canReadSharedMemory: true, canWriteMemory: true, canApproveMemory: true };
      return null;
    }

    function inferMemoryAclRole() {
      const read = $("memoryAclCanReadShared").checked;
      const write = $("memoryAclCanWriteMemory").checked;
      const approve = $("memoryAclCanApproveMemory").checked;
      if (!read && !write && !approve) return "blocked";
      if (read && !write && !approve) return "reader";
      if (read && write && !approve) return "contributor";
      if (read && !write && approve) return "reviewer";
      if (read && write && approve) return "admin";
      return "custom";
    }

    function applyMemoryAclRole() {
      const preset = memoryAclRolePreset($("memoryAclRole").value);
      if (!preset) {
        return;
      }

      $("memoryAclCanReadShared").checked = preset.canReadSharedMemory;
      $("memoryAclCanWriteMemory").checked = preset.canWriteMemory;
      $("memoryAclCanApproveMemory").checked = preset.canApproveMemory;
    }

    function updateMemoryAclRoleFromPermissions() {
      $("memoryAclRole").value = inferMemoryAclRole();
    }

    function memoryRuntimeHeaders() {
      const sessionToken = $("memoryRuntimeSessionToken").value.trim();
      if (sessionToken) {
        return { "X-Verbeam-Session": sessionToken };
      }

      const principal = $("memoryRuntimePrincipal").value.trim();
      return principal ? { "X-Verbeam-Principal": principal } : {};
    }

    function updateMemoryRuntimeStatus() {
      const sessionToken = $("memoryRuntimeSessionToken").value.trim();
      const principal = $("memoryRuntimePrincipal").value.trim();
      $("memoryRuntimeStatusLabel").textContent = sessionToken ? "session" : principal ? principal : "local";
      syncDocumentRuntimeBadges();
    }

    function useCreatedMemorySessionForRuntime() {
      const sessionToken = $("memorySessionToken").value.trim();
      if (sessionToken) {
        $("memoryRuntimeSessionToken").value = sessionToken;
      }

      const principal = $("memorySessionPrincipal").value.trim();
      if (principal) {
        $("memoryRuntimePrincipal").value = principal;
      }

      updateMemoryRuntimeStatus();
    }

    function clearMemoryRuntimeIdentity() {
      $("memoryRuntimeSessionToken").value = "";
      $("memoryRuntimePrincipal").value = "";
      updateMemoryRuntimeStatus();
    }

    async function postDocumentForm(path, formData) {
      const response = await fetch(path, {
        method: "POST",
        headers: memoryRuntimeHeaders(),
        body: formData
      });
      const text = await response.text();
      let data = null;
      if (text) {
        try {
          data = JSON.parse(text);
        } catch {
          data = { errorMessage: text };
        }
      }
      if (!response.ok) {
        throw new Error(data?.errorMessage || data?.error || data?.detail || text || response.statusText);
      }
      return data;
    }

    function isDocumentTerminal(status) {
      return ["succeeded", "failed", "canceled"].includes(String(status || "").toLowerCase());
    }

    function documentMemoryLabel() {
      const sessionToken = $("memoryRuntimeSessionToken").value.trim();
      const principal = $("memoryRuntimePrincipal").value.trim();
      return sessionToken ? "session" : principal || "local";
    }

    function syncDocumentRuntimeBadges() {
      if (!$("documentRuntimeProvider")) {
        return;
      }
      $("documentRuntimeProvider").textContent = $("translationProvider")?.value || "-";
      $("documentRuntimeModel").textContent = $("translationModel")?.value.trim() || "-";
      $("documentRuntimeMemory").textContent = documentMemoryLabel();
      if ($("documentRuntimeSummary")) {
        const provider = $("translationProvider")?.value || "-";
        const model = $("translationModel")?.value.trim() || "-";
        $("documentRuntimeSummary").textContent = `${provider} / ${model}`;
      }
      if (!$("documentOcrLanguage").value.trim() && $("ocrLanguage")) {
        $("documentOcrLanguage").value = $("ocrLanguage").value || "";
      }
    }

    function setDocumentFile(file) {
      state.documentSelectedFile = file || null;
      $("documentFileMeta").textContent = file ? `${file.name} / ${formatBytes(file.size)}` : "no file";
      if (file) {
        $("footerLeft").textContent = file.name;
        appendMessage("user", "document", `${file.name} (${formatBytes(file.size)})`, "loaded");
      }
      updateDocumentControls();
    }

    function updateDocumentControls() {
      const active = !!state.activeDocumentJobId && !state.documentCancelRequested;
      $("startDocumentJobButton").disabled = state.busy || active || !state.documentSelectedFile;
      $("cancelDocumentJobButton").disabled = !state.activeDocumentJobId || state.documentCancelRequested;
    }

    function formatDocumentUnits(job) {
      const completed = Number(job?.completedUnits || 0);
      const total = job?.totalUnits;
      return total ? `${completed}/${total}` : `${completed}`;
    }

    function formatShortDate(value) {
      if (!value) {
        return "-";
      }
      const date = new Date(value);
      if (Number.isNaN(date.getTime())) {
        return "-";
      }
      return date.toLocaleTimeString("en-GB", { hour12: false });
    }

    function formatDocumentEta(job) {
      if (!job || job.status !== "running") {
        return "-";
      }
      const progress = Number(job.progress || 0);
      const started = job.startedAt ? new Date(job.startedAt).getTime() : NaN;
      if (!Number.isFinite(started) || progress <= 0.05) {
        return "-";
      }
      const elapsed = (Date.now() - started) / 1000;
      const eta = formatEta(elapsed * (1 - progress) / progress);
      return eta === "-" ? "-" : `ETA ${eta}`;
    }

    function updateDocumentJobDisplay(job) {
      const progress = Math.max(0, Math.min(1, Number(job?.progress || 0)));
      $("documentJobId").textContent = job?.id ? job.id.slice(0, 10) : "-";
      $("documentJobStatus").textContent = job?.status || "idle";
      $("documentJobStage").textContent = job?.stage || "idle";
      $("documentJobPercent").textContent = `${Math.round(progress * 100)}%`;
      $("documentJobUnits").textContent = `${formatDocumentUnits(job)} units`;
      $("documentJobEta").textContent = formatDocumentEta(job);
      $("documentJobUpdated").textContent = formatShortDate(job?.updatedAt);
      $("documentWarningCount").textContent = `${Number(job?.warningCount ?? job?.warnings?.length ?? 0)} warnings`;
      $("documentJobProgressFill").style.width = `${Math.round(progress * 100)}%`;
      $("documentJobProgressFill").classList.toggle("failed", job?.status === "failed" || job?.status === "canceled");
      renderDocumentArtifacts(job);
      updateDocumentControls();
      if ((job?.id || "") !== state.documentPreviewJobId) {
        refreshDocumentRenderPreview(job?.id || "").catch(() => {});
      }
    }

    function renderDocumentArtifacts(job) {
      documentArtifacts.innerHTML = "";
      const artifacts = job?.artifacts || [];
      if (!artifacts.length) {
        const empty = document.createElement("div");
        empty.className = "field-hint";
        empty.textContent = job?.errorMessage ? `no artifacts - ${job.errorMessage}` : "no artifacts";
        documentArtifacts.appendChild(empty);
        return;
      }

      // PDF jobs (those with a persisted source-pdf backdrop) get the layout-preserving
      // overlay editor: render the original pages, fix/move/retranslate/lock blocks, and
      // export a translated PDF. Opens the standalone /pdf-editor scoped to this job.
      const sourcePdf = artifacts.find(a => a.kind === "source-pdf");
      if (sourcePdf && job?.id && job?.status === "succeeded") {
        const editRow = document.createElement("div");
        editRow.className = "document-artifact";
        const editMeta = document.createElement("div");
        const editName = document.createElement("strong");
        editName.textContent = "PDF overlay editor";
        const editDetail = document.createElement("span");
        editDetail.textContent = "Review translated pages, adjust blocks, and export a translated PDF.";
        editMeta.append(editName, editDetail);
        const editButton = document.createElement("button");
        editButton.type = "button";
        editButton.innerHTML = '<i class="ri-edit-2-line"></i><span>Edit PDF</span>';
        editButton.addEventListener("click", () => {
          window.open(`/pdf-editor?job=${encodeURIComponent(job.id)}`, "_blank", "noopener,noreferrer");
        });
        editRow.append(editMeta, editButton);
        documentArtifacts.appendChild(editRow);
      }
      for (const artifact of artifacts) {
        const row = document.createElement("div");
        row.className = "document-artifact";
        const meta = document.createElement("div");
        const name = document.createElement("strong");
        name.textContent = artifact.fileName || artifact.kind || "artifact";
        const detail = document.createElement("span");
        detail.textContent = `${artifact.kind || "file"} / ${formatBytes(artifact.sizeBytes || 0)}`;
        meta.append(name, detail);
        const button = document.createElement("button");
        button.type = "button";
        button.innerHTML = '<i class="ri-download-2-line"></i><span>Open</span>';
        button.addEventListener("click", () => {
          window.open(`/ocr/document-jobs/${encodeURIComponent(job.id)}/artifacts/${encodeURIComponent(artifact.id)}`, "_blank", "noopener,noreferrer");
        });
        row.append(meta, button);
        documentArtifacts.appendChild(row);
      }
    }

    function addDocumentEvent(type, payload) {
      const line = document.createElement("div");
      line.className = "document-event";
      const time = document.createElement("span");
      time.textContent = formatShortDate(new Date().toISOString());
      const body = document.createElement("span");
      const stage = payload?.stage || payload?.job?.stage || "";
      const status = payload?.job?.status || "";
      body.textContent = [type, status, stage].filter(Boolean).join(" / ") || type;
      line.append(time, body);
      documentEvents.appendChild(line);
      documentEvents.scrollTop = documentEvents.scrollHeight;
    }

    function closeDocumentEvents() {
      if (state.documentEventSource) {
        state.documentEventSource.close();
        state.documentEventSource = null;
      }
    }

    async function refreshDocumentRenderPreview(jobId) {
      const preview = $("documentRenderPreview");
      if (!preview) {
        return;
      }
      state.documentPreviewJobId = jobId || "";
      const token = ++state.documentPreviewToken;
      if (!jobId) {
        preview.classList.remove("layout-mode", "text-mode");
        preview.textContent = "no document selected";
        return;
      }

      let data = null;
      try {
        data = await api(`/ocr/document-jobs/${encodeURIComponent(jobId)}/preview`);
      } catch (error) {
        if (token === state.documentPreviewToken) {
          preview.classList.remove("layout-mode", "text-mode");
          preview.textContent = `preview unavailable: ${error.message || error}`;
        }
        return;
      }
      if (token !== state.documentPreviewToken || state.documentPreviewJobId !== jobId) {
        return;
      }

      preview.classList.toggle("layout-mode", data?.kind === "layout");
      preview.classList.toggle("text-mode", data?.kind === "text");
      if (data?.kind === "layout" && data.layoutHtml) {
        preview.innerHTML = data.layoutHtml;
        scheduleOcrOverlayFit(preview);
        return;
      }
      if (data?.kind === "html") {
        preview.innerHTML = "";
        const frame = document.createElement("iframe");
        frame.className = "document-preview-frame";
        frame.setAttribute("sandbox", "");
        frame.srcdoc = data.content || "";
        preview.appendChild(frame);
        return;
      }
      if (data?.kind === "text") {
        preview.textContent = (data.content || "") + (data.truncated ? "\n\n[truncated]" : "");
        return;
      }
      if (data?.kind === "file") {
        preview.textContent = "Translated file is ready. Download it from the artifacts below.";
        return;
      }
      if (data?.kind === "error") {
        preview.classList.remove("layout-mode", "text-mode");
        preview.textContent = `${data.status || "failed"}: ${data.errorMessage || data.errorCode || "document job failed"}`;
        return;
      }
      preview.textContent = "Waiting for the first translated page...";
    }

    function scheduleDocumentPreviewRefresh() {
      if (state.documentPreviewTimer) {
        clearTimeout(state.documentPreviewTimer);
      }
      state.documentPreviewTimer = setTimeout(() => {
        state.documentPreviewTimer = null;
        refreshDocumentRenderPreview(state.documentPreviewJobId || state.selectedDocumentJobId).catch(() => {});
      }, 800);
    }

    function applyDocumentStageEvent(payload) {
      if (!payload || (payload.jobId && state.selectedDocumentJobId && payload.jobId !== state.selectedDocumentJobId)) {
        return;
      }
      const progress = Math.max(0, Math.min(1, Number(payload.progress || 0)));
      if (payload.stage) {
        $("documentJobStage").textContent = payload.stage;
      }
      $("documentJobPercent").textContent = `${Math.round(progress * 100)}%`;
      $("documentJobUnits").textContent = `${formatDocumentUnits(payload)} units`;
      $("documentJobUpdated").textContent = formatShortDate(new Date().toISOString());
      $("documentJobProgressFill").style.width = `${Math.round(progress * 100)}%`;
    }

    function handleDocumentEvent(type, payload) {
      addDocumentEvent(type, payload);
      if (type === "stage") {
        applyDocumentStageEvent(payload);
        return;
      }
      if (type === "token_usage") {
        const usage = readTokenUsage(payload);
        if (usage) {
          if (payload && payload.cumulative === false) {
            addTokenUsage(usage, "document", "document");
          } else {
            applyTokenUsage(usage, "document");
          }
        }
        return;
      }
      if (type === "page_translated" || type === "segment_translated") {
        scheduleDocumentPreviewRefresh();
        return;
      }
      if (type === "job_done") {
        refreshDocumentRenderPreview(state.documentPreviewJobId || state.selectedDocumentJobId).catch(() => {});
      }
    }

    function connectDocumentEvents(jobId) {
      closeDocumentEvents();
      if (!jobId || typeof EventSource === "undefined") {
        return;
      }
      const source = new EventSource(`/ocr/document-jobs/${encodeURIComponent(jobId)}/events`);
      state.documentEventSource = source;
      const types = ["job_queued", "job_started", "job_resumed", "stage", "token_usage", "page_translated", "segment_translated", "cancel_requested", "job_canceled", "job_done", "error"];
      for (const type of types) {
        source.addEventListener(type, event => {
          let payload = {};
          try {
            payload = JSON.parse(event.data || "{}");
          } catch {
            payload = {};
          }
          handleDocumentEvent(type, payload);
        });
      }
      source.onerror = () => {
        if (!state.activeDocumentJobId || isDocumentTerminal($("documentJobStatus").textContent)) {
          closeDocumentEvents();
        }
      };
    }

    async function loadDocumentJob(jobId, render = true) {
      const job = await api(`/ocr/document-jobs/${encodeURIComponent(jobId)}`);
      const index = state.documentJobs.findIndex(item => item.id === job.id);
      if (index >= 0) {
        state.documentJobs[index] = job;
      } else {
        state.documentJobs.unshift(job);
      }
      if (render) {
        updateDocumentJobDisplay(job);
        renderDocumentJobs();
      }
      return job;
    }

    async function loadDocumentJobs() {
      const jobs = await api("/ocr/document-jobs?profile=default&limit=30");
      state.documentJobs = jobs || [];
      $("documentJobCount").textContent = `${state.documentJobs.length} jobs`;
      renderDocumentJobs();
      const selected = state.selectedDocumentJobId
        ? state.documentJobs.find(job => job.id === state.selectedDocumentJobId)
        : state.documentJobs[0];
      if (selected) {
        state.selectedDocumentJobId = selected.id;
        updateDocumentJobDisplay(selected);
      } else {
        updateDocumentJobDisplay(null);
      }
    }

    function renderDocumentJobs() {
      documentJobsTable.innerHTML = "";
      $("documentJobCount").textContent = `${state.documentJobs.length} jobs`;
      if (!state.documentJobs.length) {
        const row = document.createElement("tr");
        const cell = document.createElement("td");
        cell.colSpan = 5;
        cell.textContent = "no jobs";
        row.appendChild(cell);
        documentJobsTable.appendChild(row);
        return;
      }

      for (const job of state.documentJobs) {
        const row = document.createElement("tr");
        row.className = "document-job-row";
        row.classList.toggle("active", job.id === state.selectedDocumentJobId);
        row.innerHTML = `
          <td>${escapeHtml(job.fileName || job.id || "-")}</td>
          <td>${escapeHtml(job.status || "-")}</td>
          <td>${escapeHtml(job.stage || "-")}</td>
          <td>${escapeHtml(formatDocumentUnits(job))}</td>
          <td>${escapeHtml(formatShortDate(job.updatedAt))}</td>
        `;
        row.addEventListener("click", () => {
          state.selectedDocumentJobId = job.id;
          updateDocumentJobDisplay(job);
          renderDocumentJobs();
        });
        documentJobsTable.appendChild(row);
      }
    }

    function buildDocumentFormData(file) {
      const form = new FormData();
      form.append("file", file, file.name);
      form.append("contentType", file.type || "application/octet-stream");
      const sourceKind = $("documentSourceKind").value;
      if (sourceKind && sourceKind !== "auto") {
        form.append("sourceKind", sourceKind);
      }
      form.append("sourceLanguage", $("source").value || "auto");
      form.append("target", $("target").value || "zh-TW");
      form.append("mode", $("preset").value || "");
      form.append("translationProvider", $("translationProvider").value || "");
      form.append("model", $("translationModel").value.trim());
      form.append("profile", "default");
      const glossary = $("glossary").value;
      if (glossary) {
        form.append("glossary", glossary);
      }
      form.append("ocrProvider", $("ocrProvider").value || "");
      form.append("ocrLanguage", $("documentOcrLanguage").value.trim() || $("ocrLanguage").value || "");
      form.append("ocrPreference", $("documentOcrPreference").value || $("ocrPreference").value || "");
      form.append("ocrPreprocessingPreset", $("ocrPreprocessingPreset").value || "none");
      const pageRange = $("documentPageRange").value.trim();
      if (pageRange) {
        form.append("pageRange", pageRange);
      }
      form.append("allowSharedMemory", $("documentAllowSharedMemory").checked ? "true" : "false");
      return form;
    }

    async function runDocumentJob() {
      const file = state.documentSelectedFile || documentFile.files[0];
      if (!file) {
        appendMessage("error", "document", "file is empty");
        return null;
      }

      syncDocumentRuntimeBadges();
      applyTokenUsage(null, "document");
      documentEvents.innerHTML = "";
      const started = performance.now();
      const queued = await postDocumentForm("/ocr/document-jobs", buildDocumentFormData(file));
      state.activeDocumentJobId = queued.id || "";
      state.selectedDocumentJobId = queued.id || state.selectedDocumentJobId;
      state.documentCancelRequested = false;
      updateDocumentJobDisplay(queued);
      renderDocumentJobs();
      connectDocumentEvents(queued.id);
      appendMessage("result", "document job", queued.id ? `queued ${queued.id.slice(0, 10)}` : "queued", file.name);
      const completed = await waitForDocumentJob(queued.id);
      const elapsed = Math.round(performance.now() - started);
      if (completed?.status === "succeeded") {
        appendMessage("result", "document job", "succeeded", `${elapsed} ms`);
        playUiSound("success");
      } else if (completed?.status === "canceled") {
        appendMessage("result", "document job", "canceled", completed.id ? completed.id.slice(0, 10) : "job");
      } else if (completed) {
        appendMessage("error", "document job", completed.errorMessage || completed.status || "failed", completed.id ? completed.id.slice(0, 10) : "job");
      }
      return completed;
    }

    async function waitForDocumentJob(jobId) {
      if (!jobId) {
        return null;
      }
      let job = null;
      try {
        while (state.activeDocumentJobId === jobId) {
          job = await loadDocumentJob(jobId);
          if (isDocumentTerminal(job.status)) {
            return job;
          }
          await new Promise(resolve => setTimeout(resolve, 1000));
        }
        return job;
      } finally {
        if (state.activeDocumentJobId === jobId) {
          state.activeDocumentJobId = "";
          state.documentCancelRequested = false;
          closeDocumentEvents();
          updateDocumentControls();
          loadDocumentJobs().catch(error => appendMessage("error", "document jobs", error.message || String(error)));
        }
      }
    }

    async function cancelActiveDocumentJob() {
      const jobId = state.activeDocumentJobId;
      if (!jobId || state.documentCancelRequested) {
        return;
      }
      state.documentCancelRequested = true;
      updateDocumentControls();
      $("documentJobStatus").textContent = "canceling";
      await postEmpty(`/ocr/document-jobs/${encodeURIComponent(jobId)}/cancel`, {
        headers: memoryRuntimeHeaders()
      });
      appendMessage("result", "document job", "cancel requested", jobId.slice(0, 10));
    }

    function setMemoryOidcStatus(text, tone = "") {
      const label = $("memoryOidcStatusLabel");
      label.textContent = text;
      label.classList.toggle("good", tone === "good");
      label.classList.toggle("warn", tone === "warn");
      label.classList.toggle("bad", tone === "bad");
    }

    function updateMemoryOidcStatusFromHealth(health) {
      const oidc = health && health.memory && health.memory.oidc;
      state.memoryOidcEnabled = Boolean(oidc && oidc.enabled && oidc.clientConfigured && oidc.redirectUriConfigured);
      const storage = oidc && oidc.refreshTokenStorage ? oidc.refreshTokenStorage : "configured";
      setMemoryOidcStatus(state.memoryOidcEnabled ? storage : "not configured", state.memoryOidcEnabled ? "good" : "warn");
      $("memoryOidcLoginButton").disabled = !state.memoryOidcEnabled;
      $("memoryOidcCompleteButton").disabled = !state.memoryOidcEnabled;
      $("memoryOidcRefreshButton").disabled = !state.memoryOidcEnabled;
    }

    function memoryOidcQuery() {
      const query = new URLSearchParams(window.location.search);
      return {
        code: query.get("code") || query.get("memoryOidcCode") || "",
        state: query.get("state") || query.get("memoryOidcState") || "",
        error: query.get("error") || query.get("memoryOidcError") || ""
      };
    }

    function clearMemoryOidcQuery() {
      const query = new URLSearchParams(window.location.search);
      let changed = false;
      for (const key of ["code", "state", "error", "error_description", "memoryOidcCode", "memoryOidcState", "memoryOidcError"]) {
        if (query.has(key)) {
          query.delete(key);
          changed = true;
        }
      }

      if (changed) {
        const next = `${window.location.pathname}${query.toString() ? "?" + query.toString() : ""}${window.location.hash}`;
        window.history.replaceState({}, document.title, next);
      }
    }

    function applyMemoryOidcSession(result, source) {
      const principal = result.principal || result.session?.principalId || "";
      $("memorySessionToken").value = result.sessionToken || "";
      $("memoryRuntimeSessionToken").value = result.sessionToken || "";
      if (principal) {
        $("memorySessionPrincipal").value = principal;
        $("memoryCredentialPrincipal").value = principal;
        $("memoryAuditPrincipal").value = principal;
        $("memoryRuntimePrincipal").value = principal;
        $("memoryLifecyclePrincipal").value = principal;
      }

      if (result.refreshToken) {
        $("memoryOidcRefreshToken").value = result.refreshToken;
      }

      if (result.refreshTokenHandle) {
        $("memoryOidcRefreshHandle").value = result.refreshTokenHandle;
        $("memoryOidcRefreshToken").value = "";
      }

      updateMemoryRuntimeStatus();
      setMemoryOidcStatus("session ready", "good");
      appendMessage("result", "memory oidc", `${source} session created`, principal || result.session?.id || "session");
      loadMemoryPrincipalSessions(result.session?.id || null).catch(error => appendMessage("error", "memory sessions", error.message || String(error)));
      loadMemoryOidcRefreshHandles(result.refreshTokenHandle || null).catch(error => appendMessage("error", "memory oidc handles", error.message || String(error)));
    }

    async function startMemoryOidcLogin() {
      setMemoryOidcStatus("starting", "warn");
      const login = await api("/memory/oidc/login");
      $("memoryOidcState").value = login.state || "";
      setMemoryOidcStatus("redirecting", "warn");
      window.location.href = login.authorizationUrl;
    }

    async function completeMemoryOidcCallback(codeOverride = "", stateOverride = "") {
      const query = memoryOidcQuery();
      if (query.error) {
        clearMemoryOidcQuery();
        throw new Error(query.error);
      }

      const code = codeOverride || $("memoryOidcCode").value.trim() || query.code;
      const stateValue = stateOverride || $("memoryOidcState").value.trim() || query.state;
      if (!code || !stateValue) {
        throw new Error("OIDC code and state are required.");
      }

      setMemoryOidcStatus("exchanging", "warn");
      const params = new URLSearchParams({ code, state: stateValue });
      const result = await api(`/memory/oidc/callback?${params.toString()}`);
      $("memoryOidcCode").value = "";
      $("memoryOidcState").value = "";
      clearMemoryOidcQuery();
      applyMemoryOidcSession(result, "login");
    }

    async function refreshMemoryOidcSession() {
      const refreshToken = $("memoryOidcRefreshToken").value.trim();
      const refreshTokenHandle = $("memoryOidcRefreshHandle").value.trim();
      if (!refreshToken && !refreshTokenHandle) {
        throw new Error("refresh token or handle is required.");
      }

      setMemoryOidcStatus("refreshing", "warn");
      const result = await post("/memory/oidc/refresh", { refreshToken, refreshTokenHandle });
      applyMemoryOidcSession(result, "refresh");
    }

    function memoryOidcRefreshHandleQueryString() {
      const params = new URLSearchParams();
      const principal = $("memoryLifecyclePrincipal").value.trim()
        || $("memorySessionPrincipal").value.trim()
        || $("memoryCredentialPrincipal").value.trim()
        || $("memoryRuntimePrincipal").value.trim()
        || $("memoryAuditPrincipal").value.trim();
      if (principal) {
        params.set("principal", principal);
      }

      if ($("memoryOidcRefreshHandleIncludeRevoked").checked) {
        params.set("includeRevoked", "true");
      }

      params.set("limit", "100");
      return params.toString();
    }

    async function loadMemoryOidcRefreshHandles(selectId = state.selectedMemoryOidcRefreshHandleId) {
      const list = $("memoryOidcRefreshHandleList");
      list.textContent = "Loading refresh handles...";
      const handles = await api(`/memory/oidc/refresh-tokens?${memoryOidcRefreshHandleQueryString()}`, {
        headers: memoryAdminHeaders()
      });
      state.memoryOidcRefreshHandles = handles || [];
      if (!state.memoryOidcRefreshHandles.some(handle => handle.id === selectId)) {
        selectId = state.memoryOidcRefreshHandles[0]?.id || null;
      }

      renderMemoryOidcRefreshHandles();
      selectMemoryOidcRefreshHandle(selectId);
    }

    function renderMemoryOidcRefreshHandles() {
      const list = $("memoryOidcRefreshHandleList");
      list.innerHTML = "";
      $("memoryOidcRefreshHandleCountLabel").textContent = `${state.memoryOidcRefreshHandles.length} handles`;
      if (state.memoryOidcRefreshHandles.length === 0) {
        const empty = document.createElement("div");
        empty.className = "notice";
        empty.textContent = "No OIDC refresh handles match the current filter.";
        list.appendChild(empty);
        return;
      }

      for (const handle of state.memoryOidcRefreshHandles) {
        const button = document.createElement("button");
        button.type = "button";
        button.className = "memory-item";
        button.classList.toggle("active", handle.id === state.selectedMemoryOidcRefreshHandleId);
        button.addEventListener("click", () => selectMemoryOidcRefreshHandle(handle.id));

        const revoked = !!handle.revokedAt;
        const expired = handle.expiresAt && new Date(handle.expiresAt).getTime() <= Date.now();
        const head = document.createElement("div");
        head.className = "memory-item-head";
        const title = document.createElement("div");
        title.className = "memory-item-title";
        title.textContent = handle.principalId || "(principal)";
        head.append(
          title,
          memoryChip(shortText(handle.id, 12)),
          memoryChip(revoked ? "revoked" : expired ? "expired" : "active", revoked || expired ? "warn" : "good")
        );

        const meta = document.createElement("div");
        meta.className = "memory-item-meta";
        meta.append(
          memoryChip(`created ${formatOcrDate(handle.createdAt)}`),
          memoryChip(`updated ${formatOcrDate(handle.updatedAt)}`),
          memoryChip(`used ${formatOcrDate(handle.lastUsedAt)}`)
        );
        if (revoked) {
          meta.append(memoryChip(`revoked ${formatOcrDate(handle.revokedAt)}`, "warn"));
        }

        button.append(head, meta);
        list.appendChild(button);
      }
    }

    function selectMemoryOidcRefreshHandle(id) {
      state.selectedMemoryOidcRefreshHandleId = id || null;
      const handle = state.memoryOidcRefreshHandles.find(value => value.id === id);
      $("memoryOidcRefreshHandleRevokeButton").disabled = !handle || !!handle.revokedAt;
      if (handle) {
        $("memoryOidcRefreshHandle").value = handle.id || $("memoryOidcRefreshHandle").value;
        $("memoryLifecyclePrincipal").value = handle.principalId || $("memoryLifecyclePrincipal").value;
        $("memoryAuditPrincipal").value = handle.principalId || $("memoryAuditPrincipal").value;
      }

      renderMemoryOidcRefreshHandles();
    }

    async function revokeSelectedMemoryOidcRefreshHandle() {
      if (!state.selectedMemoryOidcRefreshHandleId) {
        return;
      }

      const id = state.selectedMemoryOidcRefreshHandleId;
      const result = await api(`/memory/oidc/refresh-tokens/${encodeURIComponent(id)}`, {
        method: "DELETE",
        headers: memoryAdminHeaders()
      });
      if ($("memoryOidcRefreshHandle").value.trim() === id) {
        $("memoryOidcRefreshHandle").value = "";
      }

      appendMessage("result", "memory oidc", result.revoked ? "refresh handle revoked" : "refresh handle not active", id.slice(0, 12));
      await loadMemoryOidcRefreshHandles(id);
    }

    async function completeMemoryOidcCallbackFromUrl() {
      const query = memoryOidcQuery();
      if (!query.code && !query.error) {
        return;
      }

      try {
        await completeMemoryOidcCallback(query.code, query.state);
      } catch (error) {
        clearMemoryOidcQuery();
        setMemoryOidcStatus("failed", "bad");
        appendMessage("error", "memory oidc", error.message || String(error));
      }
    }

    function setMemoryLifecycleStatus(text, tone = "") {
      const label = $("memoryLifecycleStatusLabel");
      label.textContent = text;
      label.classList.toggle("good", tone === "good");
      label.classList.toggle("warn", tone === "warn");
      label.classList.toggle("bad", tone === "bad");
    }

    async function deprovisionMemoryPrincipal() {
      const principal = $("memoryLifecyclePrincipal").value.trim()
        || $("memoryAclPrincipal").value.trim()
        || $("memorySessionPrincipal").value.trim()
        || $("memoryCredentialPrincipal").value.trim()
        || $("memoryRuntimePrincipal").value.trim();
      if (!principal) {
        throw new Error("principal is required.");
      }

      setMemoryLifecycleStatus("deprovisioning", "warn");
      const result = await post("/memory/principals/deprovision", {
        principal,
        revokeSessions: true,
        revokeCredentials: true,
        deletePermissions: $("memoryLifecycleDeletePermissions").checked
      }, {
        headers: memoryAdminHeaders()
      });

      if ($("memorySessionPrincipal").value.trim() === result.principalId) {
        $("memorySessionToken").value = "";
      }

      if ($("memoryRuntimePrincipal").value.trim() === result.principalId ||
          $("memorySessionPrincipal").value.trim() === result.principalId) {
        $("memoryRuntimeSessionToken").value = "";
        updateMemoryRuntimeStatus();
      }

      setMemoryLifecycleStatus("deprovisioned", "good");
      appendMessage(
        "result",
        "memory lifecycle",
        `revoked ${result.revokedSessions || 0} sessions, ${result.revokedCredentials || 0} credentials, ${result.revokedOidcRefreshTokens || 0} oidc refresh handles`,
        result.deletedPermissions ? `${result.deletedPermissions} ACL rows deleted` : result.principalId);
      await Promise.all([
        loadMemoryPrincipalPermissions().catch(error => appendMessage("error", "memory acl", error.message || String(error))),
        loadMemoryPrincipalCredentials().catch(error => appendMessage("error", "memory credentials", error.message || String(error))),
        loadMemoryPrincipalSessions().catch(error => appendMessage("error", "memory sessions", error.message || String(error))),
        loadMemoryOidcRefreshHandles().catch(error => appendMessage("error", "memory oidc handles", error.message || String(error))),
        loadMemoryContextAudit().catch(error => appendMessage("error", "memory audit", error.message || String(error)))
      ]);
    }

    async function loadMemoryPrincipalPermissions() {
      const list = $("memoryPrincipalPermissionList");
      list.textContent = "Loading principals...";
      const params = new URLSearchParams();
      params.set("profile", memoryAclProfile());
      const permissions = await api(`/memory/principal-permissions?${params.toString()}`, {
        headers: memoryAdminHeaders()
      });
      state.memoryPrincipalPermissions = permissions || [];
      renderMemoryPrincipalPermissions();
    }

    function renderMemoryPrincipalPermissions() {
      const list = $("memoryPrincipalPermissionList");
      list.innerHTML = "";
      $("memoryAclCountLabel").textContent = `${state.memoryPrincipalPermissions.length} principals`;
      if (state.memoryPrincipalPermissions.length === 0) {
        const empty = document.createElement("div");
        empty.className = "notice";
        empty.textContent = "No shared-memory principals for this profile.";
        list.appendChild(empty);
        return;
      }

      for (const permission of state.memoryPrincipalPermissions) {
        const button = document.createElement("button");
        button.type = "button";
        button.className = "memory-item";
        button.addEventListener("click", () => {
          $("memoryAclPrincipal").value = permission.principalId;
          $("memorySessionPrincipal").value = permission.principalId;
          $("memoryCredentialPrincipal").value = permission.principalId;
          $("memoryAuditPrincipal").value = permission.principalId;
          $("memoryRuntimePrincipal").value = permission.principalId;
          $("memoryLifecyclePrincipal").value = permission.principalId;
          $("memoryAclCanReadShared").checked = Boolean(permission.canReadSharedMemory);
          $("memoryAclCanWriteMemory").checked = Boolean(permission.canWriteMemory);
          $("memoryAclCanApproveMemory").checked = Boolean(permission.canApproveMemory);
          $("memoryAclRole").value = permission.role || inferMemoryAclRole();
          if (!$("memoryAclRole").value) {
            updateMemoryAclRoleFromPermissions();
          }
          updateMemoryRuntimeStatus();
          loadMemoryPrincipalCredentials().catch(error => appendMessage("error", "memory credentials", error.message || String(error)));
          loadMemoryPrincipalSessions().catch(error => appendMessage("error", "memory sessions", error.message || String(error)));
          loadMemoryContextAudit().catch(error => appendMessage("error", "memory audit", error.message || String(error)));
        });

        const head = document.createElement("div");
        head.className = "memory-item-head";
        const title = document.createElement("div");
        title.className = "memory-item-title";
        title.textContent = permission.principalId;
        head.append(
          title,
          memoryChip(permission.profileId),
          memoryChip(permission.role || "custom"),
          memoryChip(permission.canReadSharedMemory ? "can view shared" : "blocked", permission.canReadSharedMemory ? "good" : "warn"));

        const meta = document.createElement("div");
        meta.className = "memory-item-meta";
        meta.append(
          memoryChip(permission.canWriteMemory ? "can edit" : "read only", permission.canWriteMemory ? "good" : "warn"),
          memoryChip(permission.canApproveMemory ? "can approve" : "no approve", permission.canApproveMemory ? "good" : "warn"),
          memoryChip(formatOcrDate(permission.updatedAt))
        );

        button.append(head, meta);
        list.appendChild(button);
      }
    }

    async function saveMemoryPrincipalPermission() {
      const principal = $("memoryAclPrincipal").value.trim();
      if (!principal) {
        throw new Error("principal is required.");
      }

      const saved = await post(
        "/memory/principal-permissions",
        {
          principal,
          profile: memoryAclProfile(),
          role: $("memoryAclRole").value,
          canReadSharedMemory: $("memoryAclCanReadShared").checked,
          canWriteMemory: $("memoryAclCanWriteMemory").checked,
          canApproveMemory: $("memoryAclCanApproveMemory").checked
        },
        { headers: memoryAdminHeaders() });
      $("memoryAclPrincipal").value = saved.principalId;
      $("memoryAclRole").value = saved.role || "custom";
      $("memoryAclCanReadShared").checked = Boolean(saved.canReadSharedMemory);
      $("memoryAclCanWriteMemory").checked = Boolean(saved.canWriteMemory);
      $("memoryAclCanApproveMemory").checked = Boolean(saved.canApproveMemory);
      $("memorySessionPrincipal").value = saved.principalId;
      $("memoryCredentialPrincipal").value = saved.principalId;
      $("memoryAuditPrincipal").value = saved.principalId;
      $("memoryRuntimePrincipal").value = saved.principalId;
      $("memoryLifecyclePrincipal").value = saved.principalId;
      updateMemoryRuntimeStatus();
      appendMessage("result", "memory acl", "principal saved", saved.principalId);
      await loadMemoryPrincipalPermissions();
      await loadMemoryPrincipalCredentials();
    }

    async function deleteMemoryPrincipalPermission() {
      const principal = $("memoryAclPrincipal").value.trim();
      if (!principal) {
        return;
      }

      const params = new URLSearchParams();
      params.set("profile", memoryAclProfile());
      params.set("principal", principal);
      const result = await api(`/memory/principal-permissions?${params.toString()}`, {
        method: "DELETE",
        headers: memoryAdminHeaders()
      });
      appendMessage("result", "memory acl", result.deleted ? "principal removed" : "principal not found", principal);
      if (result.deleted) {
        $("memoryAclPrincipal").value = "";
      }
      await loadMemoryPrincipalPermissions();
    }

    function memorySessionQueryString() {
      const params = new URLSearchParams();
      const principal = $("memorySessionPrincipal").value.trim();
      if (principal) {
        params.set("principal", principal);
      }

      if ($("memorySessionIncludeRevoked").checked) {
        params.set("includeRevoked", "true");
      }

      params.set("limit", "100");
      return params.toString();
    }

    async function loadMemoryPrincipalSessions(selectId = state.selectedMemoryPrincipalSessionId) {
      const list = $("memoryPrincipalSessionList");
      list.textContent = "Loading sessions...";
      const sessions = await api(`/memory/principal-sessions?${memorySessionQueryString()}`, {
        headers: memoryAdminHeaders()
      });
      state.memoryPrincipalSessions = sessions || [];
      if (!state.memoryPrincipalSessions.some(session => session.id === selectId)) {
        selectId = state.memoryPrincipalSessions[0]?.id || null;
      }

      renderMemoryPrincipalSessions();
      selectMemoryPrincipalSession(selectId);
    }

    function renderMemoryPrincipalSessions() {
      const list = $("memoryPrincipalSessionList");
      list.innerHTML = "";
      $("memorySessionCountLabel").textContent = `${state.memoryPrincipalSessions.length} sessions`;
      if (state.memoryPrincipalSessions.length === 0) {
        const empty = document.createElement("div");
        empty.className = "notice";
        empty.textContent = "No principal sessions match the current filter.";
        list.appendChild(empty);
        return;
      }

      for (const session of state.memoryPrincipalSessions) {
        const button = document.createElement("button");
        button.type = "button";
        button.className = "memory-item";
        button.classList.toggle("active", session.id === state.selectedMemoryPrincipalSessionId);
        button.addEventListener("click", () => selectMemoryPrincipalSession(session.id));

        const revoked = !!session.revokedAt;
        const expired = session.expiresAt && new Date(session.expiresAt).getTime() <= Date.now();
        const head = document.createElement("div");
        head.className = "memory-item-head";
        const title = document.createElement("div");
        title.className = "memory-item-title";
        title.textContent = session.principalId || "(principal)";
        head.append(
          title,
          memoryChip(shortText(session.id, 12)),
          memoryChip(revoked ? "revoked" : expired ? "expired" : "active", revoked || expired ? "warn" : "good")
        );

        const meta = document.createElement("div");
        meta.className = "memory-item-meta";
        meta.append(
          memoryChip(`created ${formatOcrDate(session.createdAt)}`),
          memoryChip(`expires ${formatOcrDate(session.expiresAt)}`),
          memoryChip(`seen ${formatOcrDate(session.lastSeenAt)}`)
        );
        if (revoked) {
          meta.append(memoryChip(`revoked ${formatOcrDate(session.revokedAt)}`, "warn"));
        }

        button.append(head, meta);
        list.appendChild(button);
      }
    }

    function selectMemoryPrincipalSession(id) {
      state.selectedMemoryPrincipalSessionId = id || null;
      const session = state.memoryPrincipalSessions.find(value => value.id === id);
      $("memorySessionRevokeButton").disabled = !session || !!session.revokedAt;
      if (session) {
        $("memorySessionPrincipal").value = session.principalId || $("memorySessionPrincipal").value;
        $("memoryCredentialPrincipal").value = session.principalId || $("memoryCredentialPrincipal").value;
        $("memoryLifecyclePrincipal").value = session.principalId || $("memoryLifecyclePrincipal").value;
      }

      renderMemoryPrincipalSessions();
    }

    async function createMemoryPrincipalSession() {
      const principal = $("memorySessionPrincipal").value.trim();
      if (!principal) {
        throw new Error("principal is required.");
      }

      const expiresValue = $("memorySessionExpiresAt").value;
      const payload = { principal };
      if (expiresValue) {
        payload.expiresAt = new Date(expiresValue).toISOString();
      }

      const result = await post("/memory/principal-sessions", payload, {
        headers: memoryAdminHeaders()
      });
      $("memorySessionToken").value = result.sessionToken || "";
      $("memoryAuditPrincipal").value = result.session?.principalId || principal;
      $("memoryLifecyclePrincipal").value = result.session?.principalId || principal;
      $("memoryCredentialPrincipal").value = result.session?.principalId || principal;
      useCreatedMemorySessionForRuntime();
      appendMessage("result", "memory sessions", "session created", result.session?.id ? result.session.id.slice(0, 12) : principal);
      await loadMemoryPrincipalSessions(result.session?.id || null);
    }

    async function revokeSelectedMemoryPrincipalSession() {
      if (!state.selectedMemoryPrincipalSessionId) {
        return;
      }

      const id = state.selectedMemoryPrincipalSessionId;
      const runtimeToken = $("memoryRuntimeSessionToken").value.trim();
      const createdToken = $("memorySessionToken").value.trim();
      const result = await api(`/memory/principal-sessions/${encodeURIComponent(id)}`, {
        method: "DELETE",
        headers: memoryAdminHeaders()
      });
      $("memorySessionToken").value = "";
      if (runtimeToken && runtimeToken === createdToken) {
        $("memoryRuntimeSessionToken").value = "";
        updateMemoryRuntimeStatus();
      }

      appendMessage("result", "memory sessions", result.revoked ? "session revoked" : "session not active", id.slice(0, 12));
      await loadMemoryPrincipalSessions(id);
    }

    function memoryCredentialQueryString() {
      const params = new URLSearchParams();
      const principal = $("memoryCredentialPrincipal").value.trim();
      if (principal) {
        params.set("principal", principal);
      }

      if ($("memoryCredentialIncludeRevoked").checked) {
        params.set("includeRevoked", "true");
      }

      params.set("limit", "100");
      return params.toString();
    }

    async function loadMemoryPrincipalCredentials(selectId = state.selectedMemoryPrincipalCredentialId) {
      const list = $("memoryPrincipalCredentialList");
      list.textContent = "Loading credentials...";
      const credentials = await api(`/memory/principal-credentials?${memoryCredentialQueryString()}`, {
        headers: memoryAdminHeaders()
      });
      state.memoryPrincipalCredentials = credentials || [];
      if (!state.memoryPrincipalCredentials.some(credential => credential.id === selectId)) {
        selectId = state.memoryPrincipalCredentials[0]?.id || null;
      }

      renderMemoryPrincipalCredentials();
      selectMemoryPrincipalCredential(selectId);
    }

