      const list = $("memoryPrincipalCredentialList");
      list.innerHTML = "";
      $("memoryCredentialCountLabel").textContent = `${state.memoryPrincipalCredentials.length} credentials`;
      if (state.memoryPrincipalCredentials.length === 0) {
        const empty = document.createElement("div");
        empty.className = "notice";
        empty.textContent = "No principal credentials match the current filter.";
