        button.className = "memory-item";
        button.classList.toggle("active", credential.id === state.selectedMemoryPrincipalCredentialId);
        button.addEventListener("click", () => selectMemoryPrincipalCredential(credential.id));

        const revoked = !!credential.revokedAt;
        const expired = credential.expiresAt && new Date(credential.expiresAt).getTime() <= Date.now();
        const head = document.createElement("div");
        head.className = "memory-item-head";
        const title = document.createElement("div");
        title.className = "memory-item-title";
        title.textContent = credential.principalId || "(principal)";
        head.append(
          title,
          memoryChip(credential.label || "credential"),
          memoryChip(revoked ? "revoked" : expired ? "expired" : "active", revoked || expired ? "warn" : "good")
        );

        const meta = document.createElement("div");
        meta.className = "memory-item-meta";
        meta.append(
          memoryChip(shortText(credential.id, 12)),
          memoryChip(`created ${formatOcrDate(credential.createdAt)}`),
          memoryChip(`expires ${formatOcrDate(credential.expiresAt)}`),
          memoryChip(`used ${formatOcrDate(credential.lastUsedAt)}`)
        );
        if (revoked) {
          meta.append(memoryChip(`revoked ${formatOcrDate(credential.revokedAt)}`, "warn"));
        }

        button.append(head, meta);
        list.appendChild(button);
      }
    }

    function selectMemoryPrincipalCredential(id) {
      state.selectedMemoryPrincipalCredentialId = id || null;
      const credential = state.memoryPrincipalCredentials.find(value => value.id === id);
      $("memoryCredentialRevokeButton").disabled = !credential || !!credential.revokedAt;
      if (credential) {
        $("memoryCredentialPrincipal").value = credential.principalId || $("memoryCredentialPrincipal").value;
        $("memoryCredentialLabel").value = credential.label || "";
        $("memorySessionPrincipal").value = credential.principalId || $("memorySessionPrincipal").value;
        $("memoryAuditPrincipal").value = credential.principalId || $("memoryAuditPrincipal").value;
        $("memoryRuntimePrincipal").value = credential.principalId || $("memoryRuntimePrincipal").value;
        $("memoryLifecyclePrincipal").value = credential.principalId || $("memoryLifecyclePrincipal").value;
        updateMemoryRuntimeStatus();
      }

      renderMemoryPrincipalCredentials();
    }

    async function createMemoryPrincipalCredential() {
      const principal = $("memoryCredentialPrincipal").value.trim();
      if (!principal) {
        throw new Error("principal is required.");
      }

      const payload = { principal };
      const label = $("memoryCredentialLabel").value.trim();
      const secret = $("memoryCredentialSecret").value.trim();
      const expiresValue = $("memoryCredentialExpiresAt").value;
      if (label) {
        payload.label = label;
      }

      if (secret) {
        payload.secret = secret;
      }

      if (expiresValue) {
        payload.expiresAt = new Date(expiresValue).toISOString();
      }

      const result = await post("/memory/principal-credentials", payload, {
        headers: memoryAdminHeaders()
      });
      $("memoryCredentialSecret").value = result.secret || "";
      $("memoryCredentialPrincipal").value = result.credential?.principalId || principal;
      $("memorySessionPrincipal").value = result.credential?.principalId || principal;
      $("memoryAuditPrincipal").value = result.credential?.principalId || principal;
      $("memoryRuntimePrincipal").value = result.credential?.principalId || principal;
      $("memoryLifecyclePrincipal").value = result.credential?.principalId || principal;
      updateMemoryRuntimeStatus();
      appendMessage("result", "memory credentials", "credential created", result.credential?.id ? result.credential.id.slice(0, 12) : principal);
      await loadMemoryPrincipalCredentials(result.credential?.id || null);
    }

    async function loginMemoryPrincipalCredential() {
      const principal = $("memoryCredentialPrincipal").value.trim();
      const secret = $("memoryCredentialSecret").value.trim();
      if (!principal) {
        throw new Error("principal is required.");
      }

      if (!secret) {
        throw new Error("secret is required.");
      }

      const result = await post("/memory/principal-login", { principal, secret });
      $("memorySessionToken").value = result.sessionToken || "";
      $("memorySessionPrincipal").value = result.session?.principalId || principal;
      $("memoryAuditPrincipal").value = result.session?.principalId || principal;
      $("memoryLifecyclePrincipal").value = result.session?.principalId || principal;
      useCreatedMemorySessionForRuntime();
      appendMessage("result", "memory credentials", "login session created", result.session?.id ? result.session.id.slice(0, 12) : principal);
      await loadMemoryPrincipalCredentials();
      await loadMemoryPrincipalSessions(result.session?.id || null);
    }

    async function revokeSelectedMemoryPrincipalCredential() {
      if (!state.selectedMemoryPrincipalCredentialId) {
        return;
      }

      const id = state.selectedMemoryPrincipalCredentialId;
      const result = await api(`/memory/principal-credentials/${encodeURIComponent(id)}`, {
        method: "DELETE",
        headers: memoryAdminHeaders()
      });
      appendMessage("result", "memory credentials", result.revoked ? "credential revoked" : "credential not active", id.slice(0, 12));
      await loadMemoryPrincipalCredentials(id);
    }

    function memoryAuditQueryString() {
      const params = new URLSearchParams();
      params.set("profile", memoryAclProfile());
      const principal = $("memoryAuditPrincipal").value.trim();
      if (principal) {
        params.set("principal", principal);
      }

      const limit = Math.max(1, Math.min(500, Number.parseInt($("memoryAuditLimit").value || "100", 10) || 100));
      $("memoryAuditLimit").value = String(limit);
      params.set("limit", String(limit));
      return params.toString();
    }

    async function loadMemoryContextAudit() {
      const list = $("memoryContextAuditList");
      list.textContent = "Loading audit...";
      const entries = await api(`/memory/context-audit?${memoryAuditQueryString()}`, {
        headers: memoryAdminHeaders()
      });
      state.memoryAuditEntries = entries || [];
      renderMemoryContextAudit();
    }

    function renderMemoryContextAudit() {
      const list = $("memoryContextAuditList");
      list.innerHTML = "";
      $("memoryAuditCountLabel").textContent = `${state.memoryAuditEntries.length} audit rows`;
      if (state.memoryAuditEntries.length === 0) {
        const empty = document.createElement("div");
        empty.className = "notice";
        empty.textContent = "No memory context audit rows match the current filters.";
        list.appendChild(empty);
        return;
      }

      for (const entry of state.memoryAuditEntries) {
        const button = document.createElement("button");
        button.type = "button";
        button.className = "memory-item";
        button.classList.toggle("active", entry.memoryId === state.selectedMemoryId);
        button.addEventListener("click", () => {
          const existing = state.memoryItems.find(item => item.id === entry.memoryId);
          if (existing) {
            selectMemory(entry.memoryId);
          } else {
            appendMessage("result", "memory audit", "memory row is outside current filters", shortText(entry.memoryId, 16));
          }
        });

        const head = document.createElement("div");
        head.className = "memory-item-head";
        const title = document.createElement("div");
        title.className = "memory-item-title";
        title.textContent = shortText(entry.memoryId, 18);
        head.append(
          title,
          memoryChip(entry.memoryKind),
          memoryChip(entry.decision, entry.decision === "used" ? "good" : "warn"),
          memoryChip(entry.reason)
        );

        const body = document.createElement("div");
        body.className = "memory-item-body";
        body.textContent = `request ${shortText(entry.requestId, 18)} | context ${shortText(entry.contextHash, 18)} | snippet ${shortText(entry.snippetHash, 18)}`;

        const meta = document.createElement("div");
        meta.className = "memory-item-meta";
        meta.append(
          memoryChip(entry.principalId || "local"),
          memoryChip(entry.sessionId || "no session"),
          memoryChip(entry.trustLevel),
          memoryChip(`${entry.selectedMemoryCount || 0} mem`),
          memoryChip(`${entry.selectedRecentEventCount || 0} recent`),
          memoryChip(formatOcrDate(entry.createdAt))
        );
        if (entry.translationKey) {
          meta.append(memoryChip(`cache ${shortText(entry.translationKey, 12)}`));
        }

        button.append(head, body, meta);
        list.appendChild(button);
      }
    }

    async function loadMemoryConflicts(selectId = state.selectedMemoryId) {
      $("memoryList").textContent = "Loading memory conflicts...";
      const groups = await api(`/memories/conflicts?${memoryQueryString()}`);
      const itemsById = new Map();
      for (const group of groups || []) {
        for (const item of group.items || []) {
          itemsById.set(item.id, item);
        }
      }

      state.memoryItems = Array.from(itemsById.values());
      state.memoryConflictIds = new Set(state.memoryItems.map(item => item.id));
      appendMessage("result", "memory", `${(groups || []).length} conflict groups`, `${state.memoryItems.length} rows`);
      if (!state.memoryItems.some(item => item.id === selectId)) {
        selectId = state.memoryItems[0]?.id || null;
      }
      renderMemoryList();
      if (selectId) {
        selectMemory(selectId);
      } else {
        clearMemoryEditor();
      }
    }

    function renderMemoryList() {
      const list = $("memoryList");
      list.innerHTML = "";
      $("memoryCountLabel").textContent = `${state.memoryItems.length} items`;
      if (state.memoryItems.length === 0) {
        const empty = document.createElement("div");
        empty.className = "notice";
        empty.textContent = "No memory rows match the current filters.";
        list.appendChild(empty);
        return;
      }

      for (const item of state.memoryItems) {
        const button = document.createElement("button");
        button.type = "button";
        button.className = "memory-item";
        button.classList.toggle("active", item.id === state.selectedMemoryId);
        button.addEventListener("click", () => selectMemory(item.id));

        const head = document.createElement("div");
        head.className = "memory-item-head";
        if (memoryIsCandidate(item)) {
          const check = document.createElement("input");
          check.type = "checkbox";
          check.className = "memory-item-check";
          check.title = "Select for batch actions";
          check.checked = state.memoryBatchIds.has(item.id);
          check.addEventListener("click", event => event.stopPropagation());
          check.addEventListener("change", () => {
            if (check.checked) {
              state.memoryBatchIds.add(item.id);
            } else {
              state.memoryBatchIds.delete(item.id);
            }
            updateMemoryBatchButtons();
          });
          head.append(check);
        }
        const title = document.createElement("div");
        title.className = "memory-item-title";
        title.textContent = item.sourceText || "(empty source)";
        head.append(title, memoryChip(item.memoryKind), memoryChip(item.isActive ? "active" : "inactive", item.isActive ? "good" : "warn"));
        if (state.memoryConflictIds.has(item.id)) {
          head.append(memoryChip("conflict", "warn"));
        }

        const body = document.createElement("div");
        body.className = "memory-item-body";
        body.textContent = item.targetText || item.note || "-";

        const meta = document.createElement("div");
        meta.className = "memory-item-meta";
        meta.append(
          memoryChip(friendlyTrustLevel(item.trustLevel)),
          memoryChip(`${item.sourceLanguage}->${item.targetLanguage}`),
          memoryChip(`p${item.priority}`),
          memoryChip(Number(item.confidence || 0).toFixed(2))
        );
        const reason = memoryReasonText(item);
        if (reason) {
          meta.append(memoryChip(reason));
        }

        button.append(head, body, meta);
        list.appendChild(button);
      }
    }

    function memoryChip(text, kind = "") {
      const chip = document.createElement("span");
      chip.className = kind ? `memory-chip ${kind}` : "memory-chip";
      chip.textContent = text || "-";
      return chip;
    }

    function friendlyTrustLevel(value) {
      const map = {
        user_verified: "I verified",
        trusted_import: "Imported",
        local_generated: "Auto-generated",
        untrusted_import: "Unverified",
        quarantined: "Quarantined"
      };
      return map[value] || value || "-";
    }

    // Human-readable explanation of where a memory item came from, derived from
    // metadata_json (origin / created_from / observation_count). Returns "" when
    // there is nothing useful to show.
    function memoryReasonText(item) {
      const metadata = item && item.metadata && typeof item.metadata === "object" ? item.metadata : {};
      const createdFrom = metadata.created_from || "";
      if (createdFrom === "translation-correction") {
        return "correction";
      }
      return "";
    }
    function memoryIsCandidate(item) {
      return Boolean(item) && item.trustLevel === "local_generated";
    }

    function updateMemoryBatchButtons() {
      const count = state.memoryBatchIds.size;
      const approve = $("memoryBatchApproveButton");
      const reject = $("memoryBatchRejectButton");
      if (approve) {
        approve.disabled = count === 0;
        approve.textContent = count > 0 ? `Approve (${count})` : "Approve";
      }
      if (reject) {
        reject.disabled = count === 0;
        reject.textContent = count > 0 ? `Reject (${count})` : "Reject";
      }
    }

    // Refresh the "Pending Review" button badge with the count of active
    // auto-generated candidates for the current profile (one lightweight GET).
    async function refreshMemoryPendingCount() {
      const btn = $("memoryCandidatesButton");
      if (!btn) {
        return;
      }

      try {
        const profile = $("memoryProfile").value.trim() || "default";
        const items = await api(`/memories?profile=${encodeURIComponent(profile)}&trust=local_generated&limit=200`);
        const count = (items || []).filter(item => item.isActive).length;
        state.memoryPendingCount = count;
        btn.textContent = count > 0 ? `Pending Review (${count})` : "Pending Review";
      } catch {
        // leave the existing label untouched on failure
      }
    }

    function currentOcrProfile() {
      return $("ocrProfile").value.trim() || "default";
    }

    function formatOcrDate(value) {
      if (!value) {
        return "-";
      }

      const date = new Date(value);
      return Number.isNaN(date.getTime()) ? "-" : date.toLocaleString();
    }

    function shortText(value, limit = 140) {
      const text = String(value || "").replace(/\s+/g, " ").trim();
      return text.length > limit ? `${text.slice(0, limit - 1)}...` : text;
    }

    function formatOcrStructureSummary(summary) {
      if (!summary) {
        return "0 structure";
      }

      const blocks = Number(summary.blockCount || 0);
      const tables = Number(summary.tableBlockCount || 0);
      const formulas = Number(summary.formulaBlockCount || 0);
      const cells = Number(summary.tableCellCount || 0);
      const invalid = Number(summary.invalidTableCellCount || 0);
      const missing = Number(summary.missingTableCellCount || 0);
      const overlap = Number(summary.overlappingTableCellCount || 0);
      return `${blocks} blocks / ${tables} tables / ${formulas} formulas / ${cells} cells / ${invalid} invalid / ${missing} missing / ${overlap} overlap`;
    }

    function readOptionalCount(id) {
      const value = $(id).value.trim();
      if (!value) {
        return null;
      }

      const parsed = Number.parseInt(value, 10);
      return Number.isFinite(parsed) && parsed >= 0 ? parsed : null;
    }

    function buildExpectedOcrStructure() {
      const tableBlockCount = readOptionalCount("ocrSmokeExpectedTables");
      const formulaBlockCount = readOptionalCount("ocrSmokeExpectedFormulas");
      const tableCellCount = readOptionalCount("ocrSmokeExpectedCells");
      const tableRowCount = readOptionalCount("ocrSmokeExpectedRows");
      const tableColumnCount = readOptionalCount("ocrSmokeExpectedColumns");
      const invalidTableCellCount = readOptionalCount("ocrSmokeExpectedInvalidCells");
      const missingTableCellCount = readOptionalCount("ocrSmokeExpectedMissingCells");
      const overlappingTableCellCount = readOptionalCount("ocrSmokeExpectedOverlappingCells");
      const formulaLatexContains = $("ocrSmokeExpectedFormulaLatex").value.trim();
      const expected = {};
      if (tableBlockCount !== null) expected.tableBlockCount = tableBlockCount;
      if (formulaBlockCount !== null) expected.formulaBlockCount = formulaBlockCount;
      if (tableCellCount !== null) expected.tableCellCount = tableCellCount;
      if (tableRowCount !== null) expected.tableRowCount = tableRowCount;
      if (tableColumnCount !== null) expected.tableColumnCount = tableColumnCount;
      if (invalidTableCellCount !== null) expected.invalidTableCellCount = invalidTableCellCount;
      if (missingTableCellCount !== null) expected.missingTableCellCount = missingTableCellCount;
      if (overlappingTableCellCount !== null) expected.overlappingTableCellCount = overlappingTableCellCount;
      if (formulaLatexContains) expected.formulaLatexContains = formulaLatexContains;
      return Object.keys(expected).length > 0 ? expected : null;
    }

    function formatOcrStructureAssertion(assertion) {
      if (!assertion || !assertion.hasExpected) {
        return "-";
      }

      const issueCount = (assertion.issues || []).length;
      return assertion.passed ? "pass" : `${issueCount || (assertion.mismatches || []).length || 1} issue`;
    }

    function ocrStructureIssueChips(assertion) {
      const issues = assertion && assertion.issues ? assertion.issues : [];
      if (issues.length > 0) {
        return issues
          .slice(0, 2)
          .map((issue) => memoryChip(issue.code || issue.message || "structure issue", issue.severity === "error" ? "warn" : ""));
      }

      return ((assertion && assertion.mismatches) || [])
        .slice(0, 1)
        .map((message) => memoryChip(message, "warn"));
    }

    function ocrQualityIssueChips(item) {
      return ((item && item.issues) || [])
        .slice(0, 3)
        .map((issue) => {
          const count = Number(issue.count || 0);
          const label = `${issue.code || "ocr_issue"}${count > 1 ? ` x${count}` : ""}`;
          return memoryChip(label, issue.severity === "error" ? "warn" : "");
        });
    }

    function emptyOcrHistoryNode(message) {
      const empty = document.createElement("div");
      empty.className = "notice";
      empty.textContent = message;
      return empty;
    }

    function applyOcrEvent(event, sourceLabel = "ocr history") {
      if (!event) {
        return null;
      }

      return applyOcrResult(
        {
          text: event.correctedText || event.rawText || "",
          rawText: event.rawText || "",
          blocks: event.blocks || [],
          document: event.document || null,
          provider: event.provider || "-",
          engine: event.engine || "-",
          language: event.language || $("ocrLanguage").value,
          cacheHit: false
        },
        Number(event.latencyMs || 0),
        sourceLabel);
    }

    function renderOcrEventList() {
      const list = $("ocrEventList");
      list.innerHTML = "";
      $("ocrEventCount").textContent = `${state.ocrEvents.length} rows`;

      if (state.ocrEvents.length === 0) {
        list.appendChild(emptyOcrHistoryNode("No OCR events yet."));
        return;
      }

      for (const item of state.ocrEvents) {
        const button = document.createElement("button");
        button.type = "button";
        button.className = "memory-item";
        button.addEventListener("click", () => applyOcrEvent(item));

        const head = document.createElement("div");
        head.className = "memory-item-head";
        const title = document.createElement("div");
        title.className = "memory-item-title";
        title.textContent = shortText(item.correctedText || item.rawText || "(empty OCR)");
        head.append(title, memoryChip(item.provider), memoryChip(item.engine));

        const body = document.createElement("div");
        body.className = "memory-item-body";
        body.textContent = shortText(item.rawText || item.correctedText || "-", 180);

        const meta = document.createElement("div");
        meta.className = "memory-item-meta";
        meta.append(
          memoryChip(item.language),
          memoryChip(`${item.blocks ? item.blocks.length : 0} blocks`),
          memoryChip(`${Number(item.latencyMs || 0)} ms`),
          memoryChip(formatOcrDate(item.createdAt))
        );

        button.append(head, body, meta);
        list.appendChild(button);
      }
    }

    function renderOcrJobList() {
      const list = $("ocrJobList");
      list.innerHTML = "";
      $("ocrJobCount").textContent = `${state.ocrJobs.length} rows`;

      if (state.ocrJobs.length === 0) {
        list.appendChild(emptyOcrHistoryNode("No OCR jobs yet."));
        return;
      }

      for (const item of state.ocrJobs) {
        const button = document.createElement("button");
        button.type = "button";
        button.className = "memory-item";
        button.disabled = !item.resultEventId;
        button.addEventListener("click", () => loadOcrJobResult(item.id)
          .catch(error => appendMessage("error", "ocr job", error.message || String(error), "history")));

        const head = document.createElement("div");
        head.className = "memory-item-head";
        const title = document.createElement("div");
        title.className = "memory-item-title";
        title.textContent = `${item.status || "job"} ${item.id ? item.id.slice(0, 8) : ""}`.trim();
        const statusKind = item.status === "succeeded" ? "good" : item.status === "failed" || item.status === "canceled" ? "warn" : "";
        head.append(title, memoryChip(item.status, statusKind), memoryChip(item.provider), memoryChip(item.engine));

        const body = document.createElement("div");
        body.className = "memory-item-body";
        body.textContent = item.errorMessage || item.resultEventId || item.imageHash || "-";

        const meta = document.createElement("div");
        meta.className = "memory-item-meta";
        meta.append(
          memoryChip(item.language),
          memoryChip(`${item.blockCount || 0} blocks`),
          memoryChip(`${Math.round(Number(item.progress || 0) * 100)}%`),
          memoryChip(item.cacheHit ? "cache" : "fresh"),
          memoryChip(formatOcrDate(item.createdAt))
        );

        button.append(head, body, meta);
        list.appendChild(button);
      }
    }

    function renderOcrHistory() {
      $("ocrHistoryProfile").textContent = currentOcrProfile();
      renderOcrEventList();
      renderOcrJobList();
    }

    async function loadOcrHistory(showMessage = false) {
      $("ocrHistoryProfile").textContent = currentOcrProfile();
      $("ocrEventList").textContent = "Loading OCR events...";
      $("ocrJobList").textContent = "Loading OCR jobs...";

      const params = new URLSearchParams();
      params.set("profile", currentOcrProfile());
      params.set("limit", "8");
      const query = params.toString();
      const [events, jobs] = await Promise.all([
        api(`/ocr/events?${query}`),
        api(`/ocr/jobs?${query}`)
      ]);

      state.ocrEvents = events || [];
      state.ocrJobs = jobs || [];
      renderOcrHistory();

      if (showMessage) {
        appendMessage("result", "ocr history", `${state.ocrEvents.length} events / ${state.ocrJobs.length} jobs`, currentOcrProfile());
      }
    }

    async function loadOcrJobResult(jobId) {
      if (!jobId) {
        return null;
      }

      const jobResult = await api(`/ocr/jobs/${encodeURIComponent(jobId)}/result`);
      if (!jobResult.result) {
        throw new Error("OCR job has no stored result yet.");
      }

      return applyOcrEvent(jobResult.result, "ocr job history");
    }

    function selectedOcrCorrection() {
      return (state.ocrCorrections || []).find(item => item.id === state.selectedOcrCorrectionId) || null;
    }

    function updateOcrCorrectionEditorControls() {
      const selected = selectedOcrCorrection();
      $("ocrCorrectionToggleActiveButton").disabled = !selected;
      $("ocrCorrectionToggleActiveButton").textContent = selected && !selected.isActive ? "Reactivate" : "Deactivate";
    }

    function renderOcrCorrectionList() {
      const list = $("ocrCorrectionList");
      list.innerHTML = "";
      $("ocrCorrectionCount").textContent = `${state.ocrCorrections.length} rows`;
      updateOcrCorrectionEditorControls();

      if (state.ocrCorrections.length === 0) {
        state.selectedOcrCorrectionId = "";
        updateOcrCorrectionEditorControls();
        list.appendChild(emptyOcrHistoryNode("No OCR corrections for this profile/language."));
        return;
      }

      for (const item of state.ocrCorrections) {
        const button = document.createElement("button");
        button.type = "button";
        button.className = "memory-item";
        button.classList.toggle("active", item.id === state.selectedOcrCorrectionId);
        button.addEventListener("click", () => fillOcrCorrectionEditor(item));

        const head = document.createElement("div");
        head.className = "memory-item-head";
        const title = document.createElement("div");
        title.className = "memory-item-title";
        title.textContent = `${item.wrongText || "(empty)"} -> ${item.correctedText || "(empty)"}`;
        head.append(title, memoryChip(item.isActive ? "active" : "inactive", item.isActive ? "good" : "warn"), memoryChip(item.source));

        const body = document.createElement("div");
        body.className = "memory-item-body";
        body.textContent = item.note || "-";

        const meta = document.createElement("div");
        meta.className = "memory-item-meta";
        meta.append(
          memoryChip(item.language),
          memoryChip(`p${item.priority ?? 0}`),
          memoryChip(Number(item.confidence ?? 0).toFixed(2)),
          memoryChip(`${item.useCount || 0} uses`),
          memoryChip(formatOcrDate(item.updatedAt))
        );

        button.append(head, body, meta);
        list.appendChild(button);
      }
    }

    function fillOcrCorrectionEditor(item) {
      state.selectedOcrCorrectionId = item.id || "";
      $("ocrCorrectionWrong").value = item.wrongText || "";
      $("ocrCorrectionCorrected").value = item.correctedText || "";
      $("ocrCorrectionNote").value = item.note || "";
      $("ocrCorrectionPriority").value = String(item.priority ?? 0);
      $("ocrCorrectionConfidence").value = String(item.confidence ?? 1);
      $("ocrCorrectionEditorStatus").textContent = item.id ? item.id.slice(0, 12) : "selected";
      updateOcrCorrectionEditorControls();
      renderOcrCorrectionList();
    }

    function useLatestOcrForCorrection() {
      state.selectedOcrCorrectionId = "";
      const raw = state.latestOcrRawText || state.latestOcrText || ocrOutput.value || "";
      const corrected = state.latestOcrText || ocrOutput.value || raw;
      $("ocrCorrectionWrong").value = raw;
      $("ocrCorrectionCorrected").value = corrected;
      $("ocrCorrectionNote").value = "manual OCR correction";
      $("ocrCorrectionEditorStatus").textContent = "draft";
      updateOcrCorrectionEditorControls();
      renderOcrCorrectionList();
    }

    async function loadOcrCorrections(showMessage = false) {
      $("ocrCorrectionList").textContent = "Loading OCR corrections...";
      const params = new URLSearchParams();
      params.set("profile", currentOcrProfile());
      params.set("language", $("ocrLanguage").value.trim() || "ja");
      params.set("limit", "100");
      if ($("ocrCorrectionIncludeInactive").checked) {
        params.set("includeInactive", "true");
      }

      const items = await api(`/ocr/corrections?${params.toString()}`);
      state.ocrCorrections = items || [];
      renderOcrCorrectionList();

      if (showMessage) {
        appendMessage("result", "ocr corrections", `${state.ocrCorrections.length} rows`, currentOcrProfile());
      }
    }

    async function saveOcrCorrection() {
      const wrongText = $("ocrCorrectionWrong").value.trim();
      const correctedText = $("ocrCorrectionCorrected").value.trim();
      if (!wrongText || !correctedText) {
        appendMessage("error", "ocr correction", "wrong and corrected are required");
        return;
      }

      const saved = await post("/ocr/corrections", {
        profile: currentOcrProfile(),
        language: $("ocrLanguage").value.trim() || "ja",
        wrongText,
        correctedText,
        note: $("ocrCorrectionNote").value.trim() || "user verified correction",
        priority: Number($("ocrCorrectionPriority").value || 0),
        confidence: Number($("ocrCorrectionConfidence").value || 1),
        source: "user-verified"
      });

      state.selectedOcrCorrectionId = saved && saved.id ? saved.id : "";
      $("ocrCorrectionEditorStatus").textContent = saved && saved.id ? saved.id.slice(0, 12) : "saved";
      appendMessage("result", "ocr correction", `${wrongText} -> ${correctedText}`, saved && saved.source ? saved.source : "user-verified");
      await loadOcrCorrections();
      await loadOcrHistory();
    }

    async function toggleSelectedOcrCorrectionActive() {
      const selected = selectedOcrCorrection();
      if (!selected) {
        return;
      }

      const updated = await patch(`/ocr/corrections/${encodeURIComponent(selected.id)}`, {
        isActive: !selected.isActive
      });
      state.selectedOcrCorrectionId = updated && updated.id ? updated.id : "";
      $("ocrCorrectionEditorStatus").textContent = updated && updated.isActive ? "active" : "inactive";
      appendMessage(
        "result",
        "ocr correction",
        updated && updated.isActive ? "correction reactivated" : "correction deactivated",
        updated && updated.id ? updated.id.slice(0, 12) : "");
      await loadOcrCorrections();
      await loadOcrHistory();
    }

    function hasMemorySecurityFlags(flags) {
      return Boolean(flags && String(flags).trim() && String(flags).trim() !== "[]");
    }

    function clearMemoryEditor() {
      state.selectedMemoryId = null;
      $("memoryEditorState").textContent = "new";
      $("memoryEditorState").className = "memory-chip good";
      $("memoryEditorId").textContent = "-";
      $("memoryEditorScope").textContent = $("memoryProfile").value.trim() || "default";
      $("memoryEditorSecurityFlags").textContent = "flags []";
      $("memoryEditorSecurityFlags").className = "memory-chip good";
      const clearReasonChip = $("memoryEditorReason");
      if (clearReasonChip) {
        clearReasonChip.textContent = "";
        clearReasonChip.classList.add("hidden");
      }
      $("memoryEditorKind").disabled = false;
      $("memoryEditorSourceLang").disabled = false;
      $("memoryEditorTargetLang").disabled = false;
      $("memoryEditorKind").value = currentMemoryKindForCreate();
      $("memoryEditorSourceLang").value = $("source").value || "ja";
      $("memoryEditorTargetLang").value = $("target").value || "zh-TW";
      $("memoryEditorVisibility").value = "profile";
      $("memoryEditorSourceText").value = "";
      $("memoryEditorTargetText").value = "";
      $("memoryEditorNote").value = "";
      $("memoryEditorPriority").value = "0";
      $("memoryEditorConfidence").value = "1";
      $("memoryEditorTrust").value = "user_verified";
      $("memoryEditorActive").checked = true;
      $("memoryEditorAcknowledgeSecurityFlags").checked = false;
      $("memoryResolveConflictButton").disabled = true;
      $("memoryMergeConflictButton").disabled = true;
      $("memoryApproveCandidateButton").disabled = true;
      $("memoryRejectCandidateButton").disabled = true;
      $("memoryToggleActiveButton").disabled = true;
      $("memoryToggleActiveButton").textContent = "Deactivate";
      renderMemoryList();
      renderMemoryContextAudit();
    }

    function selectMemory(id) {
      const item = state.memoryItems.find(value => value.id === id);
      if (!item) {
        clearMemoryEditor();
        return;
      }

      state.selectedMemoryId = item.id;
      $("memoryEditorState").textContent = item.isActive ? "active" : "inactive";
      $("memoryEditorState").className = item.isActive ? "memory-chip good" : "memory-chip warn";
      $("memoryEditorId").textContent = item.id.slice(0, 12);
      $("memoryEditorScope").textContent = `${item.profileId} / ${item.sourceLanguage}->${item.targetLanguage}`;
      const securityFlags = item.securityFlagsJson || "[]";
      $("memoryEditorSecurityFlags").textContent = hasMemorySecurityFlags(securityFlags) ? `flags ${securityFlags}` : "flags []";
      $("memoryEditorSecurityFlags").className = hasMemorySecurityFlags(securityFlags) ? "memory-chip warn" : "memory-chip good";
      const reasonText = memoryReasonText(item);
      const reasonChip = $("memoryEditorReason");
      if (reasonChip) {
        reasonChip.textContent = reasonText;
        reasonChip.classList.toggle("hidden", !reasonText);
      }
      $("memoryEditorKind").value = item.memoryKind;
      $("memoryEditorKind").disabled = true;
      $("memoryEditorSourceLang").value = item.sourceLanguage;
      $("memoryEditorSourceLang").disabled = true;
      $("memoryEditorTargetLang").value = item.targetLanguage;
      $("memoryEditorTargetLang").disabled = true;
      $("memoryEditorVisibility").value = item.visibility || "profile";
      $("memoryEditorSourceText").value = item.sourceText || "";
      $("memoryEditorTargetText").value = item.targetText || "";
      $("memoryEditorNote").value = item.note || "";
      $("memoryEditorPriority").value = String(item.priority ?? 0);
      $("memoryEditorConfidence").value = String(item.confidence ?? 1);
      $("memoryEditorTrust").value = item.trustLevel || "user_verified";
      $("memoryEditorActive").checked = Boolean(item.isActive);
      $("memoryEditorAcknowledgeSecurityFlags").checked = false;
      const isCandidate = item.trustLevel === "local_generated";
      const isConflict = state.memoryConflictIds.has(item.id);
      $("memoryResolveConflictButton").disabled = !isConflict;
      $("memoryMergeConflictButton").disabled = !isConflict;
      $("memoryApproveCandidateButton").disabled = !isCandidate;
      $("memoryRejectCandidateButton").disabled = !isCandidate || !item.isActive;
      $("memoryToggleActiveButton").disabled = false;
      $("memoryToggleActiveButton").textContent = item.isActive ? "Deactivate" : "Reactivate";
      renderMemoryList();
      renderMemoryContextAudit();
    }

    function memoryPayload() {
      return {
        sourceText: $("memoryEditorSourceText").value.trim(),
        targetText: $("memoryEditorTargetText").value.trim(),
        note: $("memoryEditorNote").value.trim(),
        priority: Number.parseInt($("memoryEditorPriority").value || "0", 10),
        confidence: Number.parseFloat($("memoryEditorConfidence").value || "1"),
        trustLevel: $("memoryEditorTrust").value,
        visibility: $("memoryEditorVisibility").value,
        isActive: $("memoryEditorActive").checked,
        acknowledgeSecurityFlags: $("memoryEditorAcknowledgeSecurityFlags").checked
      };
    }

    async function saveMemoryEditor() {
      const payload = memoryPayload();
      if (!payload.sourceText || !payload.targetText) {
        throw new Error("source text and target text are required.");
      }

      let saved;
      if (state.selectedMemoryId) {
        saved = await patch(`/memories/${encodeURIComponent(state.selectedMemoryId)}`, payload);
      } else {
        saved = await post("/memories", {
          ...payload,
          profile: $("memoryProfile").value.trim() || "default",
          memoryKind: $("memoryEditorKind").value,
          source: $("memoryEditorSourceLang").value.trim() || $("source").value || "ja",
          target: $("memoryEditorTargetLang").value.trim() || $("target").value || "zh-TW",
          origin: payload.trustLevel === "local_generated" ? "local_generated" : "user_verified"
        });
      }

      appendMessage("result", "memory", state.selectedMemoryId ? "memory updated" : "memory created", saved.id ? saved.id.slice(0, 12) : "");
      await loadMemories(saved.id);
    }

    async function toggleSelectedMemoryActive() {
      if (!state.selectedMemoryId) {
        return;
      }

      const item = state.memoryItems.find(value => value.id === state.selectedMemoryId);
      if (!item) {
        return;
      }

      const saved = await patch(`/memories/${encodeURIComponent(item.id)}`, { isActive: !item.isActive });
      appendMessage("result", "memory", saved.isActive ? "memory reactivated" : "memory deactivated", saved.id.slice(0, 12));
      await loadMemories(saved.id);
    }

    async function reviewSelectedMemory(action) {
      if (!state.selectedMemoryId) {
        return;
      }

      const id = state.selectedMemoryId;
      // edit-before-approve: persist any editor edits to the candidate before
      // flipping its trust level, so the approved item carries the reviewer's
      // tweaks (target text / note / priority / confidence).
      if (action === "approve") {
        const item = state.memoryItems.find(value => value.id === id);
        const payload = memoryPayload();
        if (item && payload.targetText && (
          payload.targetText !== (item.targetText || "") ||
          payload.note !== (item.note || "") ||
          Number(payload.priority) !== Number(item.priority ?? 0) ||
          Number(payload.confidence) !== Number(item.confidence ?? 1)
        )) {
          await patch(`/memories/${encodeURIComponent(id)}`, {
            targetText: payload.targetText,
            note: payload.note,
            priority: payload.priority,
            confidence: payload.confidence,
            acknowledgeSecurityFlags: payload.acknowledgeSecurityFlags
          });
        }
      }

      const saved = await post(`/memories/${encodeURIComponent(id)}/review`, {
        action,
        reviewedBy: "workbench",
        acknowledgeSecurityFlags: $("memoryEditorAcknowledgeSecurityFlags").checked
      });
      appendMessage("result", "memory", action === "approve" ? "candidate approved" : "candidate rejected", saved.id.slice(0, 12));
      await loadMemories(saved.id);
    }

    async function batchReviewMemories(action) {
      const ids = Array.from(state.memoryBatchIds);
      if (ids.length === 0) {
        return;
      }

      const result = await post("/memories/review-batch", {
        ids,
        action,
        reviewedBy: "workbench",
        acknowledgeSecurityFlags: $("memoryEditorAcknowledgeSecurityFlags").checked
      });
      const updatedCount = result && result.updated ? result.updated.length : 0;
      const skippedCount = result && result.skipped ? result.skipped.length : 0;
      const verb = action === "approve" ? "?詨?" : "??";
      const suffix = skippedCount > 0 ? `嚗??${skippedCount} 蝑?` : "";
      appendMessage("result", "memory", `撌?{verb} ${updatedCount} 蝑${suffix}`);
      state.memoryBatchIds.clear();
      await loadMemories();
    }

    async function resolveSelectedMemoryConflict() {
      if (!state.selectedMemoryId) {
        return;
      }

      const result = await post(`/memories/${encodeURIComponent(state.selectedMemoryId)}/resolve-conflict`, {
        reviewedBy: "workbench",
        approveWinner: true,
        acknowledgeSecurityFlags: $("memoryEditorAcknowledgeSecurityFlags").checked
      });
      appendMessage(
        "result",
        "memory",
        "conflict resolved",
        `${result.deactivated ? result.deactivated.length : 0} rows deactivated`);
      await loadMemoryConflicts(result.winner?.id || state.selectedMemoryId);
    }

    async function mergeSelectedMemoryConflict() {
      if (!state.selectedMemoryId) {
        return;
      }

      const payload = memoryPayload();
      if (!payload.targetText) {
        throw new Error("target text is required for conflict merge.");
      }

      const result = await post(`/memories/${encodeURIComponent(state.selectedMemoryId)}/merge-conflict`, {
        targetText: payload.targetText,
        note: payload.note,
        priority: payload.priority,
        confidence: payload.confidence,
        reviewedBy: "workbench",
        approveWinner: true,
        acknowledgeSecurityFlags: payload.acknowledgeSecurityFlags
      });
      appendMessage(
        "result",
        "memory",
        "conflict merged",
        `${result.deactivated ? result.deactivated.length : 0} rows deactivated`);
      await loadMemoryConflicts(result.winner?.id || state.selectedMemoryId);
    }

    function normalizeWorkspaceTabs(tabs) {
      const normalized = [];
      if (!Array.isArray(tabs)) {
        return normalized;
      }

      for (const value of tabs) {
        const mode = normalizeWorkspaceMode(value);
        if (WORKSPACE_TAB_DEFS[mode] && !normalized.includes(mode)) {
          normalized.push(mode);
        }
      }
      return normalized;
    }

    function loadWorkspaceTabsPreference() {
      try {
        const raw = window.localStorage.getItem(WORKSPACE_TABS_STORAGE_KEY);
        const savedTabs = normalizeWorkspaceTabs(raw ? JSON.parse(raw) : []);
        if (savedTabs.length > 0) {
          state.workspaceTabs = savedTabs;
        }
      } catch {
        // Non-essential preference persistence can fail in private contexts.
      }
    }

    function persistWorkspaceTabs() {
      try {
        window.localStorage.setItem(WORKSPACE_TABS_STORAGE_KEY, JSON.stringify(state.workspaceTabs));
      } catch {
        // Non-essential preference persistence can fail in private contexts.
      }
    }

    function ensureWorkspaceTab(mode) {
      mode = normalizeWorkspaceMode(mode);
      if (!WORKSPACE_TAB_DEFS[mode]) {
        mode = "text";
      }
      if (!state.workspaceTabs.includes(mode)) {
        state.workspaceTabs.push(mode);
        persistWorkspaceTabs();
      }
      return mode;
    }

    function renderWorkspaceTabs() {
      const host = $("workspaceTabs");
      if (!host) {
        return;
      }

      const tabCount = Math.max(1, state.workspaceTabs.length);
      host.dataset.tabCount = String(tabCount);
      host.style.setProperty("--workspace-tab-count", String(tabCount));

      state.workspaceTabs = normalizeWorkspaceTabs(state.workspaceTabs);
      host.innerHTML = state.workspaceTabs.map(mode => {
        const item = WORKSPACE_TAB_DEFS[mode] || WORKSPACE_TAB_DEFS.text;
        const label = workspaceTabLabel(item);
        const dragTitle = formatUiTemplate("workspace.tab.dragHint", { label }, "{label} - drag to reorder");
        const closeLabel = formatUiTemplate("workspace.tab.close", { label }, "Close {label}");
        const active = state.mode === mode;
        return `
          <div id="${item.id}" class="workspace-tab${active ? " active" : ""}" role="tab" aria-selected="${active ? "true" : "false"}"${active ? ' aria-current="page" data-selected="true"' : ""} data-workspace-mode="${mode}" draggable="false" title="${escapeHtml(dragTitle)}">
            <i class="${item.icon}" aria-hidden="true"></i>
            <span class="workspace-tab-label">${escapeHtml(label)}</span>
            <button class="workspace-tab-close" type="button" draggable="false" aria-label="${escapeHtml(closeLabel)}" data-close-workspace-mode="${mode}"><i class="ri-close-line" aria-hidden="true"></i></button>
          </div>`;
      }).join("");
    }

    function clearWorkspaceTabDropState() {
      const host = $("workspaceTabs");
      if (host) {
        host.classList.remove("is-dragging");
      }
      document.body.classList.remove("is-workspace-tab-dragging");
      for (const preview of document.querySelectorAll(".workspace-tab-drag-preview")) {
        preview.remove();
      }
      for (const tab of document.querySelectorAll(".workspace-tab")) {
        tab.classList.remove("dragging", "workspace-tab-drop-before", "workspace-tab-drop-after");
      }
    }

    function workspaceTabDropPosition(tab, event) {
      const rect = tab.getBoundingClientRect();
      return event.clientX > rect.left + rect.width / 2 ? "after" : "before";
    }

    function markWorkspaceTabDropTarget(tab, position) {
      for (const item of document.querySelectorAll(".workspace-tab-drop-before, .workspace-tab-drop-after")) {
        item.classList.remove("workspace-tab-drop-before", "workspace-tab-drop-after");
      }
      tab.classList.add(position === "after" ? "workspace-tab-drop-after" : "workspace-tab-drop-before");
    }

    function reorderWorkspaceTab(dragMode, targetMode, position) {
      dragMode = normalizeWorkspaceMode(dragMode);
      targetMode = normalizeWorkspaceMode(targetMode);
      if (!WORKSPACE_TAB_DEFS[dragMode] || !WORKSPACE_TAB_DEFS[targetMode] || dragMode === targetMode) {
        return false;
      }

      const fromIndex = state.workspaceTabs.indexOf(dragMode);
      const originalTargetIndex = state.workspaceTabs.indexOf(targetMode);
      if (fromIndex < 0 || originalTargetIndex < 0) {
        return false;
      }

      state.workspaceTabs.splice(fromIndex, 1);
      const targetIndex = state.workspaceTabs.indexOf(targetMode);
      let insertIndex = position === "after" ? targetIndex + 1 : targetIndex;
      insertIndex = Math.max(0, Math.min(insertIndex, state.workspaceTabs.length));
      state.workspaceTabs.splice(insertIndex, 0, dragMode);
      persistWorkspaceTabs();
      renderWorkspaceTabs();
      return true;
    }

    function workspaceTabAtPoint(event) {
      const element = document.elementFromPoint(event.clientX, event.clientY);
      const tab = element ? element.closest("[data-workspace-mode]") : null;
      const host = $("workspaceTabs");
      return tab && host && host.contains(tab) ? tab : null;
    }

    function createWorkspaceTabDragPreview(drag, event) {
      if (drag.preview) {
        return;
      }

      const item = WORKSPACE_TAB_DEFS[drag.mode] || WORKSPACE_TAB_DEFS.text;
      const label = workspaceTabLabel(item);
      const preview = document.createElement("div");
      preview.className = "workspace-tab-drag-preview";
      preview.innerHTML = `<i class="${item.icon}" aria-hidden="true"></i><span class="workspace-tab-label">${escapeHtml(label)}</span>`;
      document.body.appendChild(preview);

      const rect = drag.sourceElement?.getBoundingClientRect();
      if (rect) {
        preview.style.width = `${Math.round(rect.width)}px`;
        drag.previewOffsetX = Math.max(16, Math.min(event.clientX - rect.left, rect.width - 16));
        drag.previewOffsetY = Math.max(10, Math.min(event.clientY - rect.top, rect.height - 8));
      } else {
        drag.previewOffsetX = 28;
        drag.previewOffsetY = 17;
      }

      drag.preview = preview;
      updateWorkspaceTabDragPreview(drag, event);
    }

    function updateWorkspaceTabDragPreview(drag, event) {
      if (!drag.preview) {
        return;
      }

      const x = Math.round(event.clientX - (drag.previewOffsetX || 28));
      const y = Math.round(event.clientY - (drag.previewOffsetY || 17));
      drag.preview.style.transform = `translate3d(${x}px, ${y}px, 0)`;
    }

    function startWorkspaceTabPointerDrag(event, tab) {
      state.workspaceTabPointer = {
        pointerId: event.pointerId,
        mode: tab.dataset.workspaceMode,
        startX: event.clientX,
        startY: event.clientY,
        dragging: false,
        targetMode: tab.dataset.workspaceMode,
        position: "after",
        sourceElement: tab,
        preview: null,
        previewOffsetX: 0,
        previewOffsetY: 0
      };
      try {
        tab.setPointerCapture(event.pointerId);
      } catch {
        // Pointer capture is optional; document-level pointer events still cover normal mouse use.
      }
    }

    function updateWorkspaceTabPointerDrag(event) {
      const drag = state.workspaceTabPointer;
      if (!drag || drag.pointerId !== event.pointerId) {
        return;
      }

      const dx = event.clientX - drag.startX;
      const dy = event.clientY - drag.startY;
      if (!drag.dragging && Math.hypot(dx, dy) < WORKSPACE_TAB_DRAG_THRESHOLD_PX) {
        return;
      }

      event.preventDefault();
      if (!drag.dragging) {
        drag.dragging = true;
        state.workspaceTabDragMode = drag.mode;
        document.body.classList.add("is-workspace-tab-dragging");
        const host = $("workspaceTabs");
        host?.classList.add("is-dragging");
        drag.sourceElement?.classList.add("dragging");
        createWorkspaceTabDragPreview(drag, event);
      } else {
        updateWorkspaceTabDragPreview(drag, event);
      }

      const target = workspaceTabAtPoint(event);
      if (!target || target.dataset.workspaceMode === drag.mode) {
        for (const item of document.querySelectorAll(".workspace-tab-drop-before, .workspace-tab-drop-after")) {
          item.classList.remove("workspace-tab-drop-before", "workspace-tab-drop-after");
        }
        drag.targetMode = drag.mode;
        return;
      }

      const position = workspaceTabDropPosition(target, event);
      drag.targetMode = target.dataset.workspaceMode;
      drag.position = position;
      markWorkspaceTabDropTarget(target, position);
    }

    function finishWorkspaceTabPointerDrag(event, commit) {
      const drag = state.workspaceTabPointer;
      if (!drag || drag.pointerId !== event.pointerId) {
        return;
      }

      if (drag.sourceElement) {
        try {
          drag.sourceElement.releasePointerCapture(event.pointerId);
        } catch {
        }
      }

      const shouldSuppressClick = commit && drag.dragging;
      const shouldCommit = shouldSuppressClick && drag.targetMode && drag.targetMode !== drag.mode;
      state.workspaceTabPointer = null;
      state.workspaceTabDragMode = "";
      clearWorkspaceTabDropState();
      if (shouldSuppressClick) {
        state.workspaceTabSuppressClick = true;
        window.setTimeout(() => { state.workspaceTabSuppressClick = false; }, 0);
      }
      if (shouldCommit) {
        const didReorder = reorderWorkspaceTab(drag.mode, drag.targetMode, drag.position);
        state.workspaceTabSuppressClick = didReorder || state.workspaceTabSuppressClick;
      }
    }

    function closeWorkspaceTab(mode) {
      const index = state.workspaceTabs.indexOf(mode);
      if (index < 0) {
        return;
      }

      state.workspaceTabs.splice(index, 1);
      if (state.workspaceTabs.length === 0) {
        state.workspaceTabs.push("text");
      }
      persistWorkspaceTabs();

      if (state.mode === mode) {
        const nextMode = state.workspaceTabs[Math.max(0, Math.min(index, state.workspaceTabs.length - 1))] || "text";
        setMode(nextMode);
        return;
      }

      renderWorkspaceTabs();
    }

    function setMode(mode) {
      mode = ensureWorkspaceTab(mode);
      state.mode = mode;
      const isText = mode === "text";
      const isOcr = mode === "ocr";
      const isDocument = mode === "document";
      const isAudio = mode === "audio";
      const isRegion = mode === "region";
      const isSettings = mode === "settings";
      $("textPane").classList.toggle("hidden", !isText);
      $("ocrPane").classList.toggle("hidden", !isOcr);
      $("documentPane").classList.toggle("hidden", !isDocument);
      $("audioPane").classList.toggle("hidden", !isAudio);
      $("regionPane").classList.toggle("hidden", !isRegion);
      $("settingsPane").classList.toggle("hidden", !isSettings);
      $("terminal").classList.toggle("hidden", isSettings || isDocument);
      $("composer").classList.toggle("hidden", isSettings);
      document.querySelector(".workspace").classList.toggle("settings-active", isSettings);
      document.querySelector(".workspace").classList.toggle("document-active", isDocument);
      document.querySelector(".workspace").classList.toggle("text-active", isText);
      document.querySelector(".workspace").classList.toggle("region-active", isRegion);
      $("composer").classList.toggle("document-active", isDocument);
      $("composer").classList.toggle("text-active", isText);
      $("composer").classList.toggle("region-active", isRegion);
      $("translateOcrTextButton").classList.toggle("hidden", !isOcr);
      $("modeLabel").textContent = workspaceModeLabel(mode);
      $("footerRight").textContent = isSettings ? "/app / settings" : "/app";
      if (isRegion) {
        window.requestAnimationFrame(renderRegionSelection);
      }
      if (isOcr) {
        // The composer overlay may have rendered while the pane was hidden
        // (zero layout size), so re-fit once it is visible.
        scheduleOcrComposerOverlayFit();
        ensureOcrAuxiliaryDataLoaded().catch(error => appendMessage("error", "ocr", error.message || String(error)));
      }
      if (isDocument) {
        syncDocumentRuntimeBadges();
        loadDocumentJobs().catch(error => appendMessage("error", "document jobs", error.message || String(error)));
      }
      if (isAudio) {
        refreshAudioSessions({ quiet: state.audioSessions.length > 0 }).catch(error => appendMessage("error", "audio source", error.message || String(error)));
      } else {
        stopAudioSessionPoll();
      }
      if (isText) {
        syncTranslateUi();
      }
      updateTokenUsageDisplays();

      const pairs = [
        ["tabTranslate", "modeTranslate", "text"],
        ["tabOcr", "modeOcr", "ocr"],
        ["tabDocument", "modeDocument", "document"],
        ["tabAudio", "modeAudio", "audio"],
        ["tabRegion", "modeRegion", "region"],
        ["tabSettings", "modeSettings", "settings"]
      ];
      for (const [navId, tabId, value] of pairs) {
        $(navId).classList.toggle("active", mode === value);
        const tab = $(tabId);
        if (tab) {
          tab.classList.toggle("active", mode === value);
          tab.setAttribute("aria-selected", mode === value ? "true" : "false");
        }
      }
      renderWorkspaceTabs();
    }

    function initialModeFromUrl() {
      const mode = new URLSearchParams(window.location.search).get("mode") || "";
      if (mode === "pipe") {
        // Legacy URL value from before OCR and OCR+Translate were merged.
        return "ocr";
      }
      const normalizedMode = normalizeWorkspaceMode(mode);
      return ["text", "ocr", "document", "audio", "region", "settings"].includes(normalizedMode)
        ? normalizedMode
        : "";
    }

    async function ensureOcrAuxiliaryDataLoaded({ quiet = true } = {}) {
      if (state.ocrAuxiliaryLoaded) {
        return;
      }

      state.ocrAuxiliaryLoaded = true;
      try {
        await Promise.all([
          loadOcrSmokeResults(),
          loadOcrHistory(),
          loadOcrCorrections()
        ]);
      } catch (error) {
        state.ocrAuxiliaryLoaded = false;
        if (!quiet) {
          appendMessage("error", "ocr", error.message || String(error));
        }
        throw error;
      }
    }

    async function ensureProviderSettingsLoaded({ quiet = true } = {}) {
      const jobs = [];
      if (!state.suppliersLoaded) {
        state.suppliersLoaded = true;
        jobs.push(loadSuppliers().catch(error => {
          state.suppliersLoaded = false;
          throw error;
        }));
      }
      if (!state.llamaCppDownloadsLoaded) {
        state.llamaCppDownloadsLoaded = true;
        jobs.push(loadLlamaCppDownloads(true).catch(error => {
          state.llamaCppDownloadsLoaded = false;
          throw error;
        }));
      }
      if (jobs.length === 0) {
        return;
      }

      try {
        await Promise.all(jobs);
      } catch (error) {
        if (!quiet) {
          appendMessage("error", "providers", error.message || String(error));
        }
        throw error;
      }
    }

    function setSettingsSection(section) {
      const knownSections = Array.from(document.querySelectorAll("[data-settings-panel]")).map(panel => panel.dataset.settingsPanel);
      if (!knownSections.includes(section)) {
        section = "general";
      }

      for (const button of document.querySelectorAll("[data-settings-section]")) {
        button.classList.toggle("active", button.dataset.settingsSection === section);
      }

      for (const panel of document.querySelectorAll("[data-settings-panel]")) {
        panel.classList.toggle("hidden", panel.dataset.settingsPanel !== section);
      }

      const floatingAddSupplier = $("floatingAddSupplierButton");
      if (floatingAddSupplier) {
        floatingAddSupplier.classList.toggle("hidden", section !== "providers");
      }

      if (section === "memory") {
        setMemorySubTab("library");
        loadMemories().catch(error => appendMessage("error", "memory", error.message || String(error)));
      } else if (section === "appearance") {
        loadMemorySummary({ quiet: true }).catch(() => {});
      } else if (section === "providers") {
        ensureProviderSettingsLoaded().catch(error => appendMessage("error", "providers", error.message || String(error)));
      } else if (section === "ocr") {
        ensureOcrAuxiliaryDataLoaded().catch(error => appendMessage("error", "ocr", error.message || String(error)));
      } else if (section === "shortcuts") {
        loadHotkeys().catch(error => appendMessage("error", "hotkeys", error.message || String(error)));
      } else if (section === "performance") {
        loadShellSettings().catch(error => appendMessage("error", "performance", error.message || String(error)));
      } else if (section === "usage") {
        loadUsageSummary();
      }
    }

    function setMemorySubTab(tab) {
      for (const button of document.querySelectorAll("[data-memory-subtab]")) {
        button.classList.toggle("active", button.dataset.memorySubtab === tab);
      }
      for (const panel of document.querySelectorAll("[data-sub-panel]")) {
        panel.classList.toggle("hidden", panel.dataset.subPanel !== tab);
      }
      if (tab === "security") {
        setMemoryAdminTab("permissions");
        loadMemoryPrincipalPermissions().catch(error => appendMessage("error", "memory acl", error.message || String(error)));
      } else if (tab === "identity") {
        updateMemoryRuntimeStatus();
      } else if (tab === "audit") {
        loadMemoryContextAudit().catch(error => appendMessage("error", "memory audit", error.message || String(error)));
      }
    }

    function toggleMemoryAdvanced() {
      const toggle = $("memoryAdvancedToggle");
      toggle.classList.toggle("active");
      syncMemoryAdvancedLabels();
      const isAdvanced = toggle.classList.contains("active");
      for (const button of document.querySelectorAll("[data-memory-subtab]")) {
        if (button.dataset.memorySubtab !== "library") {
          button.classList.toggle("hidden", !isAdvanced);
        }
      }
      if (!isAdvanced) {
        setMemorySubTab("library");
      }
    }

    function syncMemoryAdvancedLabels() {
      const toggle = $("memoryAdvancedToggle");
      if (toggle) {
        const isAdvanced = toggle.classList.contains("active");
        toggle.textContent = isAdvanced
          ? `${uiText("settings.memory.advanced", "Advanced")} <`
          : `${uiText("settings.memory.advanced", "Advanced")} >`;
      }
      const editorToggle = $("memoryEditorAdvancedToggle");
      const editorSection = $("memoryEditorAdvancedSection");
      if (editorToggle && editorSection) {
        editorToggle.textContent = editorSection.classList.contains("hidden")
          ? uiText("settings.memory.moreOptions", "More options")
          : uiText("settings.memory.lessOptions", "Less options");
      }
    }

    function setMemoryAdminTab(tab) {
      for (const button of document.querySelectorAll("[data-memory-admin-tab]")) {
        button.classList.toggle("active", button.dataset.memoryAdminTab === tab);
      }
      for (const panel of document.querySelectorAll("[data-admin-panel]")) {
        panel.classList.toggle("hidden", panel.dataset.adminPanel !== tab);
      }
      if (tab === "sessions") {
        loadMemoryPrincipalSessions().catch(error => appendMessage("error", "memory sessions", error.message || String(error)));
      } else if (tab === "credentials") {
        loadMemoryPrincipalCredentials().catch(error => appendMessage("error", "memory credentials", error.message || String(error)));
      }
    }

    function toggleMemoryEditorAdvanced() {
      const section = $("memoryEditorAdvancedSection");
      section.classList.toggle("hidden");
      syncMemoryAdvancedLabels();
    }

    function syncOcrHint() {
      const provider = $("ocrProvider").value;
      const hint = $("ocrHint");
      const selected = $("ocrProvider").selectedOptions[0];
      const description = selected
        ? {
            name: selected.dataset.helpName || selected.textContent || provider || "OCR provider",
            value: selected.dataset.helpValue || provider || "-",
            use: selected.dataset.helpUse || selected.dataset.note || "selected OCR provider will process the uploaded image."
          }
        : getOcrProviderDescription(provider, "", "");
      updateOcrProviderHelp(description);
      $("ocrEngineAvailability").textContent = selected && selected.dataset.available === "true" ? "yes" : "no";
      $("ocrEngineStatus").textContent = selected && selected.dataset.status ? selected.dataset.status : "-";
      $("ocrEngineSource").textContent = selected && selected.dataset.source ? selected.dataset.source : "-";
      if (description && description.use) {
        hint.textContent = description.use;
      } else if (selected && selected.dataset.note) {
        hint.textContent = selected.dataset.note;
      } else {
        hint.textContent = "selected OCR provider will process the uploaded image.";
      }

      if (selected && selected.dataset.defaultLanguage && !$("ocrLanguage").value.trim()) {
        $("ocrLanguage").value = selected.dataset.defaultLanguage;
      }

      syncOcrSelectTrigger();
      refreshOcrRoutePreview();
    }

    function ocrRouteQuery() {
      const params = new URLSearchParams();
      params.set("provider", $("ocrProvider").value || "auto");
      params.set("contentType", $("ocrContentType").value || "dialogue");
      params.set("preference", $("ocrPreference").value || "speed");
      params.set("profile", currentOcrProfile());
      return params.toString();
    }

    function formatRouteLatency(value) {
      const ms = Number(value) || 0;
      if (ms >= 1000) {
        return `${(ms / 1000).toFixed(ms >= 10000 ? 0 : 1)} s`;
      }

      return `${ms} ms`;
    }

    function routeCostLabel(decision) {
      if (!decision) {
        return "-";
      }

      return `${decision.speedClass || "-"} / ${formatRouteLatency(decision.expectedLatencyMs)}`;
    }

    function renderOcrRoutePreview(decision) {
      state.ocrRoutingDecision = decision || null;
      const routeIssues = decision && decision.qualityIssues
        ? decision.qualityIssues.slice(0, 2).map((issue) => issue.code).filter(Boolean).join(", ")
        : "";
      $("ocrRouteProvider").textContent = decision ? `${decision.provider} (${decision.profile})` : "-";
      $("ocrRouteCost").textContent = decision
        ? `${routeCostLabel(decision)} / ${decision.qualityStatus || "unknown"}`
        : "-";
      $("ocrRouteAsync").textContent = decision ? decision.preferAsyncJob ? "job" : "inline" : "-";
      $("ocrRouteStructure").textContent = decision
        ? `${decision.preservesStructure ? "yes" : "no"}${decision.qualityNote ? ` / ${decision.qualityNote}` : ""}${routeIssues ? ` / ${routeIssues}` : ""}`
        : "-";
    }

    async function refreshOcrRoutePreview() {
      const requestId = ++state.ocrRouteRequestId;
      try {
        const decision = await api(`/ocr/route?${ocrRouteQuery()}`);
        if (requestId !== state.ocrRouteRequestId) {
          return;
        }

        renderOcrRoutePreview(decision);
      } catch (error) {
        if (requestId !== state.ocrRouteRequestId) {
          return;
        }

        renderOcrRoutePreview(null);
        $("ocrRouteProvider").textContent = "error";
        $("ocrRouteCost").textContent = error.message || "route failed";
      }
    }

    function syncSpeechHint() {
      const selected = $("speechProvider").selectedOptions[0];
      $("speechEngineAvailability").textContent = selected && selected.dataset.available === "true" ? "yes" : "no";
      $("speechEngineSource").textContent = selected && selected.dataset.source ? selected.dataset.source : "-";
      $("speechHint").textContent = selected && selected.dataset.note
        ? selected.dataset.note
        : "selected ASR provider will process the uploaded audio.";
      if (selected && selected.dataset.defaultLanguage && !$("speechLanguage").value.trim()) {
        $("speechLanguage").value = selected.dataset.defaultLanguage;
      }
    }

    function translationPayload(text) {
      const glossary = $("glossary").value;
      return {
        text,
        source: $("source").value,
        target: $("target").value,
        mode: $("preset").value,
        surface: "text",
        provider: $("translationProvider").value,
        model: $("translationModel").value.trim() || null,
        glossary: glossary || null
      };
    }

    function speechPayload() {
      const glossary = $("glossary").value;
      const sourceUrl = audioSourceUrl.value.trim();
      return {
        audioBase64: sourceUrl ? null : audioBase64.value.trim(),
        audioMimeType: state.audioMimeType || null,
        sourceUrl: sourceUrl || null,
        provider: $("speechProvider").value,
        language: $("speechLanguage").value,
        glossary: glossary || null
      };
    }

    function isVideoSpeechUrl(value) {
      if (!value) {
        return false;
      }

      return /^mock:\/\//i.test(value) ||
        /(^|\.)youtube\.com$/i.test(safeUrlHost(value)) ||
        /(^|\.)youtu\.be$/i.test(safeUrlHost(value)) ||
        /(^|\.)bilibili\.com$/i.test(safeUrlHost(value)) ||
        /(^|\.)b23\.tv$/i.test(safeUrlHost(value));
    }

    function safeUrlHost(value) {
      try {
        return new URL(value).hostname || "";
      } catch {
        return "";
      }
    }

    function closeVideoSpeechEvents() {
      if (state.videoSpeechEventSource) {
        state.videoSpeechEventSource.close();
        state.videoSpeechEventSource = null;
      }
    }

    function appendVideoSpeechSegment(segment) {
      if (!segment || !segment.text) {
        return;
      }

      if (!state.videoSegmentKeys) {
        state.videoSegmentKeys = new Set();
      }

      const key = `${Number(segment.startSeconds || 0).toFixed(3)}:${Number(segment.endSeconds || 0).toFixed(3)}:${segment.text}`;
      if (state.videoSegmentKeys.has(key)) {
        return;
      }

      state.videoSegmentKeys.add(key);
      state.latestSpeechSegments = [...(state.latestSpeechSegments || []), segment];
      scheduleVideoSegmentRender(segment.engine || "video-session");
    }

    function speechTranslationKey(value) {
      return `${Number(value.startSeconds || 0).toFixed(3)}:${Number(value.endSeconds || 0).toFixed(3)}:${value.sourceText || value.text || ""}`;
    }

    function appendVideoSpeechTranslation(translation) {
      if (!translation) {
        return;
      }

      const key = speechTranslationKey(translation);
      const existing = state.latestSpeechTranslations || [];
      state.latestSpeechTranslations = [
        ...existing.filter(item => speechTranslationKey(item) !== key),
        translation
      ];
      const usage = mergeTokenUsages(
        state.latestSpeechTranslations.map(item => readTokenUsage(item)),
        "audio:segments");
      applyTokenUsage(usage, "audio");
      scheduleVideoSegmentRender("video-session");
    }

    function scheduleVideoSegmentRender(engine) {
      // Coalesce bursts of SSE segment events into one sort + table render.
      if (state.videoSegmentRenderTimer) {
        clearTimeout(state.videoSegmentRenderTimer);
      }

      state.videoSegmentRenderTimer = setTimeout(() => {
        state.videoSegmentRenderTimer = 0;
        state.latestSpeechSegments = (state.latestSpeechSegments || [])
          .slice()
          .sort((left, right) => (left.startSeconds || 0) - (right.startSeconds || 0))
          .map((item, index) => ({ ...item, index }));
        renderSpeechSegments({
          text: state.latestSpeechSegments.map(item => item.text || "").join("\n"),
          segments: state.latestSpeechSegments,
          engine
        }, state.latestSpeechTranslations || []);
      }, 120);
    }

    async function loadVideoSpeechSegments(sessionId, durationSeconds) {
      const end = Math.max(Number(durationSeconds) || 0, 36000);
      const segments = await api(`/asr/video-sessions/${encodeURIComponent(sessionId)}/segments?start=0&end=${end}`);
      for (const segment of segments || []) {
        appendVideoSpeechSegment(segment);
      }
    }

    function handleVideoSpeechEvent(type, data) {
      let payload = {};
      if (data) {
        try {
          payload = JSON.parse(data);
        } catch {
          payload = {};
        }
      }

      if (type === "segment") {
        appendVideoSpeechSegment(payload.segment);
        if (!state.videoSpeechFirstSegmentAt && state.videoSpeechStartedAt) {
          state.videoSpeechFirstSegmentAt = performance.now();
          $("latencyLabel").textContent = `${Math.round(state.videoSpeechFirstSegmentAt - state.videoSpeechStartedAt)} ms`;
        }
        return;
      }

      if (type === "translation") {
        appendVideoSpeechTranslation(payload.translation);
        return;
      }

      if (type === "error" || type === "media_error") {
        const message = payload.errorMessage || (payload.buffer && payload.buffer.errorMessage) || "video ASR error";
        appendMessage("error", "video asr", message, type);
        return;
      }

      if (type === "session_ready") {
        appendMessage("result", "video asr", "session ready", "scheduler");
      } else if (type === "captions_ready") {
        appendMessage("result", "video asr", "captions ready", "captions");
        const session = payload.session || state.activeVideoSpeechSession || {};
        if (session.id) {
          loadVideoSpeechSegments(session.id, session.durationSeconds)
            .catch(error => appendMessage("error", "video asr", error.message || String(error), "captions"));
        }
        closeVideoSpeechEvents();
      } else if (type === "session_completed") {
        $("speechEngineName").textContent = "video-session done";
        appendMessage("result", "video asr", "session completed", "scheduler");
        closeVideoSpeechEvents();
      } else if (type === "section_download_started") {
        $("speechEngineName").textContent = "downloading section";
      } else if (type === "section_download_done") {
        $("speechEngineName").textContent = "section buffered";
      } else if (type === "window_started") {
        $("speechEngineName").textContent = "transcribing window";
      } else if (type === "window_done") {
        $("speechEngineName").textContent = "video-session";
      }
    }

    function connectVideoSpeechEvents(sessionId) {
      closeVideoSpeechEvents();
      const source = new EventSource(`/asr/video-sessions/${encodeURIComponent(sessionId)}/events`);
      state.videoSpeechEventSource = source;
      const eventTypes = [
        "session_created",
        "caption_probe",
        "captions_ready",
        "session_ready",
        "position",
        "window_queued",
        "window_started",
        "section_download_started",
        "buffer_hit",
        "section_download_done",
        "segment",
        "translation",
        "window_done",
        "window_retry",
        "session_completed",
        "media_error",
        "error",
        "session_canceled"
      ];
      for (const type of eventTypes) {
        source.addEventListener(type, event => handleVideoSpeechEvent(type, event.data));
      }
      source.addEventListener("error", () => {
        $("speechEngineName").textContent = "event reconnect";
      });
    }

    function ocrPayload() {
      return {
        imageBase64: imageBase64.value.trim(),
        ...(state.imageMimeType ? { imageMimeType: state.imageMimeType } : {}),
        provider: $("ocrProvider").value,
        contentType: $("ocrContentType").value,
        preference: $("ocrPreference").value,
        language: $("ocrLanguage").value,
        profile: currentOcrProfile(),
        preprocessingPreset: $("ocrPreprocessingPreset").value || "none"
      };
    }

    function ocrSmokePayload() {
      const expectedStructure = buildExpectedOcrStructure();
      return {
        ...ocrPayload(),
        expectedText: $("ocrSmokeExpected").value.trim(),
        ...(expectedStructure ? { expectedStructure } : {})
      };
    }

    function ocrSmokeMatrixProviders() {
      const available = new Set(Array.from($("ocrProvider").options)
        .filter(option => !option.disabled && option.value && option.value !== "auto")
        .map(option => option.value));
      const selected = $("ocrProvider").value;
      const contentType = $("ocrContentType").value || "dialogue";
      const preference = $("ocrPreference").value || "speed";
      const structureLane = ["table", "formula", "formula_table", "document", "document_region", "structure"].includes(contentType);
      const highAccuracy = ["accuracy", "high_accuracy", "vlm"].includes(preference) ||
        ["high_accuracy", "complex_document"].includes(contentType);
      const preferred = structureLane || highAccuracy
        ? ["pp-structure-v3", "pix2text", "paddleocr", ...(highAccuracy ? ["paddleocr-vl", "dots-ocr"] : []), selected]
        : ["oneocr", "rapidocr-net-v6", "rapidocr-net", "windows", "rapidocr-ppocrv5", "paddleocr", "external", selected];

      return preferred
        .filter(value => value && value !== "auto" && available.has(value))
        .filter((value, index, values) => values.indexOf(value) === index);
    }

    function applyOcrSmokeResult(result) {
      const similarity = Number(result.similarity || 0);
      $("ocrSmokeRecognized").textContent = shortText(result.recognizedText || "-", 90);
      $("ocrSmokeSimilarity").textContent = result.expectedText ? `${Math.round(similarity * 100)}%` : "-";
      $("ocrSmokeDistance").textContent = result.expectedText ? String(result.editDistance ?? "-") : "-";
      $("ocrSmokeMatch").textContent = result.expectedText
        ? result.exactMatch ? "exact" : result.containsExpected ? "contains" : "diff"
        : "no expected";
      $("ocrSmokeStructureMatch").textContent = formatOcrStructureAssertion(result.structureAssertion);
      $("ocrSmokeLatency").textContent = `${Number(result.latencyMs || 0)} ms`;
      $("ocrSmokeStatus").textContent = result.ocr && result.ocr.cacheHit ? "cache" : "done";

      if (result.ocr) {
        applyOcrResult(result.ocr, Number(result.latencyMs || result.ocr.latencyMs || 0), "ocr smoke");
      }
    }

    function applyOcrSmokeMatrixResult(matrix) {
      const items = matrix && Array.isArray(matrix.items) ? matrix.items : [];
      const success = Number(matrix && matrix.successCount || 0);
      const failure = Number(matrix && matrix.failureCount || 0);
      $("ocrSmokeStatus").textContent = `matrix ${success}/${items.length || success + failure}`;

      const firstSuccess = items.find(item => item.succeeded && item.result);
      if (firstSuccess) {
        applyOcrSmokeResult(firstSuccess.result);
      }

      for (const item of items.filter(item => !item.succeeded)) {
        appendMessage("error", "ocr matrix", item.errorMessage || "provider failed", item.provider || "-");
      }
    }

    function applyOcrSmokeRecord(item) {
      $("ocrSmokeExpected").value = item.expectedText || "";
      $("ocrSmokeExpectedTables").value = item.structureAssertion && item.structureAssertion.expected && item.structureAssertion.expected.tableBlockCount !== null && item.structureAssertion.expected.tableBlockCount !== undefined
        ? String(item.structureAssertion.expected.tableBlockCount)
        : "";
      $("ocrSmokeExpectedFormulas").value = item.structureAssertion && item.structureAssertion.expected && item.structureAssertion.expected.formulaBlockCount !== null && item.structureAssertion.expected.formulaBlockCount !== undefined
        ? String(item.structureAssertion.expected.formulaBlockCount)
        : "";
      $("ocrSmokeExpectedCells").value = item.structureAssertion && item.structureAssertion.expected && item.structureAssertion.expected.tableCellCount !== null && item.structureAssertion.expected.tableCellCount !== undefined
        ? String(item.structureAssertion.expected.tableCellCount)
        : "";
      $("ocrSmokeExpectedRows").value = item.structureAssertion && item.structureAssertion.expected && item.structureAssertion.expected.tableRowCount !== null && item.structureAssertion.expected.tableRowCount !== undefined
        ? String(item.structureAssertion.expected.tableRowCount)
        : "";
      $("ocrSmokeExpectedColumns").value = item.structureAssertion && item.structureAssertion.expected && item.structureAssertion.expected.tableColumnCount !== null && item.structureAssertion.expected.tableColumnCount !== undefined
        ? String(item.structureAssertion.expected.tableColumnCount)
        : "";
      $("ocrSmokeExpectedFormulaLatex").value = item.structureAssertion && item.structureAssertion.expected && item.structureAssertion.expected.formulaLatexContains
        ? item.structureAssertion.expected.formulaLatexContains
        : "";
      $("ocrSmokeExpectedInvalidCells").value = item.structureAssertion && item.structureAssertion.expected && item.structureAssertion.expected.invalidTableCellCount !== null && item.structureAssertion.expected.invalidTableCellCount !== undefined
        ? String(item.structureAssertion.expected.invalidTableCellCount)
        : "";
      $("ocrSmokeExpectedMissingCells").value = item.structureAssertion && item.structureAssertion.expected && item.structureAssertion.expected.missingTableCellCount !== null && item.structureAssertion.expected.missingTableCellCount !== undefined
        ? String(item.structureAssertion.expected.missingTableCellCount)
        : "";
      $("ocrSmokeExpectedOverlappingCells").value = item.structureAssertion && item.structureAssertion.expected && item.structureAssertion.expected.overlappingTableCellCount !== null && item.structureAssertion.expected.overlappingTableCellCount !== undefined
        ? String(item.structureAssertion.expected.overlappingTableCellCount)
        : "";
      $("ocrSmokeRecognized").textContent = shortText(item.succeeded === false ? item.errorMessage || "-" : item.recognizedText || "-", 90);
      $("ocrSmokeSimilarity").textContent = item.expectedText ? `${Math.round(Number(item.similarity || 0) * 100)}%` : "-";
      $("ocrSmokeDistance").textContent = item.expectedText ? String(item.editDistance ?? "-") : "-";
      $("ocrSmokeMatch").textContent = item.expectedText
        ? item.exactMatch ? "exact" : item.containsExpected ? "contains" : "diff"
        : "no expected";
      $("ocrSmokeStructureMatch").textContent = formatOcrStructureAssertion(item.structureAssertion);
      $("ocrSmokeLatency").textContent = `${Number(item.latencyMs || 0)} ms`;
      $("ocrSmokeStatus").textContent = item.id ? item.id.slice(0, 12) : "history";
      state.latestOcrText = item.succeeded === false ? "" : item.recognizedText || "";
      state.latestOcrRawText = item.recognizedText || "";
      ocrOutput.value = state.latestOcrText;
      sourceText.value = state.latestOcrText;
      $("engineName").textContent = item.engine || "-";
      $("blockCount").textContent = String(item.structure ? item.structure.blockCount || 0 : 0);
      renderOcrStructure(null, null, item.structure || null);
    }

    function renderOcrSmokeResults() {
      const list = $("ocrSmokeResultList");
      list.innerHTML = "";
      $("ocrSmokeResultCount").textContent = `${state.ocrSmokeResults.length} rows`;

      if (state.ocrSmokeResults.length === 0) {
        list.appendChild(emptyOcrHistoryNode("No OCR smoke results yet."));
        return;
      }

      for (const item of state.ocrSmokeResults) {
        const button = document.createElement("button");
        button.type = "button";
        button.className = "memory-item";
        button.addEventListener("click", () => applyOcrSmokeRecord(item));

        const head = document.createElement("div");
        head.className = "memory-item-head";
        const title = document.createElement("div");
        title.className = "memory-item-title";
        title.textContent = `${item.provider || "-"} / ${item.engine || "-"}`;
        const score = item.succeeded === false
          ? item.errorCode || "failed"
          : item.expectedText ? `${Math.round(Number(item.similarity || 0) * 100)}%` : "no expected";
        const structureKind = item.structureAssertion && item.structureAssertion.hasExpected
          ? item.structureAssertion.passed ? "good" : "warn"
          : "";
        head.append(
          title,
          memoryChip(score, item.succeeded === false ? "warn" : Number(item.similarity || 0) >= 0.9 ? "good" : "warn"),
          memoryChip(formatOcrStructureAssertion(item.structureAssertion), structureKind),
          memoryChip(item.preprocessingPreset || "none"));

        const body = document.createElement("div");
        body.className = "memory-item-body";
        body.textContent = shortText(item.succeeded === false ? item.errorMessage || "-" : item.recognizedText || "-", 180);

        const meta = document.createElement("div");
        meta.className = "memory-item-meta";
        meta.append(
          memoryChip(item.language),
          ...(item.succeeded === false ? [memoryChip("runtime failure", "warn")] : []),
          memoryChip(`${item.editDistance ?? 0} edits`),
          memoryChip(`${item.latencyMs || 0} ms`),
          memoryChip(formatOcrStructureSummary(item.structure)),
          ...ocrStructureIssueChips(item.structureAssertion),
          memoryChip(item.exactMatch ? "exact" : item.containsExpected ? "contains" : "diff"),
          memoryChip(formatOcrDate(item.createdAt))
        );

        button.append(head, body, meta);
        list.appendChild(button);
      }
    }

    function renderOcrSmokeQuality() {
      const list = $("ocrSmokeQualityList");
      list.innerHTML = "";
      const providerRows = state.ocrSmokeQuality.filter((item) => item.scope === "provider").length;
      const engineRows = state.ocrSmokeQuality.length - providerRows;
      $("ocrSmokeQualityCount").textContent = `${providerRows} providers / ${engineRows} engines`;

      if (state.ocrSmokeQuality.length === 0) {
        list.appendChild(emptyOcrHistoryNode("No OCR smoke quality yet."));
        return;
      }

      for (const item of state.ocrSmokeQuality) {
        const card = document.createElement("div");
        card.className = "memory-item";

        const head = document.createElement("div");
        head.className = "memory-item-head";
        const title = document.createElement("div");
        title.className = "memory-item-title";
        const isProviderScope = item.scope === "provider";
        title.textContent = isProviderScope
          ? `${item.provider || "-"} / provider rollup`
          : `${item.provider || "-"} / ${item.engine || "-"}`;
        const statusKind = item.status === "pass" ? "good" : "warn";
        head.append(
          title,
          memoryChip(item.status || "warn", statusKind),
          memoryChip(isProviderScope ? "provider" : "engine"),
          memoryChip(`${item.sampleCount || 0} samples`),
          memoryChip(item.contentType || "any"));

        const body = document.createElement("div");
        body.className = "memory-item-body";
        body.textContent = item.note || "-";

        const textRate = item.textExpectedCount
          ? `${Math.round(Number(item.textPassRate || 0) * 100)}% text`
          : "no text gate";
        const structureRate = item.structureExpectedCount
          ? `${Math.round(Number(item.structurePassRate || 0) * 100)}% structure`
          : "no structure gate";

        const meta = document.createElement("div");
        meta.className = "memory-item-meta";
        meta.append(
          memoryChip(item.language || "-"),
          memoryChip(textRate, item.textExpectedCount && item.textPassRate >= 0.8 ? "good" : ""),
          memoryChip(structureRate, item.structureExpectedCount && item.structurePassRate >= 1 ? "good" : ""),
          memoryChip(`${item.tableIntegrityIssueCount || 0} table issues`, item.tableIntegrityIssueCount ? "warn" : "good"),
          memoryChip(`${item.runtimeFailureCount || 0} runtime failures`, item.runtimeFailureCount ? "warn" : "good"),
          ...ocrQualityIssueChips(item),
          memoryChip(`${item.averageLatencyMs || 0} ms`),
          memoryChip(formatOcrDate(item.lastSeenAt))
        );

        card.append(head, body, meta);
        list.appendChild(card);
      }
    }

    async function loadOcrSmokeQuality() {
      const params = new URLSearchParams();
      params.set("profile", currentOcrProfile());
      params.set("limit", "100");

      const items = await api(`/ocr/smoke/quality?${params.toString()}`);
      state.ocrSmokeQuality = items || [];
      renderOcrSmokeQuality();
    }

    async function loadOcrSmokeResults(showMessage = false) {
      $("ocrSmokeResultList").textContent = "Loading OCR smoke results...";
      const params = new URLSearchParams();
      params.set("profile", currentOcrProfile());
      params.set("limit", "12");

      const items = await api(`/ocr/smoke?${params.toString()}`);
      state.ocrSmokeResults = items || [];
      renderOcrSmokeResults();
      await loadOcrSmokeQuality();

      if (showMessage) {
        appendMessage("result", "ocr smoke", `${state.ocrSmokeResults.length} smoke rows`, currentOcrProfile());
      }
    }

    async function runOcrSmoke() {
      if (!imageBase64.value.trim()) {
        appendMessage("error", "ocr smoke", "image base64 is empty");
        return null;
      }

      $("ocrSmokeStatus").textContent = "running";
      const result = await post("/ocr/smoke", ocrSmokePayload());
      applyOcrSmokeResult(result);
      appendMessage(
        "result",
        "ocr smoke",
        result.recognizedText || "",
        result.expectedText ? `${Math.round(Number(result.similarity || 0) * 100)}%` : "no expected");
      loadOcrSmokeResults().catch(error => appendMessage("error", "ocr smoke", error.message || String(error)));
      loadOcrHistory().catch(error => appendMessage("error", "ocr history", error.message || String(error)));
      loadOcrCorrections().catch(error => appendMessage("error", "ocr corrections", error.message || String(error)));
      return result;
    }

    async function runOcrSmokeMatrix() {
      if (!imageBase64.value.trim()) {
        appendMessage("error", "ocr matrix", "image base64 is empty");
        return null;
      }

      const providers = ocrSmokeMatrixProviders();
      $("ocrSmokeStatus").textContent = providers.length > 0 ? `matrix ${providers.length}` : "matrix auto";
      const matrix = await post("/ocr/smoke/matrix", {
        ...ocrSmokePayload(),
        ...(providers.length > 0 ? { providers } : {})
      });
      applyOcrSmokeMatrixResult(matrix);
      appendMessage(
        "result",
        "ocr matrix",
        `${matrix.successCount || 0} passed / ${matrix.failureCount || 0} failed`,
        providers.length > 0 ? providers.join(", ") : "server candidates");
      loadOcrSmokeResults().catch(error => appendMessage("error", "ocr smoke", error.message || String(error)));
      loadOcrHistory().catch(error => appendMessage("error", "ocr history", error.message || String(error)));
      return matrix;
    }

    function shouldRunOcrAsJob() {
      const mode = $("ocrExecutionMode").value || "auto";
      if (mode === "job") {
        return true;
      }

      if (mode === "inline") {
        return false;
      }

      return !!(state.ocrRoutingDecision && state.ocrRoutingDecision.preferAsyncJob);
    }

    function ocrSegmentRoute(segment, shouldTranslate) {
      if (segment) {
        if (segment.errorCode && segment.errorCode !== "0") {
          return `error ${segment.errorCode}`;
        }

        if (segment.translated) {
          return segment.cacheHit ? "translated cache" : "translated";
        }

        return "pass";
      }

      return shouldTranslate ? "pending" : "pass";
    }

    function flattenOcrStructureRows(ocr, structured = null) {
      const document = structured && structured.document ? structured.document : ocr && ocr.document ? ocr.document : null;
      const byId = new Map(((structured && structured.segments) || []).map(item => [item.id, item]));
      const rows = [];

      function addRow(id, type, source, output, route, confidence) {
        rows.push({
          id: id || `${type}-${rows.length}`,
          type: type || "-",
          source: source || "",
          output: output || "",
          route: route || "-",
          confidence: typeof confidence === "number" ? confidence : 0
        });
      }

      function addBlock(block) {
        if (!block) {
          return;
        }

        const type = block.type || "text";
        if (block.table && Array.isArray(block.table.cells)) {
          addRow(block.id, type, block.text || "", block.text || "", "table", block.confidence);
          for (const cell of block.table.cells) {
            const cellId = `${block.id}:${cell.id || `r${cell.rowIndex}-c${cell.columnIndex}`}`;
            const segment = byId.get(cellId);
            addRow(
              cellId,
              "table_cell",
              blockEditedSource(cellId) || (segment ? segment.sourceText : cell.text),
              blockEditedTranslation(cellId) || (segment ? segment.translatedText : cell.text),
              ocrSegmentRoute(segment, cell.shouldTranslate !== false && !!String(cell.text || "").trim()),
              cell.confidence);
          }
        } else {
          const segment = byId.get(block.id);
          const source = blockEditedSource(block.id) || (segment ? segment.sourceText : block.formula && block.formula.latex ? block.formula.latex : block.text);
          const output = blockEditedTranslation(block.id) || (segment ? segment.translatedText : block.text);
          const shouldTranslate = block.shouldTranslate !== false &&
            type !== "formula" &&
            type !== "code" &&
            type !== "figure" &&
            !!String(block.text || "").trim();
          addRow(block.id, type, source, output, ocrSegmentRoute(segment, shouldTranslate), block.confidence);
        }

        for (const child of block.children || []) {
          addBlock(child);
        }
      }

      for (const page of document && document.pages ? document.pages : []) {
        for (const block of page.blocks || []) {
          addBlock(block);
        }
      }

      if (rows.length === 0 && ocr && Array.isArray(ocr.blocks)) {
        for (const block of ocr.blocks) {
          addRow(`block-${rows.length}`, "text", block.text || "", block.text || "", "flat");
        }
      }

      if (rows.length === 0 && structured && Array.isArray(structured.segments)) {
        for (const segment of structured.segments) {
          addRow(segment.id, segment.type, segment.sourceText, segment.translatedText, ocrSegmentRoute(segment, false));
        }
      }

      return rows;
    }

    function currentOcrImageDataUrl() {
      const value = imageBase64.value.trim();
      if (!value) {
        return "";
      }

      if (value.startsWith("data:image/")) {
        return value;
      }

      return `data:${state.imageMimeType || "image/png"};base64,${value}`;
    }

    function renderOcrOverlayControls() {
      const overlayButton = $("ocrOverlayToggleButton");
      const maskButton = $("ocrMaskToggleButton");
      const hint = $("ocrOverlayHint");
      if (overlayButton) {
        overlayButton.classList.toggle("active", state.ocrOverlayEnabled);
        overlayButton.innerHTML = `<i class="${state.ocrOverlayEnabled ? "ri-eye-line" : "ri-eye-off-line"}"></i><span>Overlay ${state.ocrOverlayEnabled ? "on" : "off"}</span>`;
      }
      if (maskButton) {
        maskButton.disabled = !state.ocrOverlayEnabled;
        maskButton.classList.toggle("active", state.ocrMaskEnabled);
        maskButton.innerHTML = `<i class="${state.ocrMaskEnabled ? "ri-paint-fill" : "ri-paint-line"}"></i><span>Mask ${state.ocrMaskEnabled ? "on" : "off"}</span>`;
      }
      if (hint) {
        hint.textContent = state.ocrOverlayEnabled
          ? "Translation is placed back on the image."
          : "Overlay off. Showing the original image.";
      }
    }

    function ocrSectionMetaText(prefix, collapsed) {
      if (prefix === "ocrText") {
        return collapsed ? "text + translation" : "editing";
      }

      if (prefix === "ocrStructure") {
        const count = state.latestOcrStructureRows ? state.latestOcrStructureRows.length : 0;
        if (count > 0) {
          return `${count} segment${count === 1 ? "" : "s"}`;
        }

        return collapsed ? "advanced" : "empty";
      }

      if (prefix === "ocrPreview") {
        return collapsed ? "show" : state.ocrPreviewMode || "overlay";
      }

      return collapsed ? "show" : "open";
    }

    function updateOcrSectionMeta(prefix, collapsed) {
      const meta = $(`${prefix}CollapseMeta`);
      if (meta) {
        meta.textContent = ocrSectionMetaText(prefix, collapsed);
      }
    }

    function hasOcrResultContent() {
      const text = $("ocrOutput") ? $("ocrOutput").value.trim() : "";
      const translation = $("ocrTranslationOutput") ? $("ocrTranslationOutput").value.trim() : "";
      return Boolean(text || translation || state.latestOcr || state.latestOcrStructured);
    }

    function updateOcrResultStackVisibility() {
      const stack = document.querySelector(".ocr-result-stack");
      if (stack) {
        stack.classList.toggle("is-empty", !hasOcrResultContent());
      }
    }

    function applyOcrSectionCollapsed(prefix, collapsed) {
      const panel = $(`${prefix}Panel`);
      const button = $(`${prefix}ToggleButton`);
      const icon = $(`${prefix}ToggleIcon`);
      if (panel) panel.classList.toggle("hidden", collapsed);
      if (button) {
        button.setAttribute("aria-expanded", collapsed ? "false" : "true");
        button.classList.toggle("is-open", !collapsed);
        const section = button.closest(".ocr-collapse-section");
        if (section) {
          section.classList.toggle("is-open", !collapsed);
        }
      }
      if (icon) icon.className = collapsed ? "ri-arrow-down-s-line" : "ri-arrow-up-s-line";
      updateOcrSectionMeta(prefix, collapsed);
      updateOcrResultStackVisibility();
    }

    function setOcrTextCollapsed(collapsed) {
      state.ocrTextCollapsed = Boolean(collapsed);
      applyOcrSectionCollapsed("ocrText", state.ocrTextCollapsed);
    }

    function setOcrStructureCollapsed(collapsed) {
      state.ocrStructureCollapsed = Boolean(collapsed);
      applyOcrSectionCollapsed("ocrStructure", state.ocrStructureCollapsed);
    }

    function setOcrPreviewCollapsed(collapsed) {
      state.ocrPreviewCollapsed = Boolean(collapsed);
      applyOcrSectionCollapsed("ocrPreview", state.ocrPreviewCollapsed);
    }

    function abortOcrImageRequest() {
      if (state.ocrImageAbort) {
        state.ocrImageAbort.abort();
        state.ocrImageAbort = null;
      }
    }

    function beginOcrImageRequest() {
      abortOcrImageRequest();
      const controller = new AbortController();
      state.ocrImageAbort = controller;
      return controller;
    }

    function finishOcrImageRequest(controller) {
      if (state.ocrImageAbort === controller) {
        state.ocrImageAbort = null;
      }
    }

    function isCurrentOcrImageSession(sessionId) {
      return sessionId === state.ocrImageSessionId;
    }

    function nextOcrImageSession() {
      state.ocrImageSessionId += 1;
      state.ocrComposerOverlayToken += 1;
      state.ocrOverlayRenderToken += 1;
      return state.ocrImageSessionId;
    }

    function resetOcrImageResultState(options = {}) {
      ocrOutput.value = "";
      ocrTranslationOutput.value = "";
      if (options.clearLastOutput !== false) {
        lastOutput.value = "";
        applyTokenUsage(null);
      }
      if (options.clearSource !== false) {
        sourceText.value = "";
      }
      state.latestOcrText = "";
      state.latestOcrRawText = "";
      state.latestOcr = null;
      state.latestOcrDocument = null;
      state.latestOcrStructured = null;
      state.latestOcrStructureRows = [];
      state.selectedOcrStructureId = "";
      state.selectedOcrStructureItem = null;
      $("blockCount").textContent = "0";
      $("engineName").textContent = "-";
      $("ocrJobStatus").textContent = "-";
      renderOcrStructure();
      setOcrTextCollapsed(true);
      setOcrStructureCollapsed(true);
      setOcrPreviewCollapsed(true);
      updateOcrComposerPreview();
    }

    function updateOcrComposerPreview() {
      const dataUrl = currentOcrImageDataUrl();
      const preview = $("ocrImagePreview");
      const image = $("ocrImagePreviewImg");
      const overlay = $("ocrComposerOverlay");
      if (!preview || !image || !overlay) {
        return;
      }

      dropZone.classList.toggle("has-image", Boolean(dataUrl));
      preview.classList.toggle("hidden", !dataUrl);
      const replaceButton = $("ocrReplaceImageButton");
      if (replaceButton) {
        replaceButton.classList.toggle("hidden", !dataUrl);
      }
      renderBlockSelectLayer();
      if (!dataUrl) {
        image.removeAttribute("src");
        overlay.innerHTML = "";
        return;
      }

      if (image.src !== dataUrl) {
        image.src = dataUrl;
      }

      const translated = (ocrTranslationOutput?.value || "").trim();
      overlay.classList.toggle("no-mask", !state.ocrMaskEnabled);
      overlay.innerHTML = "";
      if (!state.ocrOverlayEnabled || !translated) {
        return;
      }

      const token = ++state.ocrComposerOverlayToken;
      loadOcrOverlayImage(dataUrl)
        .catch(() => ({ naturalWidth: 640, naturalHeight: 360, width: 640, height: 360 }))
        .then(sourceImage => {
          if (token !== state.ocrComposerOverlayToken) {
            return;
          }

          const pageWidth = Math.max(1, Math.round(sourceImage.naturalWidth || sourceImage.width || 640));
          const pageHeight = Math.max(1, Math.round(sourceImage.naturalHeight || sourceImage.height || 360));
          if (renderOcrComposerStructuredOverlay(overlay, state.latestOcrStructured, pageWidth, pageHeight)) {
            scheduleOcrComposerOverlayFit();
            return;
          }

          const box = ocrFallbackOverlayBox(state.latestOcr, state.latestOcrStructured, pageWidth, pageHeight);
          const leftPct = box.x / pageWidth * 100;
          const topPct = box.y / pageHeight * 100;
          const widthPct = box.width / pageWidth * 100;
          const heightPct = box.height / pageHeight * 100;
          overlay.innerHTML = `
            <div class="ocr-composer-overlay-block"
              style="left:${leftPct.toFixed(4)}%;top:${topPct.toFixed(4)}%;width:${widthPct.toFixed(4)}%;height:${heightPct.toFixed(4)}%;">
              <div class="ocr-composer-overlay-text">${escapeHtmlLines(translated)}</div>
            </div>`;
          scheduleOcrComposerOverlayFit();
        });
    }

    function clearOcrOverlaySampledMasks(preview) {
      for (const node of preview.querySelectorAll(".ocr-overlay-block, .ocr-overlay-table-cell")) {
        node.classList.remove("has-sampled-mask");
        node.style.removeProperty("--ocr-mask-bg");
        node.style.removeProperty("--ocr-mask-text");
        node.style.removeProperty("--ocr-mask-border");
      }
    }

    function loadOcrOverlayImage(dataUrl) {
      return new Promise((resolve, reject) => {
        const image = new Image();
        image.onload = () => resolve(image);
        image.onerror = () => reject(new Error("overlay image could not be decoded"));
        image.src = dataUrl;
      });
    }

    function escapeHtmlLines(str) {
      return escapeHtml(String(str || "")).replace(/\r\n|\r|\n/g, "<br>");
    }

    function normalizeOcrBoundingBox(box) {
      if (!box) {
        return null;
      }

      const x = Number.parseFloat(box.x ?? box.X ?? "");
      const y = Number.parseFloat(box.y ?? box.Y ?? "");
      const width = Number.parseFloat(box.width ?? box.Width ?? "");
      const height = Number.parseFloat(box.height ?? box.Height ?? "");
      return [x, y, width, height].every(Number.isFinite) && width > 0 && height > 0
        ? { x, y, width, height }
        : null;
    }

    function collectOcrBlockBoxes(blocks, boxes) {
      for (const block of blocks || []) {
        const box = normalizeOcrBoundingBox(block.boundingBox || block.BoundingBox);
        if (box) {
          boxes.push(box);
        }

        if (block.table && Array.isArray(block.table.cells)) {
          for (const cell of block.table.cells) {
            const cellBox = normalizeOcrBoundingBox(cell.boundingBox || cell.BoundingBox);
            if (cellBox) {
              boxes.push(cellBox);
            }
          }
        }

        if (Array.isArray(block.children)) {
          collectOcrBlockBoxes(block.children, boxes);
        }
      }
    }

    function collectOcrDocumentBoxes(document, boxes) {
      for (const page of document && Array.isArray(document.pages) ? document.pages : []) {
        collectOcrBlockBoxes(page.blocks || [], boxes);
      }
    }

    function unionOcrBoundingBoxes(boxes) {
      const valid = (boxes || []).filter(Boolean);
      if (valid.length === 0) {
        return null;
      }

      const left = Math.min(...valid.map(box => box.x));
      const top = Math.min(...valid.map(box => box.y));
      const right = Math.max(...valid.map(box => box.x + box.width));
      const bottom = Math.max(...valid.map(box => box.y + box.height));
      return {
        x: left,
        y: top,
        width: Math.max(1, right - left),
        height: Math.max(1, bottom - top)
      };
    }

    function ocrFallbackOverlayBox(ocr, structured, pageWidth, pageHeight) {
      const boxes = [];
      collectOcrBlockBoxes(ocr && ocr.blocks ? ocr.blocks : [], boxes);
      collectOcrDocumentBoxes(structured && structured.document ? structured.document : ocr && ocr.document ? ocr.document : null, boxes);

      const union = unionOcrBoundingBoxes(boxes);
      if (!union) {
        return {
          x: Math.round(pageWidth * 0.06),
          y: Math.round(pageHeight * 0.06),
          width: Math.round(pageWidth * 0.88),
          height: Math.max(44, Math.round(pageHeight * 0.18))
        };
      }

      const padX = Math.max(6, Math.round(pageWidth * 0.012));
      const padY = Math.max(4, Math.round(pageHeight * 0.012));
      const x = Math.max(0, union.x - padX);
      const y = Math.max(0, union.y - padY);
      const width = Math.min(pageWidth - x, union.width + padX * 2);
      const minHeight = Math.max(34, Math.round(pageHeight * 0.12));
      const height = Math.min(pageHeight - y, Math.max(minHeight, union.height + padY * 2));
      return {
        x: Math.round(x),
        y: Math.round(y),
        width: Math.max(1, Math.round(width)),
        height: Math.max(1, Math.round(height))
      };
    }

    function renderOcrFallbackTranslationOverlay(ocr, structured, translatedText, options = {}) {
      const preview = $("ocrDocumentPreview");
      const text = String(translatedText || "").trim();
      const dataUrl = currentOcrImageDataUrl();
      if (!preview || !text || !dataUrl) {
        return false;
      }

      const token = options.useCurrentToken
        ? state.ocrOverlayRenderToken
        : ++state.ocrOverlayRenderToken;
      setOcrPreviewClass(preview, "overlay");
      preview.textContent = "Rendering translated overlay...";

      loadOcrOverlayImage(dataUrl)
        .catch(() => ({ naturalWidth: 640, naturalHeight: 360, width: 640, height: 360 }))
        .then(image => {
          if (token !== state.ocrOverlayRenderToken) {
            return;
          }

          const pageWidth = Math.max(1, Math.round(image.naturalWidth || image.width || 640));
          const pageHeight = Math.max(1, Math.round(image.naturalHeight || image.height || 360));
          const box = ocrFallbackOverlayBox(ocr, structured, pageWidth, pageHeight);
          const leftPct = box.x / pageWidth * 100;
          const topPct = box.y / pageHeight * 100;
          const widthPct = box.width / pageWidth * 100;
          const heightPct = box.height / pageHeight * 100;
          const source = ocr && ocr.text ? ocr.text : structured && structured.text ? structured.text : "";
          const fontSize = Math.max(10, Math.min(18, Math.round(box.height / 5)));

          preview.innerHTML = `
            <section class="ocr-overlay-page" data-page-index="0" data-page-width="${pageWidth}" data-page-height="${pageHeight}" style="aspect-ratio: ${pageWidth} / ${pageHeight};">
              <div class="ocr-overlay-page-surface">
                <div class="ocr-overlay-block" data-block-id="fallback-translation" data-block-type="text" data-source-text="${escapeHtml(source)}" data-translated-text="${escapeHtml(text)}" data-overlay-x="${box.x}" data-overlay-y="${box.y}" data-overlay-width="${box.width}" data-overlay-height="${box.height}" style="left:${leftPct.toFixed(4)}%;top:${topPct.toFixed(4)}%;width:${widthPct.toFixed(4)}%;height:${heightPct.toFixed(4)}%;font-size:${fontSize}px;">
                  <div class="ocr-overlay-block-inner ocr-overlay-fit">${escapeHtmlLines(text)}</div>
                </div>
              </div>
            </section>`;
          applyOcrOverlayBackground(preview);
          scheduleOcrOverlayFit(preview);
          highlightOcrPreviewTarget(state.selectedOcrStructureId, { scroll: false });
        });

      return true;
    }

    function readOcrOverlayBox(node) {
      const x = Number.parseFloat(node.dataset.overlayX || "");
      const y = Number.parseFloat(node.dataset.overlayY || "");
      const width = Number.parseFloat(node.dataset.overlayWidth || "");
      const height = Number.parseFloat(node.dataset.overlayHeight || "");
      return [x, y, width, height].every(Number.isFinite) && width > 0 && height > 0
        ? { x, y, width, height }
        : null;
    }

    function ocrOverlayNodeText(node) {
      const text = node.dataset.translatedText || node.textContent || "";
      return String(text).replace(/\r\n|\r/g, "\n").trim();
    }

    function ocrComposerPercent(value, whole, max = 100) {
      return Math.max(0, Math.min(max, whole <= 0 ? 0 : value / whole * 100));
    }

    function ocrComposerFontSize(box, node, text) {
      const fit = node.querySelector("[data-fit-text]") || node;
      const min = Math.max(12, Number.parseFloat(fit.dataset.fitMin || "") || 12);
      const max = Math.max(min, Number.parseFloat(fit.dataset.fitMax || "") || 17);
      const lineCount = Math.max(1, String(text || "").split(/\n/).length);
      const estimatedWraps = Math.max(lineCount, Math.ceil(String(text || "").length / Math.max(10, box.width / 8.5)));
      const size = Math.floor((box.height - 6) / Math.max(1.05, estimatedWraps * 1.05));
      return Math.max(min, Math.min(max, size || max));
    }

    function expandOcrComposerBox(box, pageWidth, pageHeight, text, fontSize) {
      const lines = String(text || "").split(/\n/).map(line => line.trim()).filter(Boolean);
      const longest = lines.reduce((max, line) => Math.max(max, line.length), 0);
      const lineCount = Math.max(1, lines.length);
      const desiredWidth = Math.min(pageWidth * 0.5, Math.max(box.width, longest * fontSize * 0.86 + 20));
      const desiredHeight = Math.min(pageHeight * 0.28, Math.max(box.height, lineCount * fontSize * 1.42 + 12));
      const width = Math.max(box.width, desiredWidth);
      const height = Math.max(box.height, desiredHeight);
      const x = Math.min(Math.max(0, box.x - (width - box.width) / 2), Math.max(0, pageWidth - width));
      const y = Math.min(Math.max(0, box.y - (height - box.height) / 2), Math.max(0, pageHeight - height));
      return {
        x,
        y,
        width: Math.min(width, pageWidth),
        height: Math.min(height, pageHeight)
      };
    }

    function constrainOcrComposerBoxes(entries) {
      // Expanded boxes are computed per block with no knowledge of their
      // neighbours, so dense layouts end up with overlapping translations.
      // Source boxes come from the image and do not overlap, so each block may
      // claim at most half of the gap between its own source edge and any
      // neighbouring source box: facing expansions can never collide and no
      // expansion can cover a neighbour's source text.
      const margin = 2;
      for (const entry of entries) {
        const source = entry.sourceBox;
        const sourceRight = source.x + source.width;
        const sourceBottom = source.y + source.height;
        let left = entry.box.x;
        let top = entry.box.y;
        let right = entry.box.x + entry.box.width;
        let bottom = entry.box.y + entry.box.height;

        for (const other of entries) {
          if (other === entry) {
            continue;
          }

          const o = other.sourceBox;
          const oRight = o.x + o.width;
          const oBottom = o.y + o.height;
          if (o.y < bottom && oBottom > top) {
            if (o.x >= sourceRight) {
              right = Math.min(right, sourceRight + Math.max(0, (o.x - sourceRight) / 2 - margin));
            } else if (oRight <= source.x) {
              left = Math.max(left, source.x - Math.max(0, (source.x - oRight) / 2 - margin));
            }
          }
          if (o.x < right && oRight > left) {
            if (o.y >= sourceBottom) {
              bottom = Math.min(bottom, sourceBottom + Math.max(0, (o.y - sourceBottom) / 2 - margin));
            } else if (oBottom <= source.y) {
              top = Math.max(top, source.y - Math.max(0, (source.y - oBottom) / 2 - margin));
            }
          }
        }

        entry.box = { x: left, y: top, width: right - left, height: bottom - top };
      }
    }

    function renderOcrComposerStructuredOverlay(overlay, structured, fallbackPageWidth, fallbackPageHeight) {
      const html = structured && structured.overlayHtml ? String(structured.overlayHtml) : "";
      if (!html.trim()) {
        return false;
      }

      const template = document.createElement("template");
      template.innerHTML = html;
      const page = template.content.querySelector(".ocr-overlay-page");
      if (!page) {
        return false;
      }

      const pageWidth = Number.parseFloat(page.dataset.pageWidth || "") || fallbackPageWidth;
      const pageHeight = Number.parseFloat(page.dataset.pageHeight || "") || fallbackPageHeight;
      const nodes = Array.from(page.querySelectorAll(".ocr-overlay-block, .ocr-overlay-table-cell"));
      const entries = [];

      for (const node of nodes) {
        if (node.classList.contains("ocr-overlay-block") && node.querySelector(".ocr-overlay-table-cell")) {
          continue;
        }

        const blockId = overlayNodeBlockId(node);
        // blocks marked "ignored" are excluded from the rendered overlay
        if (blockId && blockIsIgnored(blockId)) {
          continue;
        }

        // edited translations (retranslate / manual) override the baked overlay text
        const text = (blockId && blockEditedTranslation(blockId)) || ocrOverlayNodeText(node);
        const sourceBox = readOcrOverlayBox(node);
        if (!text || !sourceBox) {
          continue;
        }

        const fontSize = ocrComposerFontSize(sourceBox, node, text);
        entries.push({
          node,
          text,
          sourceBox,
          fontSize,
          box: expandOcrComposerBox(sourceBox, pageWidth, pageHeight, text, fontSize)
        });
      }

      if (entries.length === 0) {
        return false;
      }

      constrainOcrComposerBoxes(entries);
      const fragment = document.createDocumentFragment();

      for (const { node, text, fontSize, box } of entries) {
        const leftPct = ocrComposerPercent(box.x, pageWidth);
        const topPct = ocrComposerPercent(box.y, pageHeight);
        const widthPct = Math.max(0.1, Math.min(100 - leftPct, ocrComposerPercent(box.width, pageWidth)));
        const heightPct = Math.max(0.1, Math.min(100 - topPct, ocrComposerPercent(box.height, pageHeight)));
        const block = document.createElement("div");
        block.className = `ocr-composer-overlay-block${node.classList.contains("ocr-overlay-table-cell") ? " is-cell" : ""}`;
        block.style.left = `${leftPct.toFixed(4)}%`;
        block.style.top = `${topPct.toFixed(4)}%`;
        block.style.width = `${widthPct.toFixed(4)}%`;
        block.style.height = `${heightPct.toFixed(4)}%`;
        block.style.setProperty("--ocr-composer-font-size", `${fontSize}px`);
        block.title = node.dataset.sourceText && node.dataset.sourceText !== text
          ? `${node.dataset.sourceText} -> ${text}`
          : text;

        const inner = document.createElement("div");
        inner.className = "ocr-composer-overlay-text";
        inner.textContent = text;
        block.appendChild(inner);
        fragment.appendChild(block);
      }

      overlay.appendChild(fragment);
      return true;
    }

    function sampleOcrRegionColor(context, imageWidth, imageHeight, pageWidth, pageHeight, box) {
      const left = Math.max(0, Math.floor(box.x / Math.max(1, pageWidth) * imageWidth));
      const top = Math.max(0, Math.floor(box.y / Math.max(1, pageHeight) * imageHeight));
      const width = Math.max(1, Math.min(imageWidth - left, Math.ceil(box.width / Math.max(1, pageWidth) * imageWidth)));
      const height = Math.max(1, Math.min(imageHeight - top, Math.ceil(box.height / Math.max(1, pageHeight) * imageHeight)));
      if (width <= 0 || height <= 0) {
        return null;
      }

      const data = context.getImageData(left, top, width, height).data;
      const stepX = Math.max(1, Math.floor(width / 12));
      const stepY = Math.max(1, Math.floor(height / 12));
      let red = 0;
      let green = 0;
      let blue = 0;
      let count = 0;

      for (let y = 0; y < height; y += stepY) {
        for (let x = 0; x < width; x += stepX) {
          const offset = (y * width + x) * 4;
          const alpha = data[offset + 3];
          if (alpha < 24) {
            continue;
          }

          red += data[offset];
          green += data[offset + 1];
          blue += data[offset + 2];
          count += 1;
        }
      }

      if (!count) {
        return null;
      }

      return {
        r: Math.round(red / count),
        g: Math.round(green / count),
        b: Math.round(blue / count)
      };
    }

    function applyOcrSampledMask(node, color) {
      const luminance = color.r * 0.2126 + color.g * 0.7152 + color.b * 0.0722;
      const text = luminance > 150 ? "#111827" : "#f8fafc";
      const alpha = luminance > 220 ? 0.98 : 0.94;
      const borderAlpha = luminance > 150 ? 0.42 : 0.58;
      node.classList.add("has-sampled-mask");
      node.style.setProperty("--ocr-mask-bg", `rgba(${color.r}, ${color.g}, ${color.b}, ${alpha})`);
      node.style.setProperty("--ocr-mask-text", text);
      node.style.setProperty("--ocr-mask-border", `rgba(${color.r}, ${color.g}, ${color.b}, ${borderAlpha})`);
    }

    async function sampleOcrOverlayMaskColors(preview, dataUrl) {
      clearOcrOverlaySampledMasks(preview);
      if (!dataUrl) {
        return;
      }

      try {
        const image = await loadOcrOverlayImage(dataUrl);
        const canvas = document.createElement("canvas");
        canvas.width = image.naturalWidth || image.width;
        canvas.height = image.naturalHeight || image.height;
        if (!canvas.width || !canvas.height) {
          return;
        }

        const context = canvas.getContext("2d", { willReadFrequently: true });
        if (!context) {
          return;
        }

        context.drawImage(image, 0, 0, canvas.width, canvas.height);

        for (const page of preview.querySelectorAll(".ocr-overlay-page")) {
          const pageWidth = Number.parseFloat(page.dataset.pageWidth || "") || canvas.width;
          const pageHeight = Number.parseFloat(page.dataset.pageHeight || "") || canvas.height;
          for (const node of page.querySelectorAll(".ocr-overlay-block, .ocr-overlay-table-cell")) {
            const box = readOcrOverlayBox(node);
            if (!box) {
              continue;
            }

            const color = sampleOcrRegionColor(context, canvas.width, canvas.height, pageWidth, pageHeight, box);
            if (color) {
              applyOcrSampledMask(node, color);
            }
          }
        }
      } catch {
        clearOcrOverlaySampledMasks(preview);
      }
    }

    function applyOcrOverlayBackground(preview) {
      const dataUrl = currentOcrImageDataUrl();
      for (const page of preview.querySelectorAll(".ocr-overlay-page")) {
        if (!dataUrl) {
          page.classList.remove("has-background");
          page.style.removeProperty("--ocr-page-image");
          continue;
        }

        page.classList.add("has-background");
        page.style.setProperty("--ocr-page-image", cssUrl(dataUrl));
      }
      sampleOcrOverlayMaskColors(preview, dataUrl).catch(() => {});
    }

    function ocrFitTextFits(node) {
      return node.scrollWidth <= node.clientWidth + 1 && node.scrollHeight <= node.clientHeight + 1;
    }

    function ocrFitTargetIdFromNode(node) {
      if (!(node instanceof Element)) {
        return "";
      }

      const target = node.closest("[data-cell-id], [data-block-id]");
      if (!target) {
        return "";
      }

      if (target.dataset.cellId) {
        const block = target.closest("[data-block-id]");
        const blockId = block && block.dataset.blockId ? block.dataset.blockId : "";
        return blockId ? `${blockId}:${target.dataset.cellId}` : target.dataset.cellId;
      }

      return target.dataset.blockId || "";
    }

    function countOcrFitDiagnostics(preview) {
      if (!preview) {
        return { total: 0, overflowing: 0, overflowIds: [] };
      }

      const nodes = Array.from(preview.querySelectorAll("[data-fit-text='true']"));
      const overflowingNodes = nodes.filter(node => node.classList.contains("is-overflowing"));
      return {
        total: nodes.length,
        overflowing: overflowingNodes.length,
        overflowIds: Array.from(new Set(overflowingNodes.map(ocrFitTargetIdFromNode).filter(Boolean)))
      };
    }

    function updateOcrFitOverflowIds(ids = []) {
      state.ocrFitOverflowIds = new Set(ids);
      syncOcrStructureSelection();
    }

    function makeOcrFitChipButton(chip, targetId) {
      if (!chip || !targetId) {
        return chip;
      }

      chip.role = "button";
      chip.tabIndex = 0;
      chip.addEventListener("click", () => selectOcrStructureTarget(targetId));
      chip.addEventListener("keydown", event => {
        if (event.key === "Enter" || event.key === " ") {
          event.preventDefault();
          selectOcrStructureTarget(targetId);
        }
      });
      return chip;
    }

    function renderOcrFitOverflowChips(target, ids = []) {
      if (!target || ids.length === 0) {
        return;
      }

      const visibleIds = ids.slice(0, 6);
      for (const id of visibleIds) {
        const chip = ocrLayoutChip(`overflow ${id}`, "warn");
        chip.dataset.ocrFitDiagnostics = "true";
        chip.dataset.ocrFitTargetId = id;
        chip.title = id;
        makeOcrFitChipButton(chip, id);
        target.appendChild(chip);
      }

      if (ids.length > visibleIds.length) {
        const chip = ocrLayoutChip(`+${ids.length - visibleIds.length} overflow`, "warn");
        chip.dataset.ocrFitDiagnostics = "true";
        chip.title = ids.slice(visibleIds.length).join(", ");
        target.appendChild(chip);
      }
    }

    function clearOcrFitDiagnostics() {
      const target = $("ocrLayoutDiagnostics");
      if (!target) {
        updateOcrFitOverflowIds();
        return;
      }

      for (const chip of target.querySelectorAll("[data-ocr-fit-diagnostics='true']")) {
        chip.remove();
      }
      updateOcrFitOverflowIds();
    }

    function renderOcrFitDiagnostics(preview) {
      const target = $("ocrLayoutDiagnostics");
      if (!target) {
        return;
      }

      clearOcrFitDiagnostics();
      const stats = countOcrFitDiagnostics(preview);
      updateOcrFitOverflowIds(stats.overflowIds);
      if (stats.total === 0) {
        return;
      }

      const chip = stats.overflowing > 0
        ? ocrLayoutChip(`fit overflow ${stats.overflowing}/${stats.total}`, "warn")
        : ocrLayoutChip(`fit ok ${stats.total}`, "good");
      chip.dataset.ocrFitDiagnostics = "true";
      if (stats.overflowIds.length > 0) {
        chip.title = stats.overflowIds.join(", ");
        makeOcrFitChipButton(chip, stats.overflowIds[0]);
      }
      target.appendChild(chip);
      renderOcrFitOverflowChips(target, stats.overflowIds);
    }

    function fitOcrOverlayText(preview) {
      if (!preview) {
        return;
      }

      for (const node of preview.querySelectorAll("[data-fit-text='true']")) {
        node.classList.remove("is-overflowing");
        node.style.removeProperty("font-size");

        if (!node.clientWidth || !node.clientHeight) {
          continue;
        }

        const min = Number.parseFloat(node.dataset.fitMin || "7");
        const max = Number.parseFloat(node.dataset.fitMax || "14");
        let low = Number.isFinite(min) ? min : 7;
        let high = Number.isFinite(max) ? max : 14;
        // The configured max is a floor for tiny blocks, not a global cap: let
        // tall blocks use their rendered height so overlay text is not crushed
        // to 14px inside a 40px-tall box.
        high = Math.min(64, Math.max(high, node.clientHeight * 0.8));
        let best = low;

        for (let attempt = 0; attempt < 8; attempt += 1) {
          const mid = (low + high) / 2;
          node.style.fontSize = `${mid.toFixed(2)}px`;
          if (ocrFitTextFits(node)) {
            best = mid;
            low = mid;
          } else {
            high = mid;
          }
        }

        node.style.fontSize = `${best.toFixed(2)}px`;
        if (!ocrFitTextFits(node)) {
          node.classList.add("is-overflowing");
        }
      }

      renderOcrFitDiagnostics(preview);
    }

    function scheduleOcrOverlayFit(preview = $("ocrDocumentPreview")) {
      window.requestAnimationFrame(() => fitOcrOverlayText(preview));
    }

    function fitOcrComposerOverlayText() {
      const overlay = $("ocrComposerOverlay");
      if (!overlay) {
        return;
      }

      for (const block of overlay.querySelectorAll(".ocr-composer-overlay-block")) {
        const text = block.querySelector(".ocr-composer-overlay-text");
        if (!text) {
          continue;
        }

        if (block.dataset.baseHeight) {
          block.style.height = block.dataset.baseHeight;
        } else {
          block.dataset.baseHeight = block.style.height;
        }
        text.style.removeProperty("font-size");
        if (!block.clientWidth || !block.clientHeight) {
          continue;
        }

        // Block geometry is in source-image pixels but renders on the scaled
        // preview, so the estimated font size can be far too large for the
        // on-screen box: re-measure against the rendered size.
        let low = 7.5;
        let high = Math.min(40, Math.max(13, block.clientHeight * 0.85));
        let best = low;
        for (let attempt = 0; attempt < 8; attempt += 1) {
          const mid = (low + high) / 2;
          text.style.fontSize = `${mid.toFixed(2)}px`;
          if (ocrFitTextFits(text)) {
            best = mid;
            low = mid;
          } else {
            high = mid;
          }
        }

        text.style.fontSize = `${best.toFixed(2)}px`;
        if (!ocrFitTextFits(text)) {
          // Even the minimum readable size does not fit: grow the box past
          // its OCR bounds instead of clipping glyphs.
          block.style.height = "auto";
        }
      }
    }

    function scheduleOcrComposerOverlayFit() {
      window.requestAnimationFrame(fitOcrComposerOverlayText);
    }

    function htmlEscape(value) {
      const node = document.createElement("div");
      node.textContent = value || "";
      return node.innerHTML;
    }

    function cssUrl(value) {
      return `url(${JSON.stringify(String(value || ""))})`;
    }

    function jsonScriptText(value) {
      return JSON.stringify(value || {}, null, 2)
        .replace(/&/g, "\\u0026")
        .replace(/</g, "\\u003c")
        .replace(/>/g, "\\u003e")
        .replace(/\u2028/g, "\\u2028")
        .replace(/\u2029/g, "\\u2029");
    }

    function controlValue(id) {
      const control = $(id);
      return control && "value" in control ? String(control.value || "").trim() : "";
    }

    function currentOcrPreviewTitle() {
      const provider = state.latestOcr && state.latestOcr.provider ? state.latestOcr.provider : "ocr";
      const engine = state.latestOcr && state.latestOcr.engine ? state.latestOcr.engine : "document";
      return `${provider}-${engine}-${state.ocrPreviewMode || "overlay"}`.replace(/[^a-z0-9._-]+/gi, "-").replace(/^-+|-+$/g, "") || "ocr-document";
    }

    function fingerprintString(value) {
      const text = String(value || "");
      if (!text) {
        return "";
      }

      let hash = 2166136261;
      for (let index = 0; index < text.length; index += 1) {
        hash ^= text.charCodeAt(index);
        hash = Math.imul(hash, 16777619);
      }

      return `fnv1a32-${(hash >>> 0).toString(16).padStart(8, "0")}`;
    }

    function currentOcrDocumentSummary(structured = state.latestOcrStructured) {
      const document = structured && structured.document ? structured.document : state.latestOcrDocument || null;
      const pages = document && Array.isArray(document.pages) ? document.pages : [];
      const segments = structured && Array.isArray(structured.segments) ? structured.segments : [];
      const summary = {
        irVersion: document && document.version ? document.version : "",
        pageCount: pages.length,
        blockCount: 0,
        textBlockCount: 0,
        tableBlockCount: 0,
        formulaBlockCount: 0,
        tableCellCount: 0,
        segmentCount: segments.length,
        translatedSegmentCount: segments.filter(segment => segment.translated).length,
        passThroughSegmentCount: segments.filter(segment => !segment.translated).length,
        cachedSegmentCount: segments.filter(segment => segment.cacheHit).length,
        errorSegmentCount: segments.filter(segment => segment.errorCode && segment.errorCode !== "0").length
      };

      function visitBlock(block) {
        if (!block) {
          return;
        }

        summary.blockCount += 1;
        const type = String(block.type || "text").toLowerCase();
        if (type === "table" || block.table) {
          summary.tableBlockCount += 1;
          summary.tableCellCount += block.table && Array.isArray(block.table.cells) ? block.table.cells.length : 0;
        } else if (type === "formula" || block.formula) {
          summary.formulaBlockCount += 1;
        } else {
          summary.textBlockCount += 1;
        }

        for (const child of block.children || []) {
          visitBlock(child);
        }
      }

      for (const page of pages) {
        for (const block of page.blocks || []) {
          visitBlock(block);
        }
      }

      return summary;
    }

    function currentOcrExportMetadata(mode, diagnostics = null) {
      const imageValue = imageBase64.value.trim();
      const route = state.ocrRoutingDecision || null;
      return {
        app: "Verbeam",
        kind: "ocr-document-export",
        generatedAt: new Date().toISOString(),
        previewMode: mode || state.ocrPreviewMode || "overlay",
        ocr: {
          requestProvider: controlValue("ocrProvider"),
          resultProvider: state.latestOcr && state.latestOcr.provider ? state.latestOcr.provider : "",
          engine: state.latestOcr && state.latestOcr.engine ? state.latestOcr.engine : "",
          language: controlValue("ocrLanguage"),
          profile: currentOcrProfile(),
          contentType: controlValue("ocrContentType"),
          preference: controlValue("ocrPreference"),
          preprocessingPreset: controlValue("ocrPreprocessingPreset") || "none",
          routeProvider: route ? route.provider || "" : "",
          routeProfile: route ? route.profile || "" : "",
          preservesStructure: route ? Boolean(route.preservesStructure) : null,
          eventId: state.latestOcr && state.latestOcr.eventId ? state.latestOcr.eventId : "",
          cacheHit: state.latestOcr && typeof state.latestOcr.cacheHit === "boolean" ? state.latestOcr.cacheHit : null,
          blockCount: state.latestOcr && Array.isArray(state.latestOcr.blocks) ? state.latestOcr.blocks.length : null
        },
        translation: {
          provider: controlValue("translationProvider"),
          model: controlValue("translationModel"),
          source: controlValue("source"),
          target: controlValue("target"),
          mode: controlValue("preset"),
          glossary: controlValue("glossary")
        },
        image: {
          mimeType: state.imageMimeType || "",
          base64Length: imageValue.length,
          fingerprintAlgorithm: "fnv1a32-base64",
          fingerprint: fingerprintString(imageValue)
        },
        document: currentOcrDocumentSummary(),
        fit: countOcrFitDiagnostics($("ocrDocumentPreview")),
        layout: diagnostics || null
      };
    }

    function cleanOcrPreviewExportClone(clone) {
      if (!clone) {
        return;
      }

      clone.classList.remove("ocr-preview-focus");
      for (const node of clone.querySelectorAll(".ocr-preview-focus")) {
        node.classList.remove("ocr-preview-focus");
      }
    }

    function ensureOcrExportPageImage(page, dataUrl) {
      if (!page || !dataUrl || page.querySelector(":scope > .ocr-export-page-image")) {
        return;
      }

      const image = document.createElement("img");
      image.className = "ocr-export-page-image";
      image.alt = "";
      image.setAttribute("aria-hidden", "true");
      image.src = dataUrl;
      page.insertBefore(image, page.firstChild);
    }

    function prepareOcrPreviewExportBody(preview, mode, fallbackBody) {
      if (!preview) {
        return fallbackBody || "";
      }

      const clone = preview.cloneNode(true);
      cleanOcrPreviewExportClone(clone);
      if (mode === "overlay") {
        const dataUrl = currentOcrImageDataUrl();
        if (dataUrl) {
          for (const page of clone.querySelectorAll(".ocr-overlay-page")) {
            page.classList.add("has-background");
            page.setAttribute("data-export-page-image", dataUrl);
            page.style.setProperty("--ocr-page-image", cssUrl(dataUrl));
            ensureOcrExportPageImage(page, dataUrl);
          }
        }
      }

      return clone.innerHTML;
    }

    function currentOcrPreviewPayload() {
      const structured = state.latestOcrStructured || null;
      const preview = $("ocrDocumentPreview");
      const mode = state.ocrPreviewMode || "overlay";
      if (!structured) {
        return null;
      }

      if (mode === "markdown") {
        const metadata = currentOcrExportMetadata(mode, structured.layoutDiagnostics || null);
        return {
          filename: `${currentOcrPreviewTitle()}.md`,
          mimeType: "text/markdown;charset=utf-8",
          text: buildOcrPreviewMarkdownDocument(structured.markdown || structured.text || "", metadata)
        };
      }

      if (preview && (mode === "overlay" || mode === "layout")) {
        fitOcrOverlayText(preview);
      }

      const fallbackBody = mode === "document"
        ? structured.html || ""
        : mode === "layout"
          ? structured.layoutHtml || structured.overlayHtml || structured.html || ""
          : structured.overlayHtml || structured.layoutHtml || structured.html || "";
      const body = prepareOcrPreviewExportBody(preview, mode, fallbackBody);
      const metadata = currentOcrExportMetadata(mode, structured.layoutDiagnostics || null);
      return {
        filename: `${currentOcrPreviewTitle()}.html`,
        mimeType: "text/html;charset=utf-8",
        text: buildOcrPreviewHtmlDocument(body, mode, structured.layoutDiagnostics || null, metadata)
      };
    }

    function currentOcrPreviewPrintPayload() {
      const payload = currentOcrPreviewPayload();
      if (!payload) {
        return null;
      }

      if ((payload.mimeType || "").startsWith("text/html")) {
        return payload;
      }

      const structured = state.latestOcrStructured || null;
      const markdown = structured ? structured.markdown || structured.text || "" : payload.text || "";
      const metadata = structured
        ? currentOcrExportMetadata("markdown", structured.layoutDiagnostics || null)
        : null;
      const body = `<pre class="ocr-export-markdown">${htmlEscape(markdown)}</pre>`;
      return {
        filename: `${currentOcrPreviewTitle()}.html`,
        mimeType: "text/html;charset=utf-8",
        text: buildOcrPreviewHtmlDocument(body, "markdown", structured ? structured.layoutDiagnostics || null : null, metadata)
      };
    }

    function buildOcrPreviewMarkdownDocument(markdown, metadata = null) {
      if (!metadata) {
        return markdown || "";
      }

      return `<!--
Verbeam OCR export metadata
${jsonScriptText(metadata)}
-->

${markdown || ""}`;
    }

    function renderOcrExportMetadata(metadata) {
      if (!metadata) {
        return "";
      }

      const fit = metadata.fit || {};
      const fitTotal = Number(fit.total || 0);
      const fitOverflowing = Number(fit.overflowing || 0);
      const fitStatus = fitOverflowing > 0 ? "overflow" : "ok";
      const fitText = fitTotal > 0
        ? `${fitStatus === "overflow" ? "overflow" : "ok"} ${fitOverflowing > 0 ? `${fitOverflowing}/` : ""}${fitTotal}`
        : "-";
      const fitIds = Array.isArray(fit.overflowIds) ? fit.overflowIds.join(", ") : "";
      const fitChip = `<span id="ocrExportFitDiagnostics" data-fit-status="${htmlEscape(fitStatus)}"${fitIds ? ` title="${htmlEscape(fitIds)}"` : ""}${fitTotal > 0 ? "" : " hidden"}><strong>fit</strong> ${htmlEscape(fitText)}</span>`;
      const documentSummary = metadata.document || {};
      const segmentSummary = Number(documentSummary.segmentCount || 0) > 0
        ? `${Number(documentSummary.translatedSegmentCount || 0)}/${Number(documentSummary.segmentCount || 0)} translated`
        : "";
      const items = [
        ["ocr", metadata.ocr && (metadata.ocr.resultProvider || metadata.ocr.requestProvider)],
        ["engine", metadata.ocr && metadata.ocr.engine],
        ["route", metadata.ocr && [metadata.ocr.routeProvider, metadata.ocr.routeProfile].filter(Boolean).join(" / ")],
        ["translate", metadata.translation && [metadata.translation.provider, metadata.translation.model].filter(Boolean).join(" / ")],
        ["lang", metadata.translation && `${metadata.translation.source || "-"} -> ${metadata.translation.target || "-"}`],
        ["mode", metadata.translation && metadata.translation.mode],
        ["doc", Number(documentSummary.pageCount || 0) > 0 ? `${Number(documentSummary.pageCount || 0)} pages` : ""],
        ["blocks", Number(documentSummary.blockCount || 0) > 0 ? documentSummary.blockCount : ""],
        ["cells", Number(documentSummary.tableCellCount || 0) > 0 ? documentSummary.tableCellCount : ""],
        ["segments", segmentSummary],
        ["profile", metadata.ocr && metadata.ocr.profile],
        ["created", metadata.generatedAt]
      ]
        .filter(([, value]) => value !== null && value !== undefined && String(value).trim())
        .map(([label, value]) => `<span><strong>${htmlEscape(label)}</strong> ${htmlEscape(String(value))}</span>`)
        .join("");

      return `<aside class="ocr-export-metadata" aria-label="OCR export metadata">${items}${fitChip}</aside>
<script id="ocrExportMetadata" type="application/json">${jsonScriptText(metadata)}<\/script>`;
    }

    function renderOcrExportDiagnostics(diagnostics, mode) {
      if (!diagnostics) {
        return "";
      }

      const issues = Array.isArray(diagnostics.issues) ? diagnostics.issues : [];
      const issueList = issues.length > 0
        ? `<ul>${issues.slice(0, 8).map(issue => `<li><code>${htmlEscape(issue.code || "ocr_layout_issue")}</code> ${htmlEscape(issue.message || "")}</li>`).join("")}</ul>`
        : "";
      const cells = Number(diagnostics.tableCellCount || 0) > 0
        ? `<span>cells ${Number(diagnostics.tableCellsWithBoundingBox || 0)}/${Number(diagnostics.tableCellCount || 0)}</span>`
        : "";
      return `<aside class="ocr-export-diagnostics" aria-label="OCR layout diagnostics">
        <strong>${htmlEscape(mode || "preview")}</strong>
        <span>${diagnostics.layoutReady ? "layout ready" : "layout partial"}</span>
        <span>${diagnostics.overlayReady ? "overlay ready" : "overlay partial"}</span>
        <span>pages ${Number(diagnostics.pagesWithSize || 0)}/${Number(diagnostics.pageCount || 0)}</span>
        <span>boxes ${Number(diagnostics.blocksWithBoundingBox || 0)}/${Number(diagnostics.blockCount || 0)}</span>
        ${cells}
        ${issues.length > 0 ? `<span>${issues.length} issue${issues.length === 1 ? "" : "s"}</span>` : ""}
        ${issueList}
      </aside>`;
    }

    function buildOcrPreviewHtmlDocument(body, mode, diagnostics = null, metadata = null) {
      const title = currentOcrPreviewTitle();
      const className = mode === "document"
        ? "document-mode"
        : mode === "layout" ? "layout-mode" : mode === "markdown" ? "markdown-mode" : "overlay-mode";
      const exportClassName = `${className}${state.ocrPreviewTrace ? " trace-active" : ""}`;
      const metadataHtml = renderOcrExportMetadata(metadata);
      const diagnosticsHtml = renderOcrExportDiagnostics(diagnostics, mode);
      return `<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>${htmlEscape(title)}</title>
  <style>
    body { margin: 0; padding: 24px; background: #0b0b0b; color: #e5e7eb; font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif; }
    .ocr-export { max-width: 1100px; margin: 0 auto; }
    .ocr-export.document-mode { background: #f8fafc; color: #111827; padding: 18px; border-radius: 8px; }
    .ocr-export-metadata { display: flex; flex-wrap: wrap; gap: 8px; align-items: center; margin: 0 0 10px; padding: 10px 12px; border: 1px solid #334155; border-radius: 8px; background: #0f172a; color: #dbeafe; font-size: 12px; }
    .ocr-export-metadata span { display: inline-flex; align-items: center; gap: 5px; min-height: 22px; padding: 0 7px; border: 1px solid #1e3a8a; border-radius: 999px; background: #111827; }
    .ocr-export-metadata span[data-fit-status="overflow"] { border-color: #854d0e; background: #451a03; color: #fde68a; }
    .ocr-export-metadata span[data-fit-status="ok"] { border-color: #166534; background: #052e16; color: #bbf7d0; }
    .ocr-export-metadata strong { color: #93c5fd; font-weight: 650; }
    .ocr-export-diagnostics { display: flex; flex-wrap: wrap; gap: 8px; align-items: center; margin: 0 0 14px; padding: 10px 12px; border: 1px solid #3f3f46; border-radius: 8px; background: #111827; color: #e5e7eb; font-size: 12px; }
    .ocr-export-diagnostics strong { color: #f8fafc; }
    .ocr-export-diagnostics span { display: inline-flex; align-items: center; min-height: 22px; padding: 0 7px; border: 1px solid #334155; border-radius: 999px; background: #0f172a; }
    .ocr-export-diagnostics ul { flex-basis: 100%; margin: 2px 0 0; padding-left: 18px; color: #cbd5e1; }
    .ocr-export-diagnostics code { color: #fde68a; }
    .ocr-export.trace-active [data-source-text]:not([data-source-text=""]) { outline: 1px dashed rgba(96,165,250,.52); outline-offset: -1px; }
    .ocr-export.trace-active .ocr-render-text[data-source-text]::after,
    .ocr-export.trace-active .ocr-render-formula[data-source-text]::after,
    .ocr-export.trace-active .ocr-render-table [data-source-text]::after { content: "src: " attr(data-source-text); display: block; margin-top: 5px; padding-top: 4px; border-top: 1px dashed rgba(96,165,250,.42); color: #64748b; font-family: ui-monospace, SFMono-Regular, Consolas, monospace; font-size: 10px; line-height: 1.2; word-break: break-word; }
    .ocr-export.trace-active .ocr-overlay-block[data-source-text]:not([data-source-text=""])::after,
    .ocr-export.trace-active .ocr-overlay-table-cell[data-source-text]:not([data-source-text=""])::after,
    .ocr-export.trace-active .ocr-layout-block[data-source-text]:not([data-source-text=""])::after,
    .ocr-export.trace-active .ocr-layout-table-cell[data-source-text]:not([data-source-text=""])::after { content: "src: " attr(data-source-text); position: absolute; left: 3px; right: 3px; bottom: 3px; max-height: 44%; overflow: hidden; padding: 2px 4px; border: 1px solid rgba(96,165,250,.44); border-radius: 4px; background: rgba(15,23,42,.84); color: #dbeafe; font-family: ui-monospace, SFMono-Regular, Consolas, monospace; font-size: 9px; line-height: 1.15; pointer-events: none; text-align: left; word-break: break-word; }
    .ocr-render-document { display: grid; gap: 16px; }
    .ocr-render-page { display: grid; gap: 12px; min-width: 0; padding: 18px; border: 1px solid #d4d4d8; border-radius: 6px; background: #fff; color: #111827; box-shadow: 0 8px 24px rgba(15, 23, 42, .12); }
    .ocr-render-text { margin: 0; white-space: normal; word-break: break-word; }
    .ocr-render-formula { overflow-x: auto; border: 1px solid #d4d4d8; border-radius: 6px; background: #f4f4f5; padding: 10px; font-family: ui-monospace, SFMono-Regular, Consolas, monospace; color: #1f2937; }
    .ocr-render-table { width: 100%; border-collapse: collapse; font-size: 12px; background: #fff; }
    .ocr-render-table th, .ocr-render-table td { border: 1px solid #d4d4d8; padding: 8px 9px; vertical-align: top; word-break: break-word; }
    .ocr-render-table th { color: #111827; background: #eef2ff; font-weight: 650; }
    .ocr-export-markdown { margin: 0; white-space: pre-wrap; word-break: break-word; font-family: ui-monospace, SFMono-Regular, Consolas, monospace; font-size: 12px; line-height: 1.5; }
    .ocr-overlay-document { display: grid; gap: 14px; }
    .ocr-overlay-page { position: relative; width: min(100%, 860px); overflow: hidden; border: 1px solid #2d2d2d; border-radius: 8px; background: #171717; box-shadow: inset 0 0 0 1px rgba(255,255,255,.02); }
    .ocr-overlay-page.has-background { background-image: var(--ocr-page-image); background-size: 100% 100%; background-position: center; background-repeat: no-repeat; }
    .ocr-export-page-image { position: absolute; inset: 0; z-index: 0; width: 100%; height: 100%; object-fit: fill; pointer-events: none; user-select: none; }
    .ocr-overlay-page-surface { position: absolute; inset: 0; z-index: 1; background: rgba(8,8,8,.2); }
    .ocr-overlay-block, .ocr-overlay-table-cell { position: absolute; min-width: 0; min-height: 0; overflow: hidden; border: 1px solid var(--ocr-mask-border, rgba(96,165,250,.44)); background: var(--ocr-mask-bg, rgba(9,14,24,.9)); color: var(--ocr-mask-text, #f8fafc); font-size: 11px; line-height: 1.22; word-break: break-word; box-shadow: 0 0 0 1px rgba(2,6,23,.28); }
    .ocr-overlay-block-inner { position: relative; width: 100%; height: 100%; overflow: hidden; padding: 4px 5px; }
    .ocr-overlay-fit { display: block; width: 100%; height: 100%; overflow: hidden; text-wrap: pretty; }
    .ocr-overlay-fit.is-overflowing { outline: 1px solid rgba(239,68,68,.78); outline-offset: -1px; }
    .ocr-overlay-formula { border-color: rgba(214,184,106,.72); background: rgba(38,30,12,.82); color: #fde68a; font-family: ui-monospace, SFMono-Regular, Consolas, monospace; }
    .ocr-overlay-table-grid { position: absolute; inset: 0; }
    .ocr-overlay-table-cell { display: flex; align-items: flex-start; padding: 4px 5px; border-color: rgba(34,197,94,.46); }
    .ocr-overlay-table-cell .ocr-overlay-fit { flex: 1 1 auto; }
    .ocr-overlay-table-cell-header { font-weight: 650; }
    .ocr-layout-document { display: grid; gap: 14px; }
    .ocr-layout-page { position: relative; width: min(100%, 860px); overflow: hidden; border: 1px solid #d4d4d8; border-radius: 8px; background: #fff; box-shadow: 0 12px 30px rgba(15,23,42,.14); }
    .ocr-layout-page-surface { position: absolute; inset: 0; }
    .ocr-layout-block, .ocr-layout-table-cell { position: absolute; min-width: 0; min-height: 0; overflow: hidden; border: 1px solid rgba(148,163,184,.82); background: rgba(255,255,255,.96); color: #111827; font-size: 11px; line-height: 1.22; word-break: break-word; }
    .ocr-layout-block-inner { position: relative; width: 100%; height: 100%; overflow: hidden; padding: 4px 5px; }
    .ocr-layout-fit { display: block; width: 100%; height: 100%; overflow: hidden; text-wrap: pretty; }
    .ocr-layout-fit.is-overflowing { outline: 1px solid rgba(239,68,68,.78); outline-offset: -1px; }
    .ocr-layout-formula { border-color: rgba(161,98,7,.58); background: #fffbeb; color: #713f12; font-family: ui-monospace, SFMono-Regular, Consolas, monospace; }
    .ocr-layout-table { border-color: rgba(22,163,74,.58); background: #f0fdf4; }
    .ocr-layout-table-grid { position: absolute; inset: 0; }
    .ocr-layout-table-cell { display: flex; align-items: flex-start; padding: 4px 5px; border-color: rgba(34,197,94,.48); background: rgba(255,255,255,.98); }
    .ocr-layout-table-cell .ocr-layout-fit { flex: 1 1 auto; }
    .ocr-layout-table-cell-header { color: #111827; background: #dcfce7; font-weight: 650; }
    @media print {
      body { background: #fff; color: #111827; padding: 0; }
      .ocr-export { max-width: none; margin: 0; }
      .ocr-overlay-page, .ocr-layout-page, .ocr-render-page { break-inside: avoid; box-shadow: none; }
    }
  </style>
</head>
<body>
  <main class="ocr-export ${exportClassName}">
${metadataHtml}
${diagnosticsHtml}
${body}
  </main>
  <script>
    (function () {
      function cssUrl(value) {
        return "url(" + JSON.stringify(String(value || "")) + ")";
      }

      document.querySelectorAll(".ocr-overlay-page[data-export-page-image]").forEach(function (page) {
        var image = page.getAttribute("data-export-page-image");
        if (!image) {
          return;
        }

        page.classList.add("has-background");
        if (!page.querySelector(":scope > .ocr-export-page-image")) {
          var imageNode = document.createElement("img");
          imageNode.className = "ocr-export-page-image";
          imageNode.alt = "";
          imageNode.setAttribute("aria-hidden", "true");
          imageNode.src = image;
          page.insertBefore(imageNode, page.firstChild);
        }

        if (!page.style.getPropertyValue("--ocr-page-image")) {
          page.style.setProperty("--ocr-page-image", cssUrl(image));
        }
      });

      function fits(node) {
        return node.scrollWidth <= node.clientWidth + 1 && node.scrollHeight <= node.clientHeight + 1;
      }

      function fitTargetIdFromNode(node) {
        var target = node && node.closest ? node.closest("[data-cell-id], [data-block-id]") : null;
        if (!target) {
          return "";
        }

        if (target.dataset.cellId) {
          var block = target.closest("[data-block-id]");
          var blockId = block && block.dataset.blockId ? block.dataset.blockId : "";
          return blockId ? blockId + ":" + target.dataset.cellId : target.dataset.cellId;
        }

        return target.dataset.blockId || "";
      }

      function updateOcrExportMetadataFit(fit) {
        var script = document.getElementById("ocrExportMetadata");
        if (!script) {
          return;
        }

        try {
          var metadata = JSON.parse(script.textContent || "{}");
          metadata.fit = fit;
          script.textContent = JSON.stringify(metadata, null, 2);
        } catch {
        }
      }

      function updateOcrExportFitDiagnostics() {
        var target = document.getElementById("ocrExportFitDiagnostics");
        if (!target) {
          return;
        }

        var nodes = Array.prototype.slice.call(document.querySelectorAll("[data-fit-text='true']"));
        if (!nodes.length) {
          target.hidden = true;
          target.textContent = "";
          updateOcrExportMetadataFit({ total: 0, overflowing: 0, overflowIds: [] });
          return;
        }

        var overflowing = nodes.filter(function (node) {
          return node.classList.contains("is-overflowing");
        }).length;
        var ids = nodes.filter(function (node) {
          return node.classList.contains("is-overflowing");
        }).map(fitTargetIdFromNode).filter(Boolean).filter(function (id, index, values) {
          return values.indexOf(id) === index;
        });
        var status = overflowing > 0 ? "overflow" : "ok";
        target.hidden = false;
        target.dataset.fitStatus = status;
        target.title = ids.join(", ");
        target.innerHTML = "<strong>fit</strong> " + (overflowing > 0 ? "overflow " + overflowing + "/" + nodes.length : "ok " + nodes.length);
        updateOcrExportMetadataFit({ total: nodes.length, overflowing: overflowing, overflowIds: ids });
      }

      window.fitOcrExportText = function fitOcrExportText() {
        document.querySelectorAll("[data-fit-text='true']").forEach(function (node) {
          node.classList.remove("is-overflowing");
          node.style.removeProperty("font-size");
          if (!node.clientWidth || !node.clientHeight) {
            return;
          }

          var min = Number.parseFloat(node.dataset.fitMin || "7");
          var max = Number.parseFloat(node.dataset.fitMax || "14");
          var low = Number.isFinite(min) ? min : 7;
          var high = Number.isFinite(max) ? max : 14;
          // Same as the live overlay: scale the cap with the rendered box so
          // exported pages keep readable text in tall blocks.
          high = Math.min(64, Math.max(high, node.clientHeight * 0.8));
          var best = low;
          for (var attempt = 0; attempt < 8; attempt += 1) {
            var mid = (low + high) / 2;
            node.style.fontSize = mid.toFixed(2) + "px";
            if (fits(node)) {
              best = mid;
              low = mid;
            } else {
              high = mid;
            }
          }

          node.style.fontSize = best.toFixed(2) + "px";
          if (!fits(node)) {
            node.classList.add("is-overflowing");
          }
        });
        updateOcrExportFitDiagnostics();
      };

      window.addEventListener("load", window.fitOcrExportText);
      window.addEventListener("resize", function () {
        window.requestAnimationFrame(window.fitOcrExportText);
      });
      window.requestAnimationFrame(window.fitOcrExportText);
    }());
  <\/script>
</body>
</html>`;
    }

    async function copyOcrPreview() {
      const payload = currentOcrPreviewPayload();
      if (!payload || !payload.text.trim()) {
        appendMessage("error", "ocr preview", "nothing to copy");
        return;
      }

      await navigator.clipboard.writeText(payload.text);
      appendMessage("result", "ocr preview", "copied current preview", state.ocrPreviewMode || "overlay");
    }

    async function copyOcrResultText(kind) {
      const isTranslation = kind === "translation";
      const control = isTranslation ? ocrTranslationOutput : ocrOutput;
      const label = isTranslation ? "translation" : "ocr text";
      const text = control ? control.value.trim() : "";
      if (!text) {
        appendMessage("error", label, "nothing to copy");
        return;
      }

      await navigator.clipboard.writeText(text);
      appendMessage("result", label, "copied");
    }

    function downloadOcrPreview() {
      const payload = currentOcrPreviewPayload();
      if (!payload || !payload.text.trim()) {
        appendMessage("error", "ocr preview", "nothing to download");
        return;
      }

      const blob = new Blob([payload.text], { type: payload.mimeType });
      const url = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = payload.filename;
      document.body.appendChild(link);
      link.click();
      link.remove();
      window.setTimeout(() => URL.revokeObjectURL(url), 1000);
      appendMessage("result", "ocr preview", payload.filename, "download");
    }

    function openOcrPreview() {
      const payload = currentOcrPreviewPrintPayload();
      if (!payload || !payload.text.trim()) {
        appendMessage("error", "ocr preview", "nothing to open");
        return;
      }

      const previewWindow = window.open("", "_blank");
      if (!previewWindow) {
        appendMessage("error", "ocr preview", "preview window blocked");
        return;
      }

      previewWindow.document.open();
      previewWindow.document.write(payload.text);
      previewWindow.document.close();
      try {
        previewWindow.focus();
      } catch {
      }
      appendMessage("result", "ocr preview", payload.filename, "open");
    }

    function printOcrPreview() {
      const payload = currentOcrPreviewPrintPayload();
      if (!payload || !payload.text.trim()) {
        appendMessage("error", "ocr preview", "nothing to print");
        return;
      }

      const printWindow = window.open("", "_blank");
      if (!printWindow) {
        appendMessage("error", "ocr preview", "print window blocked");
        return;
      }

      printWindow.document.open();
      printWindow.document.write(payload.text);
      printWindow.document.close();
      let printStarted = false;
      const runPrint = () => {
        if (printStarted) {
          return;
        }

        printStarted = true;
        try {
          printWindow.focus();
          printWindow.print();
        } catch {
        }
      };
      printWindow.addEventListener("load", () => window.setTimeout(runPrint, 150), { once: true });
      window.setTimeout(runPrint, 600);
      appendMessage("result", "ocr preview", payload.filename, "print");
    }

    function setOcrPreviewModeButtons(mode) {
      const normalized = ["overlay", "layout", "document", "markdown"].includes(mode) ? mode : "overlay";
      state.ocrPreviewMode = normalized;
      for (const button of document.querySelectorAll("[data-ocr-preview-mode]")) {
        button.classList.toggle("active", button.dataset.ocrPreviewMode === normalized);
      }

      updateOcrSectionMeta("ocrPreview", state.ocrPreviewCollapsed);
      return normalized;
    }

    function setOcrPreviewMode(mode) {
      setOcrPreviewModeButtons(mode);

      renderOcrDocumentPreview(state.latestOcr, state.latestOcrStructured);
    }

    function setOcrPreviewTrace(enabled) {
      state.ocrPreviewTrace = Boolean(enabled);
      const button = $("ocrPreviewTraceButton");
      if (button) {
        button.classList.toggle("active", state.ocrPreviewTrace);
        button.setAttribute("aria-pressed", state.ocrPreviewTrace ? "true" : "false");
      }

      renderOcrDocumentPreview(state.latestOcr, state.latestOcrStructured);
    }

    function cssEscape(value) {
      return window.CSS && typeof window.CSS.escape === "function"
        ? window.CSS.escape(value)
        : String(value || "").replace(/["\\]/g, "\\$&");
    }

    function findOcrPreviewTarget(targetId) {
      const preview = $("ocrDocumentPreview");
      const id = String(targetId || "").trim();
      if (!preview || !id) {
        return null;
      }

      const separator = id.indexOf(":");
      if (separator > 0) {
        const blockId = id.slice(0, separator);
        const cellId = id.slice(separator + 1);
        return preview.querySelector(`[data-block-id="${cssEscape(blockId)}"] [data-cell-id="${cssEscape(cellId)}"]`) ||
          preview.querySelector(`[data-cell-id="${cssEscape(cellId)}"]`);
      }

      return preview.querySelector(`[data-block-id="${cssEscape(id)}"]`);
    }

    function syncOcrStructureSelection() {
      for (const row of ocrStructureTable.querySelectorAll("[data-ocr-target-id]")) {
        const rowId = row.dataset.ocrTargetId || "";
        const selected = state.selectedBlockIds.has(rowId) || rowId === state.selectedOcrStructureId;
        const primary = rowId === state.selectedOcrStructureId;
        row.classList.toggle("active", selected);
        row.classList.toggle("is-primary", primary);
        row.classList.toggle("fit-overflow", state.ocrFitOverflowIds.has(rowId));
        row.setAttribute("aria-selected", selected ? "true" : "false");
      }
    }

    function renderOcrStructureSelectionDetails(item = state.selectedOcrStructureItem) {
      const container = $("ocrStructureSelection");
      const type = $("ocrStructureSelectionType");
      const route = $("ocrStructureSelectionRoute");
      const id = $("ocrStructureSelectionId");
      const source = $("ocrStructureSelectionSource");
      const output = $("ocrStructureSelectionOutput");
      if (!type || !route || !id || !source || !output) {
        return;
      }

      if (container) {
        container.classList.toggle("is-empty", !item);
      }

      if (!item) {
        type.textContent = "no selection";
        route.textContent = "-";
        id.textContent = "-";
        source.textContent = "";
        output.textContent = "";
        return;
      }

      type.textContent = item.type || "-";
      route.textContent = item.route || "-";
      id.textContent = item.id || "-";
      source.textContent = item.source || "";
      output.textContent = item.output || "";
    }

    function scrollOcrStructureSelection(options = {}) {
      if (!state.selectedOcrStructureId) {
        return;
      }

      const row = ocrStructureTable.querySelector(`[data-ocr-target-id="${cssEscape(state.selectedOcrStructureId)}"]`);
      if (row && options.scroll !== false) {
        row.scrollIntoView({ block: "nearest", inline: "nearest", behavior: "smooth" });
      }
    }

    function highlightOcrPreviewTarget(targetId = state.selectedOcrStructureId, options = {}) {
      const preview = $("ocrDocumentPreview");
      if (!preview) {
        return;
      }

      for (const node of preview.querySelectorAll(".ocr-preview-focus")) {
        node.classList.remove("ocr-preview-focus");
      }

      const target = findOcrPreviewTarget(targetId);
      if (!target) {
        return;
      }

      target.classList.add("ocr-preview-focus");
      if (options.scroll !== false) {
        target.scrollIntoView({ block: "nearest", inline: "nearest", behavior: "smooth" });
      }
    }

    function selectOcrStructureTarget(targetId) {
      selectSingleBlock(String(targetId || ""));
      scrollOcrStructureSelection();
    }

    function onStructureRowClick(event, targetId) {
      const id = String(targetId || "");
      if (event.shiftKey) {
        selectBlockRangeTo(id);
      } else if (event.ctrlKey || event.metaKey) {
        toggleBlockSelection(id);
      } else {
        selectSingleBlock(id);
      }
    }

    function ocrPreviewTargetIdFromElement(element) {
      const preview = $("ocrDocumentPreview");
      if (!preview || !(element instanceof Element) || !preview.contains(element)) {
        return "";
      }

      const target = element.closest("[data-cell-id], [data-block-id]");
      if (!target || !preview.contains(target)) {
        return "";
      }

      if (target.dataset.cellId) {
        const block = target.closest("[data-block-id]");
        const blockId = block && block.dataset.blockId ? block.dataset.blockId : "";
        return blockId ? `${blockId}:${target.dataset.cellId}` : target.dataset.cellId;
      }

      return target.dataset.blockId || "";
    }

    function selectOcrStructureFromPreview(event) {
      const targetId = ocrPreviewTargetIdFromElement(event.target);
      if (!targetId) {
        return;
      }

      selectOcrStructureTarget(targetId);
    }

    function setOcrPreviewClass(preview, mode) {
      preview.classList.toggle("overlay-mode", mode === "overlay");
      preview.classList.toggle("layout-mode", mode === "layout");
      preview.classList.toggle("document-mode", mode === "document");
      preview.classList.toggle("markdown-mode", mode === "markdown");
      preview.classList.toggle("trace-active", Boolean(state.ocrPreviewTrace) && mode !== "markdown");
    }

    function renderOcrDocumentPreview(ocr = null, structured = null) {
      const preview = $("ocrDocumentPreview");
      if (!preview) {
        return;
      }

      const mode = state.ocrPreviewMode || "overlay";
      state.ocrOverlayRenderToken++;
      preview.classList.remove("overlay-mode", "layout-mode", "document-mode", "markdown-mode");
      clearOcrFitDiagnostics();

      if (mode === "overlay" && structured && structured.overlayHtml) {
        setOcrPreviewClass(preview, "overlay");
        preview.innerHTML = structured.overlayHtml;
        applyOcrOverlayBackground(preview);
        scheduleOcrOverlayFit(preview);
        highlightOcrPreviewTarget(state.selectedOcrStructureId, { scroll: false });
        return;
      }

      if (mode === "layout" && structured && structured.layoutHtml) {
        setOcrPreviewClass(preview, "layout");
        preview.innerHTML = structured.layoutHtml;
        scheduleOcrOverlayFit(preview);
        highlightOcrPreviewTarget(state.selectedOcrStructureId, { scroll: false });
        return;
      }

      if ((mode === "document" || mode === "overlay" || mode === "layout") && structured && structured.html) {
        setOcrPreviewClass(preview, "document");
        preview.innerHTML = structured.html;
        highlightOcrPreviewTarget(state.selectedOcrStructureId, { scroll: false });
        return;
      }

      if (structured && structured.markdown) {
        setOcrPreviewClass(preview, "markdown");
        preview.textContent = structured.markdown;
        return;
      }

      if ((structured && structured.document) || (ocr && ocr.document)) {
        setOcrPreviewClass(preview, mode);
        preview.textContent = "Structured preview is available after OCR translation.";
        return;
      }

      setOcrPreviewClass(preview, mode);
      preview.textContent = "No structured preview.";
    }

    function ocrLayoutChip(text, kind = "") {
      const chip = document.createElement("span");
      chip.className = `ocr-layout-chip ${kind}`.trim();
      chip.textContent = text;
      return chip;
    }

    function renderOcrLayoutDiagnostics(structured = null) {
      const target = $("ocrLayoutDiagnostics");
      if (!target) {
        return;
      }

      target.innerHTML = "";
      const diagnostics = structured && structured.layoutDiagnostics ? structured.layoutDiagnostics : null;
      target.classList.toggle("hidden", !diagnostics);
      if (!diagnostics) {
        return;
      }

      const issues = Array.isArray(diagnostics.issues) ? diagnostics.issues : [];
      const issueKind = issues.some(issue => issue.severity === "error") ? "error" : issues.length > 0 ? "warn" : "good";
      target.appendChild(ocrLayoutChip(diagnostics.overlayReady ? "overlay ready" : "overlay partial", diagnostics.overlayReady ? "good" : issueKind));
      target.appendChild(ocrLayoutChip(diagnostics.layoutReady ? "layout ready" : "layout partial", diagnostics.layoutReady ? "good" : issueKind));
      target.appendChild(ocrLayoutChip(`pages ${Number(diagnostics.pagesWithSize || 0)}/${Number(diagnostics.pageCount || 0)}`, Number(diagnostics.pagesWithSize || 0) === Number(diagnostics.pageCount || 0) ? "good" : "warn"));
      target.appendChild(ocrLayoutChip(`boxes ${Number(diagnostics.blocksWithBoundingBox || 0)}/${Number(diagnostics.blockCount || 0)}`, Number(diagnostics.blocksMissingBoundingBox || 0) === 0 ? "good" : "warn"));
      if (Number(diagnostics.tableCellCount || 0) > 0) {
        target.appendChild(ocrLayoutChip(`cells ${Number(diagnostics.tableCellsWithBoundingBox || 0)}/${Number(diagnostics.tableCellCount || 0)}`, Number(diagnostics.tableCellsMissingBoundingBox || 0) === 0 ? "good" : "warn"));
      }

      if (issues.length > 0) {
        const first = issues[0];
        const chip = ocrLayoutChip(`${issues.length} issue${issues.length === 1 ? "" : "s"}`, issueKind);
        chip.title = first.message || first.code || "";
        target.appendChild(chip);
      }
    }

    function renderOcrStructure(ocr = null, structured = null, summary = null) {
      state.latestOcr = ocr || null;
      state.latestOcrDocument = structured && structured.document ? structured.document : ocr && ocr.document ? ocr.document : null;
      state.latestOcrStructured = structured || null;
      ocrStructureTable.innerHTML = "";
      renderOcrDocumentPreview(ocr, structured);
      renderOcrLayoutDiagnostics(structured);

      const rows = flattenOcrStructureRows(ocr, structured);
      if (rows.length === 0 && summary) {
        rows.push({
          id: "summary",
          type: "summary",
          source: formatOcrStructureSummary(summary),
          output: `${Number(summary.translatableCellCount || 0)} translatable / ${Number(summary.invalidTableCellCount || 0)} invalid / ${Number(summary.missingTableCellCount || 0)} missing / ${Number(summary.overlappingTableCellCount || 0)} overlap`,
          route: "smoke history"
        });
      }

      state.latestOcrStructureRows = rows;
      updateOcrSectionMeta("ocrStructure", state.ocrStructureCollapsed);
      if (rows.length === 0) {
        state.selectedOcrStructureId = "";
        state.selectedOcrStructureItem = null;
        renderOcrStructureSelectionDetails();
        const row = document.createElement("tr");
        const cell = document.createElement("td");
        cell.colSpan = 6;
        cell.textContent = "No structure segments.";
        row.appendChild(cell);
        ocrStructureTable.appendChild(row);
        return;
      }

      if (!rows.some(item => item.id === state.selectedOcrStructureId)) {
        state.selectedOcrStructureId = "";
      }
      state.selectedOcrStructureItem = rows.find(item => item.id === state.selectedOcrStructureId) || null;

      const lowOnly = state.blockListLowConfidenceOnly;
      for (const item of rows) {
        if (lowOnly && !(Number(item.confidence) > 0 && Number(item.confidence) < state.lowConfidenceThreshold)) {
          continue;
        }

        const row = document.createElement("tr");
        row.setAttribute("data-ocr-target-id", item.id || "");
        row.tabIndex = 0;
        row.setAttribute("aria-selected", "false");
        row.addEventListener("click", event => onStructureRowClick(event, item.id));
        row.addEventListener("keydown", event => {
          if (event.key === "Enter" || event.key === " ") {
            event.preventDefault();
            selectOcrStructureTarget(item.id);
          }
        });

        const status = blockStatusFor(item);
        const confidenceText = typeof item.confidence === "number" && item.confidence > 0
          ? `${Math.round(item.confidence * 100)}%`
          : "-";
        const cells = [item.type, shortText(item.source, 180), shortText(item.output, 180), item.route, confidenceText, status];
        cells.forEach((value, index) => {
          const cell = document.createElement("td");
          cell.textContent = value || "-";
          if (index === 4 && Number(item.confidence) > 0 && Number(item.confidence) < state.lowConfidenceThreshold) {
            cell.classList.add("ocr-conf-low");
          }

          if (index === 5) {
            cell.classList.add(`ocr-status-${status}`);
          }

          row.appendChild(cell);
        });

        row.title = item.id;
        ocrStructureTable.appendChild(row);
      }

      syncOcrStructureSelection();
      renderOcrStructureSelectionDetails();
      updateOcrSectionMeta("ocrStructure", state.ocrStructureCollapsed);
      highlightOcrPreviewTarget(state.selectedOcrStructureId, { scroll: false });
    }

    // ===================================================================
    // OCR Block Workbench: selectable bbox canvas + multi-select model.
    // The selection layer renders one positioned div per OCR block on top
    // of the source image; selection state (state.selectedBlockIds) is the
    // single source of truth shared by the canvas, the structure list, and
    // the inspector.
    // ===================================================================

    function ocrBlockImageHash() {
      const ocr = state.latestOcr;
      return ocr && (ocr.imageHash || ocr.ImageHash) ? String(ocr.imageHash || ocr.ImageHash) : "";
    }

    function overlayNodeBlockId(node) {
      if (!(node instanceof Element)) {
        return "";
      }

      if (node.dataset.cellId) {
        const parent = node.closest("[data-block-id]");
        const blockId = parent && parent.dataset.blockId ? parent.dataset.blockId : "";
        return blockId ? `${blockId}:${node.dataset.cellId}` : node.dataset.cellId;
      }

      return node.dataset.blockId || "";
    }

    function collectSelectableBlocks() {
      const out = [];
      const doc = state.latestOcrDocument || (state.latestOcr && state.latestOcr.document) || null;
      if (!doc || !Array.isArray(doc.pages)) {
        return out;
      }

      const image = $("ocrImagePreviewImg");
      const fallbackW = image ? image.naturalWidth : 0;
      const fallbackH = image ? image.naturalHeight : 0;
      const segById = new Map(((state.latestOcrStructured && state.latestOcrStructured.segments) || []).map(s => [s.id, s]));

      function pushBlock(block, pageW, pageH) {
        if (!block) {
          return;
        }

        if (block.table && Array.isArray(block.table.cells)) {
          for (const cell of block.table.cells) {
            const cellBox = normalizeOcrBoundingBox(cell.boundingBox || cell.BoundingBox);
            if (!cellBox) {
              continue;
            }

            const cellId = `${block.id}:${cell.id || `r${cell.rowIndex}-c${cell.columnIndex}`}`;
            const seg = segById.get(cellId);
            out.push({
              id: cellId,
              type: "table_cell",
              text: cell.text || "",
              sourceText: blockEditedSource(cellId) || (seg ? seg.sourceText : cell.sourceText) || cell.text || "",
              translation: blockEditedTranslation(cellId) || (seg ? seg.translatedText : ""),
              confidence: typeof cell.confidence === "number" ? cell.confidence : 1,
              box: cellBox,
              readingOrder: Number(cell.rowIndex || 0) * 1000 + Number(cell.columnIndex || 0),
              engine: block.engine || "",
              language: cell.detectedLanguage || "",
              isCell: true,
              pageWidth: pageW,
              pageHeight: pageH
            });
          }
        } else {
          const box = normalizeOcrBoundingBox(block.boundingBox || block.BoundingBox);
          if (box) {
            const seg = segById.get(block.id);
            out.push({
              id: block.id,
              type: block.type || "text",
              text: block.text || "",
              sourceText: blockEditedSource(block.id) || (seg ? seg.sourceText : block.sourceText) || block.text || "",
              translation: blockEditedTranslation(block.id) || (seg ? seg.translatedText : ""),
              confidence: typeof block.confidence === "number" ? block.confidence : 1,
              box,
              readingOrder: typeof block.readingOrder === "number" ? block.readingOrder : out.length,
              engine: block.engine || "",
              language: block.detectedLanguage || "",
              isCell: false,
              pageWidth: pageW,
              pageHeight: pageH
            });
          }
        }

        for (const child of block.children || []) {
          pushBlock(child, pageW, pageH);
        }
      }

      for (const page of doc.pages) {
        const pageW = Number(page.width || page.Width) || fallbackW;
        const pageH = Number(page.height || page.Height) || fallbackH;
        for (const block of page.blocks || []) {
          pushBlock(block, pageW, pageH);
        }
      }

      return out;
    }

    function blockAnnotationFor(id) {
      return state.blockAnnotations.get(id) || null;
    }

    function blockStatusFor(item) {
      const annotation = blockAnnotationFor(item.id);
      if (annotation && annotation.status) {
        return annotation.status;
      }

      return "translated";
    }

    function blockLockedFor(id) {
      const annotation = blockAnnotationFor(id);
      return Boolean(annotation && (annotation.locked || annotation.status === "locked"));
    }

    function blockEditedTranslation(id) {
      const annotation = blockAnnotationFor(id);
      return annotation && annotation.editedTranslation ? annotation.editedTranslation : "";
    }

    function blockEditedSource(id) {
      const annotation = blockAnnotationFor(id);
      return annotation && annotation.editedSource ? annotation.editedSource : "";
    }

    function blockIsIgnored(id) {
      const annotation = blockAnnotationFor(id);
      return Boolean(annotation && annotation.status === "ignored");
    }

    function isBlockLowConfidence(item) {
      return Number(item.confidence) > 0 && Number(item.confidence) < state.lowConfidenceThreshold;
    }

    function buildBlockReadingOrder(blocks) {
      const ordered = blocks.slice().sort((a, b) => {
        if (a.readingOrder !== b.readingOrder) {
          return a.readingOrder - b.readingOrder;
        }

        const ay = a.box ? a.box.y : 0;
        const by = b.box ? b.box.y : 0;
        if (ay !== by) {
          return ay - by;
        }

        return (a.box ? a.box.x : 0) - (b.box ? b.box.x : 0);
      });
      const indexById = new Map();
      ordered.forEach((item, index) => indexById.set(item.id, index + 1));
      return { ordered, indexById };
    }

    function renderBlockSelectLayer() {
      const layer = $("ocrBlockSelectLayer");
      if (!layer) {
        return;
      }

      const blocks = collectSelectableBlocks();
      state.selectableBlocks = blocks;
      const order = buildBlockReadingOrder(blocks);
      state.blockReadingOrder = order;

      for (const node of Array.from(layer.querySelectorAll(".ocr-block-box"))) {
        node.remove();
      }

      const hasImage = Boolean(currentOcrImageDataUrl());
      // prune selection that no longer maps to a block
      const liveIds = new Set(blocks.map(item => item.id));
      for (const id of Array.from(state.selectedBlockIds)) {
        if (!liveIds.has(id)) {
          state.selectedBlockIds.delete(id);
        }
      }

      if (!hasImage || blocks.length === 0) {
        layer.classList.add("hidden");
        return;
      }

      layer.classList.remove("hidden");
      const fragment = document.createDocumentFragment();
      for (const item of blocks) {
        const pageW = item.pageWidth;
        const pageH = item.pageHeight;
        if (!pageW || !pageH || !item.box) {
          continue;
        }

        const div = document.createElement("div");
        div.className = "ocr-block-box";
        div.dataset.blockId = item.id;
        div.style.left = `${(item.box.x / pageW * 100).toFixed(4)}%`;
        div.style.top = `${(item.box.y / pageH * 100).toFixed(4)}%`;
        div.style.width = `${Math.max(0.1, item.box.width / pageW * 100).toFixed(4)}%`;
        div.style.height = `${Math.max(0.1, item.box.height / pageH * 100).toFixed(4)}%`;

        const status = blockStatusFor(item);
        if (status === "edited") {
          div.classList.add("is-edited");
        } else if (status === "ignored") {
          div.classList.add("is-ignored");
        } else {
          div.classList.add("is-translated");
        }

        if (isBlockLowConfidence(item)) {
          div.classList.add("is-low-confidence");
        }

        const orderBadge = document.createElement("span");
        orderBadge.className = "ocr-block-box-order";
        orderBadge.textContent = `#${order.indexById.get(item.id) || "?"}`;
        div.appendChild(orderBadge);

        if (blockLockedFor(item.id)) {
          const lock = document.createElement("span");
          lock.className = "ocr-block-box-lock";
          lock.innerHTML = '<i class="ri-lock-2-fill" aria-hidden="true"></i>';
          div.appendChild(lock);
        }

        fragment.appendChild(div);
      }

      layer.appendChild(fragment);
      syncBlockSelectionVisuals();
    }

    function syncBlockSelectionVisuals() {
      const layer = $("ocrBlockSelectLayer");
      if (!layer) {
        return;
      }

      for (const box of layer.querySelectorAll(".ocr-block-box")) {
        const id = box.dataset.blockId || "";
        box.classList.toggle("is-selected", state.selectedBlockIds.has(id));
        box.classList.toggle("is-hover", id === state.hoveredBlockId);
      }
    }

    function primaryBlockId() {
      if (state.blockSelectAnchorId && state.selectedBlockIds.has(state.blockSelectAnchorId)) {
        return state.blockSelectAnchorId;
      }

      const iterator = state.selectedBlockIds.values().next();
      return iterator.done ? "" : iterator.value;
    }

    function syncBlockWorkbench() {
      const primary = primaryBlockId();
      state.selectedOcrStructureId = primary;
      state.selectedOcrStructureItem = (state.latestOcrStructureRows || []).find(item => item.id === primary) || null;
      syncBlockSelectionVisuals();
      syncOcrStructureSelection();
      renderBlockInspector();
      updateSelectionToolbar();
      highlightOcrPreviewTarget(primary, { scroll: false });
    }

    function clearBlockSelection() {
      state.selectedBlockIds = new Set();
      state.blockSelectAnchorId = "";
      syncBlockWorkbench();
    }

    function selectSingleBlock(id) {
      if (!id) {
        return;
      }

      state.selectedBlockIds = new Set([id]);
      state.blockSelectAnchorId = id;
      syncBlockWorkbench();
    }

    function toggleBlockSelection(id) {
      if (!id) {
        return;
      }

      if (state.selectedBlockIds.has(id)) {
        state.selectedBlockIds.delete(id);
        if (state.blockSelectAnchorId === id) {
          state.blockSelectAnchorId = primaryBlockId();
        }
      } else {
        state.selectedBlockIds.add(id);
        state.blockSelectAnchorId = id;
      }

      syncBlockWorkbench();
    }

    function selectBlockRangeTo(id) {
      const order = state.blockReadingOrder;
      if (!order || !state.blockSelectAnchorId) {
        selectSingleBlock(id);
        return;
      }

      const anchorIndex = order.indexById.get(state.blockSelectAnchorId);
      const targetIndex = order.indexById.get(id);
      if (!anchorIndex || !targetIndex) {
        selectSingleBlock(id);
        return;
      }

      const lo = Math.min(anchorIndex, targetIndex);
      const hi = Math.max(anchorIndex, targetIndex);
      state.selectedBlockIds = new Set();
      for (const item of order.ordered) {
        const idx = order.indexById.get(item.id);
        if (idx >= lo && idx <= hi) {
          state.selectedBlockIds.add(item.id);
        }
      }

      syncBlockWorkbench();
    }

    function selectBlocksByIds(ids, baseSelection) {
      const next = baseSelection ? new Set(baseSelection) : new Set();
      for (const id of ids) {
        next.add(id);
      }

      state.selectedBlockIds = next;
      if (ids.length > 0) {
        state.blockSelectAnchorId = ids[ids.length - 1];
      }

      syncBlockWorkbench();
    }

    function selectAllBlocks() {
      state.selectedBlockIds = new Set((state.selectableBlocks || []).map(item => item.id));
      state.blockSelectAnchorId = primaryBlockId();
      syncBlockWorkbench();
    }

    function moveBlockSelection(direction) {
      const order = state.blockReadingOrder;
      if (!order || order.ordered.length === 0) {
        return;
      }

      const current = primaryBlockId();
      let index = current ? (order.indexById.get(current) || 1) - 1 : -1;
      index += direction;
      if (index < 0) {
        index = order.ordered.length - 1;
      } else if (index >= order.ordered.length) {
        index = 0;
      }

      selectSingleBlock(order.ordered[index].id);
    }

    function selectedBlockItems() {
      const byId = new Map((state.selectableBlocks || []).map(item => [item.id, item]));
      const result = [];
      for (const id of state.selectedBlockIds) {
        const item = byId.get(id);
        if (item) {
          result.push(item);
        }
      }

      // present in reading order for stable copy / batch operations
      const indexById = state.blockReadingOrder ? state.blockReadingOrder.indexById : null;
      result.sort((a, b) => (indexById ? (indexById.get(a.id) || 0) - (indexById.get(b.id) || 0) : 0));
      return result;
    }

    function blocksIntersectingRect(layer, left, top, right, bottom) {
      const hits = new Set();
      for (const box of layer.querySelectorAll(".ocr-block-box")) {
        const bl = box.offsetLeft;
        const bt = box.offsetTop;
        const br = bl + box.offsetWidth;
        const bb = bt + box.offsetHeight;
        if (br >= left && bl <= right && bb >= top && bt <= bottom) {
          hits.add(box.dataset.blockId || "");
        }
      }

      hits.delete("");
      return hits;
    }

    function onBlockLayerPointerDown(event) {
      if (event.button !== 0) {
        return;
      }

      const layer = $("ocrBlockSelectLayer");
      if (!layer || layer.classList.contains("hidden")) {
        return;
      }

      event.stopPropagation();
      event.preventDefault();
      layer.focus({ preventScroll: true });
      const boxEl = event.target instanceof Element ? event.target.closest(".ocr-block-box") : null;
      const rect = layer.getBoundingClientRect();
      state.blockSelectMarquee = {
        startX: event.clientX - rect.left,
        startY: event.clientY - rect.top,
        moved: false,
        additive: event.ctrlKey || event.metaKey || event.shiftKey,
        baseSelection: new Set(state.selectedBlockIds),
        onBox: boxEl ? boxEl.dataset.blockId || "" : "",
        pointerId: event.pointerId,
        ctrl: event.ctrlKey || event.metaKey,
        shift: event.shiftKey
      };

      try {
        layer.setPointerCapture(event.pointerId);
      } catch (error) {
        // pointer capture is best-effort
      }
    }

    function onBlockLayerPointerMove(event) {
      const marquee = state.blockSelectMarquee;
      const layer = $("ocrBlockSelectLayer");
      if (!marquee || !layer) {
        return;
      }

      const rect = layer.getBoundingClientRect();
      const x = event.clientX - rect.left;
      const y = event.clientY - rect.top;
      if (!marquee.moved && (Math.abs(x - marquee.startX) > 4 || Math.abs(y - marquee.startY) > 4)) {
        marquee.moved = true;
      }

      if (!marquee.moved) {
        return;
      }

      const left = Math.min(x, marquee.startX);
      const top = Math.min(y, marquee.startY);
      const width = Math.abs(x - marquee.startX);
      const height = Math.abs(y - marquee.startY);
      const marqueeEl = $("ocrBlockMarquee");
      if (marqueeEl) {
        marqueeEl.classList.remove("hidden");
        marqueeEl.style.left = `${left}px`;
        marqueeEl.style.top = `${top}px`;
        marqueeEl.style.width = `${width}px`;
        marqueeEl.style.height = `${height}px`;
      }

      const hits = blocksIntersectingRect(layer, left, top, left + width, top + height);
      for (const box of layer.querySelectorAll(".ocr-block-box")) {
        const id = box.dataset.blockId || "";
        box.classList.toggle("is-marquee-hit", hits.has(id) && !state.selectedBlockIds.has(id));
      }
    }

    function onBlockLayerPointerUp(event) {
      const marquee = state.blockSelectMarquee;
      const layer = $("ocrBlockSelectLayer");
      if (!marquee || !layer) {
        return;
      }

      try {
        layer.releasePointerCapture(marquee.pointerId);
      } catch (error) {
        // ignore
      }

      const marqueeEl = $("ocrBlockMarquee");
      if (marqueeEl) {
        marqueeEl.classList.add("hidden");
      }

      for (const box of layer.querySelectorAll(".is-marquee-hit")) {
        box.classList.remove("is-marquee-hit");
      }

      if (marquee.moved) {
        const rect = layer.getBoundingClientRect();
        const x = event.clientX - rect.left;
        const y = event.clientY - rect.top;
        const left = Math.min(x, marquee.startX);
        const top = Math.min(y, marquee.startY);
        const right = Math.max(x, marquee.startX);
        const bottom = Math.max(y, marquee.startY);
        const hits = Array.from(blocksIntersectingRect(layer, left, top, right, bottom));
        selectBlocksByIds(hits, marquee.additive ? marquee.baseSelection : null);
      } else if (marquee.onBox) {
        if (marquee.shift) {
          selectBlockRangeTo(marquee.onBox);
        } else if (marquee.ctrl) {
          toggleBlockSelection(marquee.onBox);
        } else {
          selectSingleBlock(marquee.onBox);
        }
      } else if (!marquee.ctrl && !marquee.shift) {
        clearBlockSelection();
      }

      state.blockSelectMarquee = null;
    }

    function onBlockLayerKeyDown(event) {
      if (event.key === "Escape") {
        clearBlockSelection();
        event.preventDefault();
        return;
      }

      if ((event.ctrlKey || event.metaKey) && (event.key === "a" || event.key === "A")) {
        selectAllBlocks();
        event.preventDefault();
        return;
      }

      if (event.key === "Tab") {
        moveBlockSelection(event.shiftKey ? -1 : 1);
        event.preventDefault();
      }
    }

    function onBlockLayerHover(event) {
      if (state.blockSelectMarquee) {
        return;
      }

      const box = event.target instanceof Element ? event.target.closest(".ocr-block-box") : null;
      const id = box ? box.dataset.blockId || "" : "";
      if (id !== state.hoveredBlockId) {
        state.hoveredBlockId = id;
        syncBlockSelectionVisuals();
      }

      // hover toolbar only when there is no active selection (selection pins it)
      if (state.selectedBlockIds.size === 0) {
        if (id) {
          state.toolbarHoverId = id;
          cancelToolbarHide();
          updateSelectionToolbar();
        } else {
          scheduleToolbarHide();
        }
      }
    }

    function onBlockLayerLeave() {
      if (state.hoveredBlockId) {
        state.hoveredBlockId = "";
        syncBlockSelectionVisuals();
      }

      if (state.selectedBlockIds.size === 0) {
        scheduleToolbarHide();
      }
    }

    async function loadBlockAnnotations() {
      const imageHash = ocrBlockImageHash();
      state.blockAnnotations = new Map();
      if (!imageHash) {
        return;
      }

      try {
        const profile = currentOcrProfile();
        const response = await fetch(`/ocr/blocks/annotations?imageHash=${encodeURIComponent(imageHash)}&profile=${encodeURIComponent(profile)}`);
        if (!response.ok) {
          return;
        }

        const items = await response.json();
        const map = new Map();
        for (const item of Array.isArray(items) ? items : []) {
          if (item && item.blockId) {
            map.set(item.blockId, item);
          }
        }

        state.blockAnnotations = map;
      } catch (error) {
        // annotations are best-effort; selection still works without them
      }
    }

    function resetBlockSelectionForNewResult() {
      state.selectedBlockIds = new Set();
      state.blockSelectAnchorId = "";
      state.hoveredBlockId = "";
      loadBlockAnnotations()
        .then(() => {
          // repaint the structure table so its status column reflects the
          // freshly loaded annotations, then refresh the canvas + inspector
          renderOcrStructure(state.latestOcr, state.latestOcrStructured);
          renderBlockSelectLayer();
          syncBlockWorkbench();
        })
        .catch(() => {});
    }

    function setInspectorMode(mode) {
      const single = $("ocrInspectorSingle");
      const multi = $("ocrInspectorMulti");
      const empty = $("ocrInspectorEmpty");
      if (single) {
        single.classList.toggle("hidden", mode !== "single");
      }
      if (multi) {
        multi.classList.toggle("hidden", mode !== "multi");
      }
      if (empty) {
        empty.classList.toggle("hidden", mode !== "empty");
      }
    }

    function setInspectorStatusBadge(status) {
      const badge = $("ocrInspectorStatus");
      if (!badge) {
        return;
      }

      badge.textContent = status || "";
      badge.className = `ocr-inspector-status${status ? ` is-${status}` : ""}`;
    }

    function blockOrderLabel(id) {
      const index = state.blockReadingOrder ? state.blockReadingOrder.indexById.get(id) : null;
      return index ? `#${index}` : "#?";
    }

    function renderBlockInspector() {
      const title = $("ocrInspectorTitle");
      if (!title) {
        return;
      }

      const count = state.selectedBlockIds.size;
      const items = selectedBlockItems();

      if (count === 0) {
        title.textContent = "no selection";
        setInspectorStatusBadge("");
        setInspectorMode("empty");
        return;
      }

      if (count === 1) {
        const item = items[0] || (state.latestOcrStructureRows || []).find(row => state.selectedBlockIds.has(row.id)) || null;
        if (!item) {
          title.textContent = "1 block selected";
          setInspectorStatusBadge("");
          setInspectorMode("empty");
          return;
        }

        const status = blockStatusFor(item);
        title.textContent = `${blockOrderLabel(item.id)} ${item.type || "block"}`;
        setInspectorStatusBadge(status);
        const ocrTextEl = $("ocrInspectorOcrText");
        const translationEl = $("ocrInspectorTranslation");
        const ocrValue = item.sourceText || item.text || "";
        const translationValue = item.translation || item.output || "";
        ocrTextEl.value = ocrValue;
        ocrTextEl.dataset.original = ocrValue;
        ocrTextEl.dataset.blockId = item.id || "";
        translationEl.value = translationValue;
        translationEl.dataset.original = translationValue;
        translationEl.dataset.blockId = item.id || "";
        $("ocrInspectorConfidence").textContent = Number(item.confidence) > 0 ? `${Math.round(item.confidence * 100)}%` : "-";
        $("ocrInspectorEngine").textContent = item.engine || "-";
        $("ocrInspectorLanguage").textContent = item.language || "-";
        $("ocrInspectorType").textContent = item.type || "-";
        $("ocrInspectorBox").textContent = item.box
          ? `${Math.round(item.box.x)},${Math.round(item.box.y)} ${Math.round(item.box.width)}?${Math.round(item.box.height)}`
          : "-";
        const idEl = $("ocrInspectorId");
        idEl.textContent = item.id || "-";
        idEl.title = item.id || "";
        setInspectorMode("single");
        return;
      }

      title.textContent = `${count} blocks selected`;
      const statuses = new Set(items.map(blockStatusFor));
      setInspectorStatusBadge(statuses.size === 1 ? Array.from(statuses)[0] : "mixed");

      const lockedCount = items.filter(item => blockLockedFor(item.id)).length;
      const lowConf = items.filter(isBlockLowConfidence).length;
      const summary = $("ocrInspectorMultiSummary");
      if (summary) {
        summary.textContent = `${items.length} blocks / ${lockedCount} locked / ${lowConf} low-confidence`;
      }

      const list = $("ocrInspectorMultiList");
      if (list) {
        list.innerHTML = "";
        for (const item of items) {
          const row = document.createElement("div");
          row.className = "ocr-inspector-multi-row";
          row.addEventListener("click", () => selectSingleBlock(item.id));
          const left = document.createElement("span");
          left.textContent = `${blockOrderLabel(item.id)} ${shortText(item.sourceText || item.text, 40)}`;
          const right = document.createElement("span");
          right.textContent = blockStatusFor(item);
          row.append(left, right);
          list.appendChild(row);
        }
      }

      setInspectorMode("multi");
    }

    function blockBoxElement(id) {
      const layer = $("ocrBlockSelectLayer");
      if (!layer || !id) {
        return null;
      }

      return layer.querySelector(`.ocr-block-box[data-block-id="${cssEscape(id)}"]`);
    }

    function selectionUnionClientRect() {
      let rect = null;
      for (const id of state.selectedBlockIds) {
        const el = blockBoxElement(id);
        if (!el) {
          continue;
        }

        const r = el.getBoundingClientRect();
        if (!rect) {
          rect = { left: r.left, top: r.top, right: r.right, bottom: r.bottom };
        } else {
          rect.left = Math.min(rect.left, r.left);
          rect.top = Math.min(rect.top, r.top);
          rect.right = Math.max(rect.right, r.right);
          rect.bottom = Math.max(rect.bottom, r.bottom);
        }
      }

      return rect;
    }

    function positionSelectionToolbar(rect) {
      const toolbar = $("ocrSelectionToolbar");
      if (!toolbar || !rect) {
        return;
      }

      toolbar.style.visibility = "hidden";
      toolbar.classList.remove("hidden");
      const width = toolbar.offsetWidth || 220;
      const height = toolbar.offsetHeight || 36;
      let top = rect.top - height - 8;
      if (top < 8) {
        top = rect.bottom + 8;
      }

      let left = rect.left;
      left = Math.max(8, Math.min(left, window.innerWidth - width - 8));
      top = Math.max(8, Math.min(top, window.innerHeight - height - 8));
      toolbar.style.left = `${Math.round(left)}px`;
      toolbar.style.top = `${Math.round(top)}px`;
      toolbar.style.visibility = "";
    }

    function updateToolbarLabels(items) {
      const countEl = $("ocrSelectionToolbarCount");
      if (countEl) {
        countEl.textContent = state.selectedBlockIds.size > 0 ? `${state.selectedBlockIds.size} selected` : "hover";
      }

      const lockedCount = items.filter(item => blockLockedFor(item.id)).length;
      const allLocked = items.length > 0 && lockedCount === items.length;
      const lockLabel = $("ocrToolbarLockLabel");
      if (lockLabel) {
        lockLabel.textContent = allLocked ? "Unlock" : "Lock";
      }

      const lockBtn = $("ocrToolbarLockButton");
      if (lockBtn) {
        lockBtn.classList.toggle("is-active", lockedCount > 0);
      }
    }

    // Selection toolbar is a floating dark pill: anchored to the selection
    // (persistent) when there is one, else to the hovered block (transient).
    function updateSelectionToolbar() {
      const toolbar = $("ocrSelectionToolbar");
      if (!toolbar) {
        return;
      }

      if (state.selectedBlockIds.size > 0) {
        const rect = selectionUnionClientRect();
        if (!rect) {
          toolbar.classList.add("hidden");
          return;
        }

        updateToolbarLabels(selectedBlockItems());
        positionSelectionToolbar(rect);
        return;
      }

      if (state.toolbarHoverId) {
        const el = blockBoxElement(state.toolbarHoverId);
        if (el) {
          const item = (state.selectableBlocks || []).find(block => block.id === state.toolbarHoverId);
          updateToolbarLabels(item ? [item] : []);
          positionSelectionToolbar(el.getBoundingClientRect());
          return;
        }
      }

      toolbar.classList.add("hidden");
      closeToolbarMenus();
    }

    function scheduleToolbarHide() {
      window.clearTimeout(state.toolbarHideTimer);
      state.toolbarHideTimer = window.setTimeout(() => {
        if (state.selectedBlockIds.size === 0) {
          state.toolbarHoverId = "";
          const toolbar = $("ocrSelectionToolbar");
          if (toolbar) {
            toolbar.classList.add("hidden");
          }
          closeToolbarMenus();
        }
      }, 160);
    }

    function cancelToolbarHide() {
      window.clearTimeout(state.toolbarHideTimer);
    }

    // Toolbar actions act on the selection; if invoked while only hovering an
    // unselected block, select that block first so every action has one path.
    function ensureToolbarSelection() {
      if (state.selectedBlockIds.size === 0 && state.toolbarHoverId) {
        selectSingleBlock(state.toolbarHoverId);
      }
    }

    // ---- inline (Word-like) block editing ----

    function blockInlineInitialValue(id, field) {
      const item = (state.selectableBlocks || []).find(block => block.id === id);
      if (!item) {
        return "";
      }

      return field === "source" ? (item.sourceText || item.text || "") : (item.translation || "");
    }

    function persistBlockEdit(id, field, value, original) {
      const existing = blockAnnotationFor(id) || {};
      const keepLocked = Boolean(existing.locked || existing.status === "locked");
      const patch = keepLocked ? {} : { status: "edited" };
      const history = field === "source"
        ? { kind: "ocr", sourceText: original, translatedText: "", engine: "", provider: "" }
        : { kind: "translation", sourceText: "", translatedText: original, engine: "", provider: "" };
      if (field === "source") {
        patch.editedSource = value;
      } else {
        patch.editedTranslation = value;
      }

      persistBlockAnnotation(id, patch, history).then(() => {
        refreshBlockWorkbenchAfterAnnotationChange();
        updateOcrComposerPreview();
      });
    }

    function beginBlockInlineEdit(id, field) {
      if (!id) {
        return;
      }

      const layer = $("ocrBlockSelectLayer");
      const boxEl = blockBoxElement(id);
      if (!layer || !boxEl) {
        return;
      }

      if (state.blockInlineEdit) {
        commitBlockInlineEdit(state.blockInlineEdit);
      }

      const original = blockInlineInitialValue(id, field);
      const textarea = document.createElement("textarea");
      textarea.className = "ocr-block-edit";
      textarea.value = original;
      textarea.style.left = boxEl.style.left;
      textarea.style.top = boxEl.style.top;
      textarea.style.width = boxEl.style.width;
      textarea.style.height = boxEl.style.height;

      const edit = { id, field, textarea, original, committed: false };
      textarea.addEventListener("pointerdown", event => event.stopPropagation());
      textarea.addEventListener("click", event => event.stopPropagation());
      textarea.addEventListener("dblclick", event => event.stopPropagation());
      textarea.addEventListener("keydown", event => {
        if (event.key === "Escape") {
          event.preventDefault();
          cancelBlockInlineEdit(edit);
        } else if (event.key === "Enter" && !event.shiftKey) {
          event.preventDefault();
          commitBlockInlineEdit(edit);
        }
      });
      textarea.addEventListener("blur", () => commitBlockInlineEdit(edit));

      layer.appendChild(textarea);
      state.blockInlineEdit = edit;
      textarea.focus();
      textarea.select();
    }

    function commitBlockInlineEdit(edit) {
      if (!edit || edit.committed) {
        return;
      }

      edit.committed = true;
      if (state.blockInlineEdit === edit) {
        state.blockInlineEdit = null;
      }

      const value = edit.textarea.value;
      if (edit.textarea.parentNode) {
        edit.textarea.parentNode.removeChild(edit.textarea);
      }

      if (value === edit.original) {
        return;
      }

      persistBlockEdit(edit.id, edit.field, value, edit.original);
    }

    function cancelBlockInlineEdit(edit) {
      const target = edit || state.blockInlineEdit;
      if (!target || target.committed) {
        return;
      }

      target.committed = true;
      if (state.blockInlineEdit === target) {
        state.blockInlineEdit = null;
      }

      if (target.textarea.parentNode) {
        target.textarea.parentNode.removeChild(target.textarea);
      }
    }

    function onBlockLayerDoubleClick(event) {
      const box = event.target instanceof Element ? event.target.closest(".ocr-block-box") : null;
      if (!box) {
        return;
      }

      event.stopPropagation();
      event.preventDefault();
      beginBlockInlineEdit(box.dataset.blockId || "", "translation");
    }

    function commitInspectorEdit(field, el) {
      const id = el.dataset.blockId || "";
      if (!id) {
        return;
      }

      const value = el.value;
      const original = el.dataset.original || "";
      if (value === original) {
        return;
      }

      el.dataset.original = value;
      persistBlockEdit(id, field, value, original);
    }

    function closeToolbarMenus() {
      for (const menuId of ["ocrToolbarCopyMenu", "ocrToolbarMoreMenu"]) {
        const menu = $(menuId);
        if (menu) {
          menu.classList.add("hidden");
        }
      }
    }

    function toggleToolbarMenu(menuId) {
      const menu = $(menuId);
      if (!menu) {
        return;
      }

      const willOpen = menu.classList.contains("hidden");
      closeToolbarMenus();
      if (willOpen) {
        menu.classList.remove("hidden");
      }
    }

    function selectedBlockItemsOrdered() {
      const toggle = $("ocrToolbarSelectionOrder");
      if (!toggle || !toggle.checked) {
        return selectedBlockItems();
      }

      const byId = new Map((state.selectableBlocks || []).map(item => [item.id, item]));
      const result = [];
      for (const id of state.selectedBlockIds) {
        const item = byId.get(id);
        if (item) {
          result.push(item);
        }
      }

      return result;
    }

    function blockCopyText(items, kind) {
      switch (kind) {
        case "ocr":
          return items.map(item => item.sourceText || item.text || "").join("\n\n");
        case "translation":
          return items.map(item => item.translation || "").join("\n\n");
        case "both":
          return items.map(item => `${item.sourceText || item.text || ""}\n${item.translation || ""}`.trim()).join("\n\n");
        case "markdown":
          return items.map(item => {
            const src = item.sourceText || item.text || "";
            const translation = item.translation || "";
            return translation ? `**${src}**\n\n${translation}` : `**${src}**`;
          }).join("\n\n");
        case "json":
          return JSON.stringify(items.map(item => ({
            id: item.id,
            type: item.type,
            source: item.sourceText || item.text || "",
            translation: item.translation || "",
            confidence: item.confidence,
            bbox: item.box || null,
            readingOrder: item.readingOrder
          })), null, 2);
        default:
          return "";
      }
    }

    async function copySelection(kind) {
      const items = selectedBlockItemsOrdered();
      if (items.length === 0) {
        appendMessage("error", "copy", "no blocks selected");
        return;
      }

      if (kind === "crops") {
        await copySelectedImageCrops(items);
        return;
      }

      const text = blockCopyText(items, kind);
      if (!text.trim()) {
        appendMessage("error", "copy", "nothing to copy");
        return;
      }

      try {
        await navigator.clipboard.writeText(text);
        appendMessage("result", "copy", `${items.length} block(s) copied`, kind);
      } catch (error) {
        appendMessage("error", "copy", error.message || String(error));
      }
    }

    async function copySelectedImageCrops(items) {
      const dataUrl = currentOcrImageDataUrl();
      const boxes = items.map(item => item.box).filter(Boolean);
      const union = unionOcrBoundingBoxes(boxes);
      if (!dataUrl || !union) {
        appendMessage("error", "copy", "no crop region");
        return;
      }

      try {
        const image = await loadOcrOverlayImage(dataUrl);
        const pageW = items[0].pageWidth || image.naturalWidth || 1;
        const pageH = items[0].pageHeight || image.naturalHeight || 1;
        const scaleX = (image.naturalWidth || pageW) / pageW;
        const scaleY = (image.naturalHeight || pageH) / pageH;
        const sx = Math.max(0, union.x * scaleX);
        const sy = Math.max(0, union.y * scaleY);
        const sw = Math.max(1, union.width * scaleX);
        const sh = Math.max(1, union.height * scaleY);
        const canvas = document.createElement("canvas");
        canvas.width = Math.round(sw);
        canvas.height = Math.round(sh);
        const ctx = canvas.getContext("2d");
        ctx.drawImage(image, sx, sy, sw, sh, 0, 0, canvas.width, canvas.height);
        const blob = await new Promise(resolve => canvas.toBlob(resolve, "image/png"));
        if (!blob || typeof ClipboardItem === "undefined") {
          appendMessage("error", "copy", "image clipboard unsupported");
          return;
        }

        await navigator.clipboard.write([new ClipboardItem({ "image/png": blob })]);
        appendMessage("result", "copy", "crop image copied");
      } catch (error) {
        appendMessage("error", "copy", error.message || String(error));
      }
    }

    // Shared persistence backbone for lock / status / edited-translation, used by
    // the lock toolbar (Phase 3/6), retranslate (Phase 4), and re-OCR (Phase 5).
    async function persistBlockAnnotation(id, patch, history) {
      const imageHash = ocrBlockImageHash();
      if (!imageHash || !id) {
        return null;
      }

      const existing = blockAnnotationFor(id) || {};
      const body = {
        imageHash,
        blockId: id,
        profile: currentOcrProfile(),
        status: patch.status !== undefined ? patch.status : (existing.status || "translated"),
        locked: patch.locked !== undefined ? patch.locked : Boolean(existing.locked),
        editedTranslation: patch.editedTranslation !== undefined ? patch.editedTranslation : (existing.editedTranslation || ""),
        editedSource: patch.editedSource !== undefined ? patch.editedSource : (existing.editedSource || ""),
        note: patch.note !== undefined ? patch.note : (existing.note || "")
      };
      if (history) {
        body.history = history;
      }

      try {
        const response = await fetch("/ocr/blocks/annotations", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(body)
        });
        if (!response.ok) {
          appendMessage("error", "blocks", "could not save block state");
          return null;
        }

        const stored = await response.json();
        if (stored && stored.blockId) {
          state.blockAnnotations.set(stored.blockId, stored);
        }

        return stored;
      } catch (error) {
        appendMessage("error", "blocks", error.message || String(error));
        return null;
      }
    }

    function refreshBlockWorkbenchAfterAnnotationChange() {
      renderOcrStructure(state.latestOcr, state.latestOcrStructured);
      renderBlockSelectLayer();
      syncBlockWorkbench();
    }

    // Resolve the language pair for a remembered correction the same way the
    // memory editor does (mirrors saveMemoryEditor): fall back to ja->zh-TW when
    // the global selectors are empty or set to auto-detect.
    function resolveCorrectionLanguages() {
      const rawSource = (($("source") && $("source").value) || "").trim();
      const rawTarget = (($("target") && $("target").value) || "").trim();
      return {
        source: (!rawSource || rawSource === "auto") ? "ja" : rawSource,
        target: rawTarget || "zh-TW"
      };
    }

    // Write a source->target pair into the global translation memory as a
    // user_verified item (origin=overlay-correction). Returns the stored item,
    // or null when either side is blank.
    async function postCorrectionMemory(sourceText, targetText) {
      const src = (sourceText || "").trim();
      const tgt = (targetText || "").trim();
      if (!src || !tgt) {
        return null;
      }

      const langs = resolveCorrectionLanguages();
      return post("/memories", {
        profile: currentOcrProfile(),
        memoryKind: "translation",
        source: langs.source,
        target: langs.target,
        sourceText: src,
        targetText: tgt,
        note: "overlay correction",
        priority: 0,
        confidence: 1,
        trustLevel: "user_verified",
        origin: "overlay-correction",
        visibility: "profile",
        acknowledgeSecurityFlags: true
      });
    }

    // Promote a single OCR block's correction into the global translation memory.
    // Uses the edited source/translation when present, otherwise the block's
    // current OCR + translation.
    async function rememberBlockCorrection(item) {
      if (!item) {
        return { ok: false, reason: "empty" };
      }

      const sourceText = blockEditedSource(item.id) || item.sourceText || item.text || "";
      const targetText = blockEditedTranslation(item.id) || item.translation || "";
      const saved = await postCorrectionMemory(sourceText, targetText);
      return saved ? { ok: true, saved } : { ok: false, reason: "empty" };
    }

    async function rememberSelectedBlockCorrections() {
      const items = selectedBlockItems();
      if (items.length === 0) {
        appendMessage("error", "memory", "Select OCR blocks before saving corrections.");
        return;
      }

      let remembered = 0;
      let skipped = 0;
      try {
        for (const item of items) {
          const result = await rememberBlockCorrection(item);
          if (result && result.ok) {
            remembered += 1;
          } else {
            skipped += 1;
          }
        }
      } catch (error) {
        appendMessage("error", "memory", error.message || String(error));
        return;
      }

      if (remembered > 0) {
        const suffix = skipped > 0 ? `; skipped ${skipped}` : "";
        appendMessage("result", "memory", `Saved ${remembered} correction${remembered === 1 ? "" : "s"}${suffix}.`);
        if (typeof loadMemories === "function") {
          loadMemories().catch(() => {});
        }
      } else {
        appendMessage("error", "memory", "No selected correction had both source and target text.");
      }
    }
    async function toggleLockSelectedBlocks() {
      const items = selectedBlockItems();
      if (items.length === 0) {
        return;
      }

      const anyUnlocked = items.some(item => !blockLockedFor(item.id));
      for (const item of items) {
        if (anyUnlocked) {
          await persistBlockAnnotation(item.id, { locked: true, status: "locked" });
        } else {
          const existing = blockAnnotationFor(item.id);
          const hadEdit = existing && existing.editedTranslation;
          await persistBlockAnnotation(item.id, { locked: false, status: hadEdit ? "edited" : "translated" });
        }
      }

      appendMessage("result", "blocks", `${items.length} block(s) ${anyUnlocked ? "locked" : "unlocked"}`);
      refreshBlockWorkbenchAfterAnnotationChange();
    }

    async function setStatusForSelectedBlocks(status) {
      const items = selectedBlockItems();
      if (items.length === 0) {
        return;
      }

      for (const item of items) {
        await persistBlockAnnotation(item.id, { status, locked: status === "locked" });
      }

      refreshBlockWorkbenchAfterAnnotationChange();
    }

    function selectedBlocksForMutation() {
      // operations that overwrite blocks must never touch locked blocks
      const items = selectedBlockItems();
      const locked = items.filter(item => blockLockedFor(item.id));
      const writable = items.filter(item => !blockLockedFor(item.id));
      return { items, writable, lockedCount: locked.length };
    }

    function retranslateSelectedBlocks() {
      openBlockActionDialog("retranslate");
    }

    function reOcrSelectedBlocks() {
      openBlockActionDialog("reocr");
    }

    // ---- shared retranslate / re-OCR preview dialog ----

    function openBlockActionDialog(mode) {
      const { writable, lockedCount } = selectedBlocksForMutation();
      if (writable.length === 0) {
        appendMessage("error", mode, lockedCount > 0 ? "all selected blocks are locked" : "no blocks selected");
        return;
      }

      state.blockDialog = { mode, items: writable, lockedCount, pending: new Map() };
      const dialog = $("ocrBlockActionDialog");
      const title = $("ocrBlockDialogTitle");
      const runLabel = $("ocrBlockDialogRunLabel");
      const apply = $("ocrBlockDialogApply");
      if (title) {
        title.textContent = mode === "retranslate"
          ? `Retranslate ${writable.length} block(s)`
          : `Re-OCR ${writable.length} block(s)`;
      }
      if (runLabel) {
        runLabel.textContent = mode === "retranslate" ? "Translate" : "Re-OCR";
      }
      if (apply) {
        apply.disabled = true;
      }

      renderBlockDialogControls(mode);
      renderBlockDialogBody();
      const hint = $("ocrBlockDialogHint");
      if (hint) {
        hint.textContent = lockedCount > 0 ? `${lockedCount} locked block(s) skipped` : "";
      }

      if (dialog) {
        dialog.classList.remove("hidden");
      }
    }

    function closeBlockActionDialog() {
      const dialog = $("ocrBlockActionDialog");
      if (dialog) {
        dialog.classList.add("hidden");
      }

      state.blockDialog = null;
    }

    function renderBlockDialogControls(mode) {
      const host = $("ocrBlockDialogControls");
      if (!host) {
        return;
      }

      host.innerHTML = "";
      if (mode === "retranslate") {
        const instruction = document.createElement("textarea");
        instruction.id = "ocrBlockDialogInstruction";
        instruction.placeholder = "Optional instruction ??e.g. ?冽?????瘞?/ 靽?撠??? / 銝?蝧餉陌?望?蝮桀神";
        host.appendChild(instruction);

        const rememberLabel = document.createElement("label");
        rememberLabel.className = "memory-check";
        rememberLabel.htmlFor = "ocrBlockDialogRemember";
        const rememberInput = document.createElement("input");
        rememberInput.id = "ocrBlockDialogRemember";
        rememberInput.type = "checkbox";
        rememberLabel.append(rememberInput, document.createTextNode("銝西?雿迨靽格迤嚗神?亦蕃霅航??塚?"));
        host.appendChild(rememberLabel);
      } else {
        renderReocrDialogControls(host);
      }
    }

    function renderBlockDialogBody() {
      const host = $("ocrBlockDialogBody");
      const dialog = state.blockDialog;
      if (!host || !dialog) {
        return;
      }

      host.innerHTML = "";
      for (const item of dialog.items) {
        const pending = dialog.pending.get(item.id);
        const card = document.createElement("div");
        card.className = `ocr-block-diff${pending && pending.error ? " is-error" : ""}`;

        const head = document.createElement("div");
        head.className = "ocr-block-diff-head";
        const left = document.createElement("span");
        left.textContent = `${blockOrderLabel(item.id)} ${item.type || "block"}`;
        const right = document.createElement("span");
        right.textContent = pending ? (pending.error ? "error" : "preview") : "pending";
        head.append(left, right);

        const cols = document.createElement("div");
        cols.className = "ocr-block-diff-cols";
        const oldPre = document.createElement("pre");
        oldPre.className = "is-old";
        const newPre = document.createElement("pre");
        newPre.className = "is-new";
        if (dialog.mode === "retranslate") {
          oldPre.textContent = item.translation || "(no translation)";
        } else {
          oldPre.textContent = item.sourceText || item.text || "(empty)";
        }
        newPre.textContent = pending ? (pending.error || pending.value || "") : "No pending edit";
        cols.append(oldPre, newPre);

        card.append(head, cols);
        host.appendChild(card);
      }
    }

    async function runBlockDialogPreview() {
      const dialog = state.blockDialog;
      if (!dialog) {
        return;
      }

      const run = $("ocrBlockDialogRun");
      if (run) {
        run.disabled = true;
      }

      try {
        if (dialog.mode === "retranslate") {
          await runRetranslatePreview(dialog);
        } else {
          await runReocrPreview(dialog);
        }
      } finally {
        if (run) {
          run.disabled = false;
        }
      }

      renderBlockDialogBody();
      const apply = $("ocrBlockDialogApply");
      const anyOk = Array.from(dialog.pending.values()).some(entry => !entry.error && entry.value !== undefined);
      if (apply) {
        apply.disabled = !anyOk;
      }
    }

    async function runRetranslatePreview(dialog) {
      const instructionEl = $("ocrBlockDialogInstruction");
      const instruction = instructionEl ? instructionEl.value.trim() : "";
      for (const item of dialog.items) {
        const source = item.sourceText || item.text || "";
        if (!source.trim()) {
          dialog.pending.set(item.id, { error: "no source text" });
          continue;
        }

        try {
          const payload = translationPayload(source);
          if (instruction) {
            payload.context = instruction;
          }

          const result = await post("/translate", payload, { headers: memoryRuntimeHeaders() });
          if (result.errorCode && result.errorCode !== "0") {
            dialog.pending.set(item.id, { error: result.errorMessage || result.result || "translate failed" });
          } else {
            dialog.pending.set(item.id, { value: result.result || "", engine: result.engine || "" });
          }
        } catch (error) {
          // per-block isolation: one failure must not abort the batch
          dialog.pending.set(item.id, { error: error.message || String(error) });
        }
      }
    }

    async function applyBlockDialog() {
      const dialog = state.blockDialog;
      if (!dialog) {
        return;
      }

      const rememberCheckbox = $("ocrBlockDialogRemember");
      const rememberCorrections = dialog.mode === "retranslate" && rememberCheckbox && rememberCheckbox.checked;

      let applied = 0;
      let remembered = 0;
      for (const item of dialog.items) {
        const pending = dialog.pending.get(item.id);
        if (!pending || pending.error || pending.value === undefined) {
          continue;
        }

        if (dialog.mode === "retranslate") {
          const history = {
            kind: "translation",
            sourceText: item.sourceText || item.text || "",
            translatedText: item.translation || "",
            engine: pending.engine || "",
            provider: ""
          };
          await persistBlockAnnotation(item.id, { status: "edited", editedTranslation: pending.value }, history);
          if (rememberCorrections) {
            try {
              const saved = await postCorrectionMemory(blockEditedSource(item.id) || item.sourceText || item.text || "", pending.value);
              if (saved) {
                remembered += 1;
              }
            } catch (error) {
              appendMessage("error", "memory", error.message || String(error));
            }
          }
        } else {
          const history = {
            kind: "ocr",
            sourceText: item.sourceText || item.text || "",
            translatedText: "",
            engine: pending.engine || "",
            provider: pending.provider || ""
          };
          await persistBlockAnnotation(item.id, { status: "edited", editedSource: pending.value }, history);
        }

        applied += 1;
      }

      const rememberSuffix = remembered > 0 ? `; remembered ${remembered}` : "";
      appendMessage("result", dialog.mode, `${applied} block(s) updated${rememberSuffix}`);
      closeBlockActionDialog();
      refreshBlockWorkbenchAfterAnnotationChange();
      updateOcrComposerPreview();
      if (remembered > 0 && typeof loadMemories === "function") {
        loadMemories().catch(() => {});
      }
    }

    function cloneSelectOptions(target, source, fallbackValues) {
      if (source && source.options.length > 0) {
        for (const option of source.options) {
          const clone = document.createElement("option");
          clone.value = option.value;
          clone.textContent = option.textContent;
          clone.disabled = option.disabled;
          target.appendChild(clone);
        }
        target.value = source.value;
        return;
      }

      for (const value of fallbackValues || []) {
        const option = document.createElement("option");
        option.value = value;
        option.textContent = value;
        target.appendChild(option);
      }
    }

    function renderReocrDialogControls(host) {
      const engineLabel = document.createElement("label");
      engineLabel.className = "ocr-block-dialog-control";
      engineLabel.append("engine ");
      const engine = document.createElement("select");
      engine.id = "ocrReocrEngine";
      cloneSelectOptions(engine, $("ocrProvider"), []);
      engineLabel.appendChild(engine);
      host.appendChild(engineLabel);

      const preLabel = document.createElement("label");
      preLabel.className = "ocr-block-dialog-control";
      preLabel.append("preprocess ");
      const pre = document.createElement("select");
      pre.id = "ocrReocrPreprocess";
      cloneSelectOptions(pre, $("ocrPreprocessingPreset"), ["none", "upscale", "flatten", "clahe-l", "threshold", "denoise", "contrast", "isolate"]);
      preLabel.appendChild(pre);
      host.appendChild(preLabel);

      const padLabel = document.createElement("label");
      padLabel.className = "ocr-block-dialog-control";
      padLabel.append("padding(px) ");
      const pad = document.createElement("input");
      pad.id = "ocrReocrPadding";
      pad.type = "number";
      pad.value = "8";
      pad.min = "0";
      pad.max = "40";
      pad.style.width = "64px";
      padLabel.appendChild(pad);
      host.appendChild(padLabel);
    }

    function cropBlockToBase64(image, item, padding) {
      const pageW = item.pageWidth || image.naturalWidth || 1;
      const pageH = item.pageHeight || image.naturalHeight || 1;
      const naturalW = image.naturalWidth || pageW;
      const naturalH = image.naturalHeight || pageH;
      const scaleX = naturalW / pageW;
      const scaleY = naturalH / pageH;
      const x = Math.max(0, item.box.x * scaleX - padding);
      const y = Math.max(0, item.box.y * scaleY - padding);
      const width = Math.min(naturalW - x, item.box.width * scaleX + padding * 2);
      const height = Math.min(naturalH - y, item.box.height * scaleY + padding * 2);
      if (width < 1 || height < 1) {
        return null;
      }

      const canvas = document.createElement("canvas");
      canvas.width = Math.round(width);
      canvas.height = Math.round(height);
      const ctx = canvas.getContext("2d");
      ctx.drawImage(image, x, y, width, height, 0, 0, canvas.width, canvas.height);
      const dataUrl = canvas.toDataURL("image/png");
      const comma = dataUrl.indexOf(",");
      return { base64: comma >= 0 ? dataUrl.slice(comma + 1) : dataUrl };
    }

    async function runReocrPreview(dialog) {
      const engine = ($("ocrReocrEngine") && $("ocrReocrEngine").value) || ($("ocrProvider") && $("ocrProvider").value) || "";
      const preprocess = ($("ocrReocrPreprocess") && $("ocrReocrPreprocess").value) || "none";
      const paddingInput = $("ocrReocrPadding");
      const padding = paddingInput ? Math.max(0, Math.min(40, Number(paddingInput.value) || 0)) : 8;

      const dataUrl = currentOcrImageDataUrl();
      if (!dataUrl) {
        for (const item of dialog.items) {
          dialog.pending.set(item.id, { error: "no source image" });
        }
        return;
      }

      let image;
      try {
        image = await loadOcrOverlayImage(dataUrl);
      } catch (error) {
        for (const item of dialog.items) {
          dialog.pending.set(item.id, { error: "image decode failed" });
        }
        return;
      }

      for (const item of dialog.items) {
        if (!item.box) {
          dialog.pending.set(item.id, { error: "no bbox" });
          continue;
        }

        try {
          const crop = cropBlockToBase64(image, item, padding);
          if (!crop) {
            dialog.pending.set(item.id, { error: "crop failed" });
            continue;
          }

          const payload = {
            imageBase64: crop.base64,
            imageMimeType: "image/png",
            provider: engine,
            contentType: $("ocrContentType") ? $("ocrContentType").value : "",
            preference: $("ocrPreference") ? $("ocrPreference").value : "",
            language: $("ocrLanguage") ? $("ocrLanguage").value : "",
            profile: currentOcrProfile(),
            preprocessingPreset: preprocess
          };
          const result = await post("/ocr", payload, { headers: memoryRuntimeHeaders() });
          const text = (result.text || result.correctedText || "").trim();
          dialog.pending.set(item.id, { value: text, engine: result.engine || engine, provider: result.provider || engine });
        } catch (error) {
          // per-block isolation: a single crop failure must not abort the batch
          dialog.pending.set(item.id, { error: error.message || String(error) });
        }
      }
    }

    function applyOcrResult(result, elapsed, sourceLabel = "ocr") {
      state.latestOcrText = result.text || result.correctedText || "";
      state.latestOcrRawText = result.rawText || result.text || result.correctedText || "";
      ocrOutput.value = state.latestOcrText;
      ocrTranslationOutput.value = "";
      sourceText.value = state.latestOcrText;
      $("blockCount").textContent = String(result.blocks ? result.blocks.length : 0);
      $("engineName").textContent = result.engine || "-";
      $("latencyLabel").textContent = `${elapsed} ms`;
      $("ocrJobStatus").textContent = result.cacheHit ? "cache" : "-";
      renderOcrStructure(result, null);
      resetBlockSelectionForNewResult();
      setOcrTextCollapsed(false);
      setOcrStructureCollapsed(true);
      setOcrPreviewCollapsed(true);
      updateOcrComposerPreview();
      appendMessage("result", sourceLabel, state.latestOcrText, `${result.provider || ""} ${elapsed} ms`.trim());
      return result;
    }

    const ocrStageSpans = { preparing: 0.10, recognizing: 0.92, assembling: 0.99 };

    function ocrStageLabel(stage, status) {
      if (!stage) {
        return status || "-";
      }

      if (stage === "recognizing") {
        return state.ocrRoutingDecision && state.ocrRoutingDecision.preservesStructure
          ? "structure analysis"
          : "recognizing";
      }

      return stage === "preparing" ? "preprocessing" : stage;
    }

    function beginOcrJobProgress(options = {}) {
      state.ocrJobProgress = {
        indeterminate: Boolean(options.indeterminate),
        status: options.indeterminate ? "running" : "queued",
        stage: options.indeterminate ? "recognizing" : "queued",
        base: 0,
        estimatedDurationMs: 0,
        engine: "",
        startedAt: performance.now(),
        stageEnteredAt: performance.now(),
        label: ""
      };
      $("ocrJobProgress").classList.remove("hidden");
      $("ocrJobProgressFill").classList.remove("failed");
      $("ocrJobProgressFill").classList.toggle("indeterminate", state.ocrJobProgress.indeterminate);
      if (state.ocrJobProgressTimer) {
        window.clearInterval(state.ocrJobProgressTimer);
      }

      state.ocrJobProgressTimer = window.setInterval(renderOcrJobProgress, 250);
      renderOcrJobProgress();
    }

    function updateOcrJobProgressFromJob(job) {
      const progress = state.ocrJobProgress;
      if (!progress) {
        return;
      }

      if ((job.stage || "") !== progress.stage) {
        progress.stage = job.stage || "";
        progress.stageEnteredAt = performance.now();
      }

      progress.status = job.status || "";
      progress.base = Number(job.progress || 0);
      progress.estimatedDurationMs = Number(job.estimatedDurationMs || 0);
      progress.engine = job.engine || job.provider || "";
      renderOcrJobProgress();
    }

    function renderOcrJobProgress() {
      const progress = state.ocrJobProgress;
      if (!progress) {
        return;
      }

      const elapsedMs = performance.now() - progress.startedAt;
      $("ocrJobProgressElapsed").textContent = `elapsed ${formatEta(elapsedMs / 1000)}`;
      $("ocrJobProgressEngine").textContent = progress.engine || "-";

      if (progress.indeterminate) {
        $("ocrJobProgressStage").textContent = progress.label || ocrStageLabel(progress.stage, progress.status);
        $("ocrJobProgressPercent").textContent = "-";
        $("ocrJobProgressEta").textContent = "-";
        return;
      }

      let fraction = progress.base;
      let etaText = "-";
      if (progress.stage === "recognizing") {
        const span = ocrStageSpans.recognizing;
        const estimate = Math.max(progress.estimatedDurationMs, 1000);
        const inStageMs = performance.now() - progress.stageEnteredAt;
        fraction = progress.base + (span - progress.base) * (1 - Math.exp(-inStageMs / estimate));
        const remainingMs = progress.estimatedDurationMs - inStageMs;
        etaText = progress.estimatedDurationMs > 0 && remainingMs > 0
          ? `ETA ${formatEta(remainingMs / 1000)}`
          : "-";
      }

      fraction = Math.min(1, Math.max(0, fraction));
      const percent = `${(fraction * 100).toFixed(1)}%`;
      $("ocrJobProgressFill").style.width = percent;
      const label = progress.label || ocrStageLabel(progress.stage, progress.status);
      $("ocrJobProgressStage").textContent = label;
      $("ocrJobProgressPercent").textContent = percent;
      $("ocrJobProgressEta").textContent = etaText;
      $("ocrJobStatus").textContent = `${progress.status || "-"} / ${label} ${Math.round(fraction * 100)}%`;
    }

    function endOcrJobProgress(outcome) {
      if (state.ocrJobProgressTimer) {
        window.clearInterval(state.ocrJobProgressTimer);
        state.ocrJobProgressTimer = null;
      }

      const fill = $("ocrJobProgressFill");
      fill.classList.remove("indeterminate");
      state.ocrJobProgress = null;

      if (outcome === "succeeded") {
        fill.style.width = "100%";
        window.setTimeout(() => $("ocrJobProgress").classList.add("hidden"), 1500);
        return;
      }

      if (outcome === "failed") {
        fill.classList.add("failed");
        window.setTimeout(() => {
          $("ocrJobProgress").classList.add("hidden");
          fill.classList.remove("failed");
        }, 2000);
        return;
      }

      $("ocrJobProgress").classList.add("hidden");
    }

    async function waitForOcrJob(jobId) {
      let consecutiveErrors = 0;
      let lastError = null;
      for (let attempt = 0; ; attempt += 1) {
        let job;
        try {
          job = await api(`/ocr/jobs/${encodeURIComponent(jobId)}`);
          consecutiveErrors = 0;
        } catch (error) {
          consecutiveErrors += 1;
          lastError = error;
          if (consecutiveErrors >= 6) {
            throw new Error(`OCR job polling failed repeatedly: ${lastError.message || lastError}`);
          }

          await new Promise(resolve => setTimeout(resolve, 1000));
          continue;
        }

        updateOcrJobProgressFromJob(job);
        $("engineName").textContent = job.engine || job.provider || "-";

        if (["succeeded", "failed", "canceled"].includes(job.status)) {
          return job;
        }

        await new Promise(resolve => setTimeout(resolve, attempt < 20 ? 500 : 1000));
      }
    }

    async function runOcrJob(started, imageSessionId = state.ocrImageSessionId) {
      state.ocrJobCancelRequested = false;
      updateOcrJobControls();

      const queued = await post("/ocr/jobs", ocrPayload());
      state.activeOcrJobId = queued.id || "";
      if (!state.activeOcrJobId) {
        throw new Error("OCR job did not return an id.");
      }

      updateOcrJobControls();
      $("ocrJobStatus").textContent = queued.id ? `queued ${queued.id.slice(0, 8)}` : "queued";
      appendMessage("result", "ocr job", queued.id || "queued", queued.provider || "job");
      beginOcrJobProgress();
      updateOcrJobProgressFromJob(queued);

      let outcome = "failed";
      try {
        const completed = await waitForOcrJob(queued.id);
        if (completed.status === "canceled") {
          outcome = "canceled";
          $("ocrJobStatus").textContent = "canceled";
          appendMessage("result", "ocr job", "canceled", completed.id ? completed.id.slice(0, 8) : "job");
          return null;
        }

        if (completed.status !== "succeeded") {
          throw new Error(completed.errorMessage || `OCR job ${completed.status}`);
        }

        outcome = "succeeded";

        const jobResult = await api(`/ocr/jobs/${encodeURIComponent(completed.id)}/result`);
        const event = jobResult.result;
        if (!event) {
          throw new Error("OCR job completed without a result.");
        }

        const elapsed = Math.round(performance.now() - started);
        if (!isCurrentOcrImageSession(imageSessionId)) {
          return null;
        }
        return applyOcrResult(
          {
            text: event.correctedText || event.rawText || "",
            rawText: event.rawText || "",
            blocks: event.blocks || [],
            provider: event.provider || completed.provider,
            engine: event.engine || completed.engine,
            language: event.language || completed.language,
            cacheHit: completed.cacheHit
          },
          elapsed,
          "ocr job");
      } finally {
        endOcrJobProgress(outcome);
        state.activeOcrJobId = "";
        state.ocrJobCancelRequested = false;
        updateOcrJobControls();
        loadOcrHistory().catch(error => appendMessage("error", "ocr history", error.message || String(error)));
        loadOcrCorrections().catch(error => appendMessage("error", "ocr corrections", error.message || String(error)));
      }
    }

    async function cancelActiveOcrJob() {
      const jobId = state.activeOcrJobId;
      if (!jobId || state.ocrJobCancelRequested) {
        return;
      }

      state.ocrJobCancelRequested = true;
      updateOcrJobControls();
      $("ocrJobStatus").textContent = `canceling ${jobId.slice(0, 8)}`;
      if (state.ocrJobProgress) {
        state.ocrJobProgress.label = "canceling";
        renderOcrJobProgress();
      }

      try {
        await post(`/ocr/jobs/${encodeURIComponent(jobId)}/cancel`, {});
        appendMessage("result", "ocr job", "cancel requested", jobId.slice(0, 8));
        loadOcrHistory().catch(error => appendMessage("error", "ocr history", error.message || String(error)));
      } catch (error) {
        state.ocrJobCancelRequested = false;
        updateOcrJobControls();
        $("ocrJobStatus").textContent = "cancel failed";
        appendMessage("error", "ocr job", error.message || String(error), "cancel");
      }
    }

    async function translateText(text, title = "source") {
      if (!text) {
        appendMessage("error", "translate", "source is empty");
        return null;
      }

      const model = $("translationModel").value.trim();
      const provider = $("translationProvider").value;
      applyTokenUsage(null);
      appendMessage("user", title, text, model ? `${provider} / ${model}` : provider);
      const started = performance.now();
      const result = await post("/translate", translationPayload(text), {
        headers: memoryRuntimeHeaders()
      });
      const elapsed = Math.round(performance.now() - started);
      $("latencyLabel").textContent = `${elapsed} ms`;

      if (result.errorCode !== "0") {
        const fallback = result.result || text;
        if (fallback) {
          lastOutput.value = fallback;
          syncTranslateUi();
        }
        appendMessage("error", "translate", result.errorMessage || result.result, `${elapsed} ms`);
        return;
      }

      const tokenUsage = result.tokenUsage || result.TokenUsage || null;
      applyTokenUsage(tokenUsage);
      lastOutput.value = result.result || "";
      syncTranslateUi();
      appendMessage("result", "translation", result.result || "", appendTokenUsageMeta(`${elapsed} ms`, tokenUsage));
      $("metricCache").textContent = "ok";
      return result;
    }

    async function runTranslate() {
      const text = sourceText.value.trim();
      await translateText(text, "source");
    }

    async function translateEditedOcrText() {
      if (state.busy) {
        return;
      }

      const text = ocrOutput.value.trim();
      if (!text) {
        appendMessage("error", "translation", "ocr text is empty");
        return;
      }

      setBusy(true);
      try {
        sourceText.value = text;
        if (imageBase64.value.trim()) {
          const imageSessionId = state.ocrImageSessionId;
          const started = performance.now();
          const controller = beginOcrImageRequest();
          let result;
          try {
            result = await post("/ocr/translate", buildOcrTranslatePayload(imageBase64.value.trim()), {
              headers: memoryRuntimeHeaders(),
              signal: controller.signal
            });
          } finally {
            finishOcrImageRequest(controller);
          }
          const elapsed = Math.round(performance.now() - started);
          if (!isCurrentOcrImageSession(imageSessionId)) {
            return;
          }
          applyOcrTranslateResult(result, elapsed, "ocr");
          return;
        }

        const result = await translateText(text, "edited ocr");
        if (result && result.errorCode === "0" && result.result) {
          ocrTranslationOutput.value = result.result || "";
          setOcrTextCollapsed(false);
          setOcrStructureCollapsed(true);
          setOcrPreviewCollapsed(true);
          updateOcrComposerPreview();
          renderOcrFallbackTranslationOverlay(state.latestOcr, state.latestOcrStructured, result.result);
        }
      } catch (error) {
        if (isAbortError(error)) {
          return;
        }
        appendMessage("error", "translation", error.message || String(error));
      } finally {
        setBusy(false);
      }
    }

    async function runOcr() {
      if (!imageBase64.value.trim()) {
        appendMessage("error", "ocr", "image base64 is empty");
        return null;
      }

      const imageSessionId = state.ocrImageSessionId;
      const started = performance.now();
      if (shouldRunOcrAsJob()) {
        return await runOcrJob(started, imageSessionId);
      }

      beginOcrJobProgress({ indeterminate: true });
      let result;
      const controller = beginOcrImageRequest();
      try {
        result = await post("/ocr", ocrPayload(), { signal: controller.signal });
        endOcrJobProgress("succeeded");
      } catch (error) {
        endOcrJobProgress(isAbortError(error) ? "canceled" : "failed");
        throw error;
      } finally {
        finishOcrImageRequest(controller);
      }

      const elapsed = Math.round(performance.now() - started);
      if (!isCurrentOcrImageSession(imageSessionId)) {
        return null;
      }
      const applied = applyOcrResult(result, elapsed, "ocr");
      applyTokenUsage(zeroTokenUsage("ocr:no-llm"), "ocr");
      loadOcrHistory().catch(error => appendMessage("error", "ocr history", error.message || String(error)));
      loadOcrCorrections().catch(error => appendMessage("error", "ocr corrections", error.message || String(error)));
      return applied;
    }

    function buildOcrTranslatePayload(imageBase64Value, imageMimeType = null, broadcastSourceKind = null, mergeTextBlocks = false, realtime = false) {
      const glossary = $("glossary").value;
      const resolvedImageMimeType = imageMimeType || state.imageMimeType || "";
      return {
        imageBase64: imageBase64Value,
        ...(resolvedImageMimeType ? { imageMimeType: resolvedImageMimeType } : {}),
        ...(broadcastSourceKind ? { broadcastSourceKind } : {}),
        ...(mergeTextBlocks ? { mergeTextBlocks: true } : {}),
        ...(realtime ? { realtime: true } : {}),
        ocrProvider: $("ocrProvider").value,
        contentType: $("ocrContentType").value,
        preference: $("ocrPreference").value,
        language: $("ocrLanguage").value,
        profile: currentOcrProfile(),
        preprocessingPreset: $("ocrPreprocessingPreset").value || "none",
        translationProvider: $("translationProvider").value,
        model: $("translationModel").value.trim() || null,
        source: $("source").value,
        target: $("target").value,
        mode: $("preset").value,
        surface: "ocr",
        glossary: glossary || null
      };
    }

    function applyOcrTranslateResult(result, elapsed, sourceLabel = "ocr") {
      $("latencyLabel").textContent = `${elapsed} ms`;

      state.latestOcrText = result.ocr.text || "";
      ocrOutput.value = state.latestOcrText;
      sourceText.value = state.latestOcrText;
      $("blockCount").textContent = String(result.ocr.blocks ? result.ocr.blocks.length : 0);
      $("engineName").textContent = result.ocr.engine || "-";
      setOcrPreviewModeButtons("overlay");
      renderOcrStructure(result.ocr, result.structured || null);
      resetBlockSelectionForNewResult();
      setOcrTextCollapsed(false);
      setOcrStructureCollapsed(true);
      setOcrPreviewCollapsed(true);

      const translation = result.translation || {};
      const tokenUsage = translation.tokenUsage || translation.TokenUsage || (result.structured && (result.structured.tokenUsage || result.structured.TokenUsage)) || null;
      applyTokenUsage(tokenUsage, "ocr");
      lastOutput.value = translation.result || "";
      ocrTranslationOutput.value = translation.result || "";
      appendMessage("user", sourceLabel, state.latestOcrText, result.ocr.provider || "");
      if (translation.errorCode && translation.errorCode !== "0") {
        appendMessage("error", "translation", translation.errorMessage || translation.result || "", appendTokenUsageMeta(`${elapsed} ms`, tokenUsage));
      } else {
        appendMessage("result", "translation", translation.result || "", appendTokenUsageMeta(`${elapsed} ms`, tokenUsage));
      }

      if (result.structured && !result.structured.overlayHtml) {
        const diagnostics = result.structured.layoutDiagnostics || {};
        const missing = Number(diagnostics.blocksMissingBoundingBox || 0) + Number(diagnostics.tableCellsMissingBoundingBox || 0);
        if (missing > 0 || !diagnostics.overlayReady) {
          appendMessage("error", "ocr overlay", "structured overlay needs OCR bounding boxes; switch OCR engine or structure lane", "no bbox");
        }
      }

      updateOcrComposerPreview();
      loadOcrHistory().catch(error => appendMessage("error", "ocr history", error.message || String(error)));
      loadOcrCorrections().catch(error => appendMessage("error", "ocr corrections", error.message || String(error)));
      return result;
    }

    async function runPipeline() {
      if (!imageBase64.value.trim()) {
        appendMessage("error", "ocr", "image base64 is empty");
        return;
      }

      const imageSessionId = state.ocrImageSessionId;
      const started = performance.now();
      const controller = beginOcrImageRequest();
      let result;
      try {
        result = await post("/ocr/translate", buildOcrTranslatePayload(imageBase64.value.trim()), {
          headers: memoryRuntimeHeaders(),
          signal: controller.signal
        });
      } finally {
        finishOcrImageRequest(controller);
      }
      const elapsed = Math.round(performance.now() - started);
      if (!isCurrentOcrImageSession(imageSessionId)) {
        return null;
      }
      return applyOcrTranslateResult(result, elapsed, "ocr");
    }

    function renderSpeechSegments(speech, translations = []) {
      const byIndex = new Map((translations || []).map(item => [item.index, item]));
      const byKey = new Map((translations || []).map(item => [speechTranslationKey(item), item]));
      const segments = speech && speech.segments ? speech.segments : [];
      state.latestSpeechSegments = segments;
      state.latestSpeechTranslations = translations || [];
      speechSegmentsTable.innerHTML = "";

      for (const segment of segments) {
        const row = document.createElement("tr");
        const time = document.createElement("td");
        const source = document.createElement("td");
        const translationCell = document.createElement("td");
        const translation = byKey.get(speechTranslationKey(segment)) || byIndex.get(segment.index);
        time.textContent = `${formatClock(segment.startSeconds)}-${formatClock(segment.endSeconds)}`;
        source.textContent = segment.text || "";
        translationCell.textContent = translation ? translation.translatedText || translation.errorMessage || "" : "";
        row.append(time, source, translationCell);
        speechSegmentsTable.appendChild(row);
      }

      const text = speech && speech.text ? speech.text : segments.map(segment => segment.text || "").join("\n");
      asrOutput.value = text;
      sourceText.value = text;
      $("speechSegmentCount").textContent = String(segments.length);
      $("speechEngineName").textContent = speech && speech.engine ? speech.engine : "-";
      if (translations && translations.length > 0) {
        lastOutput.value = translations.map(item => item.translatedText || "").filter(Boolean).join("\n");
      }
    }

    async function runAsr() {
      if (!audioSourceUrl.value.trim() && !audioBase64.value.trim()) {
        appendMessage("error", "asr", "audio input is empty");
        return null;
      }

      applyTokenUsage(null, "audio");
      const sourceUrl = audioSourceUrl.value.trim();
      if (sourceUrl && isVideoSpeechUrl(sourceUrl)) {
        return await runVideoAsrSession(sourceUrl);
      }

      const started = performance.now();
      const result = await post("/asr", speechPayload());
      const elapsed = Math.round(performance.now() - started);
      $("latencyLabel").textContent = `${elapsed} ms`;
      renderSpeechSegments(result, []);
      applyTokenUsage(zeroTokenUsage("asr:no-llm"), "audio");
      appendMessage("result", "asr", result.text || "", `${result.provider} ${elapsed} ms`);
      return result;
    }

    async function runVideoAsrSession(sourceUrl, translate = false) {
      closeVideoSpeechEvents();
      state.latestSpeechSegments = [];
      state.latestSpeechTranslations = [];
      speechSegmentsTable.innerHTML = "";
      asrOutput.value = "";
      sourceText.value = "";
      $("speechSegmentCount").textContent = "0";
      $("speechEngineName").textContent = "starting video session";
      applyTokenUsage(null, "audio");
      state.videoSpeechStartedAt = performance.now();
      state.videoSpeechFirstSegmentAt = 0;
      state.videoSegmentKeys = new Set();
      if (state.videoSegmentRenderTimer) {
        clearTimeout(state.videoSegmentRenderTimer);
        state.videoSegmentRenderTimer = 0;
      }

      const session = await post("/asr/video-sessions", {
        sourceUrl,
        speechProvider: $("speechProvider").value,
        language: $("speechLanguage").value,
        glossary: $("glossary").value || null,
        preferCaptions: !translate,
        translate,
        source: $("source").value || $("speechLanguage").value,
        target: $("target").value,
        mode: $("preset").value || "subtitle",
        translationProvider: $("translationProvider").value,
        model: $("translationModel").value.trim() || null
      }, {
        headers: memoryRuntimeHeaders()
      });
      state.activeVideoSpeechSession = session;
      connectVideoSpeechEvents(session.id);
      appendMessage("result", "video asr", `session ${session.id}`, session.platform || "media");

      await post(`/asr/video-sessions/${encodeURIComponent(session.id)}/position`, {
        positionSeconds: 0,
        playing: true,
        lookaheadSeconds: 300,
        translate
      });
      $("speechEngineName").textContent = "queued current window";
      return session;
    }

    async function runAsrPipeline() {
      if (!audioSourceUrl.value.trim() && !audioBase64.value.trim()) {
        appendMessage("error", "audio", "audio input is empty");
        return;
      }

      const glossary = $("glossary").value;
      const sourceUrl = audioSourceUrl.value.trim();
      applyTokenUsage(null, "audio");
      if (sourceUrl && isVideoSpeechUrl(sourceUrl)) {
        return await runVideoAsrSession(sourceUrl, true);
      }

      const started = performance.now();
      const result = await post(
        "/asr/translate",
        {
          audioBase64: sourceUrl ? null : audioBase64.value.trim(),
          audioMimeType: state.audioMimeType || null,
          sourceUrl: sourceUrl || null,
          speechProvider: $("speechProvider").value,
          language: $("speechLanguage").value,
          translationProvider: $("translationProvider").value,
          model: $("translationModel").value.trim() || null,
          source: $("source").value || $("speechLanguage").value,
          target: $("target").value,
          mode: $("preset").value || "subtitle",
          glossary: glossary || null
        },
        { headers: memoryRuntimeHeaders() });
      const elapsed = Math.round(performance.now() - started);
      $("latencyLabel").textContent = `${elapsed} ms`;
      renderSpeechSegments(result.speech, result.translations || []);
      const tokenUsage = readTokenUsage(result) || mergeTokenUsages((result.translations || []).map(item => readTokenUsage(item)), "audio:segments");
      applyTokenUsage(tokenUsage || zeroTokenUsage("audio:empty"), "audio");
      appendMessage("user", "asr", result.speech && result.speech.text ? result.speech.text : "", result.speech ? result.speech.provider : "");
      appendMessage("result", "audio translation", lastOutput.value, appendTokenUsageMeta(`${elapsed} ms`, tokenUsage));
    }

    function formatClock(seconds) {
      const value = Math.max(0, Number(seconds) || 0);
      const whole = Math.floor(value);
      const minutes = Math.floor(whole / 60);
      const remain = whole % 60;
      return `${String(minutes).padStart(2, "0")}:${String(remain).padStart(2, "0")}`;
    }

    function formatSubtitleTime(seconds, separator) {
      const value = Math.max(0, Number(seconds) || 0);
      const whole = Math.floor(value);
      const millis = Math.round((value - whole) * 1000);
      const hours = Math.floor(whole / 3600);
      const minutes = Math.floor((whole % 3600) / 60);
      const remain = whole % 60;
      return `${String(hours).padStart(2, "0")}:${String(minutes).padStart(2, "0")}:${String(remain).padStart(2, "0")}${separator}${String(millis).padStart(3, "0")}`;
    }

    function currentSubtitleRows() {
      const byIndex = new Map((state.latestSpeechTranslations || []).map(item => [item.index, item]));
      return (state.latestSpeechSegments || []).map(segment => {
        const translation = byIndex.get(segment.index);
        return {
          index: segment.index,
          start: segment.startSeconds,
          end: segment.endSeconds,
          text: translation && translation.translatedText ? translation.translatedText : segment.text || ""
        };
      }).filter(row => row.text);
    }

    function buildSrt() {
      return currentSubtitleRows().map((row, index) =>
        `${index + 1}\n${formatSubtitleTime(row.start, ",")} --> ${formatSubtitleTime(row.end, ",")}\n${row.text}\n`).join("\n");
    }

    function buildVtt() {
      return `WEBVTT\n\n${currentSubtitleRows().map(row =>
        `${formatSubtitleTime(row.start, ".")} --> ${formatSubtitleTime(row.end, ".")}\n${row.text}\n`).join("\n")}`;
    }

    async function copySubtitle(kind) {
      const text = kind === "vtt" ? buildVtt() : buildSrt();
      if (!text.trim()) {
        appendMessage("error", "subtitle", "no segments to export");
        return;
      }

      await navigator.clipboard.writeText(text);
      appendMessage("result", "subtitle", `${kind.toUpperCase()} copied`, "export");
    }

    function setRegionCaptureStatus(value) {
      const status = $("regionCaptureStatus");
      if (status) status.textContent = value;
      const paneStatus = $("regionPaneCaptureStatus");
      if (paneStatus) paneStatus.textContent = value;
      const dot = $("regionPaneCaptureDot");
      if (dot) dot.classList.toggle("active", value === "on");
      regionStage.classList.toggle("active", value === "on");
      regionStage.classList.toggle("has-capture", value === "on");
      $("regionPlaceholder").classList.toggle("hidden", value === "on");
    }

    function setRegionLoopStatus(value) {
      const status = $("regionLoopStatus");
      if (status) status.textContent = value;
      const paneStatus = $("regionPaneLoopStatus");
      if (paneStatus) paneStatus.textContent = value;

      const loopBtn = $("toggleRegionLoopButton");
      if (loopBtn) {
        const on = value === "on";
        loopBtn.classList.toggle("is-on", on);
        loopBtn.setAttribute("aria-pressed", String(on));
        const stateLabel = loopBtn.querySelector(".control-switch-state");
        if (stateLabel) stateLabel.textContent = on ? "On" : "Off";
      }

      const settingsLoopBtn = $("settingsToggleRegionLoopButton");
      if (settingsLoopBtn) settingsLoopBtn.textContent = value === "on" ? "Loop On" : "Loop Off";
    }

    function isValidNormRegion(region) {
      return !!region &&
        [region.x, region.y, region.width, region.height].every(Number.isFinite) &&
        region.width > 0 && region.height > 0 &&
        region.x >= 0 && region.y >= 0 &&
        region.x + region.width <= 1 && region.y + region.height <= 1;
    }

    function loadRegionSettings() {
      try {
        const raw = window.localStorage.getItem("lth.regionSettings");
        const parsed = raw ? JSON.parse(raw) : {};
        return {
          selection: isValidNormRegion(parsed.selection) ? parsed.selection : null,
          // 1500 and 700 are old defaults that got auto-saved on every run;
          // treat them as unset so existing installs pick up the faster 300ms
          // min OCR gap (the stable-tick gate still filters half-rendered frames).
          intervalMs: Number.isFinite(parsed.intervalMs) && parsed.intervalMs !== 1500 && parsed.intervalMs !== 700 && parsed.intervalMs !== 500 ? Math.max(250, parsed.intervalMs) : null,
          excludes: Array.isArray(parsed.excludes) ? parsed.excludes.filter(isValidNormRegion) : [],
          dropPatterns: typeof parsed.dropPatterns === "string" ? parsed.dropPatterns : "",
          motionMode: parsed.motionMode === true,
          preprocess: typeof parsed.preprocess === "string" ? parsed.preprocess : "none"
        };
      } catch {
        return { selection: null, intervalMs: null, excludes: [], dropPatterns: "", motionMode: false, preprocess: "none" };
      }
    }

    const regionSettings = loadRegionSettings();

    function saveRegionSettings() {
      regionSettings.selection = state.regionSelection ? { ...state.regionSelection } : null;
      regionSettings.intervalMs = getRegionInterval();
      regionSettings.excludes = state.regionExcludes.map(exclude => ({ ...exclude }));
      regionSettings.dropPatterns = $("regionDropPatterns") ? $("regionDropPatterns").value : "";
      regionSettings.motionMode = $("regionMotionMode") ? $("regionMotionMode").checked : !!regionSettings.motionMode;
      regionSettings.preprocess = $("regionPreprocess") ? $("regionPreprocess").value : (regionSettings.preprocess || "none");
      try {
        window.localStorage.setItem("lth.regionSettings", JSON.stringify(regionSettings));
      } catch {
      }
    }

    // Region backend selector: "native" (in-process CopyFromScreen + editable multi-region overlay,
    // the same engine the tray uses) or "browser" (getDisplayMedia screen-share). Persisted so the
    // user's last choice sticks. The two are mutually exclusive — switching stops the other engine.
    const REGION_BACKEND_KEY = "lth.regionBackend";
    const NATIVE_STATUS_POLL_MS = 1500;

    function loadRegionBackend() {
      try {
        const saved = window.localStorage.getItem(REGION_BACKEND_KEY);
        if (saved === "native" || saved === "browser") return saved;
      } catch {
      }
      return "native";
    }

    function persistRegionBackend(value) {
      try {
        window.localStorage.setItem(REGION_BACKEND_KEY, value);
      } catch {
      }
    }

    let regionBackend = loadRegionBackend();
    let nativeStatusPollHandle = 0;

    function applyRegionBackend(backend) {
      // native-adhoc-only hides the browser toolbar+stage and shows just the native panel;
      // removing it shows the browser toolbar+stage (Capture/Snapshot/Loop/Stop + video).
      const pane = document.getElementById("regionPane");
      if (pane) pane.classList.toggle("native-adhoc-only", backend === "native");
      const pill = document.getElementById("regionBackendPill");
      if (pill) {
        for (const btn of pill.querySelectorAll("button")) {
          const active = btn.dataset.backend === backend;
          btn.classList.toggle("active", active);
          btn.setAttribute("aria-selected", String(active));
          btn.setAttribute("tabindex", active ? "0" : "-1");
        }
      }
    }

    async function setRegionBackend(next) {
      if (next === regionBackend) return;
      // Mutual exclusion: stop the engine we're leaving so they never run concurrently.
      if (regionBackend === "native") {
        try { await postEmpty("/region/native/stop"); } catch { /* best-effort */ }
        stopNativeStatusPoll();
        clearNativeSurfaceMap();
      } else if (regionBackend === "browser") {
        stopRegionCapture();
      }
      regionBackend = next;
      persistRegionBackend(next);
      applyRegionBackend(next);
      if (next === "native") {
        // Refresh native status now + resume polling.
        api("/region/native/status").then(renderNativeStatus).catch(() => {});
        startNativeStatusPoll();
      }
      appendMessage("system", "region", "backend: " + next);
    }

    function startNativeStatusPoll() {
      stopNativeStatusPoll();
      nativeStatusPollHandle = window.setInterval(() => {
        api("/region/native/status").then(renderNativeStatus).catch(() => {});
      }, NATIVE_STATUS_POLL_MS);
    }

    function stopNativeStatusPoll() {
      if (nativeStatusPollHandle) {
        window.clearInterval(nativeStatusPollHandle);
        nativeStatusPollHandle = 0;
      }
    }

    function videoContentRect() {
      const stageBounds = regionStage.getBoundingClientRect();
      const videoBounds = regionVideo.getBoundingClientRect();
      let left = videoBounds.left - stageBounds.left;
      let top = videoBounds.top - stageBounds.top;
      let width = videoBounds.width;
      let height = videoBounds.height;
      const videoWidth = regionVideo.videoWidth;
      const videoHeight = regionVideo.videoHeight;
      if (videoWidth > 0 && videoHeight > 0 && width > 0 && height > 0) {
        // <video> letterboxes its content (object-fit: contain); map to the painted area.
        const scale = Math.min(width / videoWidth, height / videoHeight);
        const contentWidth = videoWidth * scale;
        const contentHeight = videoHeight * scale;
        left += (width - contentWidth) / 2;
        top += (height - contentHeight) / 2;
        width = contentWidth;
        height = contentHeight;
      }

      return { left, top, width: Math.max(1, width), height: Math.max(1, height) };
    }

    function stagePointToNorm(point) {
      const rect = videoContentRect();
      return {
        x: Math.max(0, Math.min(1, (point.x - rect.left) / rect.width)),
        y: Math.max(0, Math.min(1, (point.y - rect.top) / rect.height))
      };
    }

    function normRegionToStageRect(region) {
      const rect = videoContentRect();
      return {
        x: rect.left + region.x * rect.width,
        y: rect.top + region.y * rect.height,
        width: region.width * rect.width,
        height: region.height * rect.height
      };
    }

    function clampNormRegion(region) {
      const width = Math.max(0, Math.min(1, region.width));
      const height = Math.max(0, Math.min(1, region.height));
      return {
        x: Math.max(0, Math.min(1 - width, region.x)),
        y: Math.max(0, Math.min(1 - height, region.y)),
        width,
        height
      };
    }

    function regionSelectionTooSmall(region) {
      const videoWidth = regionVideo.videoWidth || 1920;
      const videoHeight = regionVideo.videoHeight || 1080;
      return region.width * videoWidth < 8 || region.height * videoHeight < 8;
    }

    function updateRegionSelectionStatus() {
      const region = state.regionSelection;
      let text = "-";
      if (region) {
        const videoWidth = regionVideo.videoWidth;
        const videoHeight = regionVideo.videoHeight;
        if (videoWidth && videoHeight) {
          text = `${Math.round(region.x * videoWidth)},${Math.round(region.y * videoHeight)} ` +
            `${Math.round(region.width * videoWidth)}x${Math.round(region.height * videoHeight)}`;
        } else {
          text = `${Math.round(region.width * 100)}% x ${Math.round(region.height * 100)}%`;
        }
      }

      const status = $("regionSelectionStatus");
      if (status) status.textContent = text;
      const paneStatus = $("regionPaneSelectionStatus");
      if (paneStatus) paneStatus.textContent = text;
    }

    function positionRegionTranslationOverlay() {
      if (!regionTranslationOverlay || !state.regionSelection) {
        return;
      }
      const rect = normRegionToStageRect(state.regionSelection);
      const stageHeight = regionStage.clientHeight || (rect.y + rect.height);
      const gap = 8;
      regionTranslationOverlay.style.left = `${rect.x + rect.width / 2}px`;
      const overlayHeight = regionTranslationOverlay.offsetHeight || 0;
      const belowTop = rect.y + rect.height + gap;
      if (belowTop + overlayHeight > stageHeight && rect.y - gap - overlayHeight > 0) {
        regionTranslationOverlay.style.top = `${rect.y - gap - overlayHeight}px`;
      } else {
        regionTranslationOverlay.style.top = `${belowTop}px`;
      }
    }

    function updateRegionTranslationOverlayVisibility() {
      if (!regionTranslationOverlay) {
        return;
      }
      const hasText = Boolean((regionTranslationOverlay.textContent || "").trim());
      const show = hasText && Boolean(state.regionSelection);
      const wasHidden = regionTranslationOverlay.classList.contains("hidden");
      regionTranslationOverlay.classList.toggle("hidden", !show);
      // Reposition only when (re)appearing; per-token stream updates keep the current anchor so we
      // do not force a layout reflow on every delta.
      if (show && wasHidden) {
        positionRegionTranslationOverlay();
      }
    }

    // Single sink for the region translation surfaces (textarea + on-video bar). Routing every
    // translation write through here keeps the perceived-speed states (stale / loading / fresh)
    // consistent across both surfaces.
    // One sink that paints BOTH region translation surfaces (textarea = primary line; on-video bar =
    // primary + optional dimmer secondary line) from state, so the perceived-speed flags and the
    // Phase-3 secondary lane stay consistent without each caller knowing about the other.
    function paintRegionTranslationSurfaces(opts = {}) {
      const primary = state.regionPrimaryTranslation || "";
      const secondary = state.regionSecondaryTranslation || "";
      const stale = Boolean(state.regionBarStale);
      const loading = Boolean(state.regionBarLoading);
      regionTranslationText.value = primary;
      regionTranslationText.classList.toggle("is-stale", stale);
      regionTranslationText.classList.toggle("is-loading", loading);
      if (!regionTranslationOverlay) {
        return;
      }
      regionTranslationOverlay.textContent = primary;
      if (secondary) {
        const span = document.createElement("span");
        span.className = "region-translation-secondary";
        span.textContent = secondary;
        regionTranslationOverlay.appendChild(span);
      }
      regionTranslationOverlay.classList.toggle("stale", stale);
      regionTranslationOverlay.classList.toggle("loading", loading);
      if (opts.fresh) {
        regionTranslationOverlay.classList.remove("fresh");
        void regionTranslationOverlay.offsetWidth;
        regionTranslationOverlay.classList.add("fresh");
      }
      updateRegionTranslationOverlayVisibility();
    }

    // Primary (main subtitle) translation writer. Animates a fade-in only on a real text change so a
    // streamed final (same text the last partial already showed) does not re-flash.
    function setRegionTranslationText(text, options = {}) {
      const value = text == null ? "" : String(text);
      const previous = state.regionPrimaryTranslation || "";
      state.regionPrimaryTranslation = value;
      state.regionBarStale = false;
      state.regionBarLoading = false;
      paintRegionTranslationSurfaces({ fresh: Boolean(options.fresh) && Boolean(value) && value !== previous });
    }

    // Low-priority secondary (persistent header / side text) line on the bar.
    function setRegionSecondaryTranslation(text) {
      const value = text == null ? "" : String(text);
      if (value === (state.regionSecondaryTranslation || "")) {
        return;
      }
      state.regionSecondaryTranslation = value;
      paintRegionTranslationSurfaces({});
    }

    // New subtitle detected: keep the previous translation on screen but grey it + show the
    // loading pulse, so the stale text never reads as the (not-yet-arrived) new translation.
    function markRegionTranslationStale() {
      state.regionBarStale = true;
      state.regionBarLoading = true;
      paintRegionTranslationSurfaces({});
    }

    function clearRegionTranslationPending() {
      state.regionBarStale = false;
      state.regionBarLoading = false;
      paintRegionTranslationSurfaces({});
    }

    function renderRegionSelection() {
      renderRegionExcludes();
      const region = state.regionSelection;
      if (!region) {
        regionSelection.classList.add("hidden");
        updateRegionTranslationOverlayVisibility();
        return;
      }

      const rect = normRegionToStageRect(region);
      regionSelection.style.left = `${rect.x}px`;
      regionSelection.style.top = `${rect.y}px`;
      regionSelection.style.width = `${rect.width}px`;
      regionSelection.style.height = `${rect.height}px`;
      regionSelection.classList.remove("hidden");
      positionRegionTranslationOverlay();
    }

    function renderRegionExcludes() {
      for (const node of regionStage.querySelectorAll(".region-exclude")) {
        node.remove();
      }
      const drag = state.regionDrag;
      const items = drag && drag.mode === "exclude" && drag.currentRegion
        ? [...state.regionExcludes, drag.currentRegion]
        : state.regionExcludes;
      for (const exclude of items) {
        const rect = normRegionToStageRect(exclude);
        const node = document.createElement("div");
        node.className = "region-exclude";
        node.style.left = `${rect.x}px`;
        node.style.top = `${rect.y}px`;
        node.style.width = `${rect.width}px`;
        node.style.height = `${rect.height}px`;
        regionStage.appendChild(node);
      }
      updateRegionExcludeCount();
    }

    function updateRegionExcludeCount() {
      const count = state.regionExcludes.length;
      const paneCount = $("regionPaneExcludeCount");
      if (paneCount) paneCount.textContent = String(count);
    }

    function setRegionExcludeMode(active) {
      state.regionExcludeMode = !!active;
      const button = $("markRegionExcludeButton");
      button.classList.toggle("active", state.regionExcludeMode);
      button.classList.toggle("is-on", state.regionExcludeMode);
      button.setAttribute("aria-pressed", state.regionExcludeMode ? "true" : "false");
      const stateLabel = button.querySelector(".control-switch-state");
      if (stateLabel) stateLabel.textContent = state.regionExcludeMode ? "On" : "Off";
      regionStage.classList.toggle("exclude-mode", state.regionExcludeMode);
      updateRegionExcludeCount();
    }

    function setRegionSelection(region) {
      state.regionSelection = region && !regionSelectionTooSmall(region) ? clampNormRegion(region) : null;
      state.regionLastFrameSample = null;
      resetRegionTextStability();
      renderRegionSelection();
      updateRegionSelectionStatus();
    }

    function getRegionPoint(event) {
      const bounds = regionStage.getBoundingClientRect();
      return {
        x: Math.max(0, Math.min(bounds.width, event.clientX - bounds.left)),
        y: Math.max(0, Math.min(bounds.height, event.clientY - bounds.top))
      };
    }

    function hitTestSelection(point) {
      const region = state.regionSelection;
      if (!region) {
        return { mode: "new" };
      }

      const rect = normRegionToStageRect(region);
      const grip = 14;
      const corners = [
        { corner: "nw", x: rect.x, y: rect.y },
        { corner: "ne", x: rect.x + rect.width, y: rect.y },
        { corner: "sw", x: rect.x, y: rect.y + rect.height },
        { corner: "se", x: rect.x + rect.width, y: rect.y + rect.height }
      ];
      for (const candidate of corners) {
        if (Math.abs(point.x - candidate.x) <= grip && Math.abs(point.y - candidate.y) <= grip) {
          return { mode: "resize", corner: candidate.corner };
        }
      }

      if (point.x >= rect.x && point.x <= rect.x + rect.width &&
          point.y >= rect.y && point.y <= rect.y + rect.height) {
        return { mode: "move" };
      }

      return { mode: "new" };
    }

    function updateRegionDrag(point) {
      const drag = state.regionDrag;
      if (!drag) {
        return;
      }

      const norm = stagePointToNorm(point);
      if (drag.mode === "exclude") {
        drag.currentRegion = clampNormRegion({
          x: Math.min(drag.startPoint.x, norm.x),
          y: Math.min(drag.startPoint.y, norm.y),
          width: Math.abs(norm.x - drag.startPoint.x),
          height: Math.abs(norm.y - drag.startPoint.y)
        });
        renderRegionExcludes();
        return;
      }

      if (drag.mode === "move") {
        const start = drag.startRegion;
        setRegionSelection({
          x: start.x + (norm.x - drag.startPoint.x),
          y: start.y + (norm.y - drag.startPoint.y),
          width: start.width,
          height: start.height
        });
        return;
      }

      let anchor = drag.startPoint;
      if (drag.mode === "resize") {
        const start = drag.startRegion;
        anchor = {
          x: drag.corner.includes("w") ? start.x + start.width : start.x,
          y: drag.corner.includes("n") ? start.y + start.height : start.y
        };
      }

      setRegionSelection({
        x: Math.min(anchor.x, norm.x),
        y: Math.min(anchor.y, norm.y),
        width: Math.abs(norm.x - anchor.x),
        height: Math.abs(norm.y - anchor.y)
      });
    }

    function setDefaultRegionSelection() {
      if (state.regionSelection || !state.regionStream) {
        return;
      }

      if (regionSettings.selection) {
        setRegionSelection({ ...regionSettings.selection });
        return;
      }

      setRegionSelection({ x: 0.14, y: 0.64, width: 0.72, height: 0.28 });
    }

    async function startRegionCapture() {
      if (state.regionCapturePromise) {
        return state.regionCapturePromise;
      }

      state.regionCapturePromise = startRegionCaptureInternal();
      try {
        return await state.regionCapturePromise;
      } finally {
        state.regionCapturePromise = null;
      }
    }

    async function startRegionCaptureInternal() {
      if (!navigator.mediaDevices || !navigator.mediaDevices.getDisplayMedia) {
        throw new Error("screen capture is not supported in this browser");
      }

      stopRegionCapture(false);
      setRegionCaptureStatus("requesting");
      // Picker hints (Chrome 107+, ignored elsewhere): list every surface type ??
      // all monitors, app windows (even ones on another screen or covered), and
      // this browser's own tabs ??and keep the "share something else" button so
      // the source can be switched mid-capture without stopping the loop.
      let stream;
      try {
        const captureQuality = browserRegionCaptureQuality();
        stream = await navigator.mediaDevices.getDisplayMedia({
          // Request the highest available capture resolution. Without width/height
          // constraints getDisplayMedia downscales the shared surface (often to
          // ~1080p or the DPI-scaled logical size), which thins small vertical CJK
          // strokes until DBNet DET drops them. Constraints are hints: Chrome caps
          // at the surface's real device-pixel resolution, so sharing a TAB (not a
          // window) with the player rendered large yields close to native pixels.
          video: {
            cursor: "always",
            width: { ideal: captureQuality.width, max: captureQuality.width },
            height: { ideal: captureQuality.height, max: captureQuality.height },
            frameRate: { ideal: captureQuality.fps, max: captureQuality.fps }
          },
          audio: false,
          selfBrowserSurface: "include",
          surfaceSwitching: "include",
          monitorTypeSurfaces: "include"
        });
      } catch (error) {
        setRegionCaptureStatus("off");
        throw error;
      }

      state.regionStream = stream;
      // Fresh OCR session per capture run so the server-side realtime layout
      // cache never reuses line boxes from a previous capture surface.
      rotateRegionOcrSession();
      resetRegionTextStability();
      regionVideo.srcObject = stream;
      await regionVideo.play();
      setRegionCaptureStatus("on");
      appendMessage("result", "region", `screen capture ready (${browserRegionCaptureQuality().label})`, "capture");

      for (const track of stream.getVideoTracks()) {
        track.addEventListener("ended", () => stopRegionCapture());
        // Surface the resolution the source is ACTUALLY delivering (after the
        // constraints above) so a low-res capture is visible at a glance: if this
        // is well below the source video's native pixels, the small vertical text
        // will be lost before OCR ever sees it (share the Tab / enlarge the player).
        const settings = track.getSettings ? track.getSettings() : {};
        if (settings.width && settings.height) {
          appendMessage("result", "region", `capture ${settings.width}x${settings.height}` +
            (settings.frameRate ? ` @${Math.round(settings.frameRate)}fps` : ""), "capture");
        }
      }

      window.setTimeout(setDefaultRegionSelection, 120);
    }

    function stopRegionCapture(showMessage = true) {
      stopRegionLoop(false);
      cancelRegionAutoSnapshot();
      if (state.regionStream) {
        for (const track of state.regionStream.getTracks()) {
          track.stop();
        }
      }

      state.regionStream = null;
      regionVideo.srcObject = null;
      resetRegionTextStability();
      setRegionCaptureStatus("off");
      if (showMessage) {
        appendMessage("result", "region", "screen capture stopped", "capture");
      }
    }

    function getRegionSourceRect() {
      if (!state.regionStream || !regionVideo.videoWidth || !regionVideo.videoHeight) {
        throw new Error("capture a screen first");
      }

      const region = state.regionSelection;
      if (!region) {
        throw new Error("drag a region over the preview first");
      }

      const videoWidth = regionVideo.videoWidth;
      const videoHeight = regionVideo.videoHeight;
      const sx = Math.max(0, Math.round(region.x * videoWidth));
      const sy = Math.max(0, Math.round(region.y * videoHeight));
      const sw = Math.max(1, Math.min(videoWidth - sx, Math.round(region.width * videoWidth)));
      const sh = Math.max(1, Math.min(videoHeight - sy, Math.round(region.height * videoHeight)));
      return { sx, sy, sw, sh };
    }

    function regionOcrSyntheticPadding(width, height) {
      return {
        x: Math.max(18, Math.min(42, Math.round(width * 0.035))),
        y: Math.max(6, Math.min(18, Math.round(height * 0.08)))
      };
    }

    function getRegionCropCanvas() {
      const { sx, sy, sw, sh } = getRegionSourceRect();
      const pad = regionOcrSyntheticPadding(sw, sh);

      // Reuse one canvas instead of allocating per call. encodeRegionCrop snapshots
      // the pixels synchronously, so a later repaint cannot corrupt an in-flight encode.
      if (!regionCropCanvas) {
        regionCropCanvas = document.createElement("canvas");
      }

      regionCropCanvas.width = sw + pad.x * 2;
      regionCropCanvas.height = sh + pad.y * 2;
      const context = regionCropCanvas.getContext("2d");
      context.fillStyle = "#000";
      context.fillRect(0, 0, regionCropCanvas.width, regionCropCanvas.height);
      context.drawImage(regionVideo, sx, sy, sw, sh, pad.x, pad.y, sw, sh);
      return regionCropCanvas;
    }

    let regionCropCanvas = null;
    let regionScaleCanvas = null;
    let regionSampleCanvas = null;

    function releaseRegionCanvases() {
      regionCropCanvas = null;
      regionScaleCanvas = null;
      regionSampleCanvas = null;
      regionBandProbeCanvas = null;
      regionBandOutCanvas = null;
    }

    function sampleRegionFrame(cropCanvas) {
      const sampleWidth = Math.max(1, Math.min(64, cropCanvas.width));
      const sampleHeight = Math.max(1, Math.round(cropCanvas.height * (sampleWidth / cropCanvas.width)));
      if (!regionSampleCanvas) {
        regionSampleCanvas = document.createElement("canvas");
      }

      regionSampleCanvas.width = sampleWidth;
      regionSampleCanvas.height = sampleHeight;
      const context = regionSampleCanvas.getContext("2d", { willReadFrequently: true });
      context.drawImage(cropCanvas, 0, 0, sampleWidth, sampleHeight);
      return context.getImageData(0, 0, sampleWidth, sampleHeight).data;
    }

    function framesDiffer(previous, sample) {
      if (!previous || !sample || previous.length !== sample.length) {
        return true;
      }

      let changedPixels = 0;
      for (let i = 0; i < sample.length; i += 4) {
        const diff = Math.abs(sample[i] - previous[i]) +
          Math.abs(sample[i + 1] - previous[i + 1]) +
          Math.abs(sample[i + 2] - previous[i + 2]);
        if (diff > 24) {
          changedPixels += 1;
        }
      }

      return changedPixels / (sample.length / 4) > 0.005;
    }

    // Text-mask perceptual fingerprint of the subtitle strip. Binarizes a small
    // downscale to the BRIGHT pixels (subtitle glyphs are high-contrast white/light),
    // which ignores mid-tone animated backgrounds and semi-transparent watermark
    // drift far better than a raw-RGB pixel diff. Comparing fingerprints lets the
    // loop OCR only when the on-screen TEXT actually changes ??event-driven instead
    // of polling every cadence (faster to react, ~0 CPU while a subtitle is static).
    let regionFpCanvas = null;
    const REGION_FP_W = 64;
    const REGION_FP_H = 16;
    function regionFpContext() {
      if (!regionFpCanvas) {
        regionFpCanvas = document.createElement("canvas");
      }
      regionFpCanvas.width = REGION_FP_W;
      regionFpCanvas.height = REGION_FP_H;
      return regionFpCanvas.getContext("2d", { willReadFrequently: true });
    }

    function regionFingerprintBits(data) {
      const n = REGION_FP_W * REGION_FP_H;
      const luma = new Float32Array(n);
      let sum = 0;
      let max = 0;
      for (let i = 0, p = 0; i < n; i++, p += 4) {
        const y = data[p] * 0.299 + data[p + 1] * 0.587 + data[p + 2] * 0.114;
        luma[i] = y; sum += y; if (y > max) { max = y; }
      }
      const mean = sum / n;
      const bits = new Uint8Array(n);
      // Near-uniform strip (no bright text) ??all-zero fingerprint, not all-one.
      if (max - mean >= 8) {
        const thr = mean + 0.45 * (max - mean);
        for (let i = 0; i < n; i++) { bits[i] = luma[i] >= thr ? 1 : 0; }
      }
      return bits;
    }

    // Per-tick change probe: downscale the source region STRAIGHT from the video to
    // the 64x16 fingerprint in one draw, skipping the full-resolution crop the old
    // path materialized every tick (the crop is only needed when we actually OCR).
    // Same source frame, roughly half the per-tick GPU work.
    function regionVideoFingerprint() {
      const { sx, sy, sw, sh } = getRegionSourceRect();
      const ctx = regionFpContext();
      ctx.drawImage(regionVideo, sx, sy, sw, sh, 0, 0, REGION_FP_W, REGION_FP_H);
      return regionFingerprintBits(ctx.getImageData(0, 0, REGION_FP_W, REGION_FP_H).data);
    }

    function regionTextFingerprint(cropCanvas) {
      const ctx = regionFpContext();
      ctx.drawImage(cropCanvas, 0, 0, REGION_FP_W, REGION_FP_H);
      return regionFingerprintBits(ctx.getImageData(0, 0, REGION_FP_W, REGION_FP_H).data);
    }

    function regionFpDistance(a, b) {
      if (!a || !b || a.length !== b.length) { return 1; }
      let diff = 0;
      for (let i = 0; i < a.length; i++) { if (a[i] !== b[i]) { diff++; } }
      return diff / a.length;
    }

    function regionFpInkRatio(fp) {
      if (!fp || !fp.length) { return 0; }
      let ink = 0;
      for (let i = 0; i < fp.length; i++) { if (fp[i]) { ink++; } }
      return ink / fp.length;
    }

    const REGION_FP_STABLE = 0.03;   // settled: <=3% of cells changed since last tick
    const REGION_FP_CHANGE = 0.05;   // new subtitle: >5% of cells differ from last OCR'd frame (lowered from 0.08 ??a short line occupies few of the 1024 cells, so even a full text swap can fall under 8%)
    const REGION_FP_DECISIVE_CHANGE = 0.10; // a large jump vs the last OCR'd frame = a full line/scene swap (not a fade):
    // OCR it immediately, skipping the settle wait (still gated by REGION_FP_MIN_GAP_MS). A rare half-rendered read is
    // caught by the garbled guard and self-corrected by the next settled re-OCR. Targets the scene-switch lag.
    // NOTE: this fingerprint delta now ONLY gates whether to OCR a frame — it no longer rotates the OCR
    // session (that's text-driven now; see REGION_TEXT_CHANGE_RATIO + maybeRotateRegionSessionOnTextChange).
    const REGION_TEXT_CHANGE_RATIO = 0.5; // OCR'd text must differ by >50% of its length (normalized edit distance)
    // to count as a real new subtitle line and rotate the session. Below this = same line drifting / OCR noise,
    // so the session stays put and the backend's incremental rec-only + ROI-lock fast path keeps engaging.
    const REGION_FP_TEXT_MIN = 0.006; // enough bright cells to be likely text; prevents a blank frame from replacing a queued fast subtitle
    const REGION_FP_SETTLE_TIMEOUT = 250; // OCR a changed frame after this even if it never settles (fast line / moving bg)
    const REGION_FP_MIN_GAP_MS = 90; // shortest time between OCRs for changed text; busy OCRs are queued instead
    const REGION_OCR_QUEUE_MAX = 1; // latest-wins: keep only the freshest changed frame while OCR is busy
    const REGION_OCR_EMPTY_HOLD_MS = 350; // mask one-frame OCR misses without delaying the next non-empty subtitle
    const REGION_OCR_NEW_PROMOTE_MS = 80; // wait briefly for fade-in / first-character recovery before translating a new line (lowered 150->80 for faster line switching on fast MVs; the garbage gate now blocks fade noise so a shorter hold is safe)
    const REGION_OCR_VARIANT_PROMOTE_MS = 220; // accept a better same-line OCR only after it persists for another tick
    const REGION_OCR_GARBLED_PROMOTE_MS = 600; // a line that keeps tripping the garbage gate but re-reads the SAME text earns promotion after this, instead of being held behind the stable text forever
    const REGION_SUPPRESS_LOG_MS = 1500; // throttle (ms) for the read-but-suppressed diagnostic so held frames do not spam the log
    const REGION_SECONDARY_MIN_FRAMES = 6; // a line must recur unchanged in >= this many recent OCR frames to count as a static header/side line
    const REGION_SECONDARY_STATIC_MS = 4000; // ...and persist at least this long; only then does it move to the low-priority secondary lane (well past typical subtitle dwell, so live dialogue is not demoted)
    const REGION_LINE_STATS_DECAY_MS = 6000; // forget a line not seen for this long, so a line that leaves the frame resets its recurrence
    const REGION_OCR_CLEAN_MIN_LETTERS = 4; // a NEW line with >= this many CJK/kana/Latin letters (after cleaning) is
    // treated as complete and translated immediately; shorter fragments and residual-timecode reads keep the
    // REGION_OCR_NEW_PROMOTE_MS fade-in hold that recovers dropped leading chars / half-renders.
    // Steady-cadence backstop is getRegionForceInterval() (~450ms): the coarse 64x16
    // fingerprint misses short / similar-looking consecutive lines, so re-OCR at least that
    // often regardless and let the OCR-text dedup keep static frames cheap (rapidocr-net is
    // ~1ms on an unchanged frame). 4000ms here previously = the main coverage hole.

    const REGION_MAX_CROP_WIDTH = 1600;
    const REGION_WIDE_TEXT_ASPECT = 3.0;
    const REGION_WIDE_TEXT_MAX_LONG_SIDE = 1200;
    const REGION_WIDE_TEXT_MIN_SHORT_SIDE = 220;
    const REGION_WIDE_TEXT_MAX_UPSCALE = 3;
    // Small crops ??esp. narrow vertical-text (蝮行?? regions ~232px ??fall below the
    // rapidocr-net detector's usable size: the .NET port doesn't upscale small images
    // (no Python limit_type=min), so det returns 0 boxes and the frame reads empty. Upscale
    // the shorter side toward this target (mirrors Python rapidocr / the `upscale` preset).
    // % overlay positioning is scale-invariant, so this is transparent to block placement.
    const REGION_MIN_CROP_SHORT_SIDE = 700;
    const REGION_MAX_UPSCALE = 4;

    function regionEncodeScale(width, height) {
      const longSide = Math.max(width, height);
      const shortSide = Math.min(width, height);
      const aspect = shortSide > 0 ? longSide / shortSide : 1;
      const wideText = width >= height && aspect >= REGION_WIDE_TEXT_ASPECT && height <= 260;
      const maxLongSide = wideText ? REGION_WIDE_TEXT_MAX_LONG_SIDE : REGION_MAX_CROP_WIDTH;
      const targetShortSide = wideText ? REGION_WIDE_TEXT_MIN_SHORT_SIDE : REGION_MIN_CROP_SHORT_SIDE;
      const maxUpscale = wideText ? REGION_WIDE_TEXT_MAX_UPSCALE : REGION_MAX_UPSCALE;
      if (longSide > maxLongSide) {
        return maxLongSide / longSide; // too large: downscale to cut encode/upload + DET cost
      }
      if (shortSide <= 0 || shortSide >= targetShortSide) {
        return 1;
      }
      // Upscale tiny crops so det fires, capped, and never past the long-side width cap.
      const scale = Math.min(
        maxUpscale,
        targetShortSide / shortSide,
        maxLongSide / longSide);
      return scale > 1.02 ? scale : 1;
    }

    function encodeRegionCrop(cropCanvas) {
      let canvas = cropCanvas;
      // Presets whose server-side preprocessing does its OWN upscale (flatten / clahe-l / upscale)
      // must NOT be pre-upscaled here too: the crop would be scaled twice (toward 700 here, then 3x
      // in the provider), overshoot the detector's sweet spot, and drop the faintest text (e.g. the
      // small されど column). Send the native-resolution crop and let the provider upscale once.
      const regionPre = $("regionPreprocess");
      const regionPreset = regionPre ? regionPre.value : "";
      const providerUpscales = regionPreset === "flatten" || regionPreset === "clahe-l" || regionPreset === "upscale";
      const scale = providerUpscales ? 1 : regionEncodeScale(cropCanvas.width, cropCanvas.height);
      if (scale !== 1) {
        if (!regionScaleCanvas) {
          regionScaleCanvas = document.createElement("canvas");
        }

        regionScaleCanvas.width = Math.max(1, Math.round(cropCanvas.width * scale));
        regionScaleCanvas.height = Math.max(1, Math.round(cropCanvas.height * scale));
        regionScaleCanvas.getContext("2d").drawImage(canvas, 0, 0, regionScaleCanvas.width, regionScaleCanvas.height);
        canvas = regionScaleCanvas;
      }

      // toBlob snapshots the canvas synchronously but encodes off the main thread,
      // unlike toDataURL which blocks for the whole JPEG encode (30-100ms at 1600px).
      return new Promise((resolve, reject) => {
        canvas.toBlob(blob => {
          if (!blob) {
            reject(new Error("region encode failed"));
            return;
          }

          resolve({
            blob,
            base64: "",
            mimeType: blob.type || "image/png",
            sourceWidth: cropCanvas.width,
            sourceHeight: cropCanvas.height,
            width: canvas.width,
            height: canvas.height,
            scale
          });
        }, "image/png");
      });
    }

    // OCR cost (oneocr) scales with image AREA ??detection runs over every pixel. A
    // subtitle is usually a thin band inside a looser selection, so trimming the empty
    // rows above/below the text shrinks the OCR image without touching the text or its
    // horizontal resolution. Conservative by design: a low-contrast strip, one where
    // no bright text is found, or one where text already fills the height is returned
    // whole. The caller also skips this when watermark exclude-zones are set, since
    // their coordinates are full-crop-relative.
    const REGION_BAND_PROBE_W = 48;
    const REGION_BAND_MAX_PROBE_H = 180;
    let regionBandProbeCanvas = null;
    let regionBandOutCanvas = null;
    function regionTextBandCrop(cropCanvas) {
      const cw = cropCanvas.width;
      const ch = cropCanvas.height;
      if (ch < 32) {
        return cropCanvas; // already a thin strip ??nothing to trim
      }

      const probeH = Math.max(16, Math.min(REGION_BAND_MAX_PROBE_H, ch));
      if (!regionBandProbeCanvas) {
        regionBandProbeCanvas = document.createElement("canvas");
      }
      regionBandProbeCanvas.width = REGION_BAND_PROBE_W;
      regionBandProbeCanvas.height = probeH;
      const ctx = regionBandProbeCanvas.getContext("2d", { willReadFrequently: true });
      ctx.drawImage(cropCanvas, 0, 0, REGION_BAND_PROBE_W, probeH);
      const data = ctx.getImageData(0, 0, REGION_BAND_PROBE_W, probeH).data;

      const npx = REGION_BAND_PROBE_W * probeH;
      const luma = new Float32Array(npx);
      let sum = 0;
      let max = 0;
      for (let i = 0, p = 0; i < npx; i++, p += 4) {
        const y = data[p] * 0.299 + data[p + 1] * 0.587 + data[p + 2] * 0.114;
        luma[i] = y; sum += y; if (y > max) { max = y; }
      }
      const mean = sum / npx;
      if (max - mean < 12) {
        return cropCanvas; // low contrast / no clear bright text ??don't risk a crop
      }

      const thr = mean + 0.5 * (max - mean);
      let top = -1;
      let bottom = -1;
      for (let r = 0; r < probeH; r++) {
        let bright = 0;
        const base = r * REGION_BAND_PROBE_W;
        for (let c = 0; c < REGION_BAND_PROBE_W; c++) {
          if (luma[base + c] >= thr) { bright++; }
        }
        if (bright >= 2) { // a couple of bright pixels on this row = a glyph stroke
          if (top < 0) { top = r; }
          bottom = r;
        }
      }
      if (top < 0 || bottom < 0) {
        return cropCanvas; // found no text rows ??send the whole crop (safe)
      }

      const pad = Math.round(probeH * 0.14) + 1;
      top = Math.max(0, top - pad);
      bottom = Math.min(probeH - 1, bottom + pad);
      if ((bottom - top + 1) / probeH >= 0.82) {
        return cropCanvas; // text already spans the height ??nothing to gain
      }

      const y0 = Math.floor((top / probeH) * ch);
      const y1 = Math.min(ch, Math.ceil(((bottom + 1) / probeH) * ch));
      const bandH = Math.max(1, y1 - y0);
      if (!regionBandOutCanvas) {
        regionBandOutCanvas = document.createElement("canvas");
      }
      regionBandOutCanvas.width = cw;
      regionBandOutCanvas.height = bandH;
      regionBandOutCanvas.getContext("2d").drawImage(cropCanvas, 0, y0, cw, bandH, 0, 0, cw, bandH);
      return regionBandOutCanvas;
    }

    function abortRegionOcrInFlight() {
      if (state.regionOcrAbort) {
        state.regionOcrAbort.abort();
        state.regionOcrAbort = null;
      }
    }

    function isRegionOcrEpochCurrent(epoch) {
      return state.regionLoopRunning &&
        epoch > 0 &&
        epoch === state.regionActiveOcrEpoch &&
        epoch > (state.regionSupersededOcrEpoch || 0);
    }

    function supersedeActiveRegionOcr() {
      const epoch = state.regionActiveOcrEpoch || 0;
      if (epoch <= 0 || epoch <= (state.regionSupersededOcrEpoch || 0)) {
        return;
      }

      state.regionSupersededOcrEpoch = epoch;
      abortRegionOcrInFlight();
    }

    function isAbortError(error) {
      return error && (error.name === "AbortError" || error.code === DOMException.ABORT_ERR);
    }

    const REGION_TRANSLATION_LRU_MAX = 16;
    const regionTranslationLru = new Map();

    function regionTranslationSettings() {
      return {
        source: $("source").value,
        target: $("target").value,
        mode: $("preset").value,
        provider: $("translationProvider").value,
        model: $("translationModel").value.trim(),
        glossary: $("glossary").value
      };
    }

    function regionTranslationKey(trimmedOcr, settings = regionTranslationSettings()) {
      // Keyed by the translation settings too, so switching target/provider/glossary
      // never serves a translation made under different settings.
      return [
        settings.source,
        settings.target,
        settings.mode,
        settings.provider,
        settings.model,
        settings.glossary,
        trimmedOcr
      ].join("\x1f");
    }

    function regionTranslationPayload(text, settings) {
      return {
        text,
        source: settings.source,
        target: settings.target,
        mode: settings.mode,
        surface: "region",
        glossary: settings.glossary || null,
        provider: settings.provider,
        model: settings.model || null,
        realtime: true,
        broadcastSourceKind: "region"
      };
    }

    function regionLruGet(key) {
      if (!regionTranslationLru.has(key)) {
        return null;
      }

      const value = regionTranslationLru.get(key);
      regionTranslationLru.delete(key);
      regionTranslationLru.set(key, value);
      return value;
    }

    function regionLruSet(key, value) {
      regionTranslationLru.delete(key);
      regionTranslationLru.set(key, value);
      while (regionTranslationLru.size > REGION_TRANSLATION_LRU_MAX) {
        regionTranslationLru.delete(regionTranslationLru.keys().next().value);
      }
    }

    function buildRegionOcrPayload(imageBase64Value, imageMimeType) {
      const preprocessEl = $("regionPreprocess");
      const preset = (preprocessEl ? preprocessEl.value : $("ocrPreprocessingPreset").value) || "none";
      return {
        imageBase64: imageBase64Value,
        ...(imageMimeType ? { imageMimeType } : {}),
        provider: $("ocrProvider").value,
        contentType: $("ocrContentType").value,
        preference: $("ocrPreference").value,
        language: $("ocrLanguage").value,
        profile: currentOcrProfile(),
        realtime: true,
        ...(state.regionOcrSessionId ? { sessionId: state.regionOcrSessionId } : {}),
        // Region capture is upright subtitle/dialogue text; explicit presets are honored.
        preprocessingPreset: preset === "none" ? "subtitle" : preset
      };
    }

    async function postRegionOcr(encoded, options = {}) {
      const payload = buildRegionOcrPayload(encoded.base64 || "", encoded.mimeType);
      if (!encoded.blob) {
        return post("/ocr", payload, options);
      }

      const params = new URLSearchParams();
      for (const [key, value] of Object.entries(payload)) {
        if (key === "imageBase64" || value === undefined || value === null || value === "") {
          continue;
        }
        params.set(key, String(value));
      }

      const headers = {
        ...(options.headers || {}),
        "content-type": encoded.mimeType || "application/octet-stream"
      };
      const response = await fetch(`/ocr/bytes?${params.toString()}`, {
        ...options,
        method: "POST",
        headers,
        body: encoded.blob
      });
      const text = await response.text();
      let data = null;
      if (text) {
        try {
          data = JSON.parse(text);
        } catch {
          data = text;
        }
      }
      if (!response.ok) {
        const message = data && (data.errorMessage || data.error || data.detail)
          ? data.errorMessage || data.error || data.detail
          : text || response.statusText;
        throw new Error(message);
      }
      return data;
    }

    function getRegionDropPatterns() {
      const input = $("regionDropPatterns");
      if (!input) {
        return [];
      }
      return input.value.split("\n").map(line => line.trim()).filter(Boolean);
    }

    function compileRegionDropPatterns() {
      return getRegionDropPatterns().map(pattern => {
        try {
          return new RegExp(pattern, "gi");
        } catch {
          return new RegExp(pattern.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"), "gi");
        }
      });
    }

    function regionExcludesForCrop() {
      const sel = state.regionSelection;
      if (!sel || !state.regionExcludes.length) {
        return [];
      }
      return state.regionExcludes.map(exclude => {
        const x0 = Math.max(0, (exclude.x - sel.x) / sel.width);
        const y0 = Math.max(0, (exclude.y - sel.y) / sel.height);
        const x1 = Math.min(1, (exclude.x + exclude.width - sel.x) / sel.width);
        const y1 = Math.min(1, (exclude.y + exclude.height - sel.y) / sel.height);
        return x1 > x0 && y1 > y0 ? { x: x0, y: y0, width: x1 - x0, height: y1 - y0 } : null;
      }).filter(Boolean);
    }

    function stripRegionPatterns(text, patterns) {
      if (!patterns.length || !text) {
        return text || "";
      }
      return String(text)
        .split("\n")
        .map(line => {
          let value = line;
          for (const pattern of patterns) {
            pattern.lastIndex = 0;
            value = value.replace(pattern, " ");
          }
          return value.replace(/\s+/g, " ").trim();
        })
        .filter(Boolean)
        .join("\n");
    }

    function stripRegionLeadingNoise(text) {
      if (!text) {
        return text || "";
      }

      return String(text)
        .split("\n")
        .map(line => {
          let value = String(line || "").trim();
          for (let i = 0; i < 3; i++) {
            const before = value;
            value = value
              .replace(/^[\s，,。.:：;；、"'“”‘’`´·•|/\\()[\]{}<>《》【】「」『』_\-—~!！?？*+＝=]+(?=[\p{Script=Han}A-Za-z])/u, "")
              .replace(/^(?:\d{1,2}[:：]\d{2}(?::\d{2})?(?:[/／]\d{1,2}(?::\d{2})?)?[:：]?)(?=\s*[\p{Script=Han}A-Za-z“"《（(])/u, "")
              .replace(/^\d{1,2}[/／]\d{1,2}[:：]\d{2}(?=\s*[\p{Script=Han}A-Za-z“"《（(]|$)/u, "")
              .replace(/^\d{1,2}(?=[\p{Script=Han}“"《（(])/u, "")
              .replace(/^[a-z]{1,2}(?=[\p{Script=Han}])/u, "")
              .trim();
            if (value === before) {
              break;
            }
          }

          if (/^(?:\d{1,2}[:：]\d{2}(?::\d{2})?|\d{1,2}[/／]\d{1,2}[:：]\d{2})$/.test(value)) {
            return "";
          }
          return value;
        })
        .filter(Boolean)
        .join("\n");
    }

    function cleanRegionOcrText(text, patterns = []) {
      return stripRegionLeadingNoise(stripRegionPatterns(text || "", patterns));
    }

    // Conservative OCR fix for Latin tokens the engine misread as digits in a CJK
    // context (e.g. "COS" -> "C05": O->0, S->5). Only touches a token that starts
    // with a letter and is made solely of letters + the highly confusable digits
    // 0/1/5 ??so real numbers (10, 5撟?, mixed codes (RTX5090, H2O) and 5G are left
    // alone. Maps 0->O, 1->I, 5->S.
    function normalizeLatinConfusables(text) {
      if (!text) {
        return text || "";
      }
      return String(text).replace(/[A-Za-z0-9]+/g, token => {
        if (!/^[A-Za-z]/.test(token) || !/^[A-Za-z015]+$/.test(token) || !/[015]/.test(token)) {
          return token;
        }
        return token.replace(/0/g, "O").replace(/1/g, "I").replace(/5/g, "S");
      });
    }

    function regionMotionMode() {
      const el = $("regionMotionMode");
      return el ? el.checked : false;
    }

    // Source-language script gate for motion mode: keep only OCR blocks predominantly in the source
    // language's script, dropping background text / logos / other-language noise over a busy scene.
    // Returns null for "auto" or unsupported source languages (then no language filtering happens).
    function regionSourceScriptMatcher() {
      const src = ($("source").value || "").toLowerCase();
      let re = null;
      if (src.startsWith("ja")) { re = /[\p{Script=Hiragana}\p{Script=Katakana}\p{Script=Han}]/gu; }
      else if (src.startsWith("ko")) { re = /[\p{Script=Hangul}]/gu; }
      else if (src.startsWith("zh")) { re = /[\p{Script=Han}]/gu; }
      else if (src.startsWith("en")) { re = /[A-Za-z]/g; }
      if (!re) { return null; }
      return (text) => {
        const value = String(text || "").trim();
        if (!value) { return false; }
        const letters = (value.match(/[\p{L}\p{N}]/gu) || []).length;
        if (letters === 0) { return false; }
        const hits = (value.match(re) || []).length;
        return hits / letters >= 0.4;
      };
    }

    // Rule-based realtime text policy (frontend mirror of RealtimeOcrTextPolicy):
    // drop OCR blocks inside user-marked watermark zones, then strip drop-pattern
    // matches, so the translation request / cache key / LRU key only see the
    // subtitle body instead of "subtitle + fixed watermark".
    function applyRegionTextPolicy(ocr, cropWidth, cropHeight) {
      const rawText = ocr && ocr.text ? ocr.text : "";
      const excludes = regionExcludesForCrop();
      const patterns = compileRegionDropPatterns();
      const motionMatcher = regionMotionMode() ? regionSourceScriptMatcher() : null;
      if (!excludes.length && !patterns.length && !motionMatcher) {
        return cleanRegionOcrText(rawText, patterns);
      }

      const blocks = ocr && Array.isArray(ocr.blocks) ? ocr.blocks : [];
      if (!blocks.length) {
        return cleanRegionOcrText(rawText, patterns);
      }

      // OCR boxes live in the coordinate space of the (possibly uniformly scaled)
      // submitted image. The page may report its size; otherwise estimate the
      // uniform scale factor from the block extents against the crop dimensions.
      const page = ocr.document && Array.isArray(ocr.document.pages) ? ocr.document.pages[0] : null;
      let imageWidth = page && Number(page.width) > 0 ? Number(page.width) : 0;
      let imageHeight = page && Number(page.height) > 0 ? Number(page.height) : 0;
      if ((!imageWidth || !imageHeight) && cropWidth > 0 && cropHeight > 0) {
        let extentX = 0;
        let extentY = 0;
        for (const block of blocks) {
          const box = block.boundingBox;
          if (box && Number(box.width) > 0 && Number(box.height) > 0) {
            extentX = Math.max(extentX, Number(box.x) + Number(box.width));
            extentY = Math.max(extentY, Number(box.y) + Number(box.height));
          }
        }
        const scale = Math.max(extentX / cropWidth, extentY / cropHeight, 0);
        if (scale > 0) {
          imageWidth = cropWidth * scale;
          imageHeight = cropHeight * scale;
        }
      }

      const kept = blocks.filter(block => {
        if (motionMatcher && !motionMatcher(block.text || "")) {
          return false; // motion mode: drop background / other-language noise blocks
        }
        const box = block.boundingBox;
        if (!box || !excludes.length || !imageWidth || !imageHeight) {
          return true;
        }
        const x = Number(box.x) / imageWidth;
        const y = Number(box.y) / imageHeight;
        const width = Math.max(Number(box.width), 1) / imageWidth;
        const height = Math.max(Number(box.height), 1) / imageHeight;
        const centerX = x + width / 2;
        const centerY = y + height / 2;
        return !excludes.some(region => {
          if (centerX >= region.x && centerX <= region.x + region.width &&
              centerY >= region.y && centerY <= region.y + region.height) {
            return true;
          }
          const overlapWidth = Math.min(x + width, region.x + region.width) - Math.max(x, region.x);
          const overlapHeight = Math.min(y + height, region.y + region.height) - Math.max(y, region.y);
          return overlapWidth > 0 && overlapHeight > 0 &&
            (overlapWidth * overlapHeight) / (width * height) >= 0.5;
        });
      });

      const joined = kept.length === blocks.length
        ? rawText
        : kept.map(block => block.text || "").filter(text => text.trim()).join("\n");
      return cleanRegionOcrText(joined, patterns);
    }

    function updateRegionFilterSummary() {
      const label = $("regionFilterSummary");
      if (!label) {
        return;
      }
      const parts = [];
      if (state.regionExcludes.length) {
        parts.push(`${state.regionExcludes.length} zone${state.regionExcludes.length === 1 ? "" : "s"}`);
      }
      const patternCount = getRegionDropPatterns().length;
      if (patternCount) {
        parts.push(`${patternCount} pattern${patternCount === 1 ? "" : "s"}`);
      }
      if (regionMotionMode()) {
        parts.push("motion");
      }
      const preprocessEl = $("regionPreprocess");
      if (preprocessEl && preprocessEl.value && preprocessEl.value !== "none") {
        parts.push(preprocessEl.value);
      }
      label.textContent = parts.length ? parts.join(" / ") : "off";
    }

    // Streaming translate: POST /translate/stream and parse the SSE body so the
    // overlay fills in token-by-token as the model generates, instead of waiting
    // for the whole sentence. onPartial receives the running text. Instant resolvers
    // (cache / OpenCC / template) arrive as one done event with no deltas. Returns
    // { result, errorCode, errorMessage } like the old post("/translate") call.
    async function streamRegionTranslate(body, controller, onPartial) {
      let resp;
      try {
        resp = await fetch("/translate/stream", {
          method: "POST",
          headers: Object.assign({ "Content-Type": "application/json" }, memoryRuntimeHeaders()),
          body: JSON.stringify(body),
          signal: controller.signal
        });
      } catch (error) {
        if (isAbortError(error)) { throw error; }
        return { result: "", errorCode: "1", errorMessage: error.message || String(error) };
      }
      if (!resp.ok || !resp.body) {
        return { result: "", errorCode: "1", errorMessage: `stream HTTP ${resp.status}` };
      }
      const reader = resp.body.getReader();
      const decoder = new TextDecoder();
      let buffer = "";
      let acc = "";
      let final = { result: "", errorCode: "0", errorMessage: "" };
      let sawDone = false;
      for (;;) {
        const { value, done } = await reader.read();
        if (done) { break; }
        buffer += decoder.decode(value, { stream: true });
        let sep;
        while ((sep = buffer.indexOf("\n\n")) >= 0) {
          const evt = buffer.slice(0, sep);
          buffer = buffer.slice(sep + 2);
          const dataLine = evt.split("\n").find(l => l.startsWith("data:"));
          if (!dataLine) { continue; }
          let data;
          try { data = JSON.parse(dataLine.slice(5).trim()); } catch { continue; }
          if (data.delta) {
            acc += data.delta;
            if (onPartial) { onPartial(acc); }
          } else if (data.done) {
            sawDone = true;
            final = {
              result: data.text != null ? data.text : acc,
              errorCode: data.errorCode || "0",
              errorMessage: data.errorMessage || "",
              tokenUsage: data.tokenUsage || data.TokenUsage || null
            };
          }
        }
      }
      if (!sawDone) {
        return { result: acc, errorCode: "stream_incomplete", errorMessage: "stream closed before completion" };
      }
      return final;
    }

    async function performRegionOcr(cropCanvas, frameSample, loop, onOcrStageDone) {
      const seq = ++state.regionSnapshotSeq;
      state.regionLastFrameSample = frameSample;
      const cropWidth = cropCanvas.width;
      const cropHeight = cropCanvas.height;
      const encoded = await encodeRegionCrop(cropCanvas);
      imageBase64.value = encoded.base64 || "";
      state.imageMimeType = encoded.mimeType;
      const previousOcr = regionOcrText.value.trim();
      const previousTranslation = regionTranslationText.value.trim();
      const started = performance.now();
      // A superseded request's result would be discarded by the seq guard anyway;
      // abort it so the backend stops spending OCR/LLM time on it.
      abortRegionOcrInFlight();
      const controller = new AbortController();
      state.regionOcrAbort = controller;
      let ocr;
      let translation;
      let llmLabel = "skip";
      let translationSettings = null;
      let translationKey = "";
      try {
        ocr = await postRegionOcr(encoded, {
          headers: memoryRuntimeHeaders(),
          signal: controller.signal
        });
        if (seq !== state.regionSnapshotSeq) {
          return null;
        }

        const rawOcrText = normalizeLatinConfusables(applyRegionTextPolicy(ocr, cropWidth, cropHeight));
        const stabilized = loop ? stabilizeRegionOcrText(rawOcrText) : acceptRegionStableOcrText(rawOcrText);
        const ocrText = stabilized.text;
        state.latestOcrText = ocrText;
        regionOcrText.value = ocrText;
        ocrOutput.value = ocrText;
        sourceText.value = ocrText;
        $("blockCount").textContent = String(ocr && ocr.blocks ? ocr.blocks.length : 0);
        $("engineName").textContent = ocr && ocr.engine ? ocr.engine : "-";
        renderOcrStructure(ocr || null, null);
        if (onOcrStageDone) {
          onOcrStageDone();
        }

        const trimmedOcr = ocrText.trim();
        translationSettings = trimmedOcr ? regionTranslationSettings() : null;
        translationKey = trimmedOcr ? regionTranslationKey(trimmedOcr, translationSettings) : "";
        // Steady-cadence re-OCR re-reads the same subtitle many times; when the
        // recognized text is unchanged from what's already shown there is nothing
        // new to translate, broadcast, or log ??skip the rest so frequent re-OCR
        // stays cheap and the loop is free to catch the NEXT change promptly.
        if (trimmedOcr && trimmedOcr === previousOcr && previousTranslation && state.regionActiveTranslationKey === translationKey) {
          return null;
        }
        const rememberedTranslation = trimmedOcr ? regionLruGet(translationKey) : null;
        if (!trimmedOcr) {
          translation = { result: "", errorCode: "0", errorMessage: "" };
        } else if (rememberedTranslation !== null) {
          // Recently translated this exact text under the same settings (covers
          // alternating subtitles, not just the immediately previous frame).
          translation = { result: rememberedTranslation, errorCode: "0", errorMessage: "", tokenUsage: zeroTokenUsage("region:cache") };
        } else {
          const llmStarted = performance.now();
          // Stream the translation so the overlay fills in as tokens arrive; the
          // seq guard stops a superseded subtitle's stream from overwriting a newer one.
          translation = await streamRegionTranslate(regionTranslationPayload(ocrText, translationSettings), controller, (partial) => {
            if (seq === state.regionSnapshotSeq) {
              setRegionTranslationText(partial);
              lastOutput.value = partial;
            }
          });
          if (seq !== state.regionSnapshotSeq) {
            return null;
          }

          llmLabel = String(Math.round(performance.now() - llmStarted));
        }
      } finally {
        if (state.regionOcrAbort === controller) {
          state.regionOcrAbort = null;
        }
      }

      const ocrText = state.latestOcrText;
      const translatedText = translation.result || "";
      const translationFailed = translation.errorCode && translation.errorCode !== "0";
      if (!translatedText && translationFailed) {
        applyTokenUsage(translation.tokenUsage || null, "region");
        const elapsed = Math.round(performance.now() - started);
        const ocrLabel = ocr && Number.isFinite(ocr.latencyMs)
          ? `${Math.round(ocr.latencyMs)}${ocr.cacheHit ? "*" : ""}`
          : "-";
        const latencySummary = appendTokenUsageMeta(`ocr ${ocrLabel} / llm ${llmLabel} / total ${elapsed} ms`, translation.tokenUsage || null);
        $("latencyLabel").textContent = latencySummary;
        appendMessage("error", "region translation", translation.errorMessage || "translation failed", latencySummary);
        clearRegionTranslationPending();
        return { ocr, translation };
      }
      setRegionTranslationText(translatedText, { fresh: true });
      lastOutput.value = translatedText;
      applyTokenUsage(translation.tokenUsage || null, "region");
      if (!ocrText.trim()) {
        state.regionActiveText = "";
        state.regionActiveTranslationKey = "";
      }
      if (ocrText.trim() && translatedText && (!translation.errorCode || translation.errorCode === "0")) {
        const finalKey = translationKey || regionTranslationKey(ocrText.trim());
        state.regionActiveText = ocrText.trim();
        state.regionActiveTranslationKey = finalKey;
        regionLruSet(finalKey, translatedText);
      }

      const elapsed = Math.round(performance.now() - started);
      const ocrLabel = ocr && Number.isFinite(ocr.latencyMs)
        ? `${Math.round(ocr.latencyMs)}${ocr.cacheHit ? "*" : ""}`
        : "-";
      const latencySummary = appendTokenUsageMeta(`ocr ${ocrLabel} / llm ${llmLabel} / total ${elapsed} ms`, translation.tokenUsage || null);
      $("latencyLabel").textContent = latencySummary;

      const changed = ocrText !== previousOcr || translatedText !== previousTranslation;
      if (!loop || changed) {
        appendMessage("user", "region ocr", ocrText, ocr && ocr.provider ? ocr.provider : "");
        if (translation.errorCode && translation.errorCode !== "0") {
          appendMessage("error", "region translation", translation.errorMessage || translatedText, latencySummary);
        } else {
          appendMessage("result", "region translation", translatedText, latencySummary);
        }
      }

      return { ocr, translation };
    }

    async function runRegionSnapshot() {
      if (!state.regionStream) {
        throw new Error("capture a screen first");
      }

      setDefaultRegionSelection();
      const cropCanvas = getRegionCropCanvas();
      const frameSample = sampleRegionFrame(cropCanvas);
      resetRegionWatchPhase();
      return performRegionOcr(cropCanvas, frameSample, false);
    }

    function getRegionInterval() {
      const value = Number.parseInt($("regionInterval").value, 10);
      return Number.isFinite(value) ? Math.max(100, value) : 200;
    }

    function getRegionForceInterval() {
      // Steady-cadence re-OCR backstop: the coarse 64x16 fingerprint misses short / similar-looking
      // consecutive lines, so re-OCR at least this often. ADAPTIVE: the slider (getRegionInterval) is
      // the CEILING (max gap); the actual backstop auto-scales to the rolling OCR cost so it is tight
      // when OCR is cheap (incremental ~20ms -> ~90-150ms, catches fast subtitles) and relaxes toward
      // the ceiling when OCR is expensive (cold full detect -> avoid forcing repeated costly re-OCRs +
      // backlog). Same principle as the backend's RealtimeRedetectInterval = max(floor, lastDet x4).
      const ceiling = getRegionInterval();
      const ewma = state.regionOcrLatencyEwma || 0;
      if (ewma <= 0) {
        return ceiling;
      }
      const adaptive = Math.round(ewma * 1.5);
      return Math.min(ceiling, Math.max(REGION_FP_MIN_GAP_MS + 30, adaptive));
    }

    function syncRegionInterval(value) {
      const parsed = Number.parseInt(value, 10);
      const normalized = Number.isFinite(parsed) ? Math.max(100, parsed) : 200;
      $("regionInterval").value = String(normalized);
      $("regionIntervalSetting").value = String(normalized);
      saveRegionSettings();
    }

    function cancelRegionAutoSnapshot() {
      if (state.regionAutoSnapTimer) {
        window.clearTimeout(state.regionAutoSnapTimer);
        state.regionAutoSnapTimer = null;
      }
    }

    // Run button → native path: opens the full-screen region selector (pre-loaded with the running
    // regions so they can be moved/resized/deleted) and starts the native watch loop. Mirrors the
    // nativeSelectButton click but is the Run-button entry point for the native backend.
    async function runNativeRegionSelect() {
      setMode("region");
      try {
        clearRegionResults();
        const status = await postEmpty("/region/native/select");
        renderNativeStatus(status);
        startNativeStatusPoll();
      } catch (error) {
        setNativeStatus("error: " + (error.message || error), "error");
        appendMessage("error", "region", error.message || String(error));
      }
    }

    async function triggerRegionSnapshot() {
      if (state.busy) {
        return;
      }

      setMode("region");
      let didSetBusy = false;
      try {
        if (!state.regionStream) {
          await startRegionCapture();
        }

        setBusy(true);
        didSetBusy = true;
        await runRegionSnapshot();
      } catch (error) {
        if (!isAbortError(error)) {
          appendMessage("error", "region", error.message || String(error));
        }
      } finally {
        if (didSetBusy) {
          setBusy(false);
        }
      }
    }

    function queueRegionAutoSnapshot() {
      if (!state.regionStream || !state.regionSelection || state.regionLoopRunning) {
        return;
      }

      cancelRegionAutoSnapshot();
      state.regionAutoSnapTimer = window.setTimeout(() => {
        state.regionAutoSnapTimer = null;
        triggerRegionSnapshot();
      }, 400);
    }

    const REGION_WATCH_TICK_MS = 100;
    const REGION_STABLE_TICKS = 1;

    // Dedicated-worker metronome: background tabs throttle main-thread timers
    // to >=1s, which stalled change detection to 1-2s whenever the workbench
    // tab was hidden while the user watches the captured video. Worker timers
    // are exempt, and the message handler still runs promptly in hidden tabs.
    let regionWatchWorker = null;

    function startRegionWatchWorker() {
      if (regionWatchWorker) {
        return true;
      }
      try {
        const source = "setInterval(function () { postMessage(0); }, " + REGION_WATCH_TICK_MS + ");";
        const worker = new Worker(URL.createObjectURL(new Blob([source], { type: "text/javascript" })));
        worker.onmessage = () => {
          if (state.regionLoopRunning) {
            regionWatchTick();
          } else {
            stopRegionWatchWorker();
          }
        };
        regionWatchWorker = worker;
        return true;
      } catch {
        regionWatchWorker = null;
        return false;
      }
    }

    function stopRegionWatchWorker() {
      if (regionWatchWorker) {
        regionWatchWorker.terminate();
        regionWatchWorker = null;
      }
    }

    function resetRegionWatchPhase() {
      state.regionWatchPhase = "idle";
      state.regionStableTicks = 0;
      state.regionLastTickSample = null;
      updateRegionLoopStatusLabel();
    }

    function updateRegionLoopStatusLabel() {
      if (!state.regionLoopRunning) {
        return;
      }

      $("regionLoopStatus").textContent = state.regionDetectBusy
        ? "ocr"
        : state.regionTranslateController
          ? "translating"
          : "watching";
    }

    function stopRegionLoop(showMessage = true) {
      state.regionLoopRunning = false;
      stopRegionWatchWorker();
      if (state.regionLoopTimer) {
        window.clearTimeout(state.regionLoopTimer);
        state.regionLoopTimer = null;
      }

      abortRegionOcrInFlight();
      if (state.regionTranslateController) {
        try { state.regionTranslateController.abort(); } catch (ignore) { /* already settled */ }
        state.regionTranslateController = null;
      }
      resetRegionTextStability();
      state.regionDetectBusy = false;
      state.regionActiveOcrEpoch = 0;
      state.regionSupersededOcrEpoch = state.regionOcrEpoch || 0;
      state.regionActiveOcrStartedAt = 0;
      state.regionLastTickFp = null;
      state.regionLastOcrFp = null;
      state.regionFpChangeStart = 0;
      clearQueuedRegionOcrFrame();
      releaseRegionCanvases();
      resetRegionWatchPhase();
      setRegionLoopStatus("off");
      if (showMessage) {
        appendMessage("result", "region", "loop stopped", "loop");
      }
    }

    async function runWatchOcr(cropCanvas, sample) {
      state.regionOcrInFlight = true;
      state.regionLastOcrAt = performance.now();
      updateRegionLoopStatusLabel();
      try {
        // The loop no longer holds the global busy flag: the seq guard and
        // abortRegionOcrInFlight already arbitrate superseded requests, and
        // clearing the in-flight flag after the OCR stage lets the watcher
        // pick up the next frame while the LLM is still translating this one.
        await performRegionOcr(cropCanvas, sample, true, () => {
          state.regionOcrInFlight = false;
          updateRegionLoopStatusLabel();
        });
        state.regionWatchPhase = "idle";
        state.regionStableTicks = 0;
      } catch (error) {
        if (!isAbortError(error)) {
          appendMessage("error", "region loop", error.message || String(error));
          stopRegionLoop(false);
        }
      } finally {
        state.regionOcrInFlight = false;
        updateRegionLoopStatusLabel();
      }
    }

    // Detection is DECOUPLED from translation. Every cadence we OCR the region to
    // read the current subtitle, regardless of whether a previous translation is
    // still streaming. A new subtitle is recognized by its TEXT changing (fuzzy, so
    // a drifting watermark does not count); only then do we supersede the in-flight
    // translation and translate the new line. This stops fast / overlapping
    // subtitles from being missed while a slow translation holds the pipeline ??the
    // old loop gated OCR on "no translation in flight", so detection ran only about
    // once per (OCR + translate) ??1.4s and dropped lines that appeared in between.
    function regionWatchTick() {
      if (!state.regionLoopRunning || !state.regionStream || !state.regionSelection) {
        return;
      }
      if (state.busy) {
        return;
      }

      let fp;
      try {
        fp = regionVideoFingerprint();
      } catch {
        return;
      }

      const now = performance.now();
      const sinceOcr = now - (state.regionLastOcrAt || 0);
      // Changed = the text mask differs from what we last OCR'd. Settled = it barely
      // changed since the previous tick (subtitle finished fading in). Ideally we OCR
      // a CHANGED+SETTLED frame (clean, no half-render), but a short line over a
      // moving background may never "settle" ??so once a change has persisted for
      // SETTLE_TIMEOUT we OCR anyway rather than drop the line. A re-OCR after it
      // truly settles self-corrects any half-rendered read.
      const tickDelta = state.regionLastTickFp ? regionFpDistance(fp, state.regionLastTickFp) : 1;
      const ocrDelta = state.regionLastOcrFp ? regionFpDistance(fp, state.regionLastOcrFp) : 1;
      state.regionLastTickFp = fp;

      const changed = ocrDelta > REGION_FP_CHANGE;
      if (!changed) {
        state.regionFpChangeStart = 0;
      } else if (!state.regionFpChangeStart) {
        state.regionFpChangeStart = now;
      }
      const settled = tickDelta <= REGION_FP_STABLE;
      const waitedEnough = state.regionFpChangeStart && (now - state.regionFpChangeStart >= REGION_FP_SETTLE_TIMEOUT);
      if (state.regionDetectBusy) {
        if (changed && regionFpInkRatio(fp) >= REGION_FP_TEXT_MIN) {
          const queue = Array.isArray(state.regionQueuedOcrFrames) ? state.regionQueuedOcrFrames : [];
          const lastQueued = queue.length > 0 ? queue[queue.length - 1] : null;
          const queuedDelta = lastQueued ? regionFpDistance(fp, lastQueued.fp) : 1;
          if (!lastQueued || queuedDelta > REGION_FP_STABLE || settled || waitedEnough) {
            queueRegionOcrFrame(fp, now);
          }
        }
        return;
      }

      const motion = regionMotionMode();
      const minGapOk = sinceOcr >= REGION_FP_MIN_GAP_MS;
      const safetyDue = sinceOcr >= getRegionForceInterval();
      // Motion mode (moving / fast subtitles): don't wait for the scene to settle — a moving line
      // never settles against an animated background — OCR as soon as a change is seen past the min gap.
      // A decisive change (large fingerprint jump vs the last OCR'd frame) is a hard line/scene cut, not a
      // fade, so OCR it immediately too instead of waiting a tick for the scene to settle. Still gated by
      // minGapOk so it can't hammer the single OCR slot.
      const decisive = ocrDelta >= REGION_FP_DECISIVE_CHANGE;
      if (!minGapOk || !((changed && (settled || waitedEnough || motion || decisive)) || safetyDue)) {
        return;
      }

      // We've decided to OCR: only now materialize the full-resolution crop, from the
      // same frame the fingerprint above sampled (this whole tick runs synchronously,
      // so the video has not advanced between the two draws).
      let cropCanvas;
      try {
        cropCanvas = getRegionCropCanvas();
      } catch {
        return;
      }

      // Never rotate the OCR session from a PRE-OCR pixel fingerprint. A drifting subtitle / animated
      // background trips `decisive` (>10% fp jump) on essentially EVERY frame, so rotating here forced a
      // backend cache miss every frame -> "whole-screen full DET per frame" (~300ms each, the measured lag)
      // and the cheap incremental / ROI-lock path NEVER engaged. The pixel fingerprint can't tell "same line
      // moving" from "new line" — only the OCR'd TEXT can. So we keep the session stable here (incremental
      // engages) and rotate AFTER OCR, in regionDetectAndTranslate, only when the recognized text actually
      // changed lines (see maybeRotateRegionSessionOnTextChange).
      dispatchRegionOcrFrame(cropCanvas, fp, now, false);
    }

    function resetRegionTextStability() {
      state.regionStableOcrText = "";
      state.regionStableOcrKey = "";
      state.regionStableOcrAt = 0;
      state.regionPendingOcrText = "";
      state.regionPendingOcrKey = "";
      state.regionPendingOcrAt = 0;
      state.regionPendingNewOcrText = "";
      state.regionPendingNewOcrKey = "";
      state.regionPendingNewOcrAt = 0;
      state.regionPendingGarbledText = "";
      state.regionPendingGarbledKey = "";
      state.regionPendingGarbledAt = 0;
      state.regionLineStats = null;
      state.regionSecondaryActiveText = "";
      if (state.regionSecondaryController) {
        try { state.regionSecondaryController.abort(); } catch (ignore) { /* already settled */ }
        state.regionSecondaryController = null;
      }
      state.regionActiveText = "";
      state.regionActiveTranslationKey = "";
      state.regionLastOcrTextKey = "";
    }

    function cloneRegionCropCanvas(cropCanvas) {
      const clone = document.createElement("canvas");
      clone.width = cropCanvas.width;
      clone.height = cropCanvas.height;
      clone.getContext("2d").drawImage(cropCanvas, 0, 0);
      return clone;
    }

    function clearQueuedRegionOcrFrame() {
      state.regionQueuedOcrFrames = [];
    }

    function queueRegionOcrFrame(fp, now) {
      if (regionFpInkRatio(fp) < REGION_FP_TEXT_MIN) {
        return;
      }

      let cropCanvas;
      try {
        cropCanvas = getRegionCropCanvas();
      } catch {
        return;
      }

      const frame = { canvas: cloneRegionCropCanvas(cropCanvas), fp, at: now };
      state.regionQueuedOcrFrames = [frame].slice(-REGION_OCR_QUEUE_MAX);
    }

    // Text-layer line-change detector that drives session rotation (replaces the pre-OCR pixel-fingerprint
    // `decisive`). Compares the just-OCR'd text against the last OCR'd text by normalized edit distance:
    // a genuine new line rotates the session (so the backend re-frames its ROI on the next frame); a same
    // line that merely drifted / re-rendered keeps the session so incremental rec-only stays engaged.
    function maybeRotateRegionSessionOnTextChange(rawText) {
      const key = regionTextKey(rawText || "");
      const prevKey = state.regionLastOcrTextKey || "";
      // Empty reads (one-frame OCR misses / blanks) must NOT rotate — the stabilizer holds the line and a
      // rotation here would needlessly re-scan whole-screen on every fade frame.
      if (!key) {
        return;
      }
      if (!prevKey) {
        state.regionLastOcrTextKey = key;
        return;
      }
      if (key === prevKey) {
        return;
      }
      // Normalized edit distance: tolerant of a few glyph wobbles (same line, OCR noise), but a real line
      // swap (most characters differ) crosses the threshold and rotates.
      const limit = Math.max(2, Math.floor(Math.max(key.length, prevKey.length) * REGION_TEXT_CHANGE_RATIO));
      const dist = regionEditDistance(key, prevKey, limit + 1);
      state.regionLastOcrTextKey = key;
      if (dist > limit) {
        rotateRegionOcrSession();
      }
    }

    function rotateRegionOcrSession() {
      // A new session id makes the backend realtime layout cache MISS, so it runs a fresh
      // full detect that re-frames the line boxes for the CURRENT subtitle. Without this, a
      // changed subtitle is recognized inside the PREVIOUS line's cached (smaller / shifted)
      // box and its leading/trailing characters get clipped until the periodic re-detect
      // (RealtimeRedetectIntervalMs ~2.5s) finally rebuilds the layout -- the "開頭被截掉,
      // 要等才會全部判斷到" symptom. Rotating ONLY on a real content change keeps the cheap
      // incremental rec-only path for static re-reads of the same line.
      state.regionOcrSessionId = "region-" + Date.now().toString(36) + "-" + Math.random().toString(36).slice(2, 8);
    }

    function dispatchRegionOcrFrame(cropCanvas, fp, now, forceFreshDetect = false) {
      if (forceFreshDetect) {
        rotateRegionOcrSession();
      }
      const epoch = ++state.regionOcrEpoch;
      state.regionActiveOcrEpoch = epoch;
      state.regionActiveOcrStartedAt = now;
      state.regionFpChangeStart = 0;
      state.regionDetectBusy = true;
      state.regionLastOcrAt = now;
      state.regionLastOcrFp = fp;
      updateRegionLoopStatusLabel();
      regionDetectAndTranslate(cropCanvas, epoch)
        .catch(error => {
          if (!isAbortError(error)) {
            appendMessage("error", "region loop", error.message || String(error));
          }
        })
        .finally(() => {
          // Rolling OCR wall-time EWMA drives the adaptive gap (getRegionForceInterval): cheap
          // incremental frames pull the backstop tight (responsive), expensive cold detects relax it.
          const elapsed = performance.now() - now;
          if (Number.isFinite(elapsed) && elapsed >= 0) {
            const prev = state.regionOcrLatencyEwma || 0;
            state.regionOcrLatencyEwma = prev > 0 ? (prev * 0.7 + elapsed * 0.3) : elapsed;
          }
          if (state.regionActiveOcrEpoch === epoch) {
            state.regionActiveOcrEpoch = 0;
            state.regionActiveOcrStartedAt = 0;
            state.regionDetectBusy = false;
          }
          updateRegionLoopStatusLabel();
          flushQueuedRegionOcrFrame();
        });
    }

    function flushQueuedRegionOcrFrame() {
      const queue = Array.isArray(state.regionQueuedOcrFrames) ? state.regionQueuedOcrFrames : [];
      if (!state.regionLoopRunning || state.regionDetectBusy || queue.length === 0) {
        return;
      }

      // Latest-only: OCR the FRESHEST queued frame and drop the older (now stale) ones. On animated /
      // moving content every tick reads as "changed", so the queue fills with distinct frames; taking the
      // oldest (queue.shift) made the loop run N detects BEHIND the live frame — an N x ~detect backlog
      // that feels far longer than a single detect. Jumping to the newest collapses it to one detect.
      const frame = queue[queue.length - 1];
      state.regionQueuedOcrFrames = [];
      // Don't force a fresh session on the flushed frame: keep the realtime layout so the backend can
      // run the cheap incremental path. A real cut still rotates via `decisive` on the live tick above.
      dispatchRegionOcrFrame(frame.canvas, frame.fp, performance.now(), false);
    }

    function regionTextKey(text) {
      return String(text || "")
        .normalize("NFKC")
        .toLowerCase()
        .replace(/[\s\p{P}\p{S}]+/gu, "");
    }

    function regionEditDistance(a, b, limit) {
      if (a === b) { return 0; }
      if (!a) { return b.length; }
      if (!b) { return a.length; }
      if (Math.abs(a.length - b.length) > limit) {
        return limit + 1;
      }

      let previous = new Array(b.length + 1);
      let current = new Array(b.length + 1);
      for (let j = 0; j <= b.length; j++) {
        previous[j] = j;
      }

      for (let i = 1; i <= a.length; i++) {
        current[0] = i;
        let rowMin = current[0];
        for (let j = 1; j <= b.length; j++) {
          const cost = a[i - 1] === b[j - 1] ? 0 : 1;
          const value = Math.min(
            previous[j] + 1,
            current[j - 1] + 1,
            previous[j - 1] + cost);
          current[j] = value;
          if (value < rowMin) {
            rowMin = value;
          }
        }

        if (rowMin > limit) {
          return limit + 1;
        }
        const swap = previous;
        previous = current;
        current = swap;
      }

      return previous[b.length];
    }

    function regionCommonSubstringLength(a, b) {
      if (!a || !b) { return 0; }
      const shorter = a.length <= b.length ? a : b;
      const longer = a.length <= b.length ? b : a;
      let previous = new Array(longer.length + 1).fill(0);
      let current = new Array(longer.length + 1).fill(0);
      let best = 0;
      for (let i = 1; i <= shorter.length; i++) {
        current[0] = 0;
        for (let j = 1; j <= longer.length; j++) {
          const value = shorter[i - 1] === longer[j - 1] ? previous[j - 1] + 1 : 0;
          current[j] = value;
          if (value > best) {
            best = value;
          }
        }
        const swap = previous;
        previous = current;
        current = swap;
        current.fill(0);
      }
      return best;
    }

    // Strict same-subtitle test for realtime de-dupe. Punctuation/spacing changes
    // are always the same line; fuzzy edit matching is intentionally narrow so a
    // short, fast new sentence that happens to resemble the previous one is not
    // swallowed by the stabilizer.
    function regionTextSimilar(a, b) {
      const ak = regionTextKey(a);
      const bk = regionTextKey(b);
      if (!ak || !bk) { return false; }
      if (ak === bk) { return true; }

      const minLen = Math.min(ak.length, bk.length);
      const maxLen = Math.max(ak.length, bk.length);
      if (maxLen < 8) {
        return false;
      }

      const delta = maxLen - minLen;
      if ((ak.startsWith(bk) || bk.startsWith(ak)) && delta <= Math.max(1, Math.floor(maxLen * 0.10))) {
        return true;
      }

      const common = regionCommonSubstringLength(ak, bk);
      if (minLen >= 7 && common / minLen >= 0.72 && common / maxLen >= 0.52) {
        return true;
      }
      if (minLen >= 7 && common / minLen >= 0.88 && common / maxLen >= 0.34) {
        return true;
      }

      const limit = maxLen < 16 ? 1 : maxLen < 32 ? 2 : 3;
      const distance = regionEditDistance(ak, bk, limit);
      return distance <= limit && distance / maxLen <= 0.12;
    }

    function regionTextVariantIsBetter(candidate, current) {
      const candidateKey = regionTextKey(candidate);
      const currentKey = regionTextKey(current);
      if (!candidateKey) { return false; }
      if (!currentKey) { return true; }
      if (candidateKey.length >= currentKey.length + 2) { return true; }
      if (candidateKey.length === currentKey.length && String(candidate || "").length + 2 < String(current || "").length) {
        return true;
      }
      return false;
    }

    function acceptRegionStableOcrText(text, now = performance.now()) {
      const value = String(text || "");
      const previous = state.regionStableOcrText || "";
      state.regionStableOcrText = value;
      state.regionStableOcrKey = regionTextKey(value);
      state.regionStableOcrAt = now;
      state.regionPendingOcrText = "";
      state.regionPendingOcrKey = "";
      state.regionPendingOcrAt = 0;
      state.regionPendingNewOcrText = "";
      state.regionPendingNewOcrKey = "";
      state.regionPendingNewOcrAt = 0;
      state.regionPendingGarbledText = "";
      state.regionPendingGarbledKey = "";
      state.regionPendingGarbledAt = 0;
      return {
        text: value,
        trimmed: value.trim(),
        changed: value.trim() !== previous.trim(),
        held: false,
        display: value
      };
    }

    function holdRegionPendingNewOcrText(value, key, now) {
      const pending = state.regionPendingNewOcrText || "";
      if (!pending || !regionTextSimilar(value, pending)) {
        state.regionPendingNewOcrText = value;
        state.regionPendingNewOcrKey = key;
        state.regionPendingNewOcrAt = now;
      } else if (regionTextVariantIsBetter(value, pending)) {
        state.regionPendingNewOcrText = value;
        state.regionPendingNewOcrKey = key;
      }
    }

    function maybePromoteRegionPendingNew(now) {
      const pending = state.regionPendingNewOcrText || "";
      const pendingAt = state.regionPendingNewOcrAt || 0;
      if (pending.trim() && pendingAt && now - pendingAt >= REGION_OCR_NEW_PROMOTE_MS) {
        return acceptRegionStableOcrText(pending, now);
      }
      return null;
    }

    // Conditional fade-in hold: translate a freshly-read NEW subtitle immediately when it already
    // looks like a complete, clean line; only "suspect" reads keep the brief hold. Suspect = a short
    // fragment (few real letters) or a residual leading timecode (frame still transitioning). Counts
    // CJK ideographs, kana, and Latin letters only (ignores digits / punctuation / spaces).
    // OCR-noise detector for washed-out / fading frames: an uppercase Latin letter fused into a CJK
    // line ("4E尽", "AE尽瓣", "尽o", "司化界 ４Ｅ尽满") is the signature. Real Japanese keeps Latin as
    // proper words ("No Destiny") or absent, and numbers ("2文字") carry no uppercase letter — verified
    // against the live log (11/11 garbage flagged, 10/10 real lyrics kept). Used to stop these frames
    // from being shown/translated; a flagged line that genuinely recurs still promotes via stability.
    function regionTextLooksGarbled(text) {
      const t = String(text || "").trim();
      if (!t) { return false; }
      const norm = t.replace(/[Ａ-Ｚａ-ｚ０-９]/g, ch => String.fromCharCode(ch.charCodeAt(0) - 0xFEE0));
      const hasCjk = /[\p{Script=Han}\p{Script=Hiragana}\p{Script=Katakana}]/u.test(norm);
      return hasCjk && /(?<![A-Za-z])[A-Z0-9]{0,1}[A-Z][A-Z0-9]{0,1}(?![A-Za-z])/.test(norm);
    }

    function regionNewTextLooksComplete(text) {
      const t = String(text || "").trim();
      if (!t) { return false; }
      if (/^\d{1,2}[:：/／]/.test(t)) { return false; } // residual leading timecode -> still transitional
      if (regionTextLooksGarbled(t)) { return false; } // OCR noise -> must earn promotion via stability, not the fast path
      const letters = (t.match(/[\p{Script=Han}\p{Script=Hiragana}\p{Script=Katakana}A-Za-z]/gu) || []).length;
      return letters >= REGION_OCR_CLEAN_MIN_LETTERS;
    }

    // Diagnostic: surface a frame that was READ but suppressed/held by a noise gate, so a legit
    // "header" / secondary line that trips a gate is visible (with the gate reason) instead of being
    // silently dropped. Throttled + de-duped by raw text to avoid flooding the message log.
    function maybeLogRegionSuppressed(rawText, stabilized) {
      if (!stabilized || !stabilized.held || stabilized.sameLine || stabilized.emptyHeld) {
        return;
      }
      const raw = String(rawText || "").trim();
      if (!raw) {
        return;
      }
      const shown = String(stabilized.display != null ? stabilized.display : (stabilized.text || "")).trim();
      if (raw === shown) {
        return;
      }
      const key = regionTextKey(raw);
      if (!key || key === state.regionLastSuppressedKey) {
        return;
      }
      const at = performance.now();
      if (state.regionLastSuppressedAt && at - state.regionLastSuppressedAt < REGION_SUPPRESS_LOG_MS) {
        return;
      }
      state.regionLastSuppressedKey = key;
      state.regionLastSuppressedAt = at;
      const reason = stabilized.garbledHeld
        ? "held: garbage-gate"
        : stabilized.candidateHeld
          ? "held: awaiting stability"
          : "held";
      appendMessage("muted", "region held", raw, reason);
    }

    function stabilizeRegionOcrText(text, now = performance.now()) {
      const value = String(text || "");
      const trimmed = value.trim();
      const valueKey = regionTextKey(value);
      const stable = state.regionStableOcrText || "";
      const stableTrimmed = stable.trim();

      // Hard-hold on an OCR-noise frame (Latin fused to CJK) once we already have a good read: keep the
      // last stable text for BOTH the readout and the translation so fade/transition garbage like
      // "4E尽瓣" / "可化尺 AE" never flickers into the output. (No stable yet -> fall through; it still
      // won't take the fast-promote path, so it holds as a pending candidate instead of showing.)
      if (trimmed && stableTrimmed && regionTextLooksGarbled(trimmed)) {
        // Genuine fade/transition noise changes every frame, so it never accumulates a stable garbled
        // candidate; a real line that merely trips the heuristic re-reads the SAME text and earns
        // promotion after REGION_OCR_GARBLED_PROMOTE_MS rather than being swallowed behind the stable
        // text forever (the "header 被當垃圾、沒觸發翻譯" case).
        const pendingGarbled = state.regionPendingGarbledText || "";
        if (pendingGarbled && regionTextSimilar(trimmed, pendingGarbled)) {
          if (regionTextVariantIsBetter(value, pendingGarbled)) {
            state.regionPendingGarbledText = value;
            state.regionPendingGarbledKey = valueKey;
          }
          if (state.regionPendingGarbledAt &&
              now - state.regionPendingGarbledAt >= REGION_OCR_GARBLED_PROMOTE_MS &&
              !regionTextSimilar(trimmed, stableTrimmed)) {
            return { ...acceptRegionStableOcrText(state.regionPendingGarbledText, now), garbledPromoted: true };
          }
        } else {
          state.regionPendingGarbledText = value;
          state.regionPendingGarbledKey = valueKey;
          state.regionPendingGarbledAt = now;
        }
        return { text: stable, trimmed: stableTrimmed, changed: false, held: true, garbledHeld: true, display: stable };
      }

      if (!trimmed || !valueKey) {
        const pendingPromoted = maybePromoteRegionPendingNew(now);
        if (pendingPromoted) {
          return { ...pendingPromoted, pendingPromoted: true };
        }
        if (stableTrimmed) {
          if (state.regionPendingOcrKey !== "__empty__") {
            state.regionPendingOcrText = "";
            state.regionPendingOcrKey = "__empty__";
            state.regionPendingOcrAt = now;
          }
          if (now - (state.regionPendingOcrAt || now) < REGION_OCR_EMPTY_HOLD_MS) {
            return { text: stable, trimmed: stableTrimmed, changed: false, held: true, emptyHeld: true, display: stable };
          }
        }
        if ((state.regionPendingNewOcrText || "").trim()) {
          return { text: stable, trimmed: stableTrimmed, changed: false, held: true, candidateHeld: true, display: stable };
        }
        return acceptRegionStableOcrText("", now);
      }

      if (!stableTrimmed) {
        if (regionNewTextLooksComplete(value)) {
          return { ...acceptRegionStableOcrText(value, now), promotedImmediate: true };
        }
        holdRegionPendingNewOcrText(value, valueKey, now);
        const pendingPromoted = maybePromoteRegionPendingNew(now);
        if (pendingPromoted) {
          return { ...pendingPromoted, pendingPromoted: true };
        }
        return { text: "", trimmed: "", changed: false, held: true, candidateHeld: true, display: value };
      }

      if (regionTextSimilar(trimmed, stableTrimmed)) {
        const key = valueKey;
        if (regionTextVariantIsBetter(value, stable)) {
          if (state.regionPendingOcrKey === key && now - (state.regionPendingOcrAt || now) >= REGION_OCR_VARIANT_PROMOTE_MS) {
            return { ...acceptRegionStableOcrText(value, now), variantPromoted: true };
          }
          state.regionPendingOcrText = value;
          state.regionPendingOcrKey = key;
          state.regionPendingOcrAt = now;
        } else if (state.regionPendingOcrKey !== key) {
          state.regionPendingOcrText = "";
          state.regionPendingOcrKey = "";
          state.regionPendingOcrAt = 0;
        }
        return { text: stable, trimmed: stableTrimmed, changed: false, held: true, sameLine: true, display: stable };
      }

      if (regionNewTextLooksComplete(value)) {
        return { ...acceptRegionStableOcrText(value, now), promotedImmediate: true };
      }
      holdRegionPendingNewOcrText(value, valueKey, now);
      const pendingPromoted = maybePromoteRegionPendingNew(now);
      if (pendingPromoted) {
        return { ...pendingPromoted, pendingPromoted: true };
      }
      return { text: stable, trimmed: stableTrimmed, changed: false, held: true, candidateHeld: true, display: value };
    }

    // Phase 3 adaptive priority: split the cleaned OCR lines into the live "primary" subtitle and any
    // persistent "secondary" header/side line, by observed recurrence (trend) rather than a fixed
    // position. A line that keeps re-reading the SAME text across many frames for a while is static;
    // the changing dialogue is primary. Graceful: if nothing is clearly static, or stripping static
    // lines would leave nothing, the whole frame stays primary (today's single-blob behaviour).
    function regionClassifyLines(rawText, now) {
      const lines = String(rawText || "").split("\n").map(line => line.trim()).filter(Boolean);
      const stats = state.regionLineStats || (state.regionLineStats = new Map());
      for (const [key, entry] of stats) {
        if (now - entry.lastAt > REGION_LINE_STATS_DECAY_MS) {
          stats.delete(key);
        }
      }
      for (const line of lines) {
        const key = regionTextKey(line);
        if (!key) {
          continue;
        }
        const entry = stats.get(key);
        if (entry) {
          entry.count += 1;
          entry.lastAt = now;
          entry.text = line;
        } else {
          stats.set(key, { text: line, count: 1, firstAt: now, lastAt: now });
        }
      }
      const primaryLines = [];
      const secondaryLines = [];
      for (const line of lines) {
        const key = regionTextKey(line);
        const entry = key ? stats.get(key) : null;
        const isStatic = Boolean(entry) &&
          entry.count >= REGION_SECONDARY_MIN_FRAMES &&
          (now - entry.firstAt) >= REGION_SECONDARY_STATIC_MS;
        if (isStatic) {
          secondaryLines.push(line);
        } else {
          primaryLines.push(line);
        }
      }
      let primaryText = primaryLines.join("\n");
      let secondaryText = secondaryLines.join("\n");
      // Never demote the WHOLE frame: if every line reads as "static" (e.g. a paused screen) keep it
      // all as primary, so the main subtitle never silently slides into the dimmer secondary line.
      if (!primaryText) {
        primaryText = lines.join("\n");
        secondaryText = "";
      }
      return { primaryText, secondaryText };
    }

    // Low-priority lane for the static secondary text: translate-once per distinct text, cached, with
    // its own controller so it never aborts or queues ahead of the primary subtitle, and it yields the
    // lane while a primary translation is streaming.
    function regionHandleSecondaryText(secondaryText) {
      const text = String(secondaryText || "").trim();
      if (!text) {
        if (state.regionSecondaryActiveText) {
          state.regionSecondaryActiveText = "";
          if (state.regionSecondaryController) {
            try { state.regionSecondaryController.abort(); } catch (ignore) { /* already settled */ }
            state.regionSecondaryController = null;
          }
          setRegionSecondaryTranslation("");
        }
        return;
      }
      if (text === (state.regionSecondaryActiveText || "")) {
        return;
      }
      // Yield to the primary lane: don't claim new secondary text while the main translation streams;
      // a later frame picks it up once primary is idle (the header is static, so it is still there).
      if (state.regionTranslateController) {
        return;
      }
      state.regionSecondaryActiveText = text;
      const settings = regionTranslationSettings();
      const cacheKey = "region-secondary\x1f" + regionTranslationKey(text, settings);
      const cached = regionLruGet(cacheKey);
      if (cached !== null) {
        setRegionSecondaryTranslation(cached);
        return;
      }
      const controller = new AbortController();
      state.regionSecondaryController = controller;
      const myText = text;
      streamRegionTranslate(regionTranslationPayload(text, settings), controller, null)
        .then(result => {
          if (state.regionSecondaryActiveText !== myText) {
            return;
          }
          const translated = (result && result.result) || "";
          if (translated && (!result.errorCode || result.errorCode === "0")) {
            regionLruSet(cacheKey, translated);
            setRegionSecondaryTranslation(translated);
          }
        })
        .catch(error => { if (!isAbortError(error)) { /* secondary lane is best-effort */ } })
        .finally(() => {
          if (state.regionSecondaryController === controller) {
            state.regionSecondaryController = null;
          }
        });
    }

    async function regionDetectAndTranslate(cropCanvas, epoch) {
      const cropWidth = cropCanvas.width;
      const cropHeight = cropCanvas.height;
      const encoded = await encodeRegionCrop(cropCanvas);
      if (!isRegionOcrEpochCurrent(epoch)) { return; }
      imageBase64.value = encoded.base64 || "";
      state.imageMimeType = encoded.mimeType;

      let ocr;
      const controller = new AbortController();
      state.regionOcrAbort = controller;
      try {
        ocr = await postRegionOcr(encoded, {
          headers: memoryRuntimeHeaders(),
          signal: controller.signal
        });
      } catch (error) {
        if (isAbortError(error)) { return; }
        throw error;
      } finally {
        if (state.regionOcrAbort === controller) {
          state.regionOcrAbort = null;
        }
      }
      if (!isRegionOcrEpochCurrent(epoch)) { return; }

      const rawOcrText = normalizeLatinConfusables(applyRegionTextPolicy(ocr, cropWidth, cropHeight));
      // Phase 3: split off any persistent header/side line into the low-priority secondary lane; the
      // primary (live subtitle) text is what the stabilizer + main translation see.
      const regionParts = regionClassifyLines(rawOcrText, performance.now());
      regionHandleSecondaryText(regionParts.secondaryText);
      const stabilized = stabilizeRegionOcrText(regionParts.primaryText);
      const ocrText = stabilized.text;
      const trimmed = stabilized.trimmed;
      // NO JS session rotation. Any text-based rotation still over-fires on a faint column whose read
      // churns even after the stabilizer (無ジョウ→ウ→心浦) -> a new session every frame -> backend
      // cache MISS -> whole-screen cold detect every frame (measured: 26 miss / 0 scoped, ~760ms/frame).
      // The session stays stable for the whole loop (set once at loop start); the BACKEND re-frames a
      // changed subtitle itself via its scoped rec-empty / script-flip escalations (~150ms) and the 5s
      // whole-screen drift rescan. This keeps F ROI-lock + incremental (~10-20ms) engaged on static
      // frames instead of forcing a cold whole-screen detect on every frame.
      // The OCR readout tracks the freshest recognized text even while a suspect line's translation
      // is briefly deferred; the translate decision below still gates on the stabilized text/trimmed.
      const displayText = stabilized.display != null ? stabilized.display : ocrText;
      const ocrLatency = ocr && Number.isFinite(ocr.latencyMs) ? ocr.latencyMs : NaN;
      state.latestOcrText = displayText;
      regionOcrText.value = displayText;
      ocrOutput.value = displayText;
      sourceText.value = displayText;
      $("blockCount").textContent = String(ocr && ocr.blocks ? ocr.blocks.length : 0);
      $("engineName").textContent = ocr && ocr.engine ? ocr.engine : "-";
      renderOcrStructure(ocr || null, null);
      maybeLogRegionSuppressed(regionParts.primaryText, stabilized);

      if (!trimmed) {
        state.regionActiveText = "";
        state.regionActiveTranslationKey = "";
        return;
      }
      const translationSettings = regionTranslationSettings();
      const translationKey = regionTranslationKey(trimmed, translationSettings);
      // Same subtitle as the one already shown / translating. The comparison is
      // strict enough to avoid swallowing short, fast new lines that share words.
      const activeText = state.regionActiveText || "";
      const activeTranslationKey = state.regionActiveTranslationKey || "";
      const isBetterActiveVariant = Boolean(stabilized.variantPromoted || stabilized.pendingPromoted) &&
        regionTextSimilar(trimmed, activeText) &&
        regionTextVariantIsBetter(trimmed, activeText);
      if (regionTextSimilar(trimmed, activeText) && translationKey === activeTranslationKey && !isBetterActiveVariant) {
        state.regionActiveText = trimmed;
        return;
      }

      // New subtitle: supersede any in-flight translation, then translate this one.
      state.regionActiveText = trimmed;
      state.regionActiveTranslationKey = translationKey;
      // Diagnostic: log EVERY detected new subtitle the instant it is recognized,
      // before translation. A "region detect" line with no following "region
      // translation" means the line was OCR'd but its translation was superseded
      // (aborted) before completing ??distinguishing that from "never detected".
      const ocrMode = ocr && ocr.engine && ocr.engine.indexOf("incremental") >= 0 ? "incr" : "full";
      // Provider-internal profiling breakdown (server-measured): q=queue wait on the single-run
      // lock, p=compute, side=side-ROI rescue cost, (reason)=why this frame ran a full detect.
      // Lets a live run tell apart queueing / interval / side-rescue / cold without reading logs.
      const t = ocr && ocr.timing ? ocr.timing : null;
      let timingMeta = "";
      if (t) {
        const parts = [];
        if (Number.isFinite(t.serviceWaitMs) && t.serviceWaitMs > 0) { parts.push(`svc${Math.round(t.serviceWaitMs)}`); }
        if (Number.isFinite(t.serviceBuildMs) && t.serviceBuildMs > 0) { parts.push(`build${Math.round(t.serviceBuildMs)}`); }
        if (Number.isFinite(t.queueWaitMs) && t.queueWaitMs > 0) { parts.push(`q${Math.round(t.queueWaitMs)}`); }
        if (Number.isFinite(t.providerMs)) { parts.push(`p${Math.round(t.providerMs)}`); }
        if (Number.isFinite(t.detectResizeMs) && t.detectResizeMs > 0) { parts.push(`resize${Math.round(t.detectResizeMs)}`); }
        if (Number.isFinite(t.fullDetectMs) && t.fullDetectMs > 0) { parts.push(`det${Math.round(t.fullDetectMs)}`); }
        if (Number.isFinite(t.sparsePreflightMs) && t.sparsePreflightMs > 0) { parts.push(`pre${Math.round(t.sparsePreflightMs)}`); }
        if (Number.isFinite(t.sparseRescueMs) && t.sparseRescueMs > 0) { parts.push(`sparse${Math.round(t.sparseRescueMs)}`); }
        if (Number.isFinite(t.languageRecMs) && t.languageRecMs > 0) { parts.push(`rec${Math.round(t.languageRecMs)}`); }
        if (Number.isFinite(t.realtimeBaseRecMs) && t.realtimeBaseRecMs > 0) { parts.push(`base${Math.round(t.realtimeBaseRecMs)}`); }
        if (Number.isFinite(t.realtimeLangRecMs) && t.realtimeLangRecMs > 0) { parts.push(`lang${Math.round(t.realtimeLangRecMs)}`); }
        if (t.recCropShape) { parts.push(`rcrop${t.recCropShape}`); }
        if (Number.isFinite(t.sideRescueMs) && t.sideRescueMs > 0) { parts.push(`side${Math.round(t.sideRescueMs)}`); }
        if (t.fullDetectReason) { parts.push(`(${t.fullDetectReason})`); }
        if (parts.length) { timingMeta = " · " + parts.join(" "); }
      }
      const encodedSize = encoded && encoded.sourceWidth && encoded.width
        ? ` img${encoded.sourceWidth}x${encoded.sourceHeight}->${encoded.width}x${encoded.height}`
        : "";
      appendMessage("user", "region detect", trimmed, `ocr ${Number.isFinite(ocrLatency) ? Math.round(ocrLatency) : "-"}ms ${ocrMode}${encodedSize}${timingMeta}`);
      if (state.regionTranslateController) {
        try { state.regionTranslateController.abort(); } catch (ignore) { /* already settled */ }
        state.regionTranslateController = null;
      }

      markRegionTranslationStale();
      const remembered = regionLruGet(translationKey);
      if (remembered !== null) {
        setRegionTranslationText(remembered, { fresh: true });
        lastOutput.value = remembered;
        const usage = zeroTokenUsage("region:cache");
        applyTokenUsage(usage, "region");
        appendMessage("result", "region translation", remembered, appendTokenUsageMeta("cache", usage));
        return;
      }

      // Fire-and-forget the (possibly slow / streaming) translation so this detect
      // call returns immediately and releases regionDetectBusy. Awaiting it here was
      // the bug: a slow translation held the detect flag for its whole duration, so
      // the loop stopped OCR-ing and dropped every subtitle that appeared meanwhile.
      regionTranslateActive(ocrText, trimmed, ocr, ocrLatency, translationSettings, translationKey);
    }

    // Background translation of the active subtitle. Not awaited by the detect loop;
    // a newer subtitle changes state.regionActiveText (and aborts this controller),
    // and the active text + translation settings key guard drops any superseded output.
    async function regionTranslateActive(ocrText, trimmed, ocr, ocrLatency, settings, translationKey) {
      const controller = new AbortController();
      state.regionTranslateController = controller;
      const myText = trimmed;
      const myTranslationKey = translationKey || regionTranslationKey(trimmed, settings);
      const started = performance.now();
      let translation;
      try {
        translation = await streamRegionTranslate(regionTranslationPayload(ocrText, settings), controller, (partial) => {
          if (state.regionActiveText === myText && state.regionActiveTranslationKey === myTranslationKey) {
            setRegionTranslationText(partial);
            lastOutput.value = partial;
          }
        });
      } catch (error) {
        if (isAbortError(error)) { return; }
        translation = { result: "", errorCode: "1", errorMessage: error.message || String(error) };
      } finally {
        if (state.regionTranslateController === controller) {
          state.regionTranslateController = null;
        }
      }

      // Token usage is a real cost the LLM already incurred — record it even when a newer subtitle
      // superseded this one. Realtime region lines change every frame, so the in-flight translation
      // is almost always "superseded" by the time it finishes; gating token usage on the supersede
      // check (as the old code did) meant region token usage was never recorded at all. Only the
      // on-screen translation TEXT is gated below — the cost is not.
      const superseded = state.regionActiveText !== myText || state.regionActiveTranslationKey !== myTranslationKey;
      if (superseded) {
        if (translation.tokenUsage && (!translation.errorCode || translation.errorCode === "0")) {
          applyTokenUsage(translation.tokenUsage, "region");
        }
        return;
      }

      const translatedText = translation.result || "";
      const translationFailed = translation.errorCode && translation.errorCode !== "0";
      if (!translatedText && translationFailed) {
        applyTokenUsage(translation.tokenUsage || null, "region");
        const elapsed = Math.round(performance.now() - started);
        const ocrLabel = Number.isFinite(ocrLatency)
          ? `${Math.round(ocrLatency)}${ocr && ocr.cacheHit ? "*" : ""}`
          : "-";
        const latencySummary = appendTokenUsageMeta(`ocr ${ocrLabel} / llm ${elapsed} ms`, translation.tokenUsage || null);
        $("latencyLabel").textContent = latencySummary;
        appendMessage("error", "region translation", translation.errorMessage || "translation failed", latencySummary);
        clearRegionTranslationPending();
        return;
      }
      setRegionTranslationText(translatedText, { fresh: true });
      lastOutput.value = translatedText;
      applyTokenUsage(translation.tokenUsage || null, "region");
      if (translatedText && (!translation.errorCode || translation.errorCode === "0")) {
        regionLruSet(myTranslationKey, translatedText);
      }

      const elapsed = Math.round(performance.now() - started);
      const ocrLabel = Number.isFinite(ocrLatency)
        ? `${Math.round(ocrLatency)}${ocr && ocr.cacheHit ? "*" : ""}`
        : "-";
      const latencySummary = appendTokenUsageMeta(`ocr ${ocrLabel} / llm ${elapsed} ms`, translation.tokenUsage || null);
      $("latencyLabel").textContent = latencySummary;
      if (translation.errorCode && translation.errorCode !== "0") {
        appendMessage("error", "region translation", translation.errorMessage || translatedText, latencySummary);
      } else {
        appendMessage("result", "region translation", translatedText, latencySummary);
      }
    }

    function requestRegionRetranslateForSettingsChange() {
      const text = (state.regionActiveText || state.regionStableOcrText || regionOcrText.value || state.latestOcrText || "").trim();
      if (!text || (!state.regionLoopRunning && state.mode !== "region")) {
        return;
      }

      const settings = regionTranslationSettings();
      const translationKey = regionTranslationKey(text, settings);
      if (state.regionActiveText === text && state.regionActiveTranslationKey === translationKey) {
        return;
      }

      state.regionActiveText = text;
      state.regionActiveTranslationKey = translationKey;
      if (state.regionTranslateController) {
        try { state.regionTranslateController.abort(); } catch (ignore) { /* already settled */ }
        state.regionTranslateController = null;
      }

      markRegionTranslationStale();
      const remembered = regionLruGet(translationKey);
      if (remembered !== null) {
        setRegionTranslationText(remembered, { fresh: true });
        lastOutput.value = remembered;
        const usage = zeroTokenUsage("region:cache");
        applyTokenUsage(usage, "region");
        appendMessage("result", "region translation", remembered, appendTokenUsageMeta("cache", usage));
        return;
      }

      applyTokenUsage(null, "region");
      appendMessage("user", "region retarget", text, `${settings.source}->${settings.target}`);
      regionTranslateActive(text, text, null, NaN, settings, translationKey);
    }

    function scheduleRegionWatch() {
      if (!state.regionLoopRunning) {
        return;
      }

      if (startRegionWatchWorker()) {
        return;
      }

      // Worker unavailable: fall back to the timeout chain (throttled to >=1s
      // in background tabs, slowing detection there).
      state.regionLoopTimer = window.setTimeout(() => {
        if (!state.regionLoopRunning) {
          return;
        }

        regionWatchTick();
        scheduleRegionWatch();
      }, REGION_WATCH_TICK_MS);
    }

    async function toggleRegionLoop() {
      if (state.regionLoopRunning) {
        stopRegionLoop();
        return;
      }

      if (!state.regionStream) {
        await startRegionCapture();
      }

      setDefaultRegionSelection();
      getRegionCropCanvas();
      cancelRegionAutoSnapshot();
      // Fresh detection state for the decoupled, fingerprint-driven loop.
      resetRegionTextStability();
      state.regionLastDetectAt = 0;
      state.regionLastOcrAt = 0;
      state.regionLastTickFp = null;
      state.regionLastOcrFp = null;
      state.regionFpChangeStart = 0;
      state.regionDetectBusy = false;
      state.regionOcrEpoch += 1;
      state.regionActiveOcrEpoch = 0;
      state.regionSupersededOcrEpoch = state.regionOcrEpoch;
      state.regionActiveOcrStartedAt = 0;
      clearQueuedRegionOcrFrame();
      if (state.regionTranslateController) {
        try { state.regionTranslateController.abort(); } catch (ignore) { /* already settled */ }
        state.regionTranslateController = null;
      }
      state.regionLoopRunning = true;
      // ONE stable session id for the whole loop, so the backend realtime layout cache (F ROI-lock +
      // incremental rec-only) actually engages. The session is NOT rotated per frame anymore — the
      // backend re-frames itself via its scoped rec-empty / script-flip / interval / 5s drift-rescan
      // guards. (Rotating on motion/decisive forced a cold whole-screen detect every frame on animated
      // content = the measured ~730ms/frame lag with ROI lock never engaging.)
      rotateRegionOcrSession();
      resetRegionWatchPhase();
      setRegionLoopStatus("on");
      updateRegionLoopStatusLabel();
      appendMessage("result", "region", `loop on (detect every ${getRegionInterval()} ms, decoupled detect?ranslate)`, "loop");

      warmRegionTranslate();
      scheduleRegionWatch();
    }

    // Pre-warm llama.cpp's prompt-prefix cache (cache_prompt) with the exact
    // source/target/mode/glossary/provider/model the loop will use, so the first
    // real subtitle is hot (~150ms) instead of paying the one-time full prompt-eval
    // (~0.5-5s, worse under GPU contention from video decode). Fire-and-forget; the
    // result is discarded and the overlay is never touched.
    function warmRegionTranslate() {
      try {
        const controller = new AbortController();
        streamRegionTranslate({
          text: "憸",
          source: $("source").value,
          target: $("target").value,
          mode: $("preset").value,
          glossary: $("glossary").value || null,
          provider: $("translationProvider").value,
          model: $("translationModel").value.trim() || null,
          realtime: true,
          broadcastSourceKind: "region"
        }, controller, null).catch(() => { /* warmup best-effort */ });
      } catch (ignore) {
        /* warmup best-effort */
      }
    }

    async function runCurrent() {
      if (state.mode === "region") {
        if (regionBackend === "browser") {
          await triggerRegionSnapshot();
        } else {
          await runNativeRegionSelect();
        }
        return;
      }

      if (state.busy) {
        return;
      }

      const busyToken = ++state.busyRunToken;
      setBusy(true);
      try {
        if (state.mode === "text") {
          await runTranslate();
        } else if (state.mode === "ocr") {
          // Merged OCR + Translate mode: async job lanes (structure/document
          // routing) keep the OCR-only job flow; the inline lane OCRs and
          // translates in one request.
          if (shouldRunOcrAsJob()) {
            await runOcr();
          } else {
            await runPipeline();
          }
        } else if (state.mode === "document") {
          await runDocumentJob();
        } else if (state.mode === "audio") {
          await runAsrPipeline();
        }
      } catch (error) {
        if (isAbortError(error)) {
          return;
        }
        appendMessage("error", state.mode, error.message || String(error));
      } finally {
        if (busyToken === state.busyRunToken) {
          setBusy(false);
        }
      }
    }

    async function readFileAsBase64(file) {
      const buffer = await file.arrayBuffer();
      const bytes = new Uint8Array(buffer);
      let binary = "";
      const chunkSize = 8192;
      for (let i = 0; i < bytes.length; i += chunkSize) {
        binary += String.fromCharCode(...bytes.subarray(i, i + chunkSize));
      }
      return btoa(binary);
    }

    async function loadImageFile(file, autoRun = true) {
      const imageSessionId = nextOcrImageSession();
      abortOcrImageRequest();
      if (state.busy) {
        state.busyRunToken += 1;
        setBusy(false);
      }
      imageBase64.value = "";
      state.imageMimeType = file.type || "image/png";
      resetOcrImageResultState();
      $("footerLeft").textContent = file.name;
      setMode("ocr");
      appendMessage("user", "image", `${file.name} (${file.size} bytes)`, "loaded");
      const base64 = await readFileAsBase64(file);
      if (!isCurrentOcrImageSession(imageSessionId)) {
        return;
      }
      imageBase64.value = base64;
      updateOcrComposerPreview();
      if (autoRun) {
        await runCurrent();
      }
    }

    // ── Window picker (capture a running app window) ──────────
    function openWindowPicker() {
      const overlay = $("windowPickerOverlay");
      if (!overlay) {
        return;
      }
      overlay.classList.remove("hidden");
      loadWindowPickerList();
    }

    function closeWindowPicker() {
      const overlay = $("windowPickerOverlay");
      if (overlay) {
        overlay.classList.add("hidden");
      }
    }

    async function loadWindowPickerList() {
      const grid = $("windowPickerGrid");
      if (!grid) {
        return;
      }
      grid.innerHTML = `<div class="window-picker-empty">Loading windows…</div>`;
      let windows;
      try {
        windows = await api("/windows");
      } catch (error) {
        grid.innerHTML = `<div class="window-picker-empty">${escapeHtml(error.message || String(error))}</div>`;
        return;
      }
      if (!Array.isArray(windows) || windows.length === 0) {
        grid.innerHTML = `<div class="window-picker-empty">No capturable windows found.</div>`;
        return;
      }

      grid.innerHTML = "";
      for (const win of windows) {
        const card = document.createElement("button");
        card.type = "button";
        card.className = "window-card";
        card.innerHTML = `
          <div class="window-card-thumb" data-hwnd="${escapeHtml(win.hwnd)}"><i class="ri-loader-4-line"></i></div>
          <div class="window-card-meta">
            <div class="window-card-title" title="${escapeHtml(win.title)}">${escapeHtml(win.title || "(untitled)")}</div>
            <div class="window-card-proc">${escapeHtml(win.processName)} · ${win.width}×${win.height}</div>
          </div>`;
        card.addEventListener("click", () => captureWindow(win.hwnd));
        grid.appendChild(card);
        // Lazily fetch each thumbnail (PrintWindow is slow; don't block the list).
        loadWindowThumb(win.hwnd, card.querySelector(".window-card-thumb"));
      }
    }

    async function loadWindowThumb(hwnd, mount) {
      if (!mount) {
        return;
      }
      try {
        const thumb = await api(`/windows/${encodeURIComponent(hwnd)}/thumbnail?width=320`);
        if (thumb && thumb.imageBase64) {
          const img = document.createElement("img");
          img.alt = "";
          img.src = `data:${thumb.imageMimeType || "image/png"};base64,${thumb.imageBase64}`;
          mount.innerHTML = "";
          mount.appendChild(img);
        } else {
          mount.textContent = "no preview";
        }
      } catch {
        mount.textContent = "no preview";
      }
    }

    async function captureWindow(hwnd) {
      if (state.busy) {
        return;
      }
      closeWindowPicker();
      $("footerLeft").textContent = "capturing window";
      try {
        const capture = await api(`/windows/${encodeURIComponent(hwnd)}/thumbnail?width=1600`);
        if (!capture || !capture.imageBase64) {
          $("footerLeft").textContent = "ready";
          appendMessage("error", "window capture", "Window could not be captured.");
          return;
        }

        const imageSessionId = nextOcrImageSession();
        abortOcrImageRequest();
        imageBase64.value = "";
        state.imageMimeType = capture.imageMimeType || "image/png";
        resetOcrImageResultState();
        const label = `window ${capture.windowWidth}×${capture.windowHeight}`;
        $("footerLeft").textContent = label;
        setMode("ocr");
        appendMessage("user", "window capture", `${label}${capture.degraded ? " (fallback)" : ""}`, "loaded");
        imageBase64.value = capture.imageBase64;
        if (!isCurrentOcrImageSession(imageSessionId)) {
          return;
        }
        updateOcrComposerPreview();
        await runCurrent();
      } catch (error) {
        appendMessage("error", "window capture", error.message || String(error));
        $("footerLeft").textContent = "ready";
      }
    }

    async function captureScreenRegion() {
      if (state.busy) {
        return;
      }

      const button = $("captureScreenRegionButton");
      button.disabled = true;
      $("footerLeft").textContent = "selecting screen region";
      try {
        const capture = await postEmpty("/ocr/screen-capture");
        if (!capture || !capture.imageBase64) {
          $("footerLeft").textContent = "ready";
          return;
        }

        const imageSessionId = nextOcrImageSession();
        abortOcrImageRequest();
        imageBase64.value = "";
        state.imageMimeType = capture.imageMimeType || "image/png";
        resetOcrImageResultState();
        $("footerLeft").textContent = capture.fileName || "screen region";
        setMode("ocr");
        appendMessage(
          "user",
          "screen capture",
          `${capture.fileName || "screen region"} (${capture.width || "?"}x${capture.height || "?"})`,
          "loaded");
        imageBase64.value = capture.imageBase64;
        if (!isCurrentOcrImageSession(imageSessionId)) {
          return;
        }

        updateOcrComposerPreview();
        await runCurrent();
      } catch (error) {
        appendMessage("error", "screen capture", error.message || String(error));
        $("footerLeft").textContent = "ready";
      } finally {
        button.disabled = false;
      }
    }

    async function loadAudioFile(file, autoRun = true) {
      audioBase64.value = await readFileAsBase64(file);
      audioSourceUrl.value = "";
      state.audioMimeType = file.type || "application/octet-stream";
      $("footerLeft").textContent = file.name;
      setMode("audio");
      appendMessage("user", "audio", `${file.name} (${file.size} bytes)`, "loaded");
      if (autoRun) {
        await runCurrent();
      }
    }

    function getFirstImageFile(fileList) {
      return Array.from(fileList || []).find(file => file.type && file.type.startsWith("image/")) || null;
    }

    function getFirstAudioFile(fileList) {
      return Array.from(fileList || []).find(file =>
        file.type && (file.type.startsWith("audio/") || file.type.startsWith("video/"))) || null;
    }

    function hexToRgba(hex, alpha) {
      hex = hex.replace('#', '');
      if (hex.length === 3) {
        hex = hex[0]+hex[0]+hex[1]+hex[1]+hex[2]+hex[2];
      }
      const r = parseInt(hex.substring(0, 2), 16) || 0;
      const g = parseInt(hex.substring(2, 4), 16) || 0;
      const b = parseInt(hex.substring(4, 6), 16) || 0;
      return `rgba(${r}, ${g}, ${b}, ${alpha})`;
    }

    function buildConfiguredProjectorUrl() {
      // Read saved config from storage or direct fallback
      const scale = window.localStorage.getItem("verbeam.projector.scale") || "1.0";
      const position = window.localStorage.getItem("verbeam.projector.position") || "bottom";
      const source = window.localStorage.getItem("verbeam.projector.source") === "1" ? "1" : "0";
      const backdrop = window.localStorage.getItem("verbeam.projector.backdrop") !== "0" ? "1" : "0";
      const fade = window.localStorage.getItem("verbeam.projector.fade") || "12";
      const font = window.localStorage.getItem("verbeam.projector.font") || "outfit";
      const color = window.localStorage.getItem("verbeam.projector.color") || "#f7f7f2";
      const bgColor = window.localStorage.getItem("verbeam.projector.bgcolor") || "#000000";
      const bgOpacity = window.localStorage.getItem("verbeam.projector.bgopacity") || "48";
      const align = window.localStorage.getItem("verbeam.projector.align") || "center";
      const shadow = window.localStorage.getItem("verbeam.projector.shadow") !== "0" ? "1" : "0";

      const alpha = (parseInt(bgOpacity, 10) / 100).toFixed(2);
      const rgbaBg = hexToRgba(bgColor, alpha);

      const params = new URLSearchParams({
        scale, position, source, backdrop, fade, font, color, bgcolor: rgbaBg, align, shadow
      });
      return `${location.origin}/projector?${params.toString()}`;
    }

    function openProjector() {
      const url = buildConfiguredProjectorUrl();
      window.open(url, "_blank", "noopener,noreferrer");
      appendMessage("result", "projector", "opened projector with saved styles", "broadcast");
    }

    async function copyProjectorUrl() {
      const url = buildConfiguredProjectorUrl();
      await navigator.clipboard.writeText(url);
      appendMessage("result", "projector", "projector URL copied", "broadcast");
    }

    function renderNativeStatus(status) {
      const ok = status && typeof status === "object";
      const regionCount = ok ? Number(status.regionCount || 0) : 0;
      nativeRunning = ok && !!status.loopActive;
      nativeRegionCount = regionCount;
      if (regionCount <= 0) {
        clearRegionResults();
        clearNativeSurfaceMap();
      }
      if (!ok) {
        setNativeStatus("0 region(s) / stopped");
        updateNativeControls();
        return;
      }
      const parts = [
        regionCount + " region(s)",
        status.loopActive ? "running" : "stopped"
      ];
      if (status.overlaysHidden) parts.push("overlays hidden");
      setNativeStatus(parts.join(" / "), nativeRunning ? "running" : "");
      updateNativeControls();
      if (regionBackend === "native") {
        refreshNativeSelectionSafety().catch(() => {});
      }
      if (regionBackend === "native" && regionCount > 0) {
        refreshNativeSurfaceMap().catch(() => {});
      }
    }

    async function refreshNativeProfiles() {
      const select = document.getElementById("nativeProfileSelect");
      if (!select) return;
      try {
        const doc = await api("/game-profiles");
        const profiles = (doc && doc.profiles) || [];
        const activeId = doc && doc.activeId;
        select.innerHTML = "";
        if (!profiles.length) {
          const opt = document.createElement("option");
          opt.value = "";
          opt.textContent = "(no profiles - manage profiles)";
          select.appendChild(opt);
          return;
        }
        for (const profile of profiles) {
          const opt = document.createElement("option");
          opt.value = profile.id;
          opt.textContent = profile.name || profile.id;
          if (profile.id === activeId) opt.selected = true;
          select.appendChild(opt);
        }
      } catch (error) {
        /* leave the select as-is on failure */
      }
    }

    function setNativeStatus(text, tone = "") {
      const el = document.getElementById("nativeEngineStatus");
      if (!el) return;
      el.textContent = text;
      el.classList.toggle("running", tone === "running");
      el.classList.toggle("error", tone === "error");
    }

    function renderNativeSelectionSafety(safety, fallbackMessage = "") {
      const box = document.getElementById("nativeSelectionSafety");
      if (!box) return;
      const text = box.querySelector("span") || box;
      const blocked = safety && safety.canOpenSelector === false;
      if (!blocked && !fallbackMessage) {
        box.classList.add("hidden");
        text.textContent = "";
        return;
      }

      const win = safety && safety.foregroundWindow ? nativeWindowLabel(safety.foregroundWindow) : "";
      const message = fallbackMessage || (safety && safety.message) || "Selector is blocked for the current foreground window.";
      text.textContent = win ? `${message} (${win})` : message;
      box.classList.remove("hidden");
    }

    async function refreshNativeSelectionSafety() {
      if (regionBackend !== "native") return;
      try {
        renderNativeSelectionSafety(await api("/region/native/selection-safety"));
      } catch {
        /* advisory only */
      }
    }

    function updateNativeControls() {
      const select = document.getElementById("nativeSelectButton");
      const start = document.getElementById("nativeStartButton");
      const stop = document.getElementById("nativeStopButton");
      const clear = document.getElementById("nativeClearButton");
      if (select) select.disabled = nativeBusy || nativeRunning;
      if (start) start.disabled = nativeBusy || nativeRunning || nativeRegionCount <= 0;
      if (stop) stop.disabled = nativeBusy || !nativeRunning;
      if (clear) clear.disabled = nativeBusy || nativeRegionCount <= 0;
    }

    async function nativeCall(path, label = "working") {
      if (nativeBusy) return;
      nativeBusy = true;
      setNativeStatus(label);
      updateNativeControls();
      try {
        renderNativeStatus(await postEmpty(path));
      } catch (error) {
        const message = error.message || String(error);
        setNativeStatus("error: " + message, "error");
        renderNativeSelectionSafety(null, message);
      } finally {
        nativeBusy = false;
        updateNativeControls();
      }
    }

    let nativeDisplayInWindow = true;
    let nativeRunning = false;
    let nativeRegionCount = 0;
    let nativeBusy = false;
    let nativeSurfaceMapBusy = false;

    function clearRegionResults() {
      const box = document.getElementById("nativeRegionResults");
      if (box) box.innerHTML = "";
    }

    function clearNativeSurfaceMap() {
      const panel = document.getElementById("nativeSurfaceMap");
      const list = document.getElementById("nativeSurfaceMapList");
      const summary = document.getElementById("nativeSurfaceMapSummary");
      if (panel) panel.classList.add("hidden");
      if (list) list.innerHTML = "";
      if (summary) summary.textContent = "";
    }

    function nativeWindowLabel(win) {
      if (!win) return "desktop";
      const title = String(win.title || "").trim();
      return `${win.processName || "unknown"}${title ? " / " + title : ""}`;
    }

    function nativeRatioText(value) {
      const ratio = Number(value || 0);
      return `${Math.round(Math.max(0, Math.min(1, ratio)) * 100)}%`;
    }

    function appendNativeSurfaceSvg(target, regionMap) {
      const region = regionMap.region || {};
      const layers = Array.isArray(regionMap.layers) ? regionMap.layers : [];
      const svg = document.createElementNS("http://www.w3.org/2000/svg", "svg");
      svg.setAttribute("viewBox", "0 0 100 56");
      svg.setAttribute("preserveAspectRatio", "none");
      const bg = document.createElementNS("http://www.w3.org/2000/svg", "rect");
      bg.setAttribute("x", "0");
      bg.setAttribute("y", "0");
      bg.setAttribute("width", "100");
      bg.setAttribute("height", "56");
      bg.setAttribute("fill", "rgba(15, 23, 42, 0.28)");
      svg.appendChild(bg);

      function pct(value, size, total) {
        if (!Number.isFinite(value) || !Number.isFinite(size) || !Number.isFinite(total) || total <= 0) return 0;
        return Math.max(0, Math.min(size, value / total * size));
      }

      [...layers].reverse().forEach((layer) => {
        const inter = layer.intersection || {};
        const x = pct(Number(inter.x || 0) - Number(region.x || 0), 100, Number(region.width || 1));
        const y = pct(Number(inter.y || 0) - Number(region.y || 0), 56, Number(region.height || 1));
        const w = pct(Number(inter.width || 0), 100, Number(region.width || 1));
        const h = pct(Number(inter.height || 0), 56, Number(region.height || 1));
        if (w <= 0 || h <= 0) return;
        const rect = document.createElementNS("http://www.w3.org/2000/svg", "rect");
        rect.setAttribute("x", String(x));
        rect.setAttribute("y", String(y));
        rect.setAttribute("width", String(w));
        rect.setAttribute("height", String(h));
        rect.setAttribute("rx", "1.2");
        rect.setAttribute("fill", layer.isOwnProcess
          ? "rgba(239, 68, 68, 0.34)"
          : layer.isDominant
            ? "rgba(34, 197, 94, 0.38)"
            : "rgba(56, 189, 248, 0.25)");
        rect.setAttribute("stroke", layer.isOwnProcess
          ? "rgba(239, 68, 68, 0.82)"
          : layer.isDominant
            ? "rgba(34, 197, 94, 0.86)"
            : "rgba(56, 189, 248, 0.62)");
        rect.setAttribute("stroke-width", layer.isDominant ? "1.2" : "0.7");
        const title = document.createElementNS("http://www.w3.org/2000/svg", "title");
        title.textContent = `${nativeWindowLabel(layer.window)} ${nativeRatioText(layer.visibleRatio)}`;
        rect.appendChild(title);
        svg.appendChild(rect);
      });

      const border = document.createElementNS("http://www.w3.org/2000/svg", "rect");
      border.setAttribute("x", "0.6");
      border.setAttribute("y", "0.6");
      border.setAttribute("width", "98.8");
      border.setAttribute("height", "54.8");
      border.setAttribute("fill", "none");
      border.setAttribute("stroke", "rgba(226, 232, 240, 0.45)");
      border.setAttribute("stroke-width", "1");
      svg.appendChild(border);
      target.appendChild(svg);
    }

    function renderNativeSurfaceMap(map) {
      const panel = document.getElementById("nativeSurfaceMap");
      const list = document.getElementById("nativeSurfaceMapList");
      const summary = document.getElementById("nativeSurfaceMapSummary");
      if (!panel || !list || !summary) return;
      const regions = map && Array.isArray(map.regions) ? map.regions : [];
      if (regions.length === 0) {
        clearNativeSurfaceMap();
        return;
      }

      panel.classList.remove("hidden");
      summary.textContent = `${regions.length} region(s)${map.ignoreOwnProcessOverlays ? " / own overlay ignored" : ""}`;
      list.innerHTML = "";
      regions.forEach((regionMap) => {
        const card = document.createElement("div");
        card.className = "native-surface-card";

        const meta = document.createElement("div");
        meta.className = "native-surface-meta";
        const left = document.createElement("span");
        left.textContent = `region ${Number(regionMap.index || 0) + 1} / ctx ${nativeRatioText(regionMap.dominantVisibleRatio)}`;
        const right = document.createElement("span");
        right.textContent = regionMap.occluded
          ? "occluded"
          : regionMap.ownOverlayPresent
            ? `clear / own ${nativeRatioText(regionMap.ownOverlayRatio)}`
            : "clear";
        meta.appendChild(left);
        meta.appendChild(right);

        const key = document.createElement("div");
        key.className = "native-surface-key";
        key.textContent = `window ${regionMap.windowKey || "native|unknown"}\nsurface ${regionMap.surfaceKey || "native|unknown"}`;

        const visual = document.createElement("div");
        visual.className = "native-surface-visual";
        appendNativeSurfaceSvg(visual, regionMap);

        const layers = document.createElement("div");
        layers.className = "native-layer-list";
        (Array.isArray(regionMap.layers) ? regionMap.layers : []).slice(0, 5).forEach((layer) => {
          const row = document.createElement("div");
          row.className = "native-layer-row";
          const name = document.createElement("strong");
          name.textContent = `${layer.isDominant ? "* " : ""}${nativeWindowLabel(layer.window)}${layer.isOwnProcess ? " [verbeam]" : ""}`;
          const ratio = document.createElement("span");
          const rawRatio = nativeRatioText(layer.visibleRatio);
          const contextRatio = nativeRatioText(layer.contextVisibleRatio ?? layer.visibleRatio);
          ratio.textContent = rawRatio === contextRatio ? rawRatio : `${rawRatio}/${contextRatio}`;
          row.appendChild(name);
          row.appendChild(ratio);
          layers.appendChild(row);
        });

        card.appendChild(meta);
        card.appendChild(key);
        card.appendChild(visual);
        card.appendChild(layers);
        list.appendChild(card);
      });
    }

    async function refreshNativeSurfaceMap() {
      if (nativeSurfaceMapBusy || regionBackend !== "native" || nativeRegionCount <= 0) return;
      nativeSurfaceMapBusy = true;
      try {
        const map = await api("/region/native/surface-map?ignoreOwnProcess=true");
        renderNativeSurfaceMap(map);
      } finally {
        nativeSurfaceMapBusy = false;
      }
    }

    function renderRegionResult(message) {
      if (!nativeDisplayInWindow) return;
      const box = document.getElementById("nativeRegionResults");
      if (!box) return;
      const index = message.segmentIndex == null ? 0 : message.segmentIndex;
      const key = message.stableKey || ("region-" + index);
      let card = box.querySelector('[data-region="' + key + '"]');
      if (!card) {
        card = document.createElement("div");
        card.setAttribute("data-region", key);
        card.className = "native-region-card";
        const meta = document.createElement("div");
        meta.className = "nrr-meta";
        const src = document.createElement("div");
        src.className = "nrr-src";
        const tr = document.createElement("div");
        tr.className = "nrr-tr";
        card.appendChild(meta);
        card.appendChild(src);
        card.appendChild(tr);
        box.appendChild(card);
      }
      card.querySelector(".nrr-meta").textContent =
        "region " + (index + 1) + " / " + (message.engine || "") + " " + (message.latencyMs || 0) + "ms" + (message.cacheHit ? " *" : "");
      card.querySelector(".nrr-src").textContent = message.sourceText || "";
      card.querySelector(".nrr-tr").textContent = message.translatedText || "";
    }

    function normalizeShellSettings(settings) {
      const fallback = {
        schemaVersion: 1,
        webView2GpuMode: "balanced",
        webView2AdditionalArgs: "",
        browserRegionQuality: "balanced",
        webView2GpuModes: [
          { id: "saver", label: "VRAM Saver", description: "Disable WebView2 GPU paths.", restart: "restart" },
          { id: "balanced", label: "Balanced preview", description: "Reduce GPU compositing while preserving preview.", restart: "restart" },
          { id: "performance", label: "Performance", description: "Keep GPU acceleration for preview-heavy use.", restart: "restart" },
          { id: "custom", label: "Custom", description: "Use custom Chromium flags.", restart: "restart" }
        ],
        browserRegionQualities: [
          { id: "saver", label: "720p / 30fps", description: "Lowest memory use.", width: 1280, height: 720, fps: 30 },
          { id: "balanced", label: "1080p / 30fps", description: "Recommended default.", width: 1920, height: 1080, fps: 30 },
          { id: "ocr", label: "1440p / 30fps", description: "Sharper OCR preview.", width: 2560, height: 1440, fps: 30 },
          { id: "max", label: "4K / 60fps", description: "Maximum preview quality.", width: 3840, height: 2160, fps: 60 }
        ],
        requiresRestart: false
      };
      return { ...fallback, ...(settings || {}) };
    }

    function populateShellSelect(select, items, value, labelFor) {
      if (!select) return;
      select.innerHTML = "";
      for (const item of items || []) {
        const option = document.createElement("option");
        option.value = item.id;
        option.textContent = labelFor ? labelFor(item) : item.label || item.id;
        option.title = item.description || "";
        select.appendChild(option);
      }
      const values = new Set(Array.from(select.options).map(option => option.value));
      select.value = values.has(value) ? value : (select.options[0]?.value || "");
    }

    function renderShellSettings(settings) {
      const normalized = normalizeShellSettings(settings);
      state.shellSettings = normalized;
      populateShellSelect(
        $("shellWebView2GpuMode"),
        normalized.webView2GpuModes,
        normalized.webView2GpuMode,
        item => item.label || item.id);
      populateShellSelect(
        $("shellBrowserRegionQuality"),
        normalized.browserRegionQualities,
        normalized.browserRegionQuality,
        item => item.label || item.id);
      if ($("shellWebView2AdditionalArgs")) {
        $("shellWebView2AdditionalArgs").value = normalized.webView2AdditionalArgs || "";
      }
      updateShellSettingsStatus(normalized.requiresRestart
        ? "Saved. Restart the App window to apply WebView2 rendering changes."
        : "Balanced preview and 1080p/30fps are recommended defaults.");
    }

    function updateShellSettingsStatus(message) {
      const status = $("shellSettingsStatus");
      if (status) status.textContent = message;
    }

    async function loadShellSettings() {
      const settings = await api("/shell-settings");
      renderShellSettings(settings);
      return settings;
    }

    function shellSettingsPayloadFromForm() {
      return {
        webView2GpuMode: $("shellWebView2GpuMode")?.value || "balanced",
        webView2AdditionalArgs: $("shellWebView2AdditionalArgs")?.value || "",
        browserRegionQuality: $("shellBrowserRegionQuality")?.value || "balanced"
      };
    }

    async function saveShellSettings() {
      updateShellSettingsStatus("Saving performance settings...");
      const settings = await api("/shell-settings", {
        method: "PUT",
        body: JSON.stringify(shellSettingsPayloadFromForm())
      });
      renderShellSettings(settings);
      appendMessage("result", "performance", "settings saved", settings.requiresRestart ? "restart required" : "ready");
    }

    async function resetShellSettings() {
      updateShellSettingsStatus("Resetting performance settings...");
      const settings = await postEmpty("/shell-settings/reset");
      renderShellSettings(settings);
      appendMessage("result", "performance", "settings reset", "restart required");
    }

    function browserRegionCaptureQuality() {
      const settings = normalizeShellSettings(state.shellSettings);
      const selected = settings.browserRegionQualities.find(item => item.id === settings.browserRegionQuality)
        || settings.browserRegionQualities.find(item => item.id === "balanced")
        || { width: 1920, height: 1080, fps: 30 };
      return {
        width: Math.max(320, Number(selected.width) || 1920),
        height: Math.max(240, Number(selected.height) || 1080),
        fps: Math.max(15, Number(selected.fps) || 30),
        label: selected.label || "1080p / 30fps"
      };
    }

    function initNativeEngine() {
      const select = document.getElementById("nativeSelectButton");
      const start = document.getElementById("nativeStartButton");
      const stop = document.getElementById("nativeStopButton");
      const clear = document.getElementById("nativeClearButton");
      if (!select || !start || !stop || !clear) return;   // region pane markup not present
      select.addEventListener("click", () => {
        clearRegionResults();
        nativeCall("/region/native/select", "selecting").then(startNativeStatusPoll);
      });
      start.addEventListener("click", () => nativeCall("/region/native/start", "starting").then(startNativeStatusPoll));
      stop.addEventListener("click", () => nativeCall("/region/native/stop", "stopping"));
      clear.addEventListener("click", () => {
        clearRegionResults();
        nativeCall("/region/native/clear", "clearing").then(startNativeStatusPoll);
      });
      const displayMode = document.getElementById("nativeDisplayMode");
      if (displayMode) {
        displayMode.addEventListener("change", () => {
          const mode = displayMode.value;
          nativeDisplayInWindow = mode !== "overlay";
          if (!nativeDisplayInWindow) clearRegionResults();
          nativeCall(mode === "window" ? "/region/native/overlays/hide" : "/region/native/overlays/show", "updating display");
        });
      }
      const refreshSurface = document.getElementById("nativeRefreshSurfaceMapButton");
      if (refreshSurface) {
        refreshSurface.addEventListener("click", () => refreshNativeSurfaceMap().catch(() => {}));
      }
      // Backend pill: switch between native (in-process CopyFromScreen) and browser (getDisplayMedia).
      const pill = document.getElementById("regionBackendPill");
      if (pill) {
        pill.querySelectorAll("button").forEach((btn) => {
          btn.addEventListener("click", () => setRegionBackend(btn.dataset.backend));
        });
      }
      applyRegionBackend(regionBackend);
      api("/region/native/status").then((status) => {
        renderNativeStatus(status);
        if (regionBackend === "native") startNativeStatusPoll();
      }).catch(() => {});
      updateNativeControls();
    }

    function connectBroadcast() {
      const protocol = location.protocol === "https:" ? "wss:" : "ws:";
      const socket = new WebSocket(`${protocol}//${location.host}/broadcast`);
      socket.addEventListener("open", () => {
        $("wsDot").classList.add("live");
        $("wsStatus").textContent = "live";
      });
      socket.addEventListener("message", event => {
        const message = JSON.parse(event.data);
        if (message.type !== "translation") {
          return;
        }
        if (message.sourceKind === "region") {
          renderRegionResult(message);
        }
        $("latestSource").textContent = message.source || "-";
        $("latestTarget").textContent = message.target || "-";
        $("latestSourceKind").textContent = message.sourceKind || "text";
        $("latestProvider").textContent = message.provider || "-";
        if (!["region", "ocr"].includes(String(message.sourceKind || "").toLowerCase())) {
          playUiSound("notification");
        }
      });
      socket.addEventListener("close", () => {
        $("wsDot").classList.remove("live");
        $("wsStatus").textContent = "reconnect";
        window.setTimeout(connectBroadcast, 1500);
      });
      socket.addEventListener("error", () => socket.close());
    }

    async function boot() {
      loadAudioSessionPreferences();
      setAudioSessionPollUi();
      updateSelectedAudioSessionPanel();
      updateMemoryRuntimeStatus();
      try {
        const [health, shellSettings, providers, ocrEngines, speechEngines, presets, glossaries, languages, latest] = await Promise.all([
          api("/health"),
          api("/shell-settings"),
          api("/providers"),
          api("/ocr/engines"),
          api("/asr/engines"),
          api("/presets"),
          api("/glossaries"),
          api("/translation/languages"),
          fetch("/broadcast/latest").then(response => response.status === 204 ? null : response.json())
        ]);

        state.promptPresets = presets || [];
        state.translationLanguages = languages || [];
        state.translationProviders = providers || [];
        renderShellSettings(shellSettings);
        populateSelect($("translationProvider"), providers, item => item.name, item => item.name, health.defaultProvider);
        renderTranslationProviders();
        populateOcrEngines(ocrEngines, health.ocr && health.ocr.defaultProvider);
        populateSpeechEngines(speechEngines, health.speech && health.speech.defaultProvider);
        populateLanguageSelect($("source"), state.translationLanguages, health.defaultSource || "auto", true);
        populateLanguageSelect($("target"), state.translationLanguages, health.defaultTarget || "zh-TW");
        populateLanguageDatalist(state.translationLanguages);
        populateSelect($("preset"), presets, item => item.id, item => item.name || item.id, health.defaultMode);
        syncPromptHint();
        populateGlossarySelect(glossaries, "");
        updateMemoryOidcStatusFromHealth(health);

        $("metricProvider").textContent = $("translationProvider").value || "-";
        const selectedProvider = $("translationProvider").value.toLowerCase();
        $("translationModel").value = selectedProvider === "llama-cpp" && health.llamaCpp && health.llamaCpp.model
          ? health.llamaCpp.model
          : health.ollama && health.ollama.model ? health.ollama.model : "";
        await loadTranslationModels();
        updateRuntimeLanguageMetric();
        syncRuntimeQuickControls();
        $("metricOcr").textContent = $("ocrProvider").value || "-";
        $("metricAsr").textContent = $("speechProvider").value || "-";
        $("healthStatus").textContent = "ok";
        $("ocrLanguage").value = health.ocr && health.ocr.defaultLanguage ? health.ocr.defaultLanguage : "ja";
        $("speechLanguage").value = health.speech && health.speech.defaultLanguage ? health.speech.defaultLanguage : "ja";
        applyOcrControlSettings();
        syncOcrSelectTrigger();
        $("metricOcr").textContent = $("ocrProvider").value || "-";
        clearMemoryEditor();
        syncDocumentRuntimeBadges();
        renderOcrOverlayControls();
        setOcrTextCollapsed(true);
        setOcrStructureCollapsed(true);
        setOcrPreviewCollapsed(true);
        updateOcrComposerPreview();
        await completeMemoryOidcCallbackFromUrl();

        if (latest) {
          $("latestSource").textContent = latest.source || "-";
          $("latestTarget").textContent = latest.target || "-";
          $("latestSourceKind").textContent = latest.sourceKind || "text";
          $("latestProvider").textContent = latest.provider || "-";
        }

        const initialMode = initialModeFromUrl();
        if (initialMode) {
          setMode(initialMode);
        }

        appendMessage("result", "system", "Verbeam app ready", "boot");
      } catch (error) {
        $("healthStatus").textContent = "error";
        appendMessage("error", "boot", error.message || String(error));
      }

      connectBroadcast();
      initNativeEngine();
    }

