    // Hover reveal: constrained boxes can force tiny fonts, so temporarily
    // enlarge the hovered block to a readable size. Only ever grows the block
    // (shrinking under the cursor would flicker hover on/off).
    $("ocrComposerOverlay").addEventListener("mouseover", event => {
      const block = event.target instanceof Element ? event.target.closest(".ocr-composer-overlay-block") : null;
      if (!block || block.classList.contains("is-hover-expanded")) {
        return;
      }
      const text = block.querySelector(".ocr-composer-overlay-text");
      const fontPx = text ? Number.parseFloat(text.style.fontSize || "") : 0;
      if (!text || !fontPx || fontPx >= 12.5) {
        return;
      }
      block.classList.add("is-hover-expanded");
      block.dataset.hoverBaseHeight = block.style.height;
      text.dataset.hoverBaseFontSize = text.style.fontSize;
      text.style.fontSize = "13px";
      block.style.height = "auto";
    });
    $("ocrComposerOverlay").addEventListener("mouseout", event => {
      const block = event.target instanceof Element ? event.target.closest(".ocr-composer-overlay-block") : null;
      if (!block || !block.classList.contains("is-hover-expanded")) {
        return;
      }
      if (event.relatedTarget instanceof Element && block.contains(event.relatedTarget)) {
        return;
      }
      block.classList.remove("is-hover-expanded");
      block.style.height = block.dataset.hoverBaseHeight || block.style.height;
      const text = block.querySelector(".ocr-composer-overlay-text");
      if (text) {
        text.style.fontSize = text.dataset.hoverBaseFontSize || "";
      }
      delete block.dataset.hoverBaseHeight;
      if (text) {
        delete text.dataset.hoverBaseFontSize;
      }
    });
