    function loadProjectorConfig() {
      try {
        projPosition.value = window.localStorage.getItem("verbeam.projector.position") || "bottom";
        projScale.value = window.localStorage.getItem("verbeam.projector.scale") || "1.0";
        projFade.value = window.localStorage.getItem("verbeam.projector.fade") || "12";
        projFont.value = window.localStorage.getItem("verbeam.projector.font") || "outfit";
        projColor.value = window.localStorage.getItem("verbeam.projector.color") || "#f7f7f2";
        projColorText.value = projColor.value;
        projBgColor.value = window.localStorage.getItem("verbeam.projector.bgcolor") || "#000000";
        projBgColorText.value = projBgColor.value;
        projBgOpacity.value = window.localStorage.getItem("verbeam.projector.bgopacity") || "48";
        projAlign.value = window.localStorage.getItem("verbeam.projector.align") || "center";
        projShowSource.checked = window.localStorage.getItem("verbeam.projector.source") === "1";
        projBackdrop.checked = window.localStorage.getItem("verbeam.projector.backdrop") !== "0";
        projShadow.checked = window.localStorage.getItem("verbeam.projector.shadow") !== "0";
      } catch {
      }
      updateProjectorPreview();
    }

    function saveProjectorConfig() {
      try {
        window.localStorage.setItem("verbeam.projector.position", projPosition.value);
        window.localStorage.setItem("verbeam.projector.scale", projScale.value);
        window.localStorage.setItem("verbeam.projector.fade", projFade.value);
        window.localStorage.setItem("verbeam.projector.font", projFont.value);
        window.localStorage.setItem("verbeam.projector.color", projColor.value);
        window.localStorage.setItem("verbeam.projector.bgcolor", projBgColor.value);
        window.localStorage.setItem("verbeam.projector.bgopacity", projBgOpacity.value);
        window.localStorage.setItem("verbeam.projector.align", projAlign.value);
        window.localStorage.setItem("verbeam.projector.source", projShowSource.checked ? "1" : "0");
        window.localStorage.setItem("verbeam.projector.backdrop", projBackdrop.checked ? "1" : "0");
        window.localStorage.setItem("verbeam.projector.shadow", projShadow.checked ? "1" : "0");
      } catch {
      }
    }

    function updateProjectorPreview() {
      projScaleValue.textContent = projScale.value;
      projFadeValue.textContent = projFade.value;
      projBgOpacityValue.textContent = projBgOpacity.value;

      let fontStack = 'var(--sans)';
      if (projFont.value === 'jetbrains mono') fontStack = 'var(--mono)';
      else if (projFont.value === 'sans-serif') fontStack = 'sans-serif';
      else if (projFont.value === 'monospace') fontStack = 'monospace';
      modalPreviewBox.style.fontFamily = fontStack;

      modalPreviewTranslation.style.color = projColor.value;
      modalPreviewBox.style.alignItems = projAlign.value === "left" ? "flex-start" : (projAlign.value === "right" ? "flex-end" : "center");
      modalPreviewTranslation.style.textAlign = projAlign.value;
      modalPreviewSource.style.textAlign = projAlign.value;

      modalPreviewBox.classList.toggle("caption-backdrop", projBackdrop.checked);
      const alpha = (parseInt(projBgOpacity.value, 10) / 100).toFixed(2);
      modalPreviewBox.style.setProperty("--preview-bg", hexToRgba(projBgColor.value, alpha));

      modalPreviewSource.classList.toggle("hidden", !projShowSource.checked);

      const shadowStyle = projShadow.checked
        ? "0 2px 8px rgba(0,0,0,0.9)"
        : "none";
      modalPreviewTranslation.style.textShadow = shadowStyle;
      modalPreviewSource.style.textShadow = shadowStyle;
    }

    openProjectorConfigButton.addEventListener("click", () => {
      console.log("[Projector Modal] Settings button clicked.");
      loadProjectorConfig();
      projectorModal.classList.remove("hidden");
      console.log("[Projector Modal] Removed hidden class. Current classList:", projectorModal.className);
    });

    const hideProjectorModal = () => {
      console.log("[Projector Modal] Hiding modal.");
      saveProjectorConfig();
