    });

    const bindColorInputs = (picker, text) => {
      picker.addEventListener("input", () => {
        text.value = picker.value;
        updateProjectorPreview();
      });
      text.addEventListener("input", () => {
        if (/^#[0-9A-F]{6}$/i.test(text.value)) {
          picker.value = text.value;
          updateProjectorPreview();
        }
      });
    };
    bindColorInputs(projColor, projColorText);
    bindColorInputs(projBgColor, projBgColorText);

    [projPosition, projScale, projFade, projFont, projBgOpacity, projAlign, projShowSource, projBackdrop, projShadow].forEach(input => {
