      const params = new URLSearchParams({
        scale: projScale.value,
        position: projPosition.value,
        source: projShowSource.checked ? "1" : "0",
        backdrop: projBackdrop.checked ? "1" : "0",
        fade: projFade.value,
        font: projFont.value,
        color: projColor.value,
        bgcolor: rgbaBg,
        align: projAlign.value,
        shadow: projShadow.checked ? "1" : "0"
      });
      window.open(`${location.origin}/projector?${params.toString()}`, "_blank", "noopener,noreferrer");
      appendMessage("result", "projector", "opened configured /projector", "broadcast");
      hideProjectorModal();
    });

