    $("supplierListGrid").addEventListener("click", async event => {
      const target = event.target instanceof Element ? event.target : event.target?.parentElement;
      const button = target ? target.closest("[data-supplier-action]") : null;
      if (!button || button.disabled || !$("supplierListGrid").contains(button)) {
        return;
      }

      event.preventDefault();
      event.stopPropagation();

      const id = button.dataset.supplierId || "";
      const action = button.dataset.supplierAction || "";
      if (!id) {
        return;
      }

      if (action === "activate") {
        await activateSupplier(id);
      } else if (action === "test") {
        await testSupplier(id, button);
      } else if (action === "fetch") {
        await fetchSupplierModels(id, button);
      } else if (action === "balance") {
        await refreshSupplierBalance(id, button);
      } else if (action === "edit") {
        await openSupplierModal(id);
      } else if (action === "delete") {
        await deleteSupplier(id);
      }
    });
