    }
    $("markRegionExcludeButton").addEventListener("click", () => setRegionExcludeMode(!state.regionExcludeMode));
    $("clearRegionExcludesButton").addEventListener("click", () => {
      state.regionExcludes = [];
      renderRegionExcludes();
      updateRegionFilterSummary();
      saveRegionSettings();
    });
    $("regionDropPatterns").addEventListener("input", () => {
      updateRegionFilterSummary();
      saveRegionSettings();
    });
    state.regionExcludes = (regionSettings.excludes || []).map(exclude => ({ ...exclude }));
    renderRegionExcludes();
    $("regionDropPatterns").value = regionSettings.dropPatterns || "";
    if ($("regionMotionMode")) {
      $("regionMotionMode").checked = !!regionSettings.motionMode;
      $("regionMotionMode").addEventListener("change", () => { updateRegionFilterSummary(); saveRegionSettings(); });
    }
    if ($("regionPreprocess")) {
      if (regionSettings.preprocess) { $("regionPreprocess").value = regionSettings.preprocess; }
      $("regionPreprocess").addEventListener("change", () => { updateRegionFilterSummary(); saveRegionSettings(); });
    }
    updateRegionFilterSummary();
    window.addEventListener("resize", () => {
      scheduleOcrOverlayFit();
      scheduleOcrComposerOverlayFit();
      renderRegionSelection();
    });
    regionVideo.addEventListener("loadedmetadata", () => window.setTimeout(() => {
      setDefaultRegionSelection();
      renderRegionSelection();
    }, 120));
    regionStage.addEventListener("pointerdown", event => {
      if (!state.regionStream) {
        return;
      }

      event.preventDefault();
      regionStage.focus();
      regionStage.setPointerCapture(event.pointerId);
      const point = getRegionPoint(event);
      if (state.regionExcludeMode) {
        state.regionDrag = { mode: "exclude", startPoint: stagePointToNorm(point) };
        return;
      }
      const hit = hitTestSelection(point);
      const startRegion = state.regionSelection ? { ...state.regionSelection } : null;
      if (hit.mode === "move" || hit.mode === "resize") {
        state.regionDrag = {
          mode: hit.mode,
          corner: hit.corner,
          startPoint: stagePointToNorm(point),
          startRegion
        };
        return;
      }

      const norm = stagePointToNorm(point);
      state.regionDrag = { mode: "new", startPoint: norm, startRegion };
      setRegionSelection(null);
    });
    regionStage.addEventListener("pointermove", event => {
      if (state.regionDrag) {
        updateRegionDrag(getRegionPoint(event));
        return;
      }

      if (!state.regionStream) {
        return;
      }

      if (state.regionExcludeMode) {
        regionStage.style.cursor = "crosshair";
        return;
      }

      const hit = hitTestSelection(getRegionPoint(event));
      regionStage.style.cursor = hit.mode === "resize"
        ? (hit.corner === "nw" || hit.corner === "se" ? "nwse-resize" : "nesw-resize")
        : hit.mode === "move" ? "move" : "crosshair";
    });
    regionStage.addEventListener("pointerup", event => {
      if (!state.regionDrag) {
        return;
      }

      updateRegionDrag(getRegionPoint(event));
      const drag = state.regionDrag;
      state.regionDrag = null;
      try {
        regionStage.releasePointerCapture(event.pointerId);
      } catch {
      }
      if (drag.mode === "exclude") {
        if (drag.currentRegion && !regionSelectionTooSmall(drag.currentRegion)) {
          state.regionExcludes.push(drag.currentRegion);
        }
        renderRegionExcludes();
        updateRegionFilterSummary();
        saveRegionSettings();
        if (state.regionSelection) {
          queueRegionAutoSnapshot();
        }
        return;
      }
      saveRegionSettings();
      if (state.regionSelection) {
        queueRegionAutoSnapshot();
      }
    });
    regionStage.addEventListener("pointercancel", event => {
      if (!state.regionDrag) {
        return;
      }

      const drag = state.regionDrag;
      state.regionDrag = null;
      if (drag.mode === "exclude") {
        renderRegionExcludes();
      } else {
        setRegionSelection(drag.startRegion);
      }
      try {
        regionStage.releasePointerCapture(event.pointerId);
      } catch {
      }
    });
    regionStage.addEventListener("keydown", event => {
      if (event.key === "Escape") {
        event.preventDefault();
        if (state.regionDrag) {
          const drag = state.regionDrag;
          state.regionDrag = null;
          if (drag.mode === "exclude") {
            renderRegionExcludes();
          } else {
            setRegionSelection(drag.startRegion);
          }
        } else if (state.regionExcludeMode) {
          setRegionExcludeMode(false);
        } else if (state.regionSelection) {
          setRegionSelection(null);
          saveRegionSettings();
        }
        return;
      }

      if (!state.regionSelection || state.regionDrag || !regionVideo.videoWidth || !regionVideo.videoHeight) {
        return;
      }

      const stepX = (event.shiftKey ? 10 : 1) / regionVideo.videoWidth;
      const stepY = (event.shiftKey ? 10 : 1) / regionVideo.videoHeight;
      const moves = {
        ArrowLeft: [-stepX, 0],
        ArrowRight: [stepX, 0],
        ArrowUp: [0, -stepY],
        ArrowDown: [0, stepY]
      };
      const move = moves[event.key];
      if (!move) {
        return;
      }

      event.preventDefault();
      const region = state.regionSelection;
      setRegionSelection({ ...region, x: region.x + move[0], y: region.y + move[1] });
      saveRegionSettings();
      queueRegionAutoSnapshot();
    });
    imageFile.addEventListener("change", event => {
      const file = event.target.files && event.target.files[0];
      if (file) {
        loadImageFile(file, true).catch(error => appendMessage("error", "file", error.message || String(error)));
      }
    });
    audioFile.addEventListener("change", event => {
      const file = event.target.files && event.target.files[0];
      if (file) {
        loadAudioFile(file, false).catch(error => appendMessage("error", "audio", error.message || String(error)));
      }
    });
    documentFile.addEventListener("change", event => {
      const file = event.target.files && event.target.files[0];
      if (file) {
        setMode("document");
        setDocumentFile(file);
      }
    });
    dropZone.addEventListener("dragover", event => {
      event.preventDefault();
      dropZone.classList.add("dragging");
    });
    dropZone.addEventListener("click", event => {
      if (event.target.closest("#ocrPreviewPanel")) {
        return;
      }

      if (event.target !== imageFile) {
        imageFile.click();
      }
    });
    dropZone.addEventListener("keydown", event => {
      if (event.target.closest("#ocrPreviewPanel")) {
        return;
      }

      if (event.key === "Enter" || event.key === " ") {
        event.preventDefault();
        imageFile.click();
      }
    });
    dropZone.addEventListener("dragleave", () => dropZone.classList.remove("dragging"));
    dropZone.addEventListener("drop", event => {
      event.preventDefault();
      dropZone.classList.remove("dragging");
      const file = getFirstImageFile(event.dataTransfer.files);
      if (!file) {
        appendMessage("error", "image", "drop an image file");
        return;
      }
      loadImageFile(file, true).catch(error => appendMessage("error", "file", error.message || String(error)));
    });

    const ocrBlockSelectLayer = $("ocrBlockSelectLayer");
    if (ocrBlockSelectLayer) {
      // the layer sits inside the drop-zone; swallow clicks so selecting a block
      // doesn't also re-open the image file picker
      ocrBlockSelectLayer.addEventListener("click", event => event.stopPropagation());
      ocrBlockSelectLayer.addEventListener("pointerdown", onBlockLayerPointerDown);
      ocrBlockSelectLayer.addEventListener("pointermove", onBlockLayerPointerMove);
      ocrBlockSelectLayer.addEventListener("pointerup", onBlockLayerPointerUp);
      ocrBlockSelectLayer.addEventListener("pointercancel", onBlockLayerPointerUp);
      ocrBlockSelectLayer.addEventListener("keydown", onBlockLayerKeyDown);
      ocrBlockSelectLayer.addEventListener("mousemove", onBlockLayerHover);
      ocrBlockSelectLayer.addEventListener("mouseleave", onBlockLayerLeave);
      ocrBlockSelectLayer.addEventListener("dblclick", onBlockLayerDoubleClick);
    }

    const ocrReplaceImageButton = $("ocrReplaceImageButton");
    if (ocrReplaceImageButton) {
      ocrReplaceImageButton.addEventListener("click", event => {
        event.stopPropagation();
        imageFile.click();
      });
    }

    const terminalDrawer = $("terminalDrawer");
    if (terminalDrawer) {
      terminalDrawer.addEventListener("toggle", () => {
        if (terminalDrawer.open) {
          clearTerminalDrawerBadge();
        }
      });
    }

    const ocrInspectorOcrTextField = $("ocrInspectorOcrText");
    if (ocrInspectorOcrTextField) {
      ocrInspectorOcrTextField.addEventListener("blur", event => commitInspectorEdit("source", event.target));
    }

    const ocrInspectorTranslationField = $("ocrInspectorTranslation");
    if (ocrInspectorTranslationField) {
      ocrInspectorTranslationField.addEventListener("blur", event => commitInspectorEdit("translation", event.target));
    }

    const ocrSelectionToolbar = $("ocrSelectionToolbar");
    if (ocrSelectionToolbar) {
      // keep clicks inside the toolbar from bubbling to the drop-zone file picker
      ocrSelectionToolbar.addEventListener("click", event => event.stopPropagation());
      // the toolbar floats outside the hovered block; keep it alive while the
      // pointer is on it so hover-triggered actions remain reachable
      ocrSelectionToolbar.addEventListener("pointerenter", cancelToolbarHide);
      ocrSelectionToolbar.addEventListener("pointerleave", () => {
        if (state.selectedBlockIds.size === 0) {
          scheduleToolbarHide();
        }
      });

      const copyButton = $("ocrToolbarCopyButton");
      if (copyButton) {
        copyButton.addEventListener("click", () => toggleToolbarMenu("ocrToolbarCopyMenu"));
      }

      const moreButton = $("ocrToolbarMoreButton");
      if (moreButton) {
        moreButton.addEventListener("click", () => toggleToolbarMenu("ocrToolbarMoreMenu"));
      }

      const copyMenu = $("ocrToolbarCopyMenu");
      if (copyMenu) {
        copyMenu.addEventListener("click", event => {
          const button = event.target instanceof Element ? event.target.closest("[data-copy]") : null;
          if (!button) {
            return;
          }

          ensureToolbarSelection();
          copySelection(button.dataset.copy);
          closeToolbarMenus();
        });
      }

      const moreMenu = $("ocrToolbarMoreMenu");
      if (moreMenu) {
        moreMenu.addEventListener("click", event => {
          const button = event.target instanceof Element ? event.target.closest("[data-action]") : null;
          if (!button) {
            return;
          }

          const action = button.dataset.action;
          if (action === "ignore") {
            ensureToolbarSelection();
            setStatusForSelectedBlocks("ignored");
          } else if (action === "unignore") {
            ensureToolbarSelection();
            setStatusForSelectedBlocks("translated");
          } else if (action === "selectAll") {
            selectAllBlocks();
          } else if (action === "clear") {
            clearBlockSelection();
          }

          closeToolbarMenus();
        });
      }

      const retranslateButton = $("ocrToolbarRetranslateButton");
      if (retranslateButton) {
        retranslateButton.addEventListener("click", () => {
          ensureToolbarSelection();
          retranslateSelectedBlocks();
        });
      }

      const reocrButton = $("ocrToolbarReocrButton");
      if (reocrButton) {
        reocrButton.addEventListener("click", () => {
          ensureToolbarSelection();
          reOcrSelectedBlocks();
        });
      }

      const editButton = $("ocrToolbarEditButton");
      if (editButton) {
        editButton.addEventListener("click", () => {
          ensureToolbarSelection();
          beginBlockInlineEdit(primaryBlockId(), "translation");
        });
      }

      const lockButton = $("ocrToolbarLockButton");
      if (lockButton) {
        lockButton.addEventListener("click", () => {
          ensureToolbarSelection();
          toggleLockSelectedBlocks();
        });
      }

      const rememberButton = $("ocrToolbarRememberButton");
      if (rememberButton) {
        rememberButton.addEventListener("click", () => {
          ensureToolbarSelection();
          rememberSelectedBlockCorrections().catch(error => appendMessage("error", "memory", error.message || String(error)));
        });
      }

      // reposition the fixed pill when the page scrolls or resizes
      const repositionToolbar = () => {
        if (!ocrSelectionToolbar.classList.contains("hidden")) {
          updateSelectionToolbar();
        }
      };
      window.addEventListener("scroll", repositionToolbar, true);
      window.addEventListener("resize", repositionToolbar);

      document.addEventListener("click", () => closeToolbarMenus());
    }

    const ocrBlockActionDialog = $("ocrBlockActionDialog");
    if (ocrBlockActionDialog) {
      const run = $("ocrBlockDialogRun");
      if (run) {
        run.addEventListener("click", () => runBlockDialogPreview());
      }

      const apply = $("ocrBlockDialogApply");
      if (apply) {
        apply.addEventListener("click", () => applyBlockDialog());
      }

      const reject = $("ocrBlockDialogReject");
      if (reject) {
        reject.addEventListener("click", () => closeBlockActionDialog());
      }

      const close = $("ocrBlockDialogClose");
      if (close) {
        close.addEventListener("click", () => closeBlockActionDialog());
      }

      ocrBlockActionDialog.addEventListener("click", event => {
        if (event.target === ocrBlockActionDialog) {
          closeBlockActionDialog();
        }
      });
    }

    documentDropZone.addEventListener("dragover", event => {
      event.preventDefault();
      documentDropZone.classList.add("dragging");
    });
    documentDropZone.addEventListener("dragleave", () => documentDropZone.classList.remove("dragging"));
    documentDropZone.addEventListener("drop", event => {
      event.preventDefault();
      documentDropZone.classList.remove("dragging");
      const file = event.dataTransfer.files && event.dataTransfer.files[0];
      if (!file) {
        appendMessage("error", "document", "drop a document file");
        return;
      }
      setMode("document");
      setDocumentFile(file);
    });
    document.addEventListener("paste", event => {
      const items = Array.from(event.clipboardData ? event.clipboardData.items : []);
      const imageItem = items.find(item => item.kind === "file" && item.type.startsWith("image/"));
      if (!imageItem) {
        return;
      }

      const file = imageItem.getAsFile();
      if (!file) {
        return;
      }

      event.preventDefault();
      loadImageFile(file, true).catch(error => appendMessage("error", "paste", error.message || String(error)));
    });
    document.addEventListener("click", event => {
      try {
        const button = event.target.closest("button");
        if (!button || (button.id && button.id.startsWith("soundTest"))) {
          return;
        }

        playUiSound("click");
      } catch (err) {
        console.error("[Click Listener] failed:", err);
      }
    }, true);
    window.addEventListener("beforeunload", () => stopRegionCapture(false));

    initializeSidebarToggle();
    initializeLayoutResizing();
    initializeAppearanceControls();
    loadWorkspaceTabsPreference();
    syncSoundControls();
    initializeRuntimeToggle();
    const bootInitialMode = initialModeFromUrl();
    if (bootInitialMode) {
      setMode(bootInitialMode);
    } else {
      setMode("text");
    }
    boot();
  </script>
</body>
</html>
""";
}
